// WebAZ — Vanilla JS SPA
// 路由：hash-based (#shop, #orders, #seller, #order/ord_xxx)

// 2026-05-22 audit P1：客户端错误上报（轻量 + throttle 防滥用）
let _errorReportLast = 0
function reportError(message, stack) {
  const now = Date.now()
  if (now - _errorReportLast < 1000) return  // 1s 节流，防错误风暴
  _errorReportLast = now
  try {
    fetch('/api/error-report', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message: String(message).slice(0, 500), stack: String(stack || '').slice(0, 2000), url: location.href }),
    }).catch(() => {})
  } catch {}
}
window.addEventListener('error', (e) => reportError(e.message || 'unknown', e.error?.stack))
window.addEventListener('unhandledrejection', (e) => {
  const r = e.reason
  reportError(r?.message || String(r), r?.stack)
})

// ─── 持久化层：localStorage + IndexedDB 双写双读（抗 iOS PWA eviction） ─────
// 现状：api_key 是长效令牌。iOS WebKit 会在 PWA 长期不用后清 localStorage，
// 导致大妈每次开桌面图标都要重新登录。
// 方案：双层冗余 + Storage.persist() + 心跳标记 + 启动期骨架屏静默鉴权。

const IDB_NAME = 'webaz_auth'
const IDB_STORE = 'kv'
function idbOpen() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(IDB_NAME, 1)
    req.onupgradeneeded = () => req.result.createObjectStore(IDB_STORE)
    req.onsuccess = () => resolve(req.result)
    req.onerror = () => reject(req.error)
  })
}
async function idbGet(key) {
  try {
    const db = await idbOpen()
    return await new Promise((resolve) => {
      const tx = db.transaction(IDB_STORE, 'readonly').objectStore(IDB_STORE).get(key)
      tx.onsuccess = () => resolve(tx.result ?? null)
      tx.onerror = () => resolve(null)
    })
  } catch { return null }
}
async function idbSet(key, value) {
  try {
    const db = await idbOpen()
    return await new Promise((resolve) => {
      const tx = db.transaction(IDB_STORE, 'readwrite').objectStore(IDB_STORE).put(value, key)
      tx.onsuccess = () => resolve(true)
      tx.onerror = () => resolve(false)
    })
  } catch { return false }
}
async function idbDel(key) {
  try {
    const db = await idbOpen()
    return await new Promise((resolve) => {
      const tx = db.transaction(IDB_STORE, 'readwrite').objectStore(IDB_STORE).delete(key)
      tx.onsuccess = () => resolve(true)
      tx.onerror = () => resolve(false)
    })
  } catch { return false }
}

// 轻量混淆：XOR + base64，前缀 'wz1:'。防的是 (a) 裸眼+剪贴板，(b) naive 扫 localStorage
// 防不住的：XSS（攻击者能读 _obfUnwrap 代码）、专业逆向。提高了"非定向攻击"的门槛。
const _obfSalt = () => {
  // 用 origin host + 固定常量组合 — 设备/浏览器配文绑定
  return 'WebAZ-v1::' + (location.origin || 'localhost')
}
function _obfWrap(plain) {
  if (!plain) return plain
  const salt = _obfSalt()
  let out = ''
  for (let i = 0; i < plain.length; i++) {
    out += String.fromCharCode(plain.charCodeAt(i) ^ salt.charCodeAt(i % salt.length))
  }
  try { return 'wz1:' + btoa(out) } catch { return plain }
}
function _obfUnwrap(stored) {
  if (!stored || typeof stored !== 'string') return stored
  if (!stored.startsWith('wz1:')) return stored  // 旧明文兼容
  try {
    const raw = atob(stored.slice(4))
    const salt = _obfSalt()
    let out = ''
    for (let i = 0; i < raw.length; i++) {
      out += String.fromCharCode(raw.charCodeAt(i) ^ salt.charCodeAt(i % salt.length))
    }
    return out
  } catch { return null }
}

// 统一存/取/删 api_key（localStorage + IndexedDB 双写、读时双 fallback、轻量混淆）
async function persistApiKey(key) {
  const wrapped = _obfWrap(key)
  try { localStorage.setItem('webaz_key', wrapped) } catch {}
  await idbSet('webaz_key', wrapped)
  await idbSet('webaz_key_set_at', Date.now())
  // 申请 persistent storage（iOS Safari / Chrome / Firefox 都支持）
  // iOS 仍可能拒（取决于使用频率/收藏状态），但申请总好过不申请
  // 2026-06-01 fix(BUG-PWA-NEW): fire-and-forget,不 await
  //   背景:permission prompt 在某些浏览器状态下 pending 不 resolve(自动化测试 / 部分 first-visit
  //   场景),会卡死整个 doLogin 流程 → 后续 navigateIntended 永不执行 → 登录后 UI 不刷新
  //   修复:不阻塞登录流程,允许 persist 在后台慢慢拿
  try { navigator.storage?.persist?.()?.catch(() => {}) } catch {}
}

// 当前域是否拿到了 persistent storage（iOS 7-day eviction 免疫指示）
async function isStoragePersistent() {
  try { return await navigator.storage?.persisted?.() } catch { return false }
}

// ─── WebAuthn / Passkey 前端工具 ────────────────────────────────
// base64url 与 ArrayBuffer 互转（WebAuthn API 用 ArrayBuffer，传输用 base64url）
function _b64uToBuf(s) {
  s = String(s).replace(/-/g, '+').replace(/_/g, '/')
  while (s.length % 4) s += '='
  const bin = atob(s)
  const buf = new Uint8Array(bin.length)
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i)
  return buf.buffer
}
function _bufToB64u(buf) {
  const bytes = new Uint8Array(buf)
  let s = ''
  for (let i = 0; i < bytes.length; i++) s += String.fromCharCode(bytes[i])
  return btoa(s).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}
window.isWebAuthnSupported = () => !!(window.PublicKeyCredential && navigator.credentials?.create)

// 注册一个新的 Passkey（设备生物识别）
window.doRegisterPasskey = async (deviceLabel) => {
  if (!isWebAuthnSupported()) { alert(t('当前设备不支持 Passkey')); return false }
  const start = await POST('/webauthn/register/start', {})
  if (start.error) { alert(start.error); return false }
  const opts = start.options
  // 反序列化 server 给的 base64url 字段
  const publicKey = {
    ...opts,
    challenge: _b64uToBuf(opts.challenge),
    user: { ...opts.user, id: _b64uToBuf(opts.user.id) },
    excludeCredentials: (opts.excludeCredentials || []).map(c => ({ ...c, id: _b64uToBuf(c.id) })),
  }
  let cred
  try { cred = await navigator.credentials.create({ publicKey }) }
  catch (e) { alert(t('注册失败：') + (e.message || e)); return false }
  // 序列化 response
  const response = {
    id: cred.id,
    rawId: _bufToB64u(cred.rawId),
    type: cred.type,
    response: {
      attestationObject: _bufToB64u(cred.response.attestationObject),
      clientDataJSON: _bufToB64u(cred.response.clientDataJSON),
      transports: cred.response.getTransports?.() || [],
    },
    clientExtensionResults: cred.getClientExtensionResults?.() || {},
  }
  const r = await POST('/webauthn/register/finish', { challenge_id: start.challenge_id, response, device_label: deviceLabel || '' })
  if (r.error) { alert(r.error); return false }
  return true
}

// 取 gate token：弹生物识别 → 拿到 60-90s 内一次性 token
window.requestPasskeyGate = async (purpose, purposeData) => {
  if (!isWebAuthnSupported()) throw new Error(t('当前设备不支持 Passkey'))
  const start = await POST('/webauthn/auth/start', { purpose, purpose_data: purposeData })
  if (start.error) throw new Error(start.error)
  const opts = start.options
  const publicKey = {
    ...opts,
    challenge: _b64uToBuf(opts.challenge),
    allowCredentials: (opts.allowCredentials || []).map(c => ({ ...c, id: _b64uToBuf(c.id) })),
  }
  const assertion = await navigator.credentials.get({ publicKey })
  const response = {
    id: assertion.id,
    rawId: _bufToB64u(assertion.rawId),
    type: assertion.type,
    response: {
      authenticatorData: _bufToB64u(assertion.response.authenticatorData),
      clientDataJSON: _bufToB64u(assertion.response.clientDataJSON),
      signature: _bufToB64u(assertion.response.signature),
      userHandle: assertion.response.userHandle ? _bufToB64u(assertion.response.userHandle) : undefined,
    },
    clientExtensionResults: assertion.getClientExtensionResults?.() || {},
  }
  const fin = await POST('/webauthn/auth/finish', { challenge_id: start.challenge_id, response })
  if (fin.error) throw new Error(fin.error)
  return fin.gate_token
}
// #1051 — Schema.org JSON-LD 注入 helper。每次路由切换 route() 会调 setJsonLd(null) 清旧;
// 然后 renderX 在末尾按需调 setJsonLd(obj) 写新。让任何浏览器内 agent / 搜索引擎 在 DOM 里直接读到结构化协议数据,不必爬 HTML 不必走 MCP。
function setJsonLd(obj) {
  try {
    const existing = document.getElementById('webaz-jsonld')
    if (existing) existing.remove()
    if (!obj) return
    const script = document.createElement('script')
    script.type = 'application/ld+json'
    script.id = 'webaz-jsonld'
    script.textContent = JSON.stringify(obj)
    document.head.appendChild(script)
  } catch { /* never break rendering */ }
}

// #1052 — 商家上架/编辑表单 SEO/Agent 友好度评分(零运行时风险,纯前端引导)
// 鼓励商家填全 Schema.org 加分字段:每填一个 + 权重分,显著提高 rich result / agent 命中精度
window.computeSeoScore = function(prefix) {
  // prefix='prd' (create form) | 'ep' (edit form) — 字段 ID 用 prefix-name
  const v = id => (document.getElementById(prefix + '-' + id)?.value || '').trim()
  const n = id => Number(v(id)) || 0
  const checks = []
  // 必填项(不评分,缺则警告)
  checks.push({ name: '商品名称', filled: v('title').length > 0, weight: 'required' })
  checks.push({ name: '商品描述', filled: v('desc').length > 10, weight: 'required' })
  checks.push({ name: '价格', filled: n('price') > 0, weight: 'required' })
  // 高 SEO 价值
  if (prefix === 'prd') {
    const imgCount = (window.state?._addProductImgs?.length) || 0
    checks.push({ name: '商品图片(至少 1 张)', filled: imgCount > 0, weight: 12 })
  } else {
    checks.push({ name: '商品图片', filled: !!document.querySelector('#ep-img-grid img'), weight: 12 })
  }
  checks.push({ name: '分类', filled: v('cat').length > 0, weight: 12 })
  checks.push({ name: '退货天数(>0)', filled: n('return') > 0, weight: 12 })
  checks.push({ name: '备货时效', filled: n('handling') > 0, weight: 10 })
  checks.push({ name: '配送范围', filled: v('ship-regions').length > 0, weight: 8 })
  // 中等 SEO 价值
  checks.push({ name: '规格参数', filled: v('specs').length > 0, weight: 8 })
  checks.push({ name: '质保天数', filled: n('warranty') > 0, weight: 6 })
  checks.push({ name: '退货条件', filled: v('return-cond').length > 0, weight: 6 })
  checks.push({ name: '预计时效', filled: v('est-days').length > 0, weight: 6 })
  // edit form 独有字段(brand/model/i18n)
  if (prefix === 'ep') {
    checks.push({ name: '品牌', filled: v('brand').length > 0, weight: 8 })
    checks.push({ name: '型号', filled: v('model').length > 0, weight: 6 })
    checks.push({ name: '英文标题(跨境)', filled: v('i18n-title-en').length > 0, weight: 4 })
  }
  const requiredMissing = checks.filter(c => c.weight === 'required' && !c.filled).map(c => c.name)
  const scorable = checks.filter(c => c.weight !== 'required')
  const max = scorable.reduce((s, c) => s + c.weight, 0)
  const got = scorable.filter(c => c.filled).reduce((s, c) => s + c.weight, 0)
  const pct = max > 0 ? Math.round((got / max) * 100) : 0
  const missing = scorable.filter(c => !c.filled).map(c => c.name)
  return { pct, missing, requiredMissing, max, got }
}

window.renderSeoScoreBar = function(prefix) {
  const bar = document.getElementById('seo-score-bar-' + prefix)
  if (!bar) return
  const { pct, missing, requiredMissing } = computeSeoScore(prefix)
  let level, color, msg
  if (requiredMissing.length) {
    level = '❌'; color = '#dc2626'; msg = t('必填项缺失: ') + requiredMissing.map(t).join(' / ')
  } else if (pct >= 85) { level = '🌟'; color = '#16a34a'; msg = t('优秀 — 商品对 agent / 搜索引擎完全友好') }
  else if (pct >= 60) { level = '📈'; color = '#0891b2'; msg = t('不错 — 再补几项达到最佳') }
  else if (pct >= 30) { level = '🌱'; color = '#ca8a04'; msg = t('起步阶段,补全信息显著提高曝光') }
  else { level = '⚠️'; color = '#dc2626'; msg = t('信息不全,搜索引擎和 agent 几乎找不到') }
  const missingTip = missing.length ? missing.map(t).join('\n') : ''
  bar.innerHTML = `
    <div style="background:#fff;border:1px solid ${color};border-radius:8px;padding:10px 14px;margin-bottom:14px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
        <span style="font-weight:600;font-size:13px;color:${color}">${level} ${t('SEO / Agent 友好度')}: ${pct}/100</span>
        ${missing.length ? `<span style="font-size:11px;color:#6b7280;cursor:help" title="${escHtml(missingTip)}">${t('还缺')} ${missing.length} ${t('项')} ▾</span>` : ''}
      </div>
      <div style="background:#f3f4f6;border-radius:99px;height:6px;overflow:hidden">
        <div style="background:${color};height:100%;width:${pct}%;transition:width 0.3s"></div>
      </div>
      <div style="font-size:11px;color:#6b7280;margin-top:6px;line-height:1.4">${escHtml(msg)}</div>
    </div>
  `
}

window.setupSeoScoreBar = function(prefix) {
  // 首渲 + 在 form 上挂 input/change 监听器实时刷新
  setTimeout(() => {
    renderSeoScoreBar(prefix)
    const formId = prefix === 'prd' ? 'add-product-form' : 'edit-form-card'
    const form = document.getElementById(formId)
    if (!form || form._seoBound) return
    form._seoBound = true
    const rerender = () => renderSeoScoreBar(prefix)
    form.addEventListener('input', rerender, { passive: true })
    form.addEventListener('change', rerender, { passive: true })
  }, 80)
}

async function loadPersistedApiKey() {
  let raw = null
  try { raw = localStorage.getItem('webaz_key') } catch {}
  if (!raw) {
    raw = await idbGet('webaz_key')
    if (raw) { try { localStorage.setItem('webaz_key', raw) } catch {} }
  }
  return _obfUnwrap(raw)
}
async function clearPersistedApiKey() {
  try { localStorage.removeItem('webaz_key') } catch {}
  await idbDel('webaz_key')
}

// 心跳：标记 PWA 处于"活跃"状态，给 iOS WebKit 续命；同时刷新 last_seen
function heartbeatTokenSync() {
  const ts = Date.now()
  try { localStorage.setItem('webaz_last_seen', String(ts)) } catch {}
  idbSet('webaz_last_seen', ts)  // fire-and-forget
}

// ─── 状态 ────────────────────────────────────────────────────

// NB: var (not const) so `state` is a global property — required for classic
// multi-script split (extracted admin/domain files reference state cross-file).
var state = {
  user: null,
  // 同步 fallback：读 + 解混淆（兼容旧明文 — _obfUnwrap 检测 wz1: 前缀）
  apiKey: _obfUnwrap(localStorage.getItem('webaz_key')) || null,
  unread: 0,
  sse: null,
  authBooted: false,
}

// M7.2.7 / L-2 fix: 优先取后端 /api/profile 返回的 region_max_levels（来自 region_config 实时计算）；
// 仅在缺省时（旧 cache）回退到硬编码 set
