      if (params[0] === 'quota-applications')     return renderAdminQuotaApps(app)
      if (params[0] === 'tokenomics')             return renderAdminTokenomics(app)
      // 新结构：三个聚合 hub + 慈善
      if (params[0] === 'content')                return renderAdminContent(app)
      if (params[0] === 'arbitration')            return renderAdminArbitration(app)
