// Wave F-4: 平台财务报表
async function renderAdminFinance(app) {
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin'); return }
  app.innerHTML = shell(loading$(), 'admin')
  const r = await GET('/admin/finance/monthly?months=12')
  if (r.error) { app.innerHTML = shell(alert$('error', r.error), 'admin'); return }
  const fmt2 = (n) => Number(n || 0).toFixed(2)
  const totals = r.totals
  const monthly = r.monthly || []

  const monthRows = monthly.length === 0
    ? `<tr><td colspan="5" style="padding:14px;text-align:center;color:#9ca3af">${t('暂无数据')}</td></tr>`
    : monthly.map(m => `
        <tr style="border-bottom:1px solid #f3f4f6;font-size:12px">
          <td style="padding:8px;font-weight:600">${m.ym}</td>
          <td style="padding:8px;text-align:right">${fmt2(m.gmv)}</td>
          <td style="padding:8px;text-align:right;color:#16a34a">+${fmt2(m.fee)}</td>
          <td style="padding:8px;text-align:right;color:#dc2626">-${fmt2(m.rewards)}</td>
          <td style="padding:8px;text-align:right;font-weight:700;color:${m.net >= 0 ? '#16a34a' : '#dc2626'}">${m.net >= 0 ? '+' : ''}${fmt2(m.net)}</td>
        </tr>
      `).join('')

  app.innerHTML = shell(`
    <button class="btn btn-gray btn-sm" style="width:auto;margin-bottom:10px" onclick="history.back()">${t('← 返回')}</button>
    <h1 class="page-title">📒 ${t('平台财务')}</h1>

    <div class="card" style="background:linear-gradient(135deg,#ecfdf5,#fff);padding:14px;margin-bottom:10px">
      <div style="font-size:13px;font-weight:600;margin-bottom:8px">${t('累计汇总')} (${t('近')} ${r.months} ${t('月')})</div>
      <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:10px;font-size:12px">
        <div><div style="color:#9ca3af">${t('协议费收入')}</div><div style="font-size:18px;font-weight:700;color:#16a34a">+${fmt2(totals.fee_revenue)} WAZ</div></div>
        <div><div style="color:#9ca3af">${t('平台拨付')}</div><div style="font-size:18px;font-weight:700;color:#dc2626">-${fmt2(totals.reward_expenditure)} WAZ</div></div>
        <div><div style="color:#9ca3af">${t('净额')}</div><div style="font-size:18px;font-weight:700;color:${totals.net >= 0 ? '#16a34a' : '#dc2626'}">${totals.net >= 0 ? '+' : ''}${fmt2(totals.net)} WAZ</div></div>
        <div><div style="color:#9ca3af">${t('累计 GMV')}</div><div style="font-size:18px;font-weight:700;color:#4f46e5">${fmt2(totals.gmv)} WAZ</div></div>
      </div>
      <div style="font-size:11px;color:#9ca3af;margin-top:8px">${t('费率')}: ${t('商家')} ${(r.fee_rate_shop * 100).toFixed(2)}% · ${t('二手')} ${(r.fee_rate_secondhand * 100).toFixed(2)}%</div>
      <div style="font-size:11px;color:#9ca3af">${t('当前 sys_protocol 余额')}: <strong style="color:${totals.sys_protocol_balance < 0 ? '#dc2626' : '#16a34a'}">${fmt2(totals.sys_protocol_balance)} WAZ</strong></div>
      <div style="font-size:10px;color:#d97706;margin-top:6px;padding:6px 8px;background:#fef3c7;border-radius:6px">⚠ ${t('注意：费率按当前 protocol_params 值追溯计算，历史费率变更未单独快照')}</div>
    </div>

    <div class="card" style="padding:0;overflow-x:auto">
      <div style="padding:10px 12px;font-size:13px;font-weight:600;background:#f9fafb;border-bottom:1px solid #e5e7eb">📅 ${t('月度明细')}</div>
      <table style="width:100%;border-collapse:collapse;min-width:480px">
        <thead><tr style="background:#fff;border-bottom:2px solid #e5e7eb;font-size:10px;color:#6b7280;text-transform:uppercase">
          <th style="padding:8px;text-align:left">${t('月份')}</th>
          <th style="padding:8px;text-align:right">GMV</th>
          <th style="padding:8px;text-align:right">${t('协议费')}</th>
          <th style="padding:8px;text-align:right">${t('拨付')}</th>
          <th style="padding:8px;text-align:right">${t('净额')}</th>
        </tr></thead>
        <tbody>${monthRows}</tbody>
      </table>
    </div>
  `, 'admin')
}

