// Wave F-2: 协议参数配置
async function renderAdminParams(app) {
  if (!state.user) { renderLogin(); return }
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin'); return }
  app.innerHTML = shell(loading$(), 'admin')
  const r = await GET('/admin/protocol-params')
  if (r.error) { app.innerHTML = shell(alert$('error', r.error), 'admin'); return }
  const items = r?.items || []
  const CAT_LABEL = () => ({ fee: '💰 ' + t('费率'), reward: '🎁 ' + t('奖励'), limit: '⛔ ' + t('上限'), general: '⚙️ ' + t('通用') })
  const cats = CAT_LABEL()
  const byCategory = {}
  for (const p of items) {
    const c = p.category || 'general'
    if (!byCategory[c]) byCategory[c] = []
    byCategory[c].push(p)
  }
  const sections = Object.entries(byCategory).map(([c, list]) => `
    <div style="margin-bottom:14px">
      <div style="font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px">${cats[c] || c}</div>
      ${list.map(p => {
        const dirty = p.value !== p.default_value
        const rangeHint = p.type === 'number' && (p.min_value != null || p.max_value != null)
          ? `<div style="font-size:10px;color:#9ca3af;margin-top:2px">${t('范围')}: [${p.min_value ?? '−∞'}, ${p.max_value ?? '+∞'}]</div>`
          : ''
        return `
          <div class="card" style="padding:10px 12px;margin-bottom:6px${dirty ? ';border-left:3px solid #d97706' : ''}">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:4px">
              <div style="flex:1;min-width:0">
                <div style="font-family:monospace;font-size:12px;font-weight:600">${escHtml(p.key)}</div>
                <div style="font-size:11px;color:#9ca3af;margin-top:2px">${escHtml(p.description || '')}</div>
                ${rangeHint}
              </div>
              ${dirty ? `<button class="btn btn-outline btn-sm" style="font-size:10px;padding:3px 8px" onclick="resetParam('${escHtml(p.key)}')">↺ ${t('重置')}</button>` : ''}
            </div>
            <div style="display:flex;gap:6px;margin-top:6px">
              <input class="form-control" id="param-${escHtml(p.key)}" value="${escHtml(p.value)}" style="flex:1;font-size:13px;font-family:monospace" data-type="${p.type}">
              <button class="btn btn-primary btn-sm" style="font-size:11px;padding:6px 12px" onclick="saveParam('${escHtml(p.key)}')">${t('保存')}</button>
            </div>
            ${dirty ? `<div style="font-size:10px;color:#9ca3af;margin-top:4px">${t('默认值')}: <code>${escHtml(p.default_value)}</code> · ${t('修改于')} ${fmtTime(p.updated_at)} · <a href="javascript:viewParamHistory('${escHtml(p.key)}')" style="color:#6366f1">${t('历史')} →</a></div>` : ''}
          </div>
        `
      }).join('')}
    </div>
  `).join('')
  app.innerHTML = shell(`
    <button class="btn btn-gray btn-sm" style="width:auto;margin-bottom:10px" onclick="history.back()">${t('← 返回')}</button>
    <h1 class="page-title">⚙️ ${t('协议参数')}</h1>
    <div style="font-size:12px;color:#6b7280;margin-bottom:14px">${t('修改后立即生效，请谨慎调整')}</div>
    ${sections}
  `, 'admin')
}

window.saveParam = async (key) => {
  const inp = document.getElementById('param-' + key)
  if (!inp) return
  const value = inp.value.trim()
  const res = await fetch('/api/admin/protocol-params/' + encodeURIComponent(key), {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + state.apiKey },
    body: JSON.stringify({ value }),
  }).then(r => r.json())
  if (res.error) { alert(res.error); return }
  toast$(t('已保存'))
  renderAdminParams(document.getElementById('app'))
}

window.resetParam = async (key) => {
  if (!confirm(t('重置该参数为默认值？'))) return
  const res = await POST(`/admin/protocol-params/${encodeURIComponent(key)}/reset`, {})
  if (res.error) { alert(res.error); return }
  toast$(t('已重置'))
  renderAdminParams(document.getElementById('app'))
}

// A-3: 查协议参数变更历史
window.viewParamHistory = async (key) => {
  const r = await GET(`/admin/protocol-params/${encodeURIComponent(key)}/history`)
  if (r.error) { alert(r.error); return }
  const items = r?.items || []
  const rows = items.length === 0
    ? `<div style="color:#9ca3af;padding:20px;text-align:center">${t('无变更记录')}</div>`
    : items.map(it => `
        <div style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:12px">
          <div style="display:flex;justify-content:space-between;margin-bottom:2px">
            <span style="color:#374151"><code style="background:#fef2f2;color:#dc2626;padding:1px 4px;border-radius:3px">${escHtml(it.old_value || '—')}</code> → <code style="background:#dcfce7;color:#16a34a;padding:1px 4px;border-radius:3px">${escHtml(it.new_value || '—')}</code></span>
            <span style="font-size:10px;color:#9ca3af">${it.action}</span>
          </div>
          <div style="font-size:10px;color:#9ca3af">${fmtTime(it.created_at)} · @${escHtml(it.changed_by_handle || it.changed_by || '?')}</div>
        </div>`).join('')
  const html = `
    <div class="js-modal" style="background:rgba(0,0,0,0.6);position:fixed;inset:0;z-index:1000;display:flex;align-items:flex-end;justify-content:center" onclick="this.remove()">
      <div style="background:#fff;width:100%;max-width:560px;border-radius:16px 16px 0 0;padding:20px;max-height:70vh;overflow-y:auto" onclick="event.stopPropagation()">
        <h2 style="font-size:16px;font-weight:700;margin-bottom:10px">📜 ${t('变更历史')}: ${escHtml(key)}</h2>
        ${rows}
        <button class="btn btn-gray" style="margin-top:14px;width:100%" onclick="this.closest('[style*=position]').remove()">${t('关闭')}</button>
      </div>
    </div>
  `
  const div = document.createElement('div')
  div.innerHTML = html
  document.body.appendChild(div.firstElementChild)
}

// Contribution / admin-intake workflows (public-ideas, task-proposal inbox/draft,
// build-task quota request/review, operator-claim) → moved to app-contribution.js
// (classic split, slice D). `_qT` now lives there as a global (var), still used by
// the contribution-facts read surface below.

// renderAdminKPI / renderAdminDashboard → moved to app-admin.js (classic split, slice C).

// 注：label 走 getter，避免 module 顶层 t() 一次性绑定后切语言不更新
const TAG_MAP = () => ({
  new:               { icon: '🆕', label: t('新用户'),     bg: '#dbeafe', fg: '#1e40af' },
  suspended:         { icon: '⛔', label: t('已暂停'),     bg: '#fee2e2', fg: '#991b1b' },
  admin:             { icon: '🛡', label: t('管理员'),     bg: '#fee2e2', fg: '#991b1b' },
  arbitrator:        { icon: '⚖',  label: t('仲裁员'),     bg: '#fce7f3', fg: '#9d174d' },
  logistics:         { icon: '🚚', label: t('物流'),       bg: '#dcfce7', fg: '#166534' },
  verifier_pending:  { icon: '⏳', label: t('申请中'),     bg: '#fffbeb', fg: '#92400e' },
  verifier_system:   { icon: '⚙', label: t('系统兜底'),   bg: '#f3e8ff', fg: '#6b21a8' },
  verifier_trial:    { icon: '🌱', label: t('试用审核员'), bg: '#ecfccb', fg: '#365314' },
  verifier_active:   { icon: '✓',  label: t('正式审核员'), bg: '#dbeafe', fg: '#1e40af' },
  login_risk:        { icon: '⚠', label: t('登录风险'),    bg: '#fef2f2', fg: '#dc2626' },
  high_balance:      { icon: '💰', label: t('高余额'),     bg: '#fefce8', fg: '#854d0e' },
  active:            { icon: '⚡', label: t('活跃'),       bg: '#f0fdf4', fg: '#15803d' },
})
function renderTagBadges(tags, max = 3) {
  const visible = tags.slice(0, max)
  const more = tags.length - max
  return visible.map(tg => {
    const m = TAG_MAP()[tg] || { icon: '·', label: tg, bg: '#f3f4f6', fg: '#374151' }
    return `<span style="display:inline-flex;align-items:center;gap:3px;background:${m.bg};color:${m.fg};font-size:11px;padding:2px 6px;border-radius:8px;margin:0 4px 4px 0">${m.icon} ${t(m.label)}</span>`
  }).join('') + (more > 0 ? `<span style="font-size:11px;color:#6b7280">+${more}</span>` : '')
}

// renderAdminSecurity → moved to app-admin.js (classic split, slice C).

async function renderAdminUsers(app, opts = {}) {
  if (!state.user) { renderLogin(); return }
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin-users'); return }
  app.innerHTML = shell(loading$(), 'admin-users')
  const q = opts.q || ''
  const roleFilter = opts.role || state._adminUserRole || ''   // 持久化（跨页跳转时保留）
  const typeFilter = opts.type || state._adminUserType || 'external'   // 默认外部用户
  const regionFilter = opts.region || state._adminUserRegion || ''
  // 一次性消费 _adminUserRole；用户后续切 chip 会清掉
  state._adminUserRole = roleFilter
  const params = new URLSearchParams()
  if (q)            params.append('q', q)
  if (roleFilter)   params.append('role', roleFilter)
  if (typeFilter)   params.append('type', typeFilter)
  if (regionFilter) params.append('region', regionFilter)
  const qs = params.toString()
  const data = await GET('/admin/users' + (qs ? `?${qs}` : ''))
  if (data.error) { app.innerHTML = shell(alert$('error', data.error), 'admin-users'); return }
  // 持久化 filter
  state._adminUserType = typeFilter
  state._adminUserRegion = regionFilter
  const myAdminType = data.my_admin_type || 'root'
  const myAdminScope = data.my_admin_scope || 'global'

  const matchHint = data.match_mode === 'id'    ? t('精确匹配 user_id')
                   : data.match_mode === 'email' ? t('精确匹配 email')
                   : data.match_mode === 'name'  ? t('名称模糊匹配')
                   : ''

  const iconMap = { buyer: '🛍', seller: '🏪', logistics: '🚚', arbitrator: '⚖', verifier: '🔍', admin: '🛡' }
  const regionFlag = { china: '🇨🇳', us: '🇺🇸', eu: '🇪🇺', india: '🇮🇳', singapore: '🇸🇬', global_north: '🌏', global: '🌐' }
  // 紧凑行式：单行 ~48px；hover 加深；点击进详情
  const list = `
    <div class="card" style="padding:0;overflow:hidden">
      ${data.users.length === 0 ? `<div style="text-align:center;color:#9ca3af;padding:30px 0">${t('暂无用户')}</div>` : data.users.map((u, i) => {
        const primaryRole = u.role
        const extraRoles = (u.roles || []).filter(r => r !== primaryRole)
        const isInternalRole = ['admin','verifier','logistics','arbitrator'].includes(primaryRole)
        return `
        <div class="admin-user-row" style="display:flex;align-items:center;gap:8px;padding:10px 12px;${i < data.users.length - 1 ? 'border-bottom:1px solid #f3f4f6;' : ''}cursor:pointer;transition:background 0.1s" onmouseover="this.style.background='#f9fafb'" onmouseout="this.style.background=''">
          <input type="checkbox" class="admin-user-check" data-uid="${u.id}" onclick="event.stopPropagation()" style="width:14px;height:14px;cursor:pointer;flex-shrink:0">
          <div style="flex:1;min-width:0;display:flex;align-items:center;gap:8px" onclick="navigate('#admin/users/${u.id}')">
            <span style="font-size:18px;flex-shrink:0">${iconMap[primaryRole] || '👤'}</span>
            <div style="flex:1;min-width:0">
              <div style="font-size:13px;font-weight:600;display:flex;align-items:center;gap:6px">
                <span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(u.name)}</span>
                ${u.email_verified ? '<span style="font-size:10px;color:#16a34a" title="邮箱已验证">✓</span>' : ''}
                ${u.suspended ? '<span style="font-size:10px;background:#fef2f2;color:#dc2626;padding:1px 6px;border-radius:99px;font-weight:600;flex-shrink:0">⛔</span>' : ''}
                ${isInternalRole ? `<span style="font-size:10px;background:#eef2ff;color:#4338ca;padding:1px 6px;border-radius:99px;font-weight:600;flex-shrink:0">${primaryRole}${u.admin_type === 'root' ? ' 🔱' : u.admin_type === 'regional' ? ' 🌏' : ''}</span>` : ''}
                ${extraRoles.length > 0 ? `<span style="font-size:10px;color:#9ca3af;flex-shrink:0">+${extraRoles.length}</span>` : ''}
              </div>
              <div style="font-size:10px;color:#9ca3af;margin-top:2px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
                <span style="font-family:monospace">${u.id}</span>
                ${u.region ? `<span>${regionFlag[u.region] || ''} ${u.region}${u.admin_scope && u.admin_scope !== 'global' ? ' · scope:' + u.admin_scope : ''}</span>` : ''}
                ${(u.tags || []).slice(0, 2).map(tg => {
                  const m = TAG_MAP()[tg] || { icon: '', label: tg }
                  return `<span>${m.icon} ${t(m.label)}</span>`
                }).join('')}
                ${(u.tags || []).length > 2 ? `<span>+${u.tags.length - 2}</span>` : ''}
              </div>
            </div>
            <span style="color:#cbd5e1;font-size:14px;flex-shrink:0">›</span>
          </div>
        </div>
      `}).join('')}
    </div>
  `

  const batchBar = data.users.length > 0 ? `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:8px 12px;background:#f9fafb;border-radius:8px;margin-bottom:10px">
      <label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:12px;color:#374151">
        <input type="checkbox" id="admin-user-all" onclick="adminUserToggleAll(this.checked)" style="width:16px;height:16px">
        ${t('全选')}
      </label>
      <div style="display:flex;gap:6px">
        <button onclick="adminUserBatch('suspend')" style="background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;padding:4px 10px;border-radius:6px;font-size:11px;cursor:pointer">⛔ ${t('批量暂停')}</button>
        <button onclick="adminUserBatch('resume')" style="background:#f0fdf4;color:#166534;border:1px solid #bbf7d0;padding:4px 10px;border-radius:6px;font-size:11px;cursor:pointer">✓ ${t('批量恢复')}</button>
      </div>
    </div>
  ` : ''

  // 内部 / 外部 tab
  const typeTabs = `
    <div style="display:flex;gap:6px;margin-bottom:10px;border-bottom:1px solid #e5e7eb">
      <button onclick="setAdminUserType('external')" style="background:none;border:none;padding:8px 14px;font-size:13px;cursor:pointer;border-bottom:2px solid ${typeFilter==='external'?'#4f46e5':'transparent'};color:${typeFilter==='external'?'#4f46e5':'#6b7280'};font-weight:${typeFilter==='external'?'600':'400'}">🛍 ${t('外部用户')} <span style="font-size:10px;color:#9ca3af">(${t('买家/卖家')})</span></button>
      <button onclick="setAdminUserType('internal')" style="background:none;border:none;padding:8px 14px;font-size:13px;cursor:pointer;border-bottom:2px solid ${typeFilter==='internal'?'#4f46e5':'transparent'};color:${typeFilter==='internal'?'#4f46e5':'#6b7280'};font-weight:${typeFilter==='internal'?'600':'400'}">🛡 ${t('内部用户')} <span style="font-size:10px;color:#9ca3af">(${t('admin/审核/物流/仲裁')})</span></button>
      <button onclick="setAdminUserType('')" style="background:none;border:none;padding:8px 14px;font-size:13px;cursor:pointer;border-bottom:2px solid ${typeFilter===''?'#4f46e5':'transparent'};color:${typeFilter===''?'#4f46e5':'#6b7280'};font-weight:${typeFilter===''?'600':'400'}">${t('全部')}</button>
    </div>
  `
  // 区域 chip 行
  const regionChip = (val, label) => {
    const on = regionFilter === val
    return `<button onclick="setAdminUserRegion('${val}')" style="padding:4px 10px;border-radius:99px;font-size:11px;border:1px solid ${on?'#4f46e5':'#e5e7eb'};background:${on?'#4f46e5':'#fff'};color:${on?'#fff':'#374151'};cursor:pointer;font-weight:${on?'600':'400'}">${label}</button>`
  }
  const regionChips = `
    <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px">
      ${regionChip('', t('全部区域'))}
      ${regionChip('china', '🇨🇳 ' + t('中国'))}
      ${regionChip('us', '🇺🇸 ' + t('美国'))}
      ${regionChip('eu', '🇪🇺 ' + t('欧盟'))}
      ${regionChip('india', '🇮🇳 ' + t('印度'))}
      ${regionChip('singapore', '🇸🇬 ' + t('新加坡'))}
      ${regionChip('global_north', '🌏 ' + t('其他发达'))}
      ${regionChip('global', '🌐 ' + t('其他'))}
    </div>
  `
  // 区域管理员标识 + manage-admins 入口
  const scopeBadge = `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:8px 12px;background:#eef2ff;border:1px solid #c7d2fe;color:#3730a3;border-radius:8px;font-size:11px;margin-bottom:10px">
      <span>${myAdminType === 'root' ? '🔱 ' + t('Root admin · 可管理全部用户') : '🌏 ' + t('Regional admin · 仅管理 ') + myAdminScope + ' ' + t('区域用户')}</span>
      <a href="#admin/manage-admins" style="color:#3730a3;font-weight:600;text-decoration:none">${t('管理员账号')} →</a>
    </div>
  `

  app.innerHTML = shell(`
    <h1 class="page-title">👥 ${t('用户管理')}</h1>
    ${scopeBadge}
    ${typeTabs}
    ${regionChips}
    <div style="display:flex;gap:8px;margin-bottom:8px">
      <input class="form-control" id="admin-user-q" placeholder="${t('搜索 user_id / email / 名称')}" value="${escHtml(q)}" style="flex:1;font-size:13px" onkeydown="if(event.key==='Enter')doAdminUserSearch()">
      <select class="form-control" id="admin-user-role" style="width:auto;font-size:13px">
        <option value="">${t('全部角色')}</option>
        ${typeFilter !== 'external' ? `
          <option value="admin"      ${roleFilter==='admin'?'selected':''}>${t('管理员')}</option>
          <option value="verifier"   ${roleFilter==='verifier'?'selected':''}>${t('审核员')}</option>
          <option value="logistics"  ${roleFilter==='logistics'?'selected':''}>${t('物流')}</option>
          <option value="arbitrator" ${roleFilter==='arbitrator'?'selected':''}>${t('仲裁员')}</option>
        ` : ''}
        ${typeFilter !== 'internal' ? `
          <option value="buyer"      ${roleFilter==='buyer'?'selected':''}>${t('买家')}</option>
          <option value="seller"     ${roleFilter==='seller'?'selected':''}>${t('卖家')}</option>
        ` : ''}
      </select>
      <button class="btn btn-primary btn-sm" style="width:auto" onclick="doAdminUserSearch()">${t('筛选')}</button>
    </div>
    ${matchHint ? `<div style="font-size:11px;color:#6366f1;margin-bottom:10px">🔍 ${matchHint}</div>` : ''}
    <div style="font-size:12px;color:#6b7280;margin-bottom:10px">${t('共')} ${data.users.length} ${t('条结果')}</div>
    <div id="admin-user-msg"></div>
    ${batchBar}
    ${list}
  `, 'admin-users')
}
window.setAdminUserType = (k) => {
  state._adminUserType = k
  state._adminUserRole = ''   // 切类型时重置角色筛选
  renderAdminUsers(document.getElementById('app'), { q: document.getElementById('admin-user-q')?.value?.trim() || '' })
}
window.setAdminUserRegion = (r) => {
  state._adminUserRegion = r
  renderAdminUsers(document.getElementById('app'), { q: document.getElementById('admin-user-q')?.value?.trim() || '' })
}

window.adminUserToggleAll = (checked) => {
  document.querySelectorAll('.admin-user-check').forEach(cb => { cb.checked = checked })
}
window.adminUserBatch = async (action) => {
  const ids = [...document.querySelectorAll('.admin-user-check')].filter(cb => cb.checked).map(cb => cb.dataset.uid)
  if (ids.length === 0) return alert(t('未选中任何用户'))
  const label = action === 'suspend' ? t('暂停') : t('恢复')
  let reason = ''
  if (action === 'suspend') {
    reason = prompt(t('暂停原因（必填，会写入审计）')) || ''
    if (!reason.trim()) return alert(t('需填写原因'))
  }
  if (!confirm(t('确认') + label + ' ' + ids.length + ' ' + t('个用户？'))) return
  let ok = 0, fail = 0
  for (const uid of ids) {
    const path = action === 'suspend' ? `/admin/users/${uid}/suspend` : `/admin/users/${uid}/resume`
    const body = action === 'suspend' ? { reason } : {}
    const r = await POST(path, body)
    if (r?.error) fail++; else ok++
  }
  alert(label + ' ' + t('完成') + ': ' + ok + (fail ? ' · ' + t('失败 ') + fail : ''))
  doAdminUserSearch()
}

window.doAdminUserSearch = () => {
  const q = document.getElementById('admin-user-q')?.value?.trim() || ''
  const role = document.getElementById('admin-user-role')?.value?.trim() || ''
  renderAdminUsers(document.getElementById('app'), { q, role })
}

async function renderAdminUserDetail(app, userId) {
  if (!state.user) { renderLogin(); return }
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin-users'); return }
  app.innerHTML = shell(loading$(), 'admin-users')
  const data = await GET('/admin/users/' + encodeURIComponent(userId) + '/profile')
  if (data.error) { app.innerHTML = shell(alert$('error', data.error), 'admin-users'); return }
  const b = data.basic, w = data.wallet, m = data.moderation, k = data.kpis || {}

  const fmtVal = (v) => v == null || v === '' ? '—' : v
  const fmtWaz = (v) => Number(v ?? 0).toFixed(2)
  const ageDays = Math.floor((Date.now() - new Date(b.created_at).getTime()) / 86400e3)

  const basicSection = `
    <div class="card" style="margin-bottom:16px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:8px">
        <div>
          <div style="font-size:20px;font-weight:700">${escHtml(b.name)}</div>
          <div style="font-size:11px;color:#9ca3af;margin-top:2px">${b.id}</div>
        </div>
        <div style="text-align:right;font-size:11px;color:#6b7280">
          ${t('注册')} ${ageDays} ${t('天前')}<br>
          ${b.updated_at ? `${t('最近')} ${fmtTime(b.updated_at)}` : ''}
        </div>
      </div>
      <div style="margin-bottom:12px">${renderTagBadges(data.tags || [], 99)}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:13px">
        <div><span style="color:#6b7280">📧 ${t('邮箱')}</span>: ${b.email ? escHtml(b.email) + (b.email_verified ? ' ✓' : '') : `<span style="color:#9ca3af">—</span>`}</div>
        <div><span style="color:#6b7280">📱 ${t('手机')}</span>: ${b.phone ? escHtml(b.phone) : `<span style="color:#9ca3af">—</span>`}</div>
        <div><span style="color:#6b7280">🔒 ${t('密码')}</span>: ${b.has_password ? `✓ ${t('已设置')}` : `<span style="color:#9ca3af">${t('未设置')}</span>`}</div>
        <div><span style="color:#6b7280">⭐ reputation</span>: ${fmtVal(b.reputation)}</div>
        <div><span style="color:#6b7280">🔑 API Key</span>: <code style="font-size:11px">${b.api_key_masked}</code></div>
        <div><span style="color:#6b7280">⚠️ ${t('登录失败')}</span>: ${b.failed_attempts}${b.locked_until ? ` (${t('锁定至')} ${fmtTime(b.locked_until)})` : ''}</div>
      </div>
      ${w ? `
      <div style="margin-top:12px;padding-top:12px;border-top:1px solid #f3f4f6;font-size:13px">
        <span style="color:#6b7280">💼 ${t('钱包')}</span>:
        <strong style="color:#059669">${fmtWaz(w.balance)} WAZ</strong>
        <span style="color:#6b7280;margin-left:8px">${t('质押')}: ${fmtWaz(w.staked)}</span>
        <span style="color:#6b7280;margin-left:8px">${t('托管')}: ${fmtWaz(w.escrowed)}</span>
        <span style="color:#6b7280;margin-left:8px">${t('累计赚')}: ${fmtWaz(w.earned)}</span>
      </div>` : ''}
      ${m?.suspended ? `
      <div style="margin-top:12px;padding:8px 12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px;color:#991b1b">
        ⛔ ${t('已暂停')} · ${escHtml(m.reason || '')} · ${t('操作者')}: ${escHtml(m.suspended_by || '')} · ${fmtTime(m.suspended_at || '')}
      </div>` : ''}
    </div>`

  // 角色 section
  const rolesSection = `
    <div class="card" style="margin-bottom:16px">
      <div style="font-weight:600;margin-bottom:8px">🎭 ${t('角色 & 权限')}</div>
      <div style="font-size:13px;margin-bottom:6px"><span style="color:#6b7280">${t('当前激活')}</span>: <strong>${b.role}</strong></div>
      <div style="font-size:13px;margin-bottom:8px"><span style="color:#6b7280">${t('全部角色')}</span>: ${(b.roles || []).map(r => `<span style="font-size:11px;background:#f3f4f6;padding:2px 6px;border-radius:8px;margin-right:4px">${r}</span>`).join('')}</div>
      <div style="font-size:13px;padding-top:8px;border-top:1px solid #f3f4f6">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
          <span><span style="color:#6b7280">🎯 ${t('L1 分享权限')}</span>: ${b.can_l1_share ? `<span style="color:#16a34a">✓ ${t('可拿分享佣金')}</span>` : `<span style="color:#9ca3af">${t('不可')}</span>`}</span>
        </div>
        <div style="display:flex;gap:4px;font-size:11px">
          <button class="btn btn-outline btn-sm" style="font-size:11px;padding:3px 6px;flex:1${b.l1_share_override===1?';background:#dcfce7':''}" onclick="doL1ShareOverride('${b.id}',1)">${t('强制允许')}</button>
          <button class="btn btn-outline btn-sm" style="font-size:11px;padding:3px 6px;flex:1${b.l1_share_override===0?';background:#f3f4f6':''}" onclick="doL1ShareOverride('${b.id}',0)">${t('Auto')}</button>
          <button class="btn btn-outline btn-sm" style="font-size:11px;padding:3px 6px;flex:1${b.l1_share_override===-1?';background:#fee2e2':''}" onclick="doL1ShareOverride('${b.id}',-1)">${t('强制禁止')}</button>
        </div>
        <div style="font-size:10px;color:#9ca3af;margin-top:4px">${t('Auto = 完成订单自动 verified；强允/强禁 = admin override')}</div>
      </div>
    </div>`

  // KPI sections
  const kpiCards = (items) => kpiGrid(items)
  let kpiSection = ''
  if (k.seller) {
    kpiSection += `<div style="font-size:13px;color:#6b7280;margin-bottom:8px">🏪 ${t('卖家')}</div>` + kpiCards([
      { label: t('商品总数'), value: k.seller.products_total },
      { label: t('在售'), value: k.seller.products_active },
      { label: t('累计销售'), value: fmtWaz(k.seller.total_sales), unit: 'WAZ' },
    ]) + kpiCards([
      { label: t('完成订单'), value: k.seller.orders_completed },
      { label: t('争议被告'), value: k.seller.disputes_as_defendant },
      { label: t('仲裁判输'), value: k.seller.disputes_lost },
    ])
  }
  if (k.buyer) {
    kpiSection += `<div style="font-size:13px;color:#6b7280;margin-bottom:8px">🛍 ${t('买家')}</div>` + kpiCards([
      { label: t('完成订单'), value: k.buyer.orders_completed },
      { label: t('累计消费'), value: fmtWaz(k.buyer.total_spent), unit: 'WAZ' },
      { label: t('最近订单'), value: k.buyer.last_order_at ? fmtTime(k.buyer.last_order_at) : '—' },
    ])
  }
  if (k.verifier) {
    const v = k.verifier
    kpiSection += `<div style="font-size:13px;color:#6b7280;margin-bottom:8px">🔍 ${t('审核员')} ${v.is_system ? '⚙ ' + t('系统兜底') : ''}</div>` + kpiCards([
      { label: t('Tier'), value: v.tier },
      { label: t('今日剩余'), value: `${v.remaining}/${v.daily_quota}` },
      { label: t('正确率'), value: v.accuracy },
    ]) + kpiCards([
      { label: t('累计正确'), value: v.tasks_correct },
      { label: t('错误 180d'), value: v.error_count_180d },
      { label: t('验证权'), value: v.verify_rights },
    ])
  }
  if (k.logistics) {
    kpiSection += `<div style="font-size:13px;color:#6b7280;margin-bottom:8px">🚚 ${t('物流')}</div>` + kpiCards([
      { label: t('配送总数'), value: k.logistics.deliveries_total },
      { label: t('完成数'), value: k.logistics.deliveries_completed },
      { label: '—', value: '—' },
    ])
  }

  // ─── 操作面板（分组 + inline form）
  const isSelf = b.id === state.user?.id
  const userRoles = b.roles || []
  const allRoleOpts = [
    { id: 'buyer',      icon: '🛍', label: t('买家') },
    { id: 'seller',     icon: '🏪', label: t('卖家') },
    { id: 'logistics',  icon: '🚚', label: t('物流') },
    { id: 'arbitrator', icon: '⚖',  label: t('仲裁员') },
    { id: 'verifier',   icon: '🔍', label: t('审核员') },
    { id: 'admin',      icon: '🛡', label: t('管理员') },
  ]

  // 账户控制组
  const acctGroup = `
    <div class="card" style="margin-bottom:12px">
      <div style="font-size:14px;font-weight:600;margin-bottom:10px">🔐 ${t('账户控制')}</div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:10px">${t('状态')}: ${m?.suspended ? `<span style="color:#dc2626">⛔ ${t('已暂停')}</span>` : `<span style="color:#16a34a">✓ ${t('正常')}</span>`}</div>
      <div style="display:flex;flex-wrap:wrap;gap:6px">
        ${m?.suspended
          ? `<button class="btn btn-outline btn-sm" style="font-size:12px" onclick="doUnsuspend('${b.id}')">${t('解除暂停')}</button>`
          : `<button class="btn btn-outline btn-sm" style="font-size:12px;color:#dc2626;border-color:#dc2626" onclick="toggleInline('frm-suspend')" ${isSelf?'disabled title="不能暂停自己"':''}>⛔ ${t('暂停账户')}</button>`}
        ${b.failed_attempts > 0 || b.locked_until
          ? `<button class="btn btn-outline btn-sm" style="font-size:12px" onclick="doResetFailedAttempts('${b.id}')">🔓 ${t('清除登录失败')}</button>` : ''}
      </div>
      <div id="frm-suspend" style="display:none;margin-top:10px;padding:12px;background:#fafafa;border:1px solid #e5e7eb;border-radius:8px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">⛔ ${t('暂停账户')}</div>
        <textarea class="form-control" id="suspend-reason" rows="3" placeholder="${t('原因（必填）')}" style="font-size:13px"></textarea>
        <div style="font-size:11px;color:#dc2626;margin:6px 0">⚠ ${t('暂停后用户所有 API 请求被拒绝')}</div>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-suspend')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px;background:#dc2626;border-color:#dc2626" onclick="doSuspendInline('${b.id}')">${t('确认暂停')}</button>
        </div>
      </div>
    </div>`

  // 角色管理组
  const isAdminTarget = userRoles.includes('admin')
  const rolesGroup = `
    <div class="card" style="margin-bottom:12px">
      <div style="font-size:14px;font-weight:600;margin-bottom:8px">🎭 ${t('角色管理')}</div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:10px">${t('当前激活')}: <strong>${b.role}</strong></div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:6px">${t('持有角色（勾选所有该用户应有的角色）')}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:10px" id="role-checkboxes">
        ${allRoleOpts.map(r => {
          const checked = userRoles.includes(r.id)
          const dangerLabel = r.id === 'admin' ? ` <span style="color:#dc2626;font-size:11px">（${t('危险')}）</span>` : ''
          const selfBlock = isSelf && r.id === 'admin' && checked
          return `
            <label style="display:flex;align-items:center;gap:6px;padding:6px 8px;border:1px solid #e5e7eb;border-radius:6px;font-size:13px;cursor:${selfBlock?'not-allowed':'pointer'};${checked?'background:#eff6ff':''}">
              <input type="checkbox" value="${r.id}" ${checked?'checked':''} ${selfBlock?'disabled':''} data-role="${r.id}">
              ${r.icon} ${t(r.label)}${dangerLabel}
            </label>`
        }).join('')}
      </div>
      ${isSelf && isAdminTarget ? `<div style="font-size:11px;color:#6b7280;margin-bottom:6px">${t('不能撤销自己的管理员角色')}</div>` : ''}
      <button class="btn btn-primary btn-sm" style="font-size:12px" onclick="doSaveRoles('${b.id}','${escHtml(b.name)}')">${t('保存角色变更')}</button>
    </div>`

  // 商家操作组
  const sellerGroup = userRoles.includes('seller') ? `
    <div class="card" style="margin-bottom:12px">
      <div style="font-size:14px;font-weight:600;margin-bottom:8px">🏪 ${t('商家操作')}</div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:6px">
        ${t('在售')}: ${k.seller?.products_active ?? 0} · ${t('已下架')}: ${k.seller?.products_paused ?? 0} · ${t('已删除')}: ${k.seller?.products_deleted ?? 0}
      </div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:10px">
        ${t('商品配额')}: <strong>${k.seller?.products_total ?? 0} / ${k.seller?.max_products ?? 200}</strong>
        · ${t('今日发布')}: <strong>${k.seller?.daily_used ?? 0} / ${k.seller?.daily_limit ?? 20}</strong>
        ${k.seller?.listing_paused ? `· <span style="color:#dc2626">⛔ ${t('已暂停发新品')}</span>` : ''}
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:6px">
        ${k.seller?.products_active > 0 ? `<button class="btn btn-outline btn-sm" style="font-size:12px;color:#dc2626;border-color:#dc2626" onclick="toggleInline('frm-delist-all')">📦 ${t('强制下架全部在售')}</button>` : ''}
        ${k.seller?.listing_paused
          ? `<button class="btn btn-outline btn-sm" style="font-size:12px" onclick="doResumeListing('${b.id}')">▶ ${t('恢复发新品')}</button>`
          : `<button class="btn btn-outline btn-sm" style="font-size:12px;color:#dc2626;border-color:#dc2626" onclick="toggleInline('frm-pause-listing')">⏸ ${t('暂停发新品')}</button>`}
        <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-set-quota')">⚙ ${t('调商品配额')}</button>
      </div>

      <div id="frm-delist-all" style="display:none;margin-top:10px;padding:12px;background:#fafafa;border:1px solid #e5e7eb;border-radius:8px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">📦 ${t('强制下架全部在售商品')} (${k.seller?.products_active ?? 0} ${t('件')})</div>
        <textarea class="form-control" id="delist-reason" rows="3" placeholder="${t('原因（必填）')}" style="font-size:13px"></textarea>
        <div style="font-size:11px;color:#6b7280;margin:6px 0">⚠ ${t('商品状态改为 paused，可后续恢复')}</div>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-delist-all')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px;background:#dc2626;border-color:#dc2626" onclick="doForceDelistAllInline('${b.id}')">${t('确认下架')}</button>
        </div>
      </div>

      <div id="frm-pause-listing" style="display:none;margin-top:10px;padding:12px;background:#fafafa;border:1px solid #e5e7eb;border-radius:8px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">⏸ ${t('暂停发新品')}</div>
        <textarea class="form-control" id="pause-listing-reason" rows="3" placeholder="${t('原因（必填）')}" style="font-size:13px"></textarea>
        <div style="font-size:11px;color:#6b7280;margin:6px 0">${t('暂停后该卖家无法新建/导入商品（现有商品不受影响）')}</div>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-pause-listing')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px;background:#dc2626;border-color:#dc2626" onclick="doPauseListing('${b.id}')">${t('确认暂停')}</button>
        </div>
      </div>

      <div id="frm-set-quota" style="display:none;margin-top:10px;padding:12px;background:#fafafa;border:1px solid #e5e7eb;border-radius:8px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">⚙ ${t('调商品配额')}</div>
        <select class="form-control" id="quota-select" style="font-size:13px;margin-bottom:6px">
          <option value="200"  ${(k.seller?.max_products ?? 200)===200?'selected':''}>200</option>
          <option value="500"  ${k.seller?.max_products===500?'selected':''}>500</option>
          <option value="1000" ${k.seller?.max_products===1000?'selected':''}>1000</option>
        </select>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-set-quota')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px" onclick="doSetProductQuota('${b.id}')">${t('保存')}</button>
        </div>
      </div>
    </div>` : ''

  // 审核员操作组
  const verifierGroup = (userRoles.includes('verifier') && k.verifier && !k.verifier.is_system) ? `
    <div class="card" style="margin-bottom:12px">
      <div style="font-size:14px;font-weight:600;margin-bottom:8px">🔍 ${t('审核员操作')}</div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:10px">
        ${t('当前 Tier')}: <strong>${k.verifier.tier}</strong> (${k.verifier.daily_quota} ${t('单/日')})
        · ${t('累计正确')}: ${k.verifier.tasks_correct} · ${t('错误 180d')}: ${k.verifier.error_count_180d}
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px">
        <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-tier')">⬆ ${t('调整 Tier')}</button>
        <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-v-suspend')">⏸ ${t('暂停审核')}</button>
        <button class="btn btn-outline btn-sm" style="font-size:12px;color:#dc2626;border-color:#dc2626" onclick="toggleInline('frm-v-revoke')">🚫 ${t('撤销审核资格')}</button>
      </div>

      <div id="frm-tier" style="display:none;padding:12px;background:#fafafa;border:1px solid #e5e7eb;border-radius:8px;margin-top:6px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">⬆ ${t('调整 Tier')}</div>
        <select class="form-control" id="tier-select" style="font-size:13px;margin-bottom:6px">
          <option value="trial-1"  ${k.verifier.tier==='trial-1' ?'selected':''}>trial-1 (2 ${t('单/日')})</option>
          <option value="trial-2"  ${k.verifier.tier==='trial-2' ?'selected':''}>trial-2 (5 ${t('单/日')})</option>
          <option value="trial-3"  ${k.verifier.tier==='trial-3' ?'selected':''}>trial-3 (15 ${t('单/日')})</option>
          <option value="active-1" ${k.verifier.tier==='active-1'?'selected':''}>active-1 (30 ${t('单/日')})</option>
          <option value="active-2" ${k.verifier.tier==='active-2'?'selected':''}>active-2 (60 ${t('单/日')})</option>
        </select>
        <div style="font-size:11px;color:#6b7280;margin:6px 0">${t('系统会自动按表现升降，仅特殊情况手动调')}</div>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-tier')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px" onclick="doSaveTier('${b.id}')">${t('保存')}</button>
        </div>
      </div>

      <div id="frm-v-suspend" style="display:none;padding:12px;background:#fafafa;border:1px solid #e5e7eb;border-radius:8px;margin-top:6px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">⏸ ${t('暂停审核资格')}</div>
        <select class="form-control" id="v-suspend-days" style="font-size:13px;margin-bottom:6px">
          <option value="7">7 ${t('天')}</option>
          <option value="14">14 ${t('天')}</option>
          <option value="30">30 ${t('天')}</option>
          <option value="custom">${t('自定义')}</option>
        </select>
        <input class="form-control" id="v-suspend-days-custom" placeholder="${t('自定义天数')}" type="number" min="1" style="font-size:13px;margin-bottom:6px;display:none">
        <textarea class="form-control" id="v-suspend-reason" rows="2" placeholder="${t('原因（可选）')}" style="font-size:13px;margin-bottom:6px"></textarea>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-v-suspend')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px" onclick="doVerifierSuspendInline('${b.id}')">${t('确认暂停')}</button>
        </div>
      </div>

      <div id="frm-v-revoke" style="display:none;padding:12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;margin-top:6px">
        <div style="font-size:13px;font-weight:600;margin-bottom:6px;color:#991b1b">🚫 ${t('撤销审核资格')}</div>
        <div style="font-size:11px;color:#991b1b;margin-bottom:8px">
          ⚠ ${t('不可逆操作')}<br>
          · ${t('3 个月内不能重新申请')}<br>
          · ${t('50% 质押将被没收')}<br>
          · ${t('此账户的审核记录保留')}
        </div>
        <textarea class="form-control" id="v-revoke-reason" rows="3" placeholder="${t('原因（必填）')}" style="font-size:13px;margin-bottom:6px"></textarea>
        <label style="display:flex;align-items:center;gap:6px;font-size:12px;margin-bottom:6px">
          <input type="checkbox" id="v-revoke-confirm"> ${t('我确认了解后果')}
        </label>
        <div style="display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="toggleInline('frm-v-revoke')">${t('取消')}</button>
          <button class="btn btn-primary btn-sm" style="font-size:12px;background:#dc2626;border-color:#dc2626" onclick="doVerifierRevokeInline('${b.id}')">${t('确认撤销')}</button>
        </div>
      </div>
    </div>` : ''

  const opsSection = `
    <h2 style="font-size:15px;font-weight:600;margin:16px 0 8px">⚡ ${t('管理操作')}</h2>
    <div id="user-op-msg" style="margin-bottom:8px"></div>
    ${acctGroup}
    ${rolesGroup}
    ${sellerGroup}
    ${verifierGroup}`

  // ─── 时间轴
  const activitySection = (data.activity || []).length === 0 ? '' : `
    <h2 style="font-size:15px;font-weight:600;margin:16px 0 8px">📋 ${t('最近活动')}</h2>
    <div class="card" style="margin-bottom:16px;padding:0">
      ${data.activity.map(e => `
        <div style="display:flex;gap:10px;padding:10px 14px;border-bottom:1px solid #f3f4f6;font-size:13px">
          <div style="flex-shrink:0;width:24px;font-size:16px;text-align:center">${e.icon}</div>
          <div style="flex:1;min-width:0">
            <div>${escHtml(e.summary)}</div>
            ${e.ref_id ? `<div style="font-size:11px;color:#9ca3af;margin-top:2px">${escHtml(e.ref_type || '')}: ${escHtml(e.ref_id)}</div>` : ''}
          </div>
          <div style="font-size:11px;color:#9ca3af;white-space:nowrap">${fmtTime(e.ts)}</div>
        </div>`).join('')}
    </div>`

  // ─── 风险信号
  const sevColor = { high: '#dc2626', medium: '#d97706', low: '#65a30d' }
  const sevBg    = { high: '#fef2f2', medium: '#fffbeb', low: '#f7fee7' }
  const risksSection = (data.risks || []).length === 0 ? '' : `
    <h2 style="font-size:15px;font-weight:600;margin:16px 0 8px">⚠️ ${t('风险信号')}</h2>
    <div style="margin-bottom:16px">
      ${data.risks.map(r => `
        <div style="background:${sevBg[r.severity] || '#f9fafb'};border-left:3px solid ${sevColor[r.severity] || '#9ca3af'};padding:8px 12px;margin-bottom:6px;border-radius:0 6px 6px 0;font-size:13px">
          <div style="font-weight:600;color:${sevColor[r.severity] || '#374151'}">${escHtml(r.label)}</div>
          <div style="font-size:12px;color:#6b7280;margin-top:2px">${escHtml(r.detail)}</div>
        </div>`).join('')}
    </div>`

  // ─── 审计历史（admin 对此用户的操作）
  const auditSection = (data.audit || []).length === 0 ? '' : `
    <h2 style="font-size:15px;font-weight:600;margin:16px 0 8px">📜 ${t('管理审计')}</h2>
    <div class="card" style="margin-bottom:16px;padding:0">
      ${data.audit.map(a => `
        <div style="display:flex;justify-content:space-between;gap:8px;padding:10px 14px;border-bottom:1px solid #f3f4f6;font-size:13px">
          <div style="flex:1;min-width:0">
            <div><strong>${escHtml(a.action)}</strong> · <span style="color:#6b7280">${escHtml(a.admin_name || a.admin_id || '—')}</span></div>
            ${a.detail && typeof a.detail === 'object' && Object.keys(a.detail).length > 0 ? `<div style="font-size:11px;color:#6b7280;margin-top:2px;font-family:monospace">${escHtml(JSON.stringify(a.detail))}</div>` : ''}
          </div>
          <div style="font-size:11px;color:#9ca3af;white-space:nowrap">${fmtTime(a.created_at)}</div>
        </div>`).join('')}
    </div>`

  app.innerHTML = shell(`
    <div style="margin-bottom:12px"><a href="#admin/users" style="font-size:13px;color:#6b7280;text-decoration:none">← ${t('返回用户列表')}</a></div>
    ${basicSection}
    ${rolesSection}
    ${kpiSection ? `<h2 style="font-size:15px;font-weight:600;margin:16px 0 8px">📊 ${t('使用 KPI')}</h2>${kpiSection}` : ''}
    ${risksSection}
    ${activitySection}
    ${auditSection}
    ${opsSection}
  `, 'admin-users')
}

window.showQuotaApplyForm = () => {
  const el = document.getElementById('quota-apply-form')
  if (el) el.style.display = ''
}

window.doApplyQuotaIncrease = async (nextTier) => {
  const reason = document.getElementById('quota-reason')?.value?.trim() || ''
  const msg = document.getElementById('quota-msg')
  const res = await POST('/seller/apply-quota-increase', { requested_quota: nextTier, reason })
  if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
  if (msg) msg.innerHTML = alert$('success', t('申请已提交，等待管理员审核'))
  setTimeout(() => renderSeller(document.getElementById('app')), 1000)
}

// inline form 工具：toggle 显示
window.toggleInline = (formId) => {
  const el = document.getElementById(formId)
  if (!el) return
  el.style.display = el.style.display === 'none' ? '' : 'none'
}

function showUserOpMsg(html) {
  const msg = document.getElementById('user-op-msg')
  if (msg) msg.innerHTML = html
}

window.doResetFailedAttempts = async (userId) => {
  if (!confirm(t('清除登录失败次数？'))) return
  const res = await POST(`/admin/users/${userId}/reset-failed-attempts`, {})
  if (res.error) return showUserOpMsg(alert$('error', res.error))
  renderAdminUserDetail(document.getElementById('app'), userId)
}

window.doSuspendInline = async (userId) => {
  const reason = document.getElementById('suspend-reason')?.value?.trim()
  if (!reason) return showUserOpMsg(alert$('error', t('请填写暂停原因')))
  const res = await POST(`/admin/users/${userId}/suspend`, { reason })
  if (res.error) return showUserOpMsg(alert$('error', res.error))
  renderAdminUserDetail(document.getElementById('app'), userId)
}

window.doSaveRoles = async (userId, name) => {
  const checked = [...document.querySelectorAll('#role-checkboxes input[type=checkbox]:checked')].map(c => c.value)
  if (checked.length === 0) return showUserOpMsg(alert$('error', t('至少保留一个角色')))
  const res = await POST(`/admin/users/${userId}/set-roles`, { roles: checked })
  if (res.error) return showUserOpMsg(alert$('error', res.error))
  const added   = (res.added   || []).join(', ') || '—'
  const removed = (res.removed || []).join(', ') || '—'
  showUserOpMsg(alert$('success', `${t('角色已更新')} · ${t('新增')}: ${added} · ${t('移除')}: ${removed}`))
  setTimeout(() => renderAdminUserDetail(document.getElementById('app'), userId), 800)
}

window.doForceDelistAllInline = async (userId) => {
  const reason = document.getElementById('delist-reason')?.value?.trim()
  if (!reason) return showUserOpMsg(alert$('error', t('请填写下架原因')))
  const res = await POST(`/admin/users/${userId}/force-delist-all`, { reason })
  if (res.error) return showUserOpMsg(alert$('error', res.error))
  showUserOpMsg(alert$('success', `${t('已下架')} ${res.count} ${t('件商品')}`))
  setTimeout(() => renderAdminUserDetail(document.getElementById('app'), userId), 1000)
}

