function refreshAdminUserContext(userId) {
  if (location.hash.startsWith('#admin/users/')) {
    renderAdminUserDetail(document.getElementById('app'), userId)
  } else {
    renderAdminUsers(document.getElementById('app'))
  }
}

window.doSuspend = async (userId, name) => {
  const reason = prompt(`${t('暂停账户')}「${name}」\n${t('原因（可选）')}`)
  if (reason === null) return
  const res = await POST(`/admin/users/${userId}/suspend`, { reason: reason || null })
  const msg = document.getElementById('admin-user-msg') || document.getElementById('user-op-msg')
  if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
  refreshAdminUserContext(userId)
}

window.doUnsuspend = async (userId) => {
  if (!confirm(t('确认解除暂停？'))) return
  const res = await POST(`/admin/users/${userId}/unsuspend`, {})
  const msg = document.getElementById('admin-user-msg') || document.getElementById('user-op-msg')
  if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
  refreshAdminUserContext(userId)
}

window.showGrantRole = (userId, name, existingRoles) => {
  const all = ['buyer','seller','logistics','arbitrator','verifier','admin']
  const addable = all.filter(r => !existingRoles.includes(r))
  if (addable.length === 0) { alert(t('该用户已拥有全部角色')); return }
  const role = prompt(`${t('为')}「${name}」${t('授予角色')}\n${t('可选')}: ${addable.join(' / ')}`)
  if (!role || !addable.includes(role)) return
  POST(`/admin/users/${userId}/grant-role`, { role }).then(res => {
    const msg = document.getElementById('admin-user-msg') || document.getElementById('user-op-msg')
    if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
    refreshAdminUserContext(userId)
  })
}

async function renderAdminProducts(app, opts = {}) {
  if (!state.user) { renderLogin(); return }
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin'); return }
  app.innerHTML = shell(loading$(), 'admin')
  const status = opts.status || ''
  const qs = status ? `?status=${encodeURIComponent(status)}` : ''
  const data = await GET('/admin/products' + qs)
  if (data.error) { app.innerHTML = shell(alert$('error', data.error), 'admin'); return }
  const statusBadge = (s) => {
    const map = { active: ['#dcfce7','#166534'], paused: ['#fef3c7','#92400e'], deleted: ['#fee2e2','#991b1b'] }
    const [bg, fg] = map[s] || ['#f3f4f6', '#374151']
    return `<span style="background:${bg};color:${fg};padding:2px 8px;border-radius:8px;font-size:11px">${s}</span>`
  }
  const list = data.products.map(p => `
    <div class="card" style="margin-bottom:10px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
        <div style="flex:1;min-width:0">
          <div style="font-weight:600">${escHtml(p.title)}</div>
          <div style="font-size:12px;color:#6b7280;margin-top:2px">${p.price} WAZ · ${t('库存')} ${p.stock} · ${p.category || '—'}</div>
          <div style="font-size:11px;color:#6b7280;margin-top:6px">${t('卖家')}: ${p.seller_id ? `<a href="#u/${p.seller_id}" style="color:#6366f1;text-decoration:none">${escHtml(p.seller_name)} ›</a>` : escHtml(p.seller_name)}</div>
          <div style="font-size:11px;color:#9ca3af;margin-top:2px">${p.id}</div>
        </div>
        <div style="display:flex;flex-direction:column;gap:6px;flex-shrink:0;align-items:flex-end">
          ${statusBadge(p.status)}
          ${p.status === 'active'
            ? `<button class="btn btn-outline btn-sm" style="font-size:11px;padding:4px 8px;color:#dc2626;border-color:#dc2626" onclick="doForceDelist('${p.id}','${escHtml(p.title)}')">${t('强制下架')}</button>`
            : ''}
        </div>
      </div>
    </div>`).join('') || `<div class="empty"><div class="empty-icon">📦</div><div class="empty-text">${t('暂无数据')}</div></div>`
  app.innerHTML = shell(`
    <h1 class="page-title">📦 ${t('商品管理')}</h1>
    <div style="display:flex;gap:8px;margin-bottom:16px">
      <select class="form-control" id="admin-product-status" style="width:auto;font-size:13px" onchange="doAdminProductFilter()">
        <option value=""        ${status===''       ?'selected':''}>${t('全部状态')}</option>
        <option value="active"  ${status==='active' ?'selected':''}>${t('在售')}</option>
        <option value="paused"  ${status==='paused' ?'selected':''}>${t('已下架')}</option>
        <option value="deleted" ${status==='deleted'?'selected':''}>${t('已删除')}</option>
      </select>
      <button class="btn btn-outline btn-sm" style="width:auto" onclick="navigate('#admin')">${t('返回概览')}</button>
    </div>
    <div style="font-size:12px;color:#6b7280;margin-bottom:10px">${t('共')} ${data.products.length} ${t('条结果')}</div>
    <div id="admin-product-msg"></div>
    ${list}
  `, 'admin')
}

window.doAdminProductFilter = () => {
  const status = document.getElementById('admin-product-status')?.value?.trim() || ''
  renderAdminProducts(document.getElementById('app'), { status })
}

window.doForceDelist = async (productId, title) => {
  const reason = prompt(`${t('强制下架商品')}「${title}」\n${t('原因（必填）')}`)
  if (!reason || !reason.trim()) return
  const res = await POST(`/admin/products/${productId}/force-delist`, { reason: reason.trim() })
  const msg = document.getElementById('admin-product-msg')
  if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
  renderAdminProducts(document.getElementById('app'))
}

