      <div style="margin-top:10px;font-size:13px;color:#3f3f46">📝 ${T('两岗均需 onboarding 测试合格分', 'Both roles: onboarding quiz pass score')} ≥ <strong>${esc(j.quiz_pass_score ?? 80)}%</strong></div>
