window.submitIdea = async () => {
  const content = document.getElementById('idea-content')?.value?.trim() || ''
  const contact = document.getElementById('idea-contact')?.value?.trim() || ''
  const msg = document.getElementById('idea-msg')
  if (content.length < 10) { if (msg) msg.innerHTML = `<span style="color:#dc2626">${t('内容至少 10 字')}</span>`; return }
  if (msg) msg.innerHTML = `<span style="color:#6366f1">${t('提交中…')}</span>`
  const hp = document.getElementById('idea-hp')?.value || ''
  const r = await POST('/public-ideas', { content, contact, _hp: hp })
  if (r?.error) { if (msg) msg.innerHTML = `<span style="color:#dc2626">${r.error}</span>`; return }
  if (msg) msg.innerHTML = `<span style="color:#16a34a">✓ ${t('已收到，谢谢！')}</span>`
  setTimeout(() => { document.querySelector('.js-modal')?.remove() }, 1200)
}

