// 健壮复制：先 clipboard API，失败回退 execCommand（不依赖 focus/activation）
// 任何 async 后调用都安全。window.copyText 暴露给 inline onclick handlers
async function copyText(text) {
  // ① 试 navigator.clipboard.writeText（需 secure context + focus）
  if (navigator.clipboard?.writeText) {
    try {
      await navigator.clipboard.writeText(text)
      return true
    } catch (e) { /* fall through to execCommand */ }
  }
  // ② Fallback: 隐藏 textarea + execCommand('copy')（不需 focus / 兼容性最好）
  try {
    const ta = document.createElement('textarea')
    ta.value = text
    ta.setAttribute('readonly', '')
    ta.style.cssText = 'position:fixed;top:0;left:0;width:1px;height:1px;opacity:0;pointer-events:none'
    document.body.appendChild(ta)
    ta.focus()
    ta.select()
    ta.setSelectionRange(0, text.length)
    const ok = document.execCommand('copy')
    document.body.removeChild(ta)
    return ok
  } catch (e) {
    console.warn('[copyText fallback]', e)
    return false
  }
}
window.copyText = copyText

// 通用分享：Web Share API（手机优先）→ 桌面端回退剪贴板
async function webShareOrCopy(opts) {
  const { title, text, url } = opts
  const composed = text ? `${text}\n${url}` : url
  // Mobile: navigator.share (Web Share API)
  if (navigator.share && /Mobi|Android|iPhone/i.test(navigator.userAgent)) {
    try {
      await navigator.share({ title, text, url })
      return 'shared'
    } catch (e) { if (e?.name !== 'AbortError') console.warn('[share]', e) }
  }
  // Desktop / share 失败：复制
  const ok = await copyText(composed)
  return ok ? 'copied' : 'failed'
}

