window.doLogoutAll = async () => {
  const pwd = document.getElementById('la-pwd-inp')?.value || ''
  const msg = document.getElementById('la-msg')
  if (!pwd) { if (msg) msg.innerHTML = alert$('error', t('请输入密码')); return }
  if (msg) msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('处理中...')}</div>`
  const r = await POST('/auth/logout-all', { password: pwd })
  if (r.error) { if (msg) msg.innerHTML = alert$('error', r.error); return }
  // 服务器返回 new_api_key — 立即更新本地双层存储
  await persistApiKey(r.new_api_key)
  state.apiKey = r.new_api_key
  closeModal()
  toast$(t('已全部登出，本设备已切换到新 Key'))
  setTimeout(() => renderProfile(document.getElementById('app')), 500)
}

