// B-5: 创作者评测全局 feed
async function renderReviewsFeed(app) {
  app.innerHTML = shell(loading$(), 'discover')
  const r = await GET('/reviews/recent?limit=50')
  const items = r?.items || []
  const platformIcon = (pl) => ({ youtube: '📺', tiktok: '🎵', xiaohongshu: '📕', bilibili: '🅱', instagram: '📷', twitter: '🐦' }[pl] || '🔗')
  const rows = items.length === 0
    ? `<div style="text-align:center;padding:40px;color:#9ca3af"><div style="font-size:48px">📺</div><div style="font-size:13px;margin-top:8px">${t('暂无评测内容')}</div></div>`
    : items.map(s => {
        let prodImg = ''
        try { const imgs = typeof s.product_images === 'string' ? JSON.parse(s.product_images) : s.product_images; if (Array.isArray(imgs) && imgs[0]) prodImg = imgs[0] } catch {}
        return `
          <div class="card" style="padding:10px 12px;margin-bottom:8px;cursor:pointer" onclick="openExternalReview('${s.id}', '${escHtml(s.external_url || '').replace(/'/g, "\\'")}')">
            <div style="display:flex;gap:10px;align-items:center">
              ${s.thumbnail_url ? `<img src="${escHtml(s.thumbnail_url)}" style="width:80px;height:60px;object-fit:cover;border-radius:6px;flex-shrink:0" onerror="this.style.display='none'">` : `<div style="width:80px;height:60px;background:#f3f4f6;border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:30px;flex-shrink:0">${platformIcon(s.external_platform)}</div>`}
              <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical">${escHtml(s.title || s.external_url || '(无标题)')}</div>
                <div style="font-size:11px;color:#9ca3af;margin-top:2px">@${escHtml(s.owner_handle || s.owner_name || '?')} · ${s.click_count} 👁 · ❤ ${s.like_count || 0} · ${fmtTime(s.created_at)}</div>
                ${s.product_title ? `<div style="font-size:11px;color:#6366f1;margin-top:2px">📦 ${escHtml(s.product_title)} · ${s.product_price} WAZ</div>` : ''}
              </div>
            </div>
          </div>`
      }).join('')
  app.innerHTML = shell(`
    <h1 class="page-title">📺 ${t('创作者评测')}</h1>
    <div style="font-size:12px;color:#6b7280;margin-bottom:14px">${t('全平台最新评测内容 — 点击跳转源平台')}</div>
    ${rows}
  `, 'discover')
}

// 口令入口 — 观众侧从外站口播跳来 + 输入口令 → 跳目标商品页 + 写 30 天 attribution
async function renderAnchorEntry(app) {
  if (!state.user) { renderLogin(); return }
  const q = state._urlQuery || {}
  state._urlQuery = {}
  const presetCode = (q.code || '').toLowerCase().replace(/^@/, '')
  // 读最近成功使用过的口令（localStorage，最多 5 条）
  let recent = []
  try { recent = JSON.parse(localStorage.getItem('webaz_recent_anchors') || '[]') } catch {}
  recent = Array.isArray(recent) ? recent.slice(0, 5) : []

  app.innerHTML = shell(`
    <div style="padding:14px;max-width:560px;margin:0 auto">
      <h1 class="page-title">🎯 ${t('输入口令')}</h1>
      <p style="font-size:12px;color:#6b7280;margin-bottom:14px;line-height:1.6">${t('从外站视频 / 朋友推荐看到的 @ 口令，在这里输入 → 跳到对应商品 + 锁定推荐人 30 天')}</p>
      <div class="card" style="padding:16px">
        <div style="display:flex;gap:6px;align-items:stretch;margin-bottom:8px">
          <input id="anchor-input" class="form-control" placeholder="${t('例：@friend7798')}" value="${escHtml(presetCode)}" style="flex:1;font-family:ui-monospace,Consolas,monospace" onkeydown="if(event.key==='Enter')lookupAnchorAction()">
          <button class="btn btn-primary btn-sm" style="white-space:nowrap;padding:8px 16px" onclick="lookupAnchorAction()">🔍 ${t('查找')}</button>
        </div>
        <div style="font-size:10px;color:#9ca3af;line-height:1.5">${t('口令格式：@账号名+4 位数字 / 字母（如 @friend7798）。无须带 @ 前缀也可。')}</div>
        <div id="anchor-result" style="margin-top:12px"></div>
      </div>

      ${recent.length > 0 ? `
        <div style="margin-top:18px">
          <div style="font-size:12px;font-weight:600;color:#6b7280;margin-bottom:8px">⏰ ${t('最近用过')}</div>
          ${recent.map(c => `
            <div style="display:flex;justify-content:space-between;align-items:center;padding:8px 12px;background:#f9fafb;border-radius:6px;margin-bottom:6px;cursor:pointer" onclick="document.getElementById('anchor-input').value='${escHtml(c)}'; lookupAnchorAction()">
              <span style="font-family:ui-monospace,Consolas,monospace;font-size:13px;color:#4f46e5">@${escHtml(c)}</span>
              <span style="font-size:10px;color:#9ca3af">→</span>
            </div>`).join('')}
        </div>` : ''}
    </div>
  `, 'discover')

  if (presetCode) setTimeout(() => lookupAnchorAction(), 200)
}

window.lookupAnchorAction = async () => {
  const inp = document.getElementById('anchor-input')
  const result = document.getElementById('anchor-result')
  if (!inp || !result) return
  const raw = (inp.value || '').trim().replace(/^@/, '').toLowerCase()
  if (!raw) { result.innerHTML = `<div class="alert alert-warn">${t('请输入口令')}</div>`; return }
  result.innerHTML = `<div style="font-size:12px;color:#6b7280"><span class="spinner"></span> ${t('查找中...')}</div>`

  // Step 1: lookup
  let r
  try { r = await GET('/anchor/' + raw + '/lookup') } catch { r = { found: false } }
  if (!r.found) {
    result.innerHTML = `<div class="alert alert-error">❌ ${t('未找到该口令')} <span style="font-size:11px;color:#9ca3af;display:block;margin-top:4px">${t('请检查拼写，或确认口令未过期')}</span></div>`
    return
  }
  if (r.status === 'retired') {
    result.innerHTML = `<div class="alert alert-warn">⏳ ${t('该口令已归档')}<br><span style="font-size:11px">${t('原推荐人停用此码；可询问其新口令')}</span></div>`
    return
  }

  // Step 2: touch（写 attribution + 锁定 30 天）
  let touchRes
  try { touchRes = await POST('/anchor/' + raw + '/touch', {}) } catch { touchRes = { error: 'touch_failed' } }

  // 保存到 localStorage 历史
  try {
    let cur = []
    try { cur = JSON.parse(localStorage.getItem('webaz_recent_anchors') || '[]') } catch {}
    cur = [raw, ...cur.filter(x => x !== raw)].slice(0, 5)
    localStorage.setItem('webaz_recent_anchors', JSON.stringify(cur))
  } catch {}

  // Step 3: 2026-05-24 富结果卡 — 让用户确认"没找错"再点跳转（不再 1s 自动跳）
  const tier = r.tier_letter ? ` · tier ${r.tier_letter}` : ''
  // 推荐人区块（达人信息）
  const ownerBlock = r.owner ? `
    <div style="display:flex;align-items:center;gap:10px;padding:12px;background:#eef2ff;border-radius:8px;margin-bottom:10px">
      <div style="font-size:28px">👤</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:14px;font-weight:700;color:#1f2937">${escHtml(r.owner.name || raw)}${r.owner.handle ? ` <span style="font-size:11px;color:#6366f1;font-weight:500">@${escHtml(r.owner.handle)}</span>` : ''}</div>
        <div style="font-size:11px;color:#6b7280;margin-top:2px">
          ${r.owner.follower_count > 0 ? `👥 ${r.owner.follower_count} ${t('关注')}` : ''}
          ${r.owner.total_likes_received > 0 ? ` · ❤️ ${r.owner.total_likes_received} ${t('收赞')}` : ''}
          ${r.tier_letter ? ` · 🏅 tier ${r.tier_letter}` : ''}
        </div>
      </div>
    </div>` : ''
  // 推荐指数（基于 recommend_count + completion + likes + avg_rating）
  const calcIndex = (p) => {
    const rec = Number(p.recommend_count || 0)
    const compl = Number(p.completion_count || 0)
    const likes = Number(p.total_likes || 0)
    const avg = Number(p.avg_rating || 0)
    // 推荐指数 0-10：avg_rating 占 50% + 推荐人数 log 占 30% + 完成单数 log 占 20%
    if (compl === 0) return null
    const rateScore = avg * 2  // 5 星 → 10 分
    const recScore = Math.min(10, Math.log10(rec + 1) * 5)
    const complScore = Math.min(10, Math.log10(compl + 1) * 4)
    return (rateScore * 0.5 + recScore * 0.3 + complScore * 0.2).toFixed(1)
  }
  // 商品区块
  const productBlock = (r.product) ? (() => {
    const p = r.product
    let img = ''
    try {
      const imgs = typeof p.images === 'string' ? JSON.parse(p.images) : p.images
      if (Array.isArray(imgs) && imgs[0]) img = String(imgs[0])
    } catch {}
    const idx = calcIndex(p)
    const idxColor = idx == null ? '#9ca3af' : idx >= 8 ? '#dc2626' : idx >= 6 ? '#f59e0b' : '#6b7280'
    return `
      <div style="border:1px solid #e5e7eb;border-radius:8px;padding:12px;margin-bottom:10px">
        <div style="display:flex;gap:10px;margin-bottom:10px">
          ${img ? `<img src="${img}" style="width:64px;height:64px;object-fit:cover;border-radius:6px;flex-shrink:0">` : `<div style="width:64px;height:64px;background:#f3f4f6;border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:24px;color:#9ca3af;flex-shrink:0">📦</div>`}
          <div style="flex:1;min-width:0">
            <div style="font-size:14px;font-weight:600;color:#1f2937;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden">${escHtml(p.title)}</div>
            <div style="font-size:17px;font-weight:800;color:#dc2626;margin-top:4px">${Number(p.price).toFixed(2)} <span style="font-size:11px;color:#9ca3af;font-weight:500">WAZ</span></div>
            <div style="font-size:11px;color:#6b7280;margin-top:2px">@${escHtml(p.seller_handle || p.seller_name?.slice(0,8) || '?')}</div>
          </div>
        </div>
        ${idx != null ? `<div style="display:flex;align-items:center;gap:10px;padding:8px 10px;background:linear-gradient(135deg,#fef3c7,#fffbeb);border-radius:6px;margin-bottom:6px">
          <div style="font-size:22px;font-weight:800;color:${idxColor}">${idx}</div>
          <div style="flex:1">
            <div style="font-size:11px;color:#92400e;font-weight:600">🔥 ${t('推荐指数')} / 10</div>
            <div style="font-size:10px;color:#6b7280;margin-top:1px">${idx >= 8 ? t('强烈推荐') : idx >= 6 ? t('值得购买') : t('一般水平')}</div>
          </div>
        </div>` : `<div style="font-size:11px;color:#9ca3af;padding:6px 10px;background:#f9fafb;border-radius:6px;text-align:center">${t('暂无评价数据')}</div>`}
        <div style="display:flex;gap:14px;font-size:11px;color:#6b7280;justify-content:center;flex-wrap:wrap">
          ${p.completion_count > 0 ? `<span>🛒 ${p.completion_count} ${t('单成交')}</span>` : ''}
          ${p.recommend_count > 0 ? `<span>👍 ${p.recommend_count} ${t('人推荐')}</span>` : ''}
          ${p.total_likes > 0 ? `<span>❤️ ${p.total_likes} ${t('点赞')}</span>` : ''}
          ${p.rating_count > 0 ? `<span>⭐ ${Number(p.avg_rating).toFixed(1)} (${p.rating_count})</span>` : ''}
        </div>
      </div>`
  })() : ''
  // 跳转 CTA
  let jumpHash = ''
  let ctaLabel = ''
  if (r.target_kind === 'product') { jumpHash = '#order-product/' + r.target_id; ctaLabel = t('立即查看商品') + ' →' }
  else if (r.target_kind === 'shareable') { jumpHash = '#note/' + r.target_id; ctaLabel = t('查看笔记 / 外链') + ' →' }
  else if (r.target_kind === 'user') { jumpHash = '#u/' + r.owner_id; ctaLabel = t('进入主页') + ' →' }

  result.innerHTML = `
    <div style="margin-top:14px">
      <div style="display:flex;align-items:center;gap:6px;font-size:13px;color:#059669;font-weight:600;margin-bottom:10px">
        ✅ ${t('已锁定推荐人 30 天')}${tier}
      </div>
      ${ownerBlock}
      ${productBlock}
      ${jumpHash ? `<button class="btn btn-primary" style="width:100%;padding:12px;font-size:14px;font-weight:600" onclick="navigate('${jumpHash}')">${ctaLabel}</button>` : `<div class="alert alert-info">${t('找到')} target_kind=${r.target_kind}</div>`}
    </div>
  `
}

// editor-picks (public + admin mgmt) + flash-sale (modal/submit/live) → moved to
// app-shop.js (classic split, slice I). group-buy stays here: join/leave create a
// paid order + wallet escrow/refund (group-buys.ts) — a money/order/status path,
// not a plain shop utility; defer to a dedicated group-buy PR. renderSellerFlashSales
// (seller mgmt page) also stays here.

// B-3: 群组团购
async function renderGroupBuysLive(app) {
  app.innerHTML = shell(loading$(), 'discover')
  const r = await GET('/group-buys/live')
  const items = r?.items || []
  const rows = items.length === 0
    ? `<div style="text-align:center;padding:40px;color:#9ca3af"><div style="font-size:48px">👥</div><div style="font-size:13px;margin-top:8px">${t('暂无进行中的团购')}</div></div>`
    : items.map(it => {
        let imageUrl = ''
        try { const imgs = typeof it.images === 'string' ? JSON.parse(it.images) : it.images; if (Array.isArray(imgs) && imgs[0]) imageUrl = imgs[0] } catch {}
        const pct = (Number(it.discount_pct) * 100).toFixed(0)
        const final = (Number(it.original_price) * (1 - Number(it.discount_pct))).toFixed(2)
        const progress = Math.min(100, (Number(it.joined_count) / Number(it.target_count)) * 100)
        return `
          <div class="card" style="padding:12px;margin-bottom:8px;cursor:pointer;border-left:3px solid #16a34a" onclick="location.hash='#group-buy/${it.id}'">
            <div style="display:flex;gap:10px;align-items:center;margin-bottom:8px">
              <div style="font-size:32px;flex-shrink:0">${imageUrl ? `<img src="${escHtml(imageUrl)}" style="width:48px;height:48px;border-radius:6px;object-fit:cover">` : getCategoryIcon(it.category) || '📦'}</div>
              <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(it.product_title)}</div>
                <div style="font-size:12px;margin-top:2px"><span style="color:#16a34a;font-weight:700">${final}</span> WAZ <span style="font-size:10px;color:#9ca3af;text-decoration:line-through margin-left:4px">${it.original_price}</span> <span style="font-size:10px;color:#16a34a;background:#dcfce7;padding:1px 5px;border-radius:99px;margin-left:4px;font-weight:600">-${pct}%</span></div>
                <div style="font-size:10px;color:#9ca3af;margin-top:2px">@${escHtml(it.seller_handle || '')} · ${t('截止')} ${fmtTime(it.ends_at)}</div>
              </div>
            </div>
            <div style="display:flex;justify-content:space-between;align-items:center;font-size:11px;color:#374151;margin-bottom:4px">
              <span>${t('已成团')} ${it.joined_count}/${it.target_count}</span>
              <span style="color:#16a34a">${progress.toFixed(0)}%</span>
            </div>
            <div style="height:6px;background:#f3f4f6;border-radius:3px;overflow:hidden"><div style="height:100%;width:${progress}%;background:#16a34a;transition:width 0.3s"></div></div>
          </div>`
      }).join('')
  app.innerHTML = shell(`
    <h1 class="page-title">👥 ${t('群组团购')}</h1>
    <div style="font-size:12px;color:#6b7280;margin-bottom:14px">${t('多人凑单解锁折扣 · 未达成全额退款')}</div>
    ${rows}
  `, 'discover')
}

async function renderGroupBuyDetail(app, id) {
  if (!id) { navigate('#group-buys'); return }
  app.innerHTML = shell(loading$(), 'discover')
  const r = await GET(`/group-buys/${id}`)
  if (r.error) { app.innerHTML = shell(alert$('error', r.error), 'discover'); return }
  const pct = (Number(r.discount_pct) * 100).toFixed(0)
  const final = (Number(r.original_price) * (1 - Number(r.discount_pct))).toFixed(2)
  const isParticipant = state.user && (r.participants || []).some(p => p.buyer_id === state.user.id)
  const isOwn = state.user?.id === r.seller_id
  const joined = (r.participants || []).length
  const progress = Math.min(100, joined / Number(r.target_count) * 100)
  const expired = new Date(r.ends_at) <= new Date()
  const remaining = expired ? null : Math.max(0, new Date(r.ends_at).getTime() - Date.now())
  const remainingStr = remaining != null ? `${Math.floor(remaining / 3600000)}h ${Math.floor((remaining % 3600000) / 60000)}m` : t('已结束')

  app.innerHTML = shell(`
    <button class="btn btn-gray btn-sm" style="width:auto;margin-bottom:10px" onclick="navigate('#group-buys')">${t('← 全部团购')}</button>
    <h1 class="page-title">👥 ${escHtml(r.product_title)}</h1>
    <div class="card" style="background:linear-gradient(135deg,#ecfdf5,#fff);padding:14px;margin-bottom:10px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <div><div style="font-size:24px;font-weight:800;color:#16a34a">${final} WAZ</div><div style="font-size:11px;color:#9ca3af;text-decoration:line-through">${r.original_price} WAZ</div></div>
        <div style="font-size:18px;font-weight:700;color:#16a34a;background:#dcfce7;padding:6px 12px;border-radius:8px">-${pct}%</div>
      </div>
      <div style="font-size:12px;color:#374151;margin-bottom:4px">${t('已成团')} <strong>${joined}/${r.target_count}</strong> · ${t('剩余时间')} ${remainingStr}</div>
      <div style="height:8px;background:#f3f4f6;border-radius:4px;overflow:hidden;margin-bottom:8px"><div style="height:100%;width:${progress}%;background:#16a34a"></div></div>
      ${r.status === 'succeeded' ? `<div style="color:#16a34a;font-weight:600">🎉 ${t('已成团')}</div>`
        : r.status === 'failed' ? `<div style="color:#dc2626;font-weight:600">⏰ ${t('未成团已退款')}</div>`
        : expired ? `<div style="color:#9ca3af">${t('已结束，等待结算')}</div>`
        : isOwn ? `<div style="color:#9ca3af">${t('自己开的团，等待成团')}</div>`
        : isParticipant ? `<button class="btn btn-outline btn-sm" style="width:100%;color:#dc2626;border-color:#fca5a5" onclick="leaveGroupBuy('${r.id}')">${t('退出团购')}</button>`
        : state.user?.role === 'buyer' ? `<button class="btn btn-primary" style="width:100%" onclick="openJoinGroupBuy('${r.id}')">+ ${t('加入团购')} (${r.original_price} WAZ ${t('预付')})</button>`
        : `<div style="color:#9ca3af">${t('仅买家可加入')}</div>`}
    </div>
    <div style="font-size:13px;font-weight:600;margin:14px 0 8px">${t('已加入')} (${joined})</div>
    ${(r.participants || []).map(p => `
      <div class="card" style="padding:8px 10px;margin-bottom:4px;font-size:12px;display:flex;justify-content:space-between">
        <span>@${escHtml(p.buyer_handle || '?')}</span>
        <span style="color:#9ca3af">${fmtTime(p.created_at)}</span>
      </div>
    `).join('')}
  `, 'discover')
}

window.openJoinGroupBuy = (id) => {
  const html = `
    <div class="js-modal" style="background:rgba(0,0,0,0.6);position:fixed;inset:0;z-index:1000;display:flex;align-items:flex-end;justify-content:center" onclick="this.remove()">
      <div style="background:#fff;width:100%;max-width:560px;border-radius:16px 16px 0 0;padding:20px" onclick="event.stopPropagation()">
        <h2 style="font-size:16px;font-weight:700;margin-bottom:8px">👥 ${t('加入团购')}</h2>
        <div style="font-size:12px;color:#6b7280;margin-bottom:12px">${t('预付原价，成团后退差价；未成团全额退款')}</div>
        <div class="form-group">
          <label class="form-label">${t('收货地址')} *</label>
          <input class="form-control" id="gb-addr" placeholder="${t('省市区 详细地址')}">
        </div>
        <div id="gb-msg" style="margin:8px 0"></div>
        <div style="display:flex;gap:8px">
          <button class="btn btn-gray" style="flex:1" onclick="this.closest('[style*=position]').remove()">${t('取消')}</button>
          <button class="btn btn-primary" style="flex:1" onclick="submitJoinGroupBuy('${id}')">${t('确认加入')}</button>
        </div>
      </div>
    </div>
  `
  const div = document.createElement('div')
  div.innerHTML = html
  document.body.appendChild(div.firstElementChild)
}

window.submitJoinGroupBuy = async (id) => {
  const addr = document.getElementById('gb-addr').value.trim()
  if (!addr) { document.getElementById('gb-msg').innerHTML = alert$('error', t('请填写收货地址')); return }
  const res = await POST(`/group-buys/${id}/join`, { shipping_address: addr })
  if (res.error) { document.getElementById('gb-msg').innerHTML = alert$('error', res.error); return }
  document.querySelector('.js-modal')?.remove()
  toast$(`${t('已加入')} (${res.joined_count}/${res.target_count})`)
  renderGroupBuyDetail(document.getElementById('app'), id)
}

window.leaveGroupBuy = async (id) => {
  if (!confirm(t('确认退出？预付金额将退回'))) return
  const res = await fetch(`/api/group-buys/${id}/leave`, { method: 'DELETE', headers: { Authorization: 'Bearer ' + state.apiKey } }).then(r => r.json())
  if (res.error) { alert(res.error); return }
  toast$(t('已退出'))
  renderGroupBuyDetail(document.getElementById('app'), id)
}

// seller 自己的 flash sales
async function renderSellerFlashSales(app) {
  if (state.user?.role !== 'seller') { app.innerHTML = shell(`<div class="empty">${t('仅卖家可访问')}</div>`, 'me'); return }
  app.innerHTML = shell(loading$(), 'me')
  const r = await GET('/sellers/me/flash-sales')
  const items = r?.items || []
  const now = Date.now()
  const rows = items.length === 0
    ? `<div style="text-align:center;padding:40px;color:#9ca3af"><div style="font-size:48px">⚡</div><div style="font-size:13px;margin-top:8px">${t('暂无促销活动')}</div></div>`
    : items.map(it => {
        const startsAt = new Date(it.starts_at).getTime()
        const endsAt = new Date(it.ends_at).getTime()
        const phase = endsAt <= now ? 'expired' : startsAt > now ? 'scheduled' : 'live'
        const phaseColor = { live: '#dc2626', scheduled: '#d97706', expired: '#6b7280' }[phase]
        const phaseLabel = { live: t('进行中'), scheduled: t('已排期'), expired: t('已结束') }[phase]
        return `
          <div class="card" style="padding:10px 12px;margin-bottom:8px;border-left:3px solid ${phaseColor}">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
              <div style="font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:60%">${escHtml(it.product_title)}</div>
              <span style="font-size:10px;font-weight:600;color:#fff;background:${phaseColor};padding:2px 8px;border-radius:99px">${phaseLabel}</span>
            </div>
            <div style="font-size:12px;color:#374151">${it.sale_price} WAZ <span style="font-size:11px;color:#9ca3af;text-decoration:line-through;margin-left:4px">${it.original_price}</span></div>
            <div style="font-size:11px;color:#9ca3af;margin-top:2px">${fmtTime(it.starts_at)} → ${fmtTime(it.ends_at)}${it.max_qty > 0 ? ' · ' + t('已售') + ' ' + it.sold_count + '/' + it.max_qty : ''}</div>
            ${phase === 'scheduled' ? `<button class="btn btn-outline btn-sm" style="margin-top:6px;font-size:10px;padding:3px 8px;color:#dc2626;border-color:#fca5a5" onclick="deleteFlashSale('${it.id}')">${t('取消')}</button>` : ''}
          </div>`
      }).join('')
  app.innerHTML = shell(`
    <h1 class="page-title">⚡ ${t('我的促销')}</h1>
    ${rows}
  `, 'me')
}

window.deleteFlashSale = async (id) => {
  if (!confirm(t('取消该促销？'))) return
  const res = await fetch('/api/flash-sales/' + id, { method: 'DELETE', headers: { Authorization: 'Bearer ' + state.apiKey } }).then(r => r.json())
  if (res.error) { alert(res.error); return }
  renderSellerFlashSales(document.getElementById('app'))
}

// D-3: KYC 实名认证（buyer 视角）
async function renderKyc(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'me')
  const r = await GET('/kyc/me')
  const kyc = r?.kyc || null
  const STATUS_LABEL = () => ({ pending: t('审核中'), approved: t('已通过'), rejected: t('被拒绝') })
  const STATUS_COLOR = { pending: '#d97706', approved: '#16a34a', rejected: '#dc2626' }

  if (kyc && kyc.status === 'approved') {
    app.innerHTML = shell(`
      <h1 class="page-title">🆔 ${t('实名认证')}</h1>
      <div class="card" style="background:linear-gradient(135deg,#ecfdf5,#fff);padding:14px;text-align:center">
        <div style="font-size:48px">✓</div>
        <div style="font-size:16px;font-weight:700;color:#16a34a;margin-top:8px">${t('已通过认证')}</div>
        <div style="font-size:12px;color:#6b7280;margin-top:4px">${t('证件')} ${kyc.id_type} · ****${kyc.id_number_last4}</div>
        <div style="font-size:11px;color:#9ca3af;margin-top:4px">${fmtTime(kyc.reviewed_at)}</div>
      </div>
    `, 'me')
    return
  }

  if (kyc && kyc.status === 'pending') {
    app.innerHTML = shell(`
      <h1 class="page-title">🆔 ${t('实名认证')}</h1>
      <div class="card" style="background:#fef3c7;padding:14px;text-align:center">
        <div style="font-size:48px">⏳</div>
        <div style="font-size:16px;font-weight:700;color:#d97706;margin-top:8px">${t('审核中')}</div>
        <div style="font-size:12px;color:#92400e;margin-top:4px">${t('提交于')} ${fmtTime(kyc.submitted_at)}</div>
      </div>
    `, 'me')
    return
  }

  // 表单（rejected 或 未提交）
  app.innerHTML = shell(`
    <h1 class="page-title">🆔 ${t('实名认证')}</h1>
    ${kyc && kyc.status === 'rejected' ? `<div class="alert alert-error">${t('上次认证被拒绝')}: ${escHtml(kyc.reject_reason || '')}</div>` : ''}
    <div style="font-size:12px;color:#6b7280;margin-bottom:14px">${t('提交真实身份信息提升账户可信度；管理员审核后通过')}</div>
    <div class="card" style="padding:14px">
      <div class="form-group"><label class="form-label">${t('真实姓名')} *</label><input class="form-control" id="kyc-name" maxlength="60"></div>
      <div class="form-group"><label class="form-label">${t('证件类型')} *</label>
        <select class="form-control" id="kyc-type">
          <option value="national_id">${t('身份证')}</option>
          <option value="passport">${t('护照')}</option>
          <option value="driver_license">${t('驾照')}</option>
          <option value="other">${t('其他')}</option>
        </select>
      </div>
      <div class="form-group"><label class="form-label">${t('证件号码')} *</label><input class="form-control" id="kyc-id"><div style="font-size:10px;color:#9ca3af;margin-top:2px">🔒 ${t('号码本地 hash 后存储 + 末 4 位明文供核对，原始号不留存')}</div></div>
      <div id="kyc-msg" style="margin:8px 0"></div>
      <button class="btn btn-primary" onclick="submitKyc()">${t('提交认证')}</button>
    </div>
  `, 'me')
}

window.submitKyc = async () => {
  const body = {
    real_name: document.getElementById('kyc-name').value.trim(),
    id_type: document.getElementById('kyc-type').value,
    id_number: document.getElementById('kyc-id').value.trim(),
  }
  const msg = document.getElementById('kyc-msg')
  if (!body.real_name || !body.id_number) { msg.innerHTML = alert$('error', t('请填写完整')); return }
  msg.innerHTML = loading$()
  const res = await POST('/kyc/submit', body)
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  toast$(t('已提交，等待审核'))
  renderKyc(document.getElementById('app'))
}

// D-3: KYC admin
async function renderAdminKyc(app) {
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin'); return }
  app.innerHTML = shell(loading$(), 'admin')
  const r = await GET('/admin/kyc/pending')
  const items = r?.items || []
  const rows = items.length === 0
    ? `<div style="text-align:center;padding:40px;color:#9ca3af">${t('暂无待审核 KYC')}</div>`
    : items.map(it => `
        <div class="card" style="padding:12px;margin-bottom:8px">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
            <div style="font-size:13px;font-weight:600">${escHtml(it.real_name)} (@${escHtml(it.handle || '')})</div>
            <span style="font-size:10px;color:#d97706">${t('待审')}</span>
          </div>
          <div style="font-size:11px;color:#9ca3af">${it.id_type} ****${it.id_number_last4} · ${it.role} · ${fmtTime(it.submitted_at)}</div>
          <div style="display:flex;gap:6px;margin-top:8px">
            <button class="btn btn-success btn-sm" style="font-size:11px;padding:4px 10px" onclick="approveKyc('${it.user_id}')">${t('通过')}</button>
            <button class="btn btn-outline btn-sm" style="font-size:11px;padding:4px 10px;color:#dc2626" onclick="rejectKyc('${it.user_id}')">${t('拒绝')}</button>
          </div>
        </div>
      `).join('')
  app.innerHTML = shell(`
    <button class="btn btn-gray btn-sm" style="width:auto;margin-bottom:10px" onclick="history.back()">${t('← 返回')}</button>
    <h1 class="page-title">🆔 ${t('KYC 审核')}</h1>
    ${rows}
  `, 'admin')
}

window.approveKyc = async (id) => {
  const res = await POST(`/admin/kyc/${id}/approve`, {})
  if (res.error) { alert(res.error); return }
  toast$(t('已通过'))
  renderAdminKyc(document.getElementById('app'))
}
window.rejectKyc = async (id) => {
  const reason = (prompt(t('拒绝原因'), '') || '').trim()
  if (!reason) return
  const res = await POST(`/admin/kyc/${id}/reject`, { reason })
  if (res.error) { alert(res.error); return }
  toast$(t('已拒绝'))
  renderAdminKyc(document.getElementById('app'))
}

// G-3: AI 异常检测
window.runAnomalyCheck = async (userId) => {
  const out = document.getElementById('anomaly-result')
  if (out) out.innerHTML = loading$()
  const res = await POST(`/admin/ai/anomaly-check/${userId}`, {})
  if (!out) return
  if (res.error) { out.innerHTML = alert$('error', res.error); return }
  const levelColor = { low: '#16a34a', medium: '#d97706', high: '#dc2626' }[res.level] || '#9ca3af'
  out.innerHTML = `
    <div class="card" style="padding:14px;background:linear-gradient(135deg,#f5f3ff,#fff);border:1px solid #c4b5fd">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <div style="font-size:13px;font-weight:600">✨ ${t('AI 异常评估')}</div>
        <div style="font-size:18px;font-weight:800;color:${levelColor}">${res.risk_score}/100 · ${res.level}</div>
      </div>
      <div style="font-size:12px;color:#374151;margin-bottom:6px">${escHtml(res.recommendation || '')}</div>
      ${(res.flags || []).map(f => `<div style="font-size:11px;color:#7c3aed;padding:2px 0">· ${escHtml(f)}</div>`).join('')}
    </div>
  `
}

// G-2: AI 价格建议
window.aiSuggestPrice = async () => {
  const title = document.getElementById('ep-title')?.value.trim()
  const desc = document.getElementById('ep-desc')?.value.trim()
  if (!title) { alert(t('请先填商品名称')); return }
  const hint = document.getElementById('ep-price-hint')
  if (hint) hint.innerHTML = loading$()
  const res = await POST('/ai/price-suggestion', { title, description: desc })
  if (res.error) { if (hint) hint.innerHTML = '<span style="color:#dc2626">' + escHtml(res.error) + '</span>'; return }
  const priceInp = document.getElementById('ep-price')
  if (hint) {
    hint.innerHTML = `💡 ${t('建议')} <strong style="color:#16a34a;cursor:pointer;text-decoration:underline" onclick="document.getElementById('ep-price').value=${res.suggested_price}">${res.suggested_price}</strong> WAZ · ${t('区间')} ${res.low_price}-${res.high_price} · ${escHtml(res.reasoning || '')}`
  }
}

// G-1: AI 文案生成
window.genAiDescription = async (productId, category) => {
  const titleInp = document.getElementById('ep-title')
  const descInp = document.getElementById('ep-desc')
  if (!titleInp || !descInp) return
  const title = titleInp.value.trim()
  if (!title) { alert(t('请先填商品名称')); return }
  const btn = event.target
  btn.disabled = true; const orig = btn.innerHTML; btn.innerHTML = '...'
  const res = await POST('/ai/generate-description', { title, category, language: window._lang || 'zh' })
  btn.disabled = false; btn.innerHTML = orig
  if (res.error) { alert(res.error); return }
  if (descInp.value.trim() && !confirm(t('覆盖现有描述？'))) return
  descInp.value = res.description
  toast$(t('已生成'))
}

