// 客户端随机生成符合规则的 4 字符 middle
// 设计原则：人类可读 + 达人叙事友好（口播好记），不是纯随机乱码
// 规则：4 alphanumeric · ≥1 数字 · 非顺序 · 非保留 · 非混淆字符 · 非交叉模式
// 排除字符：o / 0（视觉混淆）· i / l / 1（视觉混淆）
// 排除模式：字母数字交错（如 a1b2 / 1a2b）— 必须字母段 + 数字段连续
// 生成策略：
//   - 70% 纯数字（如 7798 · 8866 · 1986）— 最易记 + 易口播
//   - 30% 辅音+元音+2 数字 连续（如 ka26 · mu88）— 字母段在前数字段在后
const _ANCHOR_RESERVED = new Set(['admin','sys','webaz','test','null','root','help','mail','user','info','home','www0','site'])
const _ANCHOR_SEQUENTIAL = new Set(['0000','1111','2222','3333','4444','5555','6666','7777','8888','9999','1234','2345','3456','4567','5678','6789','0123','abcd','qwer'])
// 视觉易混淆字符：o（混 0）/ i / l（混 1）
const _ANCHOR_CONFUSING = /[oil]/
// 非交叉模式：纯数字 / 字母段+数字段 / 数字段+字母段
function _isContiguousPattern(m) {
  return /^\d{4}$/.test(m) || /^[a-z]+\d+$/.test(m) || /^\d+[a-z]+$/.test(m)
}

function _genReadableMiddle() {
  const digit = '23456789'                  // 排除 0 / 1 防混淆 + 让数字段更"中段"
  const easyConsonants = 'bcdfghjkmnprstv'  // 去 l / q / w / x / y / z
  const vowels = 'aeu'                       // 去 i / o

  for (let attempt = 0; attempt < 50; attempt++) {
    let m = ''
    const r = Math.random()
    if (r < 0.7) {
      // 70% 纯 4 数字（生日 / 纪念日 / 幸运数 风格，从 23456789 中选避开 0/1）
      for (let i = 0; i < 4; i++) m += digit[Math.floor(Math.random() * digit.length)]
    } else {
      // 30% 辅音+元音+2 数字（连续段，不交叉） — 如 ka26 · mu88
      m = easyConsonants[Math.floor(Math.random() * easyConsonants.length)]
        + vowels[Math.floor(Math.random() * vowels.length)]
        + digit[Math.floor(Math.random() * digit.length)]
        + digit[Math.floor(Math.random() * digit.length)]
    }
    if (!/[0-9]/.test(m)) continue
    if (_ANCHOR_CONFUSING.test(m)) continue
    if (!_isContiguousPattern(m)) continue
    if (_ANCHOR_RESERVED.has(m)) continue
    if (_ANCHOR_SEQUENTIAL.has(m)) continue
    return m
  }
  return null
}
// 兼容旧名
function _genRandomMiddle() { return _genReadableMiddle() }

window.oneClickGenAnchorMiddle = () => {
  const m = _genRandomMiddle()
  if (!m) return toast$(t('生成失败，请手动输入'), 'error')
  const el = document.getElementById('ext-anchor-middle')
  if (el) { el.value = m; updateAnchorPreview() }
}

window.updateAnchorPreview = () => {
  const el = document.getElementById('ext-anchor-middle')
  const previewEl = document.getElementById('ext-anchor-preview')
  const broadcastEl = document.getElementById('ext-anchor-broadcast')
  if (!el || !previewEl) return
  const setError = (msg) => {
    previewEl.innerHTML = `<div style="font-size:11px;color:#dc2626">${msg}</div>`
    if (broadcastEl) broadcastEl.textContent = ''
  }
  const middle = (el.value || '').trim().toLowerCase()
  const handle = (state.user?.handle || '').toLowerCase()
  if (!middle) { previewEl.innerHTML = ''; if (broadcastEl) broadcastEl.textContent = ''; return }
  if (middle.length !== 4) return setError(t('需要正好 4 字符'))
  if (!/^[a-z0-9]{4}$/.test(middle)) return setError(t('仅允许字母 + 数字'))
  if (!/[0-9]/.test(middle)) return setError(t('至少含 1 个数字'))
  if (_ANCHOR_CONFUSING.test(middle)) return setError(t('避开易混淆字符 o / i / l'))
  if (!_isContiguousPattern(middle)) return setError(t('字母和数字不能交错 — 如 ka26 ✓ / a1b2 ✗'))
  if (_ANCHOR_RESERVED.has(middle)) return setError(t('保留词不可用'))
  if (_ANCHOR_SEQUENTIAL.has(middle)) return setError(t('顺序串不可用'))
  if (!handle) return setError(t('请先在个人设置中设置 handle'))
  // ── 两段语义视觉化：@handle (达人身份) + middle (商品定位)
  // tier 等级在 anchor lookup 结果 / profile 显示，不内嵌字符串（permalink 永久）
  previewEl.innerHTML = `
    <div style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:8px;padding:10px 12px">
      <div style="font-size:10px;color:#6b7280;margin-bottom:4px">📡 ${t('完整口令')}</div>
      <div style="font-family:ui-monospace,Consolas,monospace;font-size:16px;font-weight:700;letter-spacing:0.5px">
        <span style="color:#4f46e5">@${handle}</span><span style="color:#7c3aed">${middle}</span>
      </div>
      <div style="display:flex;gap:0;margin-top:6px;font-size:9px;line-height:1.4">
        <div style="flex:0 0 auto;color:#4f46e5;width:${handle.length + 1}ch;text-align:center">↑${t('达人身份')}</div>
        <div style="flex:0 0 auto;color:#7c3aed;width:4ch;text-align:center">↑${t('商品定位')}</div>
      </div>
      <div style="font-size:10px;color:#6b7280;margin-top:6px;line-height:1.5">
        ${t('你的 @handle 锁定；只需为每个商品换中间 4 位。等级在你的主页显示，不影响口令。')}
      </div>
    </div>`
  // 达人口播预览：明确分三段读
  if (broadcastEl) {
    broadcastEl.innerHTML = `🎙 ${t('达人口播参考')}："${t('在 WebAZ 输入')} <strong style="color:#4f46e5">@${handle}</strong> <strong style="color:#7c3aed">${middle}</strong>${t('，记得加我')}"`
  }
}

window.submitAddExternal = async () => {
  const external_url = document.getElementById('ext-url-inp').value.trim()
  const title = document.getElementById('ext-title-inp').value.trim()
  const description = document.getElementById('ext-desc-inp').value.trim()
  const related_product_id = document.getElementById('ext-pid-inp').value.trim()
  const anchorMiddle = (document.getElementById('ext-anchor-middle')?.value || '').trim().toLowerCase()
  const msg = document.getElementById('ext-msg')
  if (!external_url) { msg.innerHTML = alert$('error', t('请填写外链 URL')); return }
  if (!related_product_id) { msg.innerHTML = alert$('error', t('请填写关联商品 ID')); return }
  if (!anchorMiddle) { msg.innerHTML = alert$('error', t('请填写关联口令（或点一键生成）')); return }
  if (anchorMiddle.length !== 4 || !/^[a-z0-9]{4}$/.test(anchorMiddle) || !/[0-9]/.test(anchorMiddle)) {
    msg.innerHTML = alert$('error', t('口令格式错误 — 4 个字母 / 数字，至少 1 个数字'))
    return
  }
  msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('生成口令 + 保存中...')}</div>`
  // Step 1: 调 /api/anchor/generate 生成完整 anchor（拼接 prefix+middle+tier_letter）
  const anchorRes = await POST('/anchor/generate', {
    middle: anchorMiddle,
    target_kind: 'product',
    target_id: related_product_id,
  })
  if (anchorRes.error) {
    msg.innerHTML = alert$('error', `${t('口令生成失败')}: ${anchorRes.error}`)
    return
  }
  const related_anchor = anchorRes.anchor
  // Step 2: 创建 shareable 关联商品 + 完整 anchor
  const res = await POST('/shareables', { external_url, title, description, related_product_id, related_anchor })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  // 保存成功 — 不自动关闭，显示完整 anchor + 一键复制（便于达人贴到外站）
  const handle = (state.user?.handle || '').toLowerCase()
  const middleOnly = anchorMiddle
  const broadcastText = `${t('在 WebAZ 输入')} @${handle}${middleOnly}${t('，记得加我')}`
  msg.innerHTML = `
    <div style="background:#ecfdf5;border:1px solid #86efac;border-radius:10px;padding:14px;margin-top:8px">
      <div style="font-size:13px;font-weight:600;color:#16a34a;margin-bottom:8px">✅ ${t('已添加，可以传播了')}</div>
      <div style="font-family:ui-monospace,Consolas,monospace;font-size:15px;font-weight:700;background:#fff;padding:10px 12px;border-radius:6px;border:1px solid #d1fae5;margin-bottom:8px;word-break:break-all">
        <span style="color:#4f46e5">@${handle}</span><span style="color:#7c3aed">${middleOnly}</span>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
        <button class="btn btn-primary btn-sm" style="font-size:11px;padding:8px" onclick="copyAnchorOneClick('@${handle}${middleOnly}', this)">📋 ${t('复制口令')}</button>
        <button class="btn btn-outline btn-sm" style="font-size:11px;padding:8px" onclick="copyAnchorOneClick(\`${broadcastText.replace(/`/g, '\\`')}\`, this)">📤 ${t('复制口播文案')}</button>
      </div>
      <div style="font-size:11px;color:#16a34a;margin-top:8px;line-height:1.5">
        🎙 ${t('口播参考')}："${broadcastText}"
      </div>
      <div style="margin-top:10px;text-align:right">
        <button class="btn btn-outline btn-sm" style="font-size:11px;padding:5px 12px" onclick="closeModal(); renderPromoter(document.getElementById('app'))">${t('完成')}</button>
      </div>
    </div>`
}

// 一键复制 anchor 或口播文案 — 复用 webShareOrCopy（Web Share API 优先）
window.copyAnchorOneClick = async (text, btnEl) => {
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(text)
    } else {
      // fallback
      const ta = document.createElement('textarea')
      ta.value = text
      document.body.appendChild(ta)
      ta.select()
      document.execCommand('copy')
      ta.remove()
    }
    if (btnEl) {
      const origText = btnEl.textContent
      btnEl.textContent = `✓ ${t('已复制')}`
      btnEl.style.background = '#16a34a'
      btnEl.style.color = '#fff'
      btnEl.style.borderColor = '#16a34a'
      setTimeout(() => {
        btnEl.textContent = origText
        btnEl.style.background = ''
        btnEl.style.color = ''
        btnEl.style.borderColor = ''
      }, 1500)
    }
  } catch {
    toast$(t('复制失败 — 请手动选中复制'), 'error')
  }
}

