window.handleNativeTypeChange = () => {
  const v = document.getElementById('native-type-sel').value
  document.getElementById('native-text-wrap').style.display = v === 'text' ? '' : 'none'
  document.getElementById('native-image-wrap').style.display = v === 'image' ? '' : 'none'
}

window.handleNativeImageChange = async (e) => {
  const file = e.target.files?.[0]
  if (!file) return
  if (file.size > 5 * 1024 * 1024) { alert(t('单图 ≤ 5MB')); e.target.value = ''; return }
  const url = URL.createObjectURL(file)
  document.getElementById('native-image-preview').innerHTML = `<img src="${url}" style="max-width:200px;max-height:200px;border-radius:6px;border:1px solid #e5e7eb"><div style="font-size:11px;color:#6b7280;margin-top:4px">${(file.size/1024).toFixed(1)} KB</div>`
}

window.submitCreateNative = async () => {
  const type = document.getElementById('native-type-sel').value
  const title = document.getElementById('native-title-inp').value.trim()
  const description = document.getElementById('native-desc-inp').value.trim()
  const related_product_id = document.getElementById('native-pid-inp').value.trim() || null
  const related_anchor = document.getElementById('native-anchor-inp').value.trim() || null
  const confirmed = document.getElementById('native-confirm-cb').checked
  const msg = document.getElementById('native-msg')
  if (!confirmed) { msg.innerHTML = alert$('error', t('请勾选确认')); return }
  if (!title) { msg.innerHTML = alert$('error', t('请填写标题')); return }
  if (!related_product_id && !related_anchor) { msg.innerHTML = alert$('error', t('请关联商品或口令')); return }

  let blob, content_type, thumbnail_data_uri = null
  if (type === 'text') {
    const text = document.getElementById('native-text-inp').value.trim()
    if (!text) { msg.innerHTML = alert$('error', t('请填写文字内容')); return }
    blob = new Blob([text], { type: 'text/plain; charset=utf-8' })
    content_type = 'text/plain'
  } else {
    const file = document.getElementById('native-image-inp').files?.[0]
    if (!file) { msg.innerHTML = alert$('error', t('请选择图片')); return }
    blob = file
    content_type = file.type
    try { thumbnail_data_uri = await generateThumbnailDataUri(file) } catch {}
  }

  msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('哈希 + 签名 + 发布中...')}</div>`
  try {
    const r = await p2pPublishContent({ blob, content_type, title, description, related_product_id, related_anchor, thumbnail_data_uri })
    msg.innerHTML = alert$('success', `${t('发布成功')} · hash ${r.hash.slice(0, 12)}…`)
    setTimeout(() => { closeModal(); renderPromoter(document.getElementById('app')) }, 1000)
  } catch (e) {
    msg.innerHTML = alert$('error', e.message || t('发布失败'))
  }
}

window.deleteShareable = async (id) => {
  if (!confirm(t('确认删除该分享？'))) return
  const r = await DELETE(`/shareables/${id}`)
  if (r.error) return toast$(r.error, 'error')
  toast$(t('已删除'))
  renderPromoter(document.getElementById('app'))
}

window.takedownManifest = async (hash) => {
  const reason = prompt(t('下架原因（可选）'), '')
  if (reason === null) return   // cancel
  const r = await api('PATCH', `/manifests/${hash}/takedown`, { reason })
  if (r.error) return toast$(r.error, 'error')
  // 同步本地 evict
  try { await p2pEvictContent(hash) } catch {}
  toast$(t('已下架'))
  renderPromoter(document.getElementById('app'))
}

// 进入 promoter 页时同步当前偏好到下拉
async function syncPlacementPref() {
  try {
    const st = await GET('/profile/placement-status')
    const sel = document.getElementById('placement-pref-select')
    if (sel && st?.placement_pref) {
      // legacy left/right 在 UI 上回落为 team_count（DB 已被静默迁移，此处仅兜底缓存）
      const v = (st.placement_pref === 'left' || st.placement_pref === 'right') ? 'team_count' : st.placement_pref
      sel.value = v
    }
  } catch {}
}

