function getCategoryIcon(cat) {
  const map = { '茶具':'🍵', '家居':'🏠', '食品':'🍱', '服装':'👗', '电子':'📱', '手工':'🎨' }
  return map[cat] || '📦'
}

function repBadge(level) {
  const map = { new:'', trusted:'⭐', quality:'🌟', star:'💫', legend:'🔥' }
  return map[level] || ''
}
function repLabel(level) {
  const map = { new:'新手', trusted:'可信', quality:'优质', star:'明星', legend:'传奇' }
  return map[level] || ''
}
// 入驻时长 — 天 / 个月 / 年 自适应
function joinDuration(createdAt) {
  if (!createdAt) return ''
  const ms = Date.now() - new Date(String(createdAt).replace(' ', 'T') + 'Z').getTime()
  if (!Number.isFinite(ms) || ms < 0) return ''
  const days = Math.floor(ms / 86400000)
  if (days < 1) return t('今天')
  if (days < 30) return days + ' ' + t('天')
  const months = Math.floor(days / 30)
  if (months < 12) return months + ' ' + t('个月')
  const years = Math.floor(days / 365)
  return years + ' ' + t('年')
}

// 卖家信誉简评：信誉等级 + 累计成交（带标签，更直观）
// 商品详情图片画廊 — 协议化设计：先用 manifest 里的 thumbnail 即时展示，
// 同时尝试 IDB 中找原图 blob → object URL（点击放大时优先用大图）。
// 节点离线 + 自己没缓存 → 只显示 thumbnail（不致命，仍能浏览）
function productImageGallery(p) {
  let hashes = []
  try { hashes = typeof p?.images === 'string' ? JSON.parse(p.images) : (p?.images || []) } catch {}
  if (!Array.isArray(hashes) || hashes.length === 0) {
    return `<div style="font-size:60px;text-align:center;padding:20px 0">${getCategoryIcon(p?.category)}</div>`
  }
  const pid = p?.id || 'gal'
  // 同步占位 — async 拿 manifest thumbnail 填充
  setTimeout(() => hydrateProductGallery(pid, hashes), 0)
  return `<div id="pg-${pid}" data-hashes='${JSON.stringify(hashes)}' style="margin:0 -16px 12px">
    <div style="aspect-ratio:4/3;background:#f3f4f6;position:relative;overflow:hidden;display:flex;align-items:center;justify-content:center">
      <img id="pg-${pid}-main" style="width:100%;height:100%;object-fit:cover;display:none;cursor:zoom-in" onclick="openImageLightbox('${pid}', 0)">
      <div id="pg-${pid}-loading" style="color:#9ca3af;font-size:12px">${t('加载图片…')}</div>
      ${hashes.length > 1 ? `<div style="position:absolute;bottom:8px;right:8px;background:rgba(0,0,0,0.55);color:#fff;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600" id="pg-${pid}-cnt">1 / ${hashes.length}</div>` : ''}
    </div>
    ${hashes.length > 1 ? `
    <div id="pg-${pid}-thumbs" style="display:flex;gap:6px;padding:8px 16px 0;overflow-x:auto;scrollbar-width:none"></div>` : ''}
  </div>`
}

async function hydrateProductGallery(pid, hashes) {
  const wrap = document.getElementById('pg-' + pid)
  if (!wrap) return
  // 1. 拉 manifests 拿到 thumbnails（即时可显示）
  const manifests = await GET(`/manifests/by-product/${pid}`).catch(() => ({ items: [] }))
  const byHash = {}
  for (const m of (manifests.items || manifests || [])) byHash[m.hash] = m
  // 2. 对每个 hash 解析显示 URL：优先 IDB 原图 → 否则 thumbnail
  const urls = []
  for (const h of hashes) {
    let url = null
    try {
      const row = await p2pGetContent(h)
      if (row?.blob) url = URL.createObjectURL(row.blob)
    } catch {}
    if (!url) url = byHash[h]?.thumbnail_data_uri || null
    urls.push(url)
  }
  // 3. 渲染主图（首张）
  const main = document.getElementById('pg-' + pid + '-main')
  const loading = document.getElementById('pg-' + pid + '-loading')
  if (urls[0]) {
    if (main) { main.src = urls[0]; main.style.display = 'block' }
    if (loading) loading.style.display = 'none'
  } else if (loading) {
    loading.textContent = '🌐 ' + t('图片暂不可达（卖家节点离线）')
  }
  // 4. 缩略图 strip
  const thumbsEl = document.getElementById('pg-' + pid + '-thumbs')
  if (thumbsEl) {
    thumbsEl.innerHTML = urls.map((u, i) => `
      <img src="${u || ''}" onclick="switchGalleryImage('${pid}', ${i}, ${u ? '' : 'true'})" style="width:54px;height:54px;border-radius:6px;object-fit:cover;cursor:pointer;flex-shrink:0;border:2px solid ${i === 0 ? '#4f46e5' : 'transparent'};background:#e5e7eb" data-gal-idx="${i}" data-url="${u || ''}">
    `).join('')
  }
}

window._galleryData = window._galleryData || {}

window.switchGalleryImage = (pid, idx) => {
  const main = document.getElementById('pg-' + pid + '-main')
  const cnt = document.getElementById('pg-' + pid + '-cnt')
  const wrap = document.getElementById('pg-' + pid)
  if (!main || !wrap) return
  const thumbs = wrap.querySelectorAll('img[data-gal-idx]')
  const url = thumbs[idx]?.dataset?.url || thumbs[idx]?.src
  if (url) { main.src = url; main.style.display = 'block' }
  if (cnt) cnt.textContent = `${idx + 1} / ${thumbs.length}`
  thumbs.forEach((tImg, i) => { tImg.style.border = '2px solid ' + (i === idx ? '#4f46e5' : 'transparent') })
}

window.openImageLightbox = (pid, idx) => {
  const wrap = document.getElementById('pg-' + pid)
  if (!wrap) return
  const thumbs = Array.from(wrap.querySelectorAll('img[data-gal-idx]'))
  const urls = thumbs.length ? thumbs.map(t => t.src) : [document.getElementById('pg-' + pid + '-main')?.src].filter(Boolean)
  if (!urls.length) return
  let cur = idx
  const overlay = document.createElement('div')
  overlay.className = 'js-modal'
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.92);z-index:10000;display:flex;align-items:center;justify-content:center'
  overlay.innerHTML = `
    <img id="lb-img" src="${escAttr(urls[cur])}" style="max-width:96vw;max-height:90vh;object-fit:contain">
    <button onclick="this.closest('.js-modal').remove()" style="position:absolute;top:14px;right:14px;background:rgba(255,255,255,0.18);border:none;color:#fff;width:36px;height:36px;border-radius:50%;font-size:22px;cursor:pointer;line-height:1">×</button>
    ${urls.length > 1 ? `
    <div style="position:absolute;bottom:24px;left:50%;transform:translateX(-50%);background:rgba(0,0,0,0.5);color:#fff;font-size:12px;padding:4px 14px;border-radius:99px" id="lb-cnt">${cur+1} / ${urls.length}</div>
    <button onclick="event.stopPropagation();window._lbStep(-1)" style="position:absolute;left:14px;top:50%;transform:translateY(-50%);background:rgba(255,255,255,0.18);border:none;color:#fff;width:42px;height:42px;border-radius:50%;font-size:22px;cursor:pointer;line-height:1">‹</button>
    <button onclick="event.stopPropagation();window._lbStep(1)" style="position:absolute;right:14px;top:50%;transform:translateY(-50%);background:rgba(255,255,255,0.18);border:none;color:#fff;width:42px;height:42px;border-radius:50%;font-size:22px;cursor:pointer;line-height:1">›</button>
    ` : ''}
  `
  overlay.onclick = (e) => { if (e.target === overlay) overlay.remove() }
  window._lbStep = (d) => {
    cur = (cur + d + urls.length) % urls.length
    document.getElementById('lb-img').src = urls[cur]
    const c = document.getElementById('lb-cnt'); if (c) c.textContent = `${cur+1} / ${urls.length}`
  }
  document.body.appendChild(overlay)
}

// 买家端库存只显示状态，不显示精确数字（除非 ≤3 的"仅剩 N 件"清仓提示）
// 后端 low_stock 字段已带语义保护（stock ≤3 且近 7d 有成交才标）
function stockBadgeHtml(p) {
  const stock = Number(p?.stock || 0)
  if (stock <= 0) return `<span style="color:#dc2626;font-weight:500">${t('缺货')}</span>`
  const low = Number(p?.low_stock || 0)
  if (low > 0) return `<span style="color:#dc2626;font-weight:600">⚡ ${t('仅剩')} ${low} ${t('件')}</span>`
  return `<span style="color:#16a34a">● ${t('有货')}</span>`
}
// 限购上限（与 server MAX_PER_ORDER 保持一致）
const BUY_MAX_PER_ORDER = 10
function buyMaxFor(p) {
  const stock = Number(p?.stock || 0)
  if (stock <= 0) return 0
  return Math.max(1, Math.min(stock, BUY_MAX_PER_ORDER))
}

function sellerTrustLine(p) {
  const parts = []
  const lvl = p.rep_level
  if (lvl && lvl !== 'new') {
    parts.push(t('信誉') + '：' + repBadge(lvl) + ' ' + t(repLabel(lvl)))
  }
  const tx = Number(p.seller_tx_count || 0)
  if (tx > 0) {
    parts.push(t('已成交') + '：' + tx + ' ' + t('单'))
  } else if (lvl === 'new' || !lvl) {
    parts.push(t('信誉') + '：🌱 ' + t('新手'))
  }
  return parts.join(' · ')
}

// 卖家 4 维信誉详情懒加载（展开 details 触发，幂等）
const _smCache = new Map()
window.loadSellerMetrics = async (sellerId, detailsEl) => {
  if (!detailsEl?.open) return                            // 只在展开时加载
  if (detailsEl.dataset.loaded === '1') return            // 幂等
  detailsEl.dataset.loaded = '1'
  const box = document.getElementById('sm-' + sellerId)
  if (!box) return
  let data = _smCache.get(sellerId)
  if (!data) {
    try {
      const r = await fetch('/api/reputation/' + sellerId).then(r => r.json())
      data = r?.metrics
      if (data) _smCache.set(sellerId, data)
    } catch { data = null }
  }
  box.innerHTML = renderSellerMetrics(data)
}
function renderSellerMetrics(m) {
  if (!m) return `<div style="font-size:12px;color:#9ca3af">${t('信誉数据暂不可用')}</div>`
  if (m.is_new_seller) {
    return `<div style="font-size:12px;color:#9ca3af;display:flex;gap:6px;align-items:center">
      <span>🌱</span><span>${t('新卖家')} · ${t('成交')} ${m.sample_size} ${t('单')} · ${t('样本不足，暂不显示评率')}</span>
    </div>`
  }
  const bar = (label, val, hint, good /* true: 高=好 */) => {
    if (val == null) return `<div style="font-size:12px;color:#9ca3af;margin:6px 0">${label}：${t('暂无数据')}</div>`
    const pct = Math.round(val * 100)
    const tone = good
      ? (pct >= 95 ? '#16a34a' : pct >= 85 ? '#3b82f6' : pct >= 70 ? '#f59e0b' : '#dc2626')
      : (pct <= 2  ? '#16a34a' : pct <= 5  ? '#3b82f6' : pct <= 10 ? '#f59e0b' : '#dc2626')
    return `<div style="margin:8px 0">
      <div style="display:flex;justify-content:space-between;font-size:12px;color:#374151;margin-bottom:3px">
        <span>${label}${hint ? ` <span style="color:#9ca3af;font-size:10px">${hint}</span>` : ''}</span>
        <span style="font-weight:600;color:${tone}">${pct}%</span>
      </div>
      <div style="background:#e5e7eb;height:4px;border-radius:2px;overflow:hidden">
        <div style="width:${pct}%;height:100%;background:${tone}"></div>
      </div>
    </div>`
  }
  return `<div>
    <div style="font-size:11px;color:#6b7280;margin-bottom:6px">${t('基于近期')} <strong>${m.sample_size}</strong> ${t('单已完成订单统计')} · <span style="color:#9ca3af">${t('信誉分按月 2% 衰减')}</span></div>
    ${bar(t('履约率'), m.fulfillment_rate, t('完成 ÷ 完成+取消+超时'), true)}
    ${bar(t('准时发货率'), m.on_time_rate, t('准时发货 ÷ 完成单'), true)}
    ${m.dispute_count > 0 ? bar(t('争议胜诉率'), m.dispute_win_rate, `${m.dispute_count} ${t('次争议')}`, true) : `<div style="font-size:12px;color:#9ca3af;margin:6px 0">${t('争议胜诉率')}：${t('暂无争议')}</div>`}
    ${bar(t('退款率'), m.refund_rate, t('退款单 ÷ 完成单'), false)}
  </div>`
}

