// Sprint 1: 商品声明验证 公开展示 + 发起入口
function renderProductClaimsBlock(claims, product, user) {
  const isOwner = user && user.id === product.seller_id
  const canStart = user && !isOwner && (user.role === 'buyer' || user.role === 'seller')
  const upheld = claims.filter(c => c.status === 'resolved_upheld')
  const dismissed = claims.filter(c => c.status === 'resolved_dismissed')
  const open = claims.filter(c => c.status === 'open' || c.status === 'sealed')
  const badge = upheld.length > 0
    ? `<span style="background:#fef2f2;color:#991b1b;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600">⚠ ${upheld.length} ${t('项声明被验证不实')}</span>`
    : (dismissed.length > 0
        ? `<span style="background:#dcfce7;color:#166534;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600">✓ ${dismissed.length} ${t('项声明验证属实')}</span>`
        : (open.length > 0
            ? `<span style="background:#fef3c7;color:#92400e;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600">⏳ ${open.length} ${t('项验证中')}</span>`
            : ''))
  const targetLabels = {
    title: t('标题'), description: t('描述'), condition: t('成色/状态'),
    return_days: t('退货天数'), handling_hours: t('发货时效'), warranty_days: t('质保'),
    shipping_regions: t('配送范围'), origin: t('产地'), specs: t('规格'), other: t('其他'),
  }
  const claimRow = (c) => `
    <div style="padding:8px 12px;border-bottom:1px solid #f3f4f6;font-size:12px">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:6px">
        <span style="font-weight:600;color:#374151">${targetLabels[c.claim_target] || c.claim_target}</span>
        <span style="font-size:10px;color:${c.status==='resolved_upheld'?'#dc2626':c.status==='resolved_dismissed'?'#16a34a':'#f59e0b'};font-weight:600">
          ${c.status==='resolved_upheld'?'⚠ '+t('被验证不实'):c.status==='resolved_dismissed'?'✓ '+t('验证属实'):c.status==='sealed'?'⏳ '+t('结算中'):'⏳ '+(c.votes_count||0)+'/3 '+t('票')}
        </span>
      </div>
      <div style="color:#6b7280;margin-top:4px;line-height:1.4">${escHtml(c.claim_text)}</div>
      <div style="color:#9ca3af;font-size:10px;margin-top:2px">${t('发起人')}：${escHtml(c.claimant_name||'')} · ${fmtTime(c.created_at)}</div>
    </div>`
  return `
    <details ${(claims.length > 0 || canStart) ? '' : 'style="display:none"'} style="margin-top:14px;background:#fff;border:1px solid #e5e7eb;border-radius:8px" ${upheld.length > 0 ? 'open' : ''}>
      <summary style="padding:10px 12px;font-size:14px;font-weight:600;cursor:pointer;display:flex;justify-content:space-between;align-items:center">
        <span>🔎 ${t('声明验证')} (${claims.length})</span>
        ${badge}
      </summary>
      <div style="padding:0">
        ${claims.length === 0 ? `<div style="padding:14px;text-align:center;font-size:12px;color:#9ca3af">${t('暂无声明 — 你可以对商品描述的真实性发起验证')}</div>` : claims.map(claimRow).join('')}
      </div>
      ${canStart ? `
        <div style="padding:10px 12px;border-top:1px solid #f3f4f6">
          <details>
            <summary style="cursor:pointer;font-size:12px;color:#4f46e5;font-weight:600">+ ${t('对该商品发起声明验证')}</summary>
            <div style="padding:10px 0">
              <div style="font-size:11px;color:#6b7280;margin-bottom:8px;line-height:1.5">${t('锁定 5 WAZ 质押 · 3 verifier 共识投票 · 多数支持→你退 80% + 卖家失分；少数支持→你失质押')}</div>
              <select id="pcl-target-${product.id}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;margin-bottom:6px">
                <option value="title">${t('标题不符')}</option>
                <option value="description">${t('描述不符')}</option>
                <option value="condition">${t('成色/状态不符')}</option>
                <option value="return_days">${t('退货承诺不符')}</option>
                <option value="handling_hours">${t('发货时效不符')}</option>
                <option value="warranty_days">${t('质保承诺不符')}</option>
                <option value="shipping_regions">${t('配送范围不符')}</option>
                <option value="origin">${t('产地不符')}</option>
                <option value="specs">${t('规格不符')}</option>
                <option value="other">${t('其他')}</option>
              </select>
              <textarea id="pcl-text-${product.id}" rows="3" placeholder="${t('陈述具体不符内容，至少 6 字')}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;margin-bottom:6px"></textarea>
              <input id="pcl-evid-${product.id}" placeholder="${t('证据 URL（可选）')}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;margin-bottom:8px">
              <button class="btn btn-primary btn-sm" onclick="submitProductClaim('${product.id}')" style="width:100%">${t('提交声明验证（锁 5 WAZ）')}</button>
              <div id="pcl-msg-${product.id}" style="margin-top:8px"></div>
            </div>
          </details>
        </div>
      ` : ''}
    </details>
  `
}

