// 点击原生 review → P2P 拉取 + 内嵌展示
window.openNativeReview = async (hash) => {
  _openModal(`
    <h2 style="font-size:16px;font-weight:600;margin-bottom:12px">📡 ${t('原生评测')}</h2>
    <div id="native-view" style="min-height:200px">
      <div class="alert alert-info"><span class="spinner"></span>${t('正在通过 P2P 拉取内容…')}</div>
    </div>
    <div id="native-pin-row" style="display:none;margin-top:10px"></div>
    <button class="btn btn-outline btn-sm" style="margin-top:10px;width:100%" onclick="closeModal()">${t('关闭')}</button>
  `)
  try {
    const res = await p2pFetchContent(hash)
    const view = document.getElementById('native-view')
    if (!view) return
    if (res.content_type.startsWith('image/')) {
      const url = URL.createObjectURL(res.blob)
      view.innerHTML = `<img src="${url}" style="max-width:100%;border-radius:8px"><div style="font-size:11px;color:#9ca3af;margin-top:6px">${t('来源')} ${res.source} · ${(res.size/1024).toFixed(1)}KB · hash ${hash.slice(0,12)}…</div>`
    } else if (res.content_type.startsWith('text/')) {
      const text = await res.blob.text()
      view.innerHTML = `<div style="white-space:pre-wrap;background:#f9fafb;padding:12px;border-radius:6px;font-size:13px;line-height:1.5">${escHtml(text)}</div><div style="font-size:11px;color:#9ca3af;margin-top:6px">${t('来源')} ${res.source} · ${(res.size/1024).toFixed(1)}KB · hash ${hash.slice(0,12)}…</div>`
    } else {
      view.innerHTML = `<div class="alert alert-warn">${t('不支持的内容类型')}: ${escHtml(res.content_type)}</div>`
    }
    // Pin 控件：让用户决定是否长期保留 + 帮忙分发
    const local = await p2pGetContent(hash)
    if (local && !local.is_owner_content) {
      const pinRow = document.getElementById('native-pin-row')
      pinRow.style.display = ''
      const isPinned = !!local.pinned
      pinRow.innerHTML = `
        <div style="background:#f5f3ff;border:1px solid #ddd6fe;border-radius:8px;padding:10px;font-size:12px">
          <div style="font-weight:600;color:#6b21a8;margin-bottom:6px">📌 ${t('帮忙分发可分 pin 收益')}</div>
          <div style="color:#6b7280;margin-bottom:8px">${t('保留此内容并在你在线时为其他用户提供 P2P 服务。每订单 0.5% basin 拨款，去重后均分给最近 5 个 pinner。')}</div>
          <button class="btn ${isPinned ? 'btn-outline' : 'btn-primary'} btn-sm" style="width:100%" onclick="${isPinned ? `p2pUnpinContent('${hash}');closeModal()` : `p2pPinContent('${hash}');closeModal()`}">${isPinned ? '✓ ' + t('已 Pin · 点击取消') : '📌 ' + t('Pin 这个内容')}</button>
        </div>`
    }
  } catch (e) {
    const view = document.getElementById('native-view')
    if (view) view.innerHTML = alert$('error', e.message || t('拉取失败'))
  }
}

window.addToCart = async (productId) => {
  const r = await POST('/cart', { product_id: productId, qty: 1 })
  const msg = document.getElementById('buy-msg')
  if (r.error) { msg.innerHTML = alert$('error', r.error); return }
  msg.innerHTML = alert$('success', `${t('已加入购物车')} <a href="#cart" style="color:inherit;font-weight:700;text-decoration:underline">${t('去结账 →')}</a>`)
  refreshCartBadge()
}

window.qtyStep = (delta, max) => {
  const inp = document.getElementById('inp-qty'); if (!inp) return
  const cur = Math.floor(Number(inp.value) || 1)
  const next = Math.max(1, Math.min(max, cur + delta))
  inp.value = next
}

// B5 捐赠 chip 选择 — 高亮当前选中 + 更新提示文案
window.setDonationPct = (pct, basePrice) => {
  state._orderDonationPct = pct
  document.querySelectorAll('#donation-chips [data-don]').forEach(b => {
    const v = Number(b.getAttribute('data-don'))
    const on = v === pct
    b.style.background = on ? (v === 0 ? '#eef2ff' : '#fecaca') : '#fff'
    b.style.color = on ? (v === 0 ? '#4338ca' : '#7f1d1d') : (v === 0 ? '#4f46e5' : '#991b1b')
    b.style.borderColor = on ? (v === 0 ? '#4f46e5' : '#dc2626') : (v === 0 ? '#c7d2fe' : '#fca5a5')
    b.style.borderWidth = on ? '2px' : '1px'
  })
  const hint = document.getElementById('donation-amount-hint')
  if (hint) {
    if (pct > 0) {
      const amt = Math.round(Number(basePrice) * pct * 100) / 100
      hint.innerHTML = `❤️ ${t('额外捐赠')} <strong>${amt} WAZ</strong> ${t('进入慈善基金')}`
    } else {
      hint.innerHTML = ''
    }
  }
}
window.qtyClamp = (max) => {
  const inp = document.getElementById('inp-qty'); if (!inp) return
  let v = Math.floor(Number(inp.value) || 1)
  if (!Number.isFinite(v) || v < 1) v = 1
  if (v > max) v = max
  inp.value = v
}

window.doBuy = async (productId, price) => {
  const addr = document.getElementById('inp-addr').value.trim()
  const notes = document.getElementById('inp-notes').value.trim()
  const coupon_code = document.getElementById('inp-coupon')?.value?.trim() || null
  if (!addr) { document.getElementById('buy-msg').innerHTML = alert$('error', t('请填写收货地址')); return }
  // 推土机：孤儿用户首次绑 sponsor（cookie hint 30 天内有效）
  const hint = readShareHint()
  const sponsor_hint = hint?.sponsor_id || null
  // Wave B-5: 配送时间窗
  const wDay = document.getElementById('inp-window-day')?.value || 'any'
  const wTime = document.getElementById('inp-window-time')?.value || 'any'
  const wFlex = document.getElementById('inp-window-flex')?.checked !== false
  const delivery_window = (wDay !== 'any' || wTime !== 'any') ? { day_type: wDay, time_range: wTime, flexible: wFlex } : null
  // Wave C-1: variants
  const variant_id = state._selectedVariantId || null
  // 商品有 variants 但用户未选
  if ((state._variants || []).length > 0 && !variant_id) {
    document.getElementById('buy-msg').innerHTML = alert$('error', t('请先选择规格')); return
  }
  // Wave D-4 P0-1: 价格保护 — 把 buyer 看到的价格发回服务端校验
  const expected_price = Number(price)
  // C-2: 礼物订单字段
  const giftName = document.getElementById('gift-name')?.value.trim() || ''
  const giftPayload = giftName ? {
    is_gift: true,
    gift_recipient_name: giftName,
    gift_recipient_phone: document.getElementById('gift-phone')?.value.trim() || null,
    gift_message: document.getElementById('gift-message')?.value.trim() || null,
  } : {}
  // C-3: 保险
  const buy_insurance = document.getElementById('inp-insurance')?.checked || false
  // B2: 匿名收货
  const anonymous_recipient = document.getElementById('inp-anonymous')?.checked || false
  // B5: 主动捐赠
  const donation_pct = state._orderDonationPct ?? 0
  // 数量（默认 1）— 服务端会再校验 stock + MAX_PER_ORDER
  const qtyInp = document.getElementById('inp-qty')
  const quantity = qtyInp ? Math.max(1, Math.min(Number(qtyInp.max) || 1, Math.floor(Number(qtyInp.value) || 1))) : 1
  const payment_rail = window.dpSelectedRail ? window.dpSelectedRail() : 'escrow'; if (!payment_rail) { const _dp=document.querySelector('input[name="dp-rail"]:checked')?.value==='direct_p2p'; const _m=document.getElementById('buy-msg'); if(_m) _m.innerHTML = alert$('error', _dp ? t('直付暂未就绪或不可用,请稍候重试或改选支付方式') : t('请选择支付方式')); const _b=document.getElementById('dp-rail-block'); if(_b) _b.open=true; return } if (window.closeSheet) window.closeSheet()  // #28 空 rail 一律拦(永不静默落 escrow);[PRELAUNCH-WAZ-SIM] 未选→空;校验通过才关 sheet(块内 return 不关→提示+展开可见,修 P2)
  const res = await POST('/orders', { product_id: productId, shipping_address: addr, notes, sponsor_hint, coupon_code, delivery_window, variant_id, expected_price, buy_insurance, anonymous_recipient, donation_pct, quantity, payment_rail, ...giftPayload })
  if (payment_rail === 'direct_p2p') return void (window.dpAfterCreate && window.dpAfterCreate(res))
  if (res.error_code === 'PRICE_CHANGED') {
    document.getElementById('buy-msg').innerHTML = alert$('error', `${t('价格已变动')}：${res.old_price} → ${res.new_price} WAZ · ${t('请刷新页面')}`)
    return
  }
  if (res.error) { document.getElementById('buy-msg').innerHTML = alert$('error', res.error); return }
  document.getElementById('buy-msg').innerHTML = alert$('success', `${t('下单成功！')}${price} WAZ ${t('已托管，等待卖家接单')}`)
  setTimeout(() => navigate(`#order/${res.order_id}`), 1500)
}

// Wave A-3: 优惠码验证
window.checkCoupon = async (productId, basePrice) => {
  const code = document.getElementById('inp-coupon')?.value?.trim()
  const resultEl = document.getElementById('coupon-result')
  const btnEl = document.getElementById('btn-doBuy')
  if (!code) { resultEl.innerHTML = `<span style="color:#9ca3af">${t('请输入优惠码')}</span>`; return }
  // P1-1: 限时促销中不允许叠加 coupon
  if (state._flashSale) {
    resultEl.innerHTML = `<span style="color:#dc2626">⚡ ${t('限时促销中，不可与优惠券叠加')}</span>`
    return
  }
  const r = await GET(`/coupons/preview?code=${encodeURIComponent(code)}&product_id=${productId}`)
  if (!r.ok) {
    resultEl.innerHTML = `<span style="color:#dc2626">✗ ${escHtml(r.error || t('优惠码无效'))}</span>`
    if (btnEl) btnEl.innerHTML = `${t('立即下单')} · ${basePrice} WAZ`
    return
  }
  resultEl.innerHTML = `<span style="color:#16a34a">✓ ${t('已优惠')} ${r.discount} WAZ · ${t('最终')} ${r.final_price} WAZ</span>`
  if (btnEl) btnEl.innerHTML = `${t('立即下单')} · ${r.final_price} WAZ <span style="font-size:10px;text-decoration:line-through;opacity:0.7">${basePrice}</span>`
}

