async function refreshCartBadge() {
  if (!state.user || state.user.role !== 'buyer') return
  try {
    const r = await GET('/cart')
    const count = (r.items || []).reduce((s, x) => s + Number(x.qty || 0), 0)
    state.cartCount = count
    document.querySelectorAll('#cart-badge').forEach(b => {
      b.textContent = count > 0 ? count : ''
      b.style.display = count > 0 ? 'inline' : 'none'
    })
  } catch (_) { /* ignore */ }
}

async function renderCart(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'buy')   // 购物车归属智能购买流
  const data = await GET('/cart')
  const items = data.items || []

  // 全选 + 单选状态默认全选
  const selectAllBar = items.length > 0 ? `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:8px 12px;background:#f9fafb;border-radius:8px;margin-bottom:10px">
      <label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:12px;color:#374151">
        <input type="checkbox" id="cart-select-all" checked onclick="cartToggleAll(this.checked)" style="width:16px;height:16px">
        ${t('全选')} (${items.length})
      </label>
      <button onclick="cartRemoveChecked()" style="background:none;border:none;color:#dc2626;font-size:11px;cursor:pointer">${t('删除选中')}</button>
    </div>
  ` : ''

  const lowStockItems = items.filter(it => Number(it.stock) < Number(it.qty))
  const stockBanner = lowStockItems.length > 0 ? `
    <div style="background:#fef2f2;border:1px solid #fecaca;color:#b91c1c;padding:8px 12px;border-radius:8px;font-size:12px;margin-bottom:10px">
      ⚠ <strong>${lowStockItems.length}</strong> ${t('个商品库存不足')} — ${t('点商品旁的减号调整')}
    </div>
  ` : ''

  const list = items.length === 0
    ? `<div class="empty"><div class="empty-icon">🛒</div><div class="empty-text">${t('购物车空空如也')}</div><button class="btn btn-outline btn-sm" style="margin-top:12px;width:auto" onclick="navigate('#discover')">${t('去发现好物 →')}</button></div>`
    : items.map(it => {
        const subtotal = Number(it.price) * Number(it.qty)
        const lowStock = Number(it.stock) < Number(it.qty)
        return `<div class="card" style="margin-bottom:8px;padding:12px${lowStock ? ';border-left:3px solid #dc2626' : ''}">
          <div style="display:flex;gap:10px;align-items:center">
            <input type="checkbox" class="cart-item-check" data-pid="${it.product_id}" checked onclick="cartRecalcTotal()" style="width:18px;height:18px">
            <div style="font-size:28px">${getCategoryIcon(it.category)}</div>
            <div style="flex:1;min-width:0">
              <div style="font-weight:600;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(it.title)}</div>
              <div style="font-size:11px;color:#9ca3af">@${escHtml(it.seller_name)} · ${Number(it.stock) <= 0 ? `<span style="color:#dc2626">${t('缺货')}</span>` : Number(it.stock) <= 3 ? `<span style="color:#dc2626">⚡ ${t('仅剩')} ${it.stock} ${t('件')}</span>` : `<span style="color:#16a34a">● ${t('有货')}</span>`}</div>
              <div style="font-size:12px;color:#4f46e5;font-weight:600;margin-top:2px">${it.price} WAZ × ${it.qty} = ${subtotal.toFixed(2)} WAZ</div>
              ${lowStock ? `<div style="font-size:11px;color:#dc2626;margin-top:4px">⚠ ${t('库存不足，请减少数量')}</div>` : ''}
            </div>
          </div>
          <div style="display:flex;gap:6px;margin-top:10px;align-items:center">
            <button class="btn btn-outline btn-sm" style="padding:4px 10px;width:auto" onclick="cartChangeQty('${it.product_id}', ${Number(it.qty) - 1})">−</button>
            <span style="font-size:13px;min-width:30px;text-align:center">${it.qty}</span>
            <button class="btn btn-outline btn-sm" style="padding:4px 10px;width:auto" onclick="cartChangeQty('${it.product_id}', ${Number(it.qty) + 1})">+</button>
            <button class="btn btn-outline btn-sm" style="margin-left:auto;padding:4px 10px;width:auto;color:#dc2626" onclick="cartRemove('${it.product_id}')">${t('删除')}</button>
          </div>
        </div>`
      }).join('')

  const totalAll = items.reduce((s, x) => s + Number(x.price) * Number(x.qty), 0)

  app.innerHTML = shell(`
    <h1 class="page-title">🛒 ${t('购物车')}</h1>
    ${stockBanner}
    ${selectAllBar}
    ${list}
    ${items.length > 0 ? `
      <div class="card" style="position:sticky;bottom:80px;background:#fff;box-shadow:0 -2px 8px rgba(0,0,0,0.05);margin-top:12px">
        <div class="form-group">
          <label class="form-label" style="font-size:12px">${t('收货地址')}</label>
          <input class="form-control" id="cart-addr" placeholder="${t('省市区 详细地址')}" style="font-size:13px">
        </div>
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">
          <span style="font-size:13px;color:#6b7280">${t('已选合计')}</span>
          <span id="cart-checked-total" style="font-size:18px;font-weight:700;color:#4f46e5">${totalAll.toFixed(2)} WAZ</span>
        </div>
        <button class="btn btn-primary" onclick="cartCheckout()">${t('批量结账（每商品独立订单）')}</button>
        <div id="cart-msg" style="margin-top:8px"></div>
      </div>
    ` : ''}
  `, 'buy')
}

