window.submitBatchShip = async (ids) => {
  const choice = document.getElementById('bs-logistics').value
  const msg = document.getElementById('bs-msg')
  msg.innerHTML = loading$()
  // 自发货:不传 logistics_company_id(后端保持 logistics_id 空 → seller self-fulfill)
  const body = (choice && choice !== 'self') ? { order_ids: ids, logistics_company_id: choice } : { order_ids: ids }
  const res = await POST('/orders/batch-ship', body)
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  document.querySelector('.js-modal')?.remove()
  toast$(`${t('已发货')} ${res.shipped} / ${ids.length}`)
  renderSeller(document.getElementById('app'))
}

window.batchAcceptOrders = async (ids) => {
  if (!Array.isArray(ids) || ids.length === 0) return
  if (!confirm(t('确认接单 ') + ids.length + t(' 个？'))) return
  let ok = 0, fail = 0
  for (const id of ids) {
    const r = await POST(`/orders/${id}/action`, { action: 'accept' })
    if (r?.error) fail++; else ok++
  }
  alert(t('已接单 ') + ok + (fail ? ' · ' + t('失败 ') + fail : ''))
  renderSeller(document.getElementById('app'))
}

window.cartToggleAll = (checked) => {
  document.querySelectorAll('.cart-item-check').forEach(cb => { cb.checked = checked })
  cartRecalcTotal()
}
window.cartRecalcTotal = () => {
  const cards = document.querySelectorAll('.card')
  let total = 0
  document.querySelectorAll('.cart-item-check').forEach(cb => {
    if (!cb.checked) return
    const card = cb.closest('.card')
    const m = card?.innerText.match(/(\d+(?:\.\d+)?) WAZ × (\d+) = (\d+(?:\.\d+)?) WAZ/)
    if (m) total += parseFloat(m[3])
  })
  const el = document.getElementById('cart-checked-total')
  if (el) el.innerText = total.toFixed(2) + ' WAZ'
}
window.cartRemoveChecked = async () => {
  const ids = [...document.querySelectorAll('.cart-item-check')].filter(cb => cb.checked).map(cb => cb.dataset.pid)
  if (ids.length === 0) return alert(t('未选中任何商品'))
  if (!confirm(t('确认删除选中的 ') + ids.length + t(' 个商品？'))) return
  for (const pid of ids) await POST('/cart/remove', { product_id: pid })
  renderCart(document.getElementById('app'))
}

window.cartChangeQty = async (productId, qty) => {
  if (qty < 1) return cartRemove(productId)
  if (qty > 99) return
  const r = await PATCH(`/cart/${productId}`, { qty })
  if (r.error) return alert(r.error)
  renderCart(document.getElementById('app'))
  refreshCartBadge()
}

window.cartRemove = async (productId) => {
  await DELETE(`/cart/${productId}`)
  renderCart(document.getElementById('app'))
  refreshCartBadge()
}

window.cartCheckout = async () => {
  const addr = document.getElementById('cart-addr').value.trim()
  const msg = document.getElementById('cart-msg')
  if (!addr) { msg.innerHTML = alert$('error', t('请填写收货地址')); return }
  msg.innerHTML = loading$()
  // C-1: 单次后端事务批量下单（多 seller 自动分订单）
  const r = await POST('/cart/checkout', { shipping_address: addr })
  if (r.error) { msg.innerHTML = alert$('error', r.error + (r.skipped?.length ? ` · ${t('跳过')} ${r.skipped.length}` : '')); return }
  let html = `<div class="alert alert-success">${t('成功下单')} ${r.orders_created} ${t('单')} · ${t('共支付')} ${Number(r.total_paid || 0).toFixed(2)} WAZ</div>`
  if ((r.skipped || []).length > 0) {
    html += `<div class="alert alert-warn" style="font-size:11px">${t('跳过')}: ${r.skipped.map(s => s.product_id.slice(0,10) + '… (' + escHtml(s.reason) + ')').join('；')}</div>`
  }
  msg.innerHTML = html
  refreshCartBadge()
  setTimeout(() => navigate('#orders'), 1500)
}

// ─── 订单列表页 ───────────────────────────────────────────────

async function renderOrders(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'orders')
  // URL query 协议：?tab=share 自动切到订单分享 tab（跨入口跳转用）
  if (state._urlQuery?.tab === 'share') {
    state.ordersMainTab = 'share'
    state._urlQuery = {}  // 消费一次性，避免影响后续手动切回
  }
  const mainTab = state.ordersMainTab || 'manage'
  const mainTabsHtml = `
    <div style="display:flex;gap:6px;margin-bottom:12px;border-bottom:1px solid #e5e7eb">
      <button onclick="setOrdersMainTab('manage')" style="background:none;border:none;padding:8px 14px;font-size:13px;cursor:pointer;border-bottom:2px solid ${mainTab==='manage'?'#4f46e5':'transparent'};color:${mainTab==='manage'?'#4f46e5':'#6b7280'};font-weight:${mainTab==='manage'?'600':'400'}">📋 ${t('订单管理')}</button>
      <button onclick="setOrdersMainTab('share')" style="background:none;border:none;padding:8px 14px;font-size:13px;cursor:pointer;border-bottom:2px solid ${mainTab==='share'?'#4f46e5':'transparent'};color:${mainTab==='share'?'#4f46e5':'#6b7280'};font-weight:${mainTab==='share'?'600':'400'}">🔗 ${t('订单分享')}</button>
    </div>`

  if (mainTab === 'share') return renderOrdersShare(app, mainTabsHtml)

  // 订单管理（默认）— 原 P13 内容
  let orders = await GET('/orders')
  // 卖家默认只看"我卖的"（专业化）；可点击 chip 切换
  const ordersScope = state.ordersScope || (state.user.role === 'seller' ? 'sold' : 'all')
  if (ordersScope === 'sold')      orders = orders.filter(o => o.seller_id === state.user.id)
  else if (ordersScope === 'bought') orders = orders.filter(o => o.buyer_id === state.user.id)
  const groups = {
    all:        { label: t('全部'),         icon: '📋', match: () => true },
    pay:        { label: t('待付款'),       icon: '💳', match: o => o.status === 'created' },
    ship:       { label: t('待发货'),       icon: '📦', match: o => ['paid', 'accepted'].includes(o.status) },
    receive:    { label: t('待收货'),       icon: '🚚', match: o => ['shipped', 'picked_up', 'in_transit', 'delivered'].includes(o.status) },
    done:       { label: t('已完成'),       icon: '✅', match: o => ['confirmed', 'completed'].includes(o.status) },
    exception:  { label: t('退款 / 异常'),  icon: '⚠',  match: o => ['disputed', 'cancelled', 'fault_seller', 'fault_buyer', 'fault_logistics', 'resolved_for_seller', 'refunded_partial', 'refunded_full', 'dispute_dismissed', 'expired'].includes(o.status) },
  }
  const counts = Object.fromEntries(Object.entries(groups).map(([k, g]) => [k, orders.filter(g.match).length]))
  const activeGroup = state.orderGroup || 'all'
  // 等我操作的状态（买家 / 卖家视角不同）→ 排序时浮顶
  const isMine = (o) => o.buyer_id === state.user.id
  const isPending = (o) => {
    if (isMine(o)) {
      // 买家待操作：待付款 / 待确认（delivered）/ 有争议待举证
      return ['created', 'delivered'].includes(o.status) ||
             (o.status === 'disputed' && o.dispute_pending_evidence_from === 'buyer')
    } else {
      // 卖家待操作：待接单 / 待发货 / 有争议待举证
      return ['paid', 'accepted'].includes(o.status) ||
             (o.status === 'disputed' && o.dispute_pending_evidence_from === 'seller')
    }
  }
  const filtered = orders.filter(groups[activeGroup].match).sort((a, b) => {
    const pa = isPending(a) ? 0 : 1
    const pb = isPending(b) ? 0 : 1
    if (pa !== pb) return pa - pb
    return (b.created_at || '').localeCompare(a.created_at || '')
  })
  const pendingCount = filtered.filter(isPending).length

  // 视角切换 chip（仅 seller / buyer 多角色才显示；admin/verifier/logistics 等单角色不显示）
  const scopeChipsHtml = (state.user.role === 'seller' || state.user.role === 'buyer') ? `
    <div style="display:flex;gap:6px;margin-bottom:10px">
      ${['all','sold','bought'].map(s => {
        const label = { all: t('全部'), sold: '🏪 ' + t('我卖的'), bought: '🛒 ' + t('我买的') }[s]
        const on = ordersScope === s
        return `<button onclick="setOrdersScope('${s}')" style="padding:4px 10px;border-radius:12px;font-size:11px;border:1px solid ${on?'#7c2d12':'#e5e7eb'};background:${on?'#7c2d12':'#fff'};color:${on?'#fff':'#374151'};cursor:pointer;font-weight:${on?'600':'400'}">${label}</button>`
      }).join('')}
    </div>` : ''

  // chip 风格：紧凑 + 自动换行，小屏 2 行优雅显示
  const tabsHtml = `<div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:14px">
    ${Object.entries(groups).map(([k, g]) => {
      const on = activeGroup === k
      return `<button onclick="setOrderGroup('${k}')" style="display:inline-flex;align-items:center;gap:4px;padding:5px 11px;border-radius:16px;font-size:12px;border:1px solid ${on?'#4f46e5':'#e5e7eb'};background:${on?'#4f46e5':'#fff'};color:${on?'#fff':'#374151'};cursor:pointer;white-space:nowrap;font-weight:${on?'600':'400'};line-height:1.4">
        <span>${g.icon}</span><span>${g.label}</span>${counts[k] > 0 ? `<span style="background:${on?'rgba(255,255,255,0.25)':'#f3f4f6'};padding:0 7px;border-radius:99px;font-size:11px;font-weight:600;color:${on?'#fff':'#6b7280'}">${counts[k]}</span>` : ''}
      </button>`
    }).join('')}
  </div>`

  const pendingBanner = pendingCount > 0 ? `
    <div style="background:#fef3c7;border:1px solid #fde68a;color:#92400e;padding:8px 12px;border-radius:8px;font-size:12px;margin-bottom:10px;display:flex;align-items:center;gap:6px">
      ⏰ <strong>${pendingCount}</strong> ${t('个订单等你操作 — 已置顶')}
    </div>
  ` : ''

  const list = filtered.length === 0
    ? `<div class="empty"><div class="empty-icon">📭</div><div class="empty-text">${t('该分组暂无订单')}</div></div>`
    : filtered.map(o => {
        const pending = isPending(o)
        // 已完成订单（buyer 视角）显示"再次购买"按钮
        const canRebuy = isMine(o) && ['completed', 'confirmed'].includes(o.status) && o.product_id
        return `
      <div class="card" style="cursor:pointer${pending ? ';border-left:3px solid #f59e0b' : ''}">
        <div class="order-item" onclick="navigate('#order/${o.id}')">
          <div class="order-icon">${pending ? '⏰' : getCategoryIcon(o.category)}</div>
          <div class="order-info">
            <div class="order-title">${escHtml(o.product_title)}</div>
            <div class="order-meta">${fmtTime(o.created_at)} · ${o.buyer_id === state.user.id ? t('我买的') : t('我卖的')}</div>
            <div style="margin-top:6px">${orderStatusBadges(o)}</div>
          </div>
          <div class="order-amount">${o.total_amount}</div>
        </div>
        ${canRebuy ? `<div style="border-top:1px solid #f3f4f6;padding:8px 14px;display:flex;justify-content:flex-end"><button onclick="event.stopPropagation();navigate('#order-product/${o.product_id}')" style="background:#eef2ff;color:#3730a3;border:1px solid #c7d2fe;padding:4px 12px;border-radius:99px;font-size:11px;font-weight:600;cursor:pointer">🔁 ${t('再次购买')}</button></div>` : ''}
      </div>`
      }).join('')

  const exportRole = state.user?.role === 'seller' ? 'seller' : 'buyer'
  const exportBtn = `<button class="btn btn-outline btn-sm" style="float:right;font-size:11px;padding:4px 10px" onclick="exportOrders('${exportRole}')">📥 ${t('导出 CSV')}</button>`
  app.innerHTML = shell(`<h1 class="page-title">${t('我的订单')} ${exportBtn}</h1>${mainTabsHtml}${scopeChipsHtml}${notePromptPlaceholder('orders')}${tabsHtml}${pendingBanner}${list}`, 'orders')
  hydrateNotePrompt('orders')
}

window.printOrderReceipt = async (orderId) => {
  const data = await GET(`/orders/${orderId}`)
  if (data.error) { alert(data.error); return }
  const { order, product } = data
  let variantStr = ''
  try {
    const v = order.variant_options_snapshot ? JSON.parse(order.variant_options_snapshot) : null
    if (v) variantStr = Object.entries(v).map(([k, val]) => `${k}: ${val}`).join(' · ')
  } catch {}
  const w = window.open('', '_blank')
  if (!w) { alert(t('请允许弹窗以打印收据')); return }
  w.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>${t('收据')} — ${order.id}</title>
    <style>
      body { font-family: -apple-system, Segoe UI, sans-serif; padding: 30px; max-width: 600px; margin: 0 auto; color: #111; }
      h1 { font-size: 22px; margin: 0 0 4px }
      .muted { color: #666; font-size: 12px }
      .row { display: flex; justify-content: space-between; padding: 6px 0; border-bottom: 1px solid #eee }
      .total { font-size: 20px; font-weight: 700; color: #4f46e5; margin-top: 12px }
      @media print { @page { margin: 1cm } button { display: none } }
    </style>
    </head><body>
    <h1>WebAZ ${t('收据')}</h1>
    <div class="muted">${t('订单号')}: ${order.id}</div>
    <div class="muted">${t('下单时间')}: ${fmtTime(order.created_at)}</div>
    <hr style="margin:14px 0;border:none;border-top:1px solid #ddd">
    <div class="row"><span>${t('商品')}</span><strong>${escHtml(product?.title || '—')}</strong></div>
    ${variantStr ? `<div class="row"><span>${t('规格')}</span><span>${escHtml(variantStr)}</span></div>` : ''}
    <div class="row"><span>${t('数量')}</span><span>${order.quantity}</span></div>
    <div class="row"><span>${t('单价')}</span><span>${order.unit_price} WAZ</span></div>
    ${Number(order.coupon_discount) > 0 ? `<div class="row"><span>${t('优惠')}</span><span style="color:#dc2626">-${order.coupon_discount} WAZ</span></div>` : ''}
    <div class="total">${t('总计')}: ${order.total_amount} WAZ</div>
    <hr style="margin:14px 0;border:none;border-top:1px solid #ddd">
    <div class="muted">${t('收货地址')}: ${escHtml(order.shipping_address || '—')}</div>
    <div class="muted">${t('订单状态')}: ${order.status}</div>
    <button onclick="window.print()" style="margin-top:20px;padding:8px 20px;background:#4f46e5;color:#fff;border:none;border-radius:6px;cursor:pointer">🖨 ${t('打印')}</button>
    </body></html>`)
  w.document.close()
}

window.exportOrders = (role) => {
  // 直接打开端点 → 浏览器下载（Authorization 头通过 token query 传递）
  const url = `/api/orders/export?role=${role}&token=${encodeURIComponent(state.apiKey)}`
  // 浏览器导航触发下载（Content-Disposition: attachment）
  // 由于 auth() 当前只读 Authorization 头，导出端点需支持 query token；改用 fetch + blob 下载更稳
  fetch(`/api/orders/export?role=${role}`, { headers: { Authorization: 'Bearer ' + state.apiKey } })
    .then(async (r) => {
      const truncated = r.headers.get('X-Truncated') === '1'
      const limit = r.headers.get('X-Truncated-Limit')
      const blob = await r.blob()
      const a = document.createElement('a')
      const objUrl = URL.createObjectURL(blob)
      a.href = objUrl
      a.download = `webaz-orders-${role}-${new Date().toISOString().slice(0, 10)}.csv`
      document.body.appendChild(a); a.click(); a.remove()
      URL.revokeObjectURL(objUrl)
      if (truncated) {
        alert(t('导出仅含最近') + ' ' + limit + ' ' + t('条；超出部分未包含'))
      } else {
        toast$(t('导出完成'))
      }
    })
    .catch(() => toast$(t('导出失败'), 'error'))
}

window.setOrderGroup = (key) => {
  state.orderGroup = key
  renderOrders(document.getElementById('app'))
}

window.setOrdersMainTab = (k) => {
  state.ordersMainTab = k
  renderOrders(document.getElementById('app'))
}

window.setOrdersScope = (s) => {
  state.ordersScope = s
  renderOrders(document.getElementById('app'))
}

// 订单分享子页 — 待分享 / 已分享 + KPI + 取消分享两步验证
async function renderOrdersShare(app, mainTabsHtml) {
  const [orders, mySharesData] = await Promise.all([
    GET('/orders'),
    GET('/shareables/me').catch(() => ({ shareables: [] })),
  ])
  const completedAsBuyer = orders.filter(o => o.buyer_id === state.user.id && ['confirmed', 'completed'].includes(o.status))
  const myShareables = mySharesData.shareables || []

  // 已分享：我的 shareable 中 related_product_id 是我买过的商品
  const myBoughtProductIds = new Set(completedAsBuyer.map(o => o.product_id))
  const shared = myShareables.filter(s => s.related_product_id && myBoughtProductIds.has(s.related_product_id))

  // 按 product_id 聚合：每 product 的 shared 数 + 点击 + 创建时间
  const sharedByProduct = new Map()
  // 按 order_id 聚合笔记数（订单维度）
  const noteByOrder = new Map()
  // 按 product_id 聚合口令/外链数（product 维度，type != 'note'）
  const anchorByProduct = new Map()
  for (const s of shared) {
    const cur = sharedByProduct.get(s.related_product_id) || { count: 0, clicks: 0, latest: '' }
    cur.count += 1
    cur.clicks += Number(s.click_count || 0)
    if (s.created_at > cur.latest) cur.latest = s.created_at
    sharedByProduct.set(s.related_product_id, cur)
    if (s.type === 'note' && s.related_order_id) {
      noteByOrder.set(s.related_order_id, (noteByOrder.get(s.related_order_id) || 0) + 1)
    } else if (s.type !== 'note' && s.related_product_id) {
      anchorByProduct.set(s.related_product_id, (anchorByProduct.get(s.related_product_id) || 0) + 1)
    }
  }

  // 待分享订单：completed 订单中 product 还没分享过
  // 已分享订单：completed 订单中 product 已有分享（按订单一行，不按 product 聚合）
  const pending = completedAsBuyer.filter(o => !sharedByProduct.has(o.product_id))
  const sharedOrders = completedAsBuyer.filter(o => sharedByProduct.has(o.product_id))

  const subTab = state.ordersShareSubTab || 'pending'
  const sortBy = state.ordersShareSort || 'time'
  if (sortBy === 'click') {
    sharedOrders.sort((a, b) => (sharedByProduct.get(b.product_id)?.clicks || 0) - (sharedByProduct.get(a.product_id)?.clicks || 0))
  } else {
    sharedOrders.sort((a, b) => (b.updated_at || '').localeCompare(a.updated_at || ''))
  }

  const totalClicks = shared.reduce((sum, s) => sum + Number(s.click_count || 0), 0)
  const totalShares = shared.length

  const subTabsHtml = `
    <div style="display:flex;gap:6px;margin-bottom:12px">
      <button class="btn ${subTab==='pending'?'btn-primary':'btn-outline'} btn-sm" style="width:auto;padding:6px 14px;font-size:12px" onclick="setOrdersShareSubTab('pending')">📌 ${t('待分享订单')} (${pending.length})</button>
      <button class="btn ${subTab==='shared'?'btn-primary':'btn-outline'} btn-sm" style="width:auto;padding:6px 14px;font-size:12px" onclick="setOrdersShareSubTab('shared')">🔗 ${t('已分享订单')} (${sharedOrders.length})</button>
    </div>`

  const platformIcon = (p) => ({ youtube: '📺', tiktok: '🎵', xiaohongshu: '📕', bilibili: '🅱', instagram: '📷', twitter: '🐦' }[p] || '🔗')

  const pendingHtml = pending.length === 0
    ? `<div class="empty" style="padding:30px"><div class="empty-icon">✨</div><div class="empty-text">${t('暂无待分享订单（你已完成购买的商品都已设置分享，或还没有完成的订单）')}</div></div>`
    : pending.map(o => {
        const orderShort = o.id.slice(-7)
        return `
        <div class="card" style="display:flex;gap:10px;padding:10px;cursor:default;align-items:center;margin-bottom:8px">
          <div style="font-size:28px;flex-shrink:0">${getCategoryIcon(o.category)}</div>
          <div style="flex:1;min-width:0">
            <div style="font-size:13px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(o.product_title)}</div>
            <div style="font-size:11px;color:#6b7280;margin-top:2px"><a href="#order/${o.id}" style="color:#6b7280;text-decoration:none">${t('订单')} ${orderShort}</a> · ${fmtTime(o.updated_at || o.created_at)}${typeof o.total_amount !== 'undefined' ? ` · ${o.total_amount} WAZ` : ''}</div>
          </div>
          <div style="display:flex;gap:4px;flex-shrink:0">
            <button class="btn btn-outline btn-sm" style="width:auto;padding:5px 8px;font-size:10px;white-space:nowrap" onclick="shareCompletedOrder('${o.product_id}', '${escHtml(o.product_title || '').replace(/'/g, "\\'")}')">🔗 ${t('添加口令')}</button>
            <button class="btn btn-primary btn-sm" style="width:auto;padding:5px 8px;font-size:10px;white-space:nowrap" onclick="navigate('#note-new/${o.id}')">📝 ${t('创作笔记')}</button>
          </div>
        </div>`
      }).join('')

  const kpiCard = `
    <div class="card" style="background:linear-gradient(135deg,#eef2ff,#fae8ff);margin-bottom:10px">
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;font-size:13px">
        <div><div style="font-size:11px;color:#6b7280">${t('总分享数')}</div><div style="font-size:22px;font-weight:700">${totalShares}</div></div>
        <div><div style="font-size:11px;color:#6b7280">${t('累计点击')}</div><div style="font-size:22px;font-weight:700;color:#4f46e5">${totalClicks}</div></div>
      </div>
    </div>`

  const sortBar = `
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;font-size:11px">
      <div style="color:#6b7280">${t('排序')}：
        <span onclick="setOrdersShareSort('time')" style="color:${sortBy==='time'?'#4f46e5':'#9ca3af'};cursor:pointer;font-weight:${sortBy==='time'?'600':'400'};margin-left:6px">${t('时间')}</span> ·
        <span onclick="setOrdersShareSort('click')" style="color:${sortBy==='click'?'#4f46e5':'#9ca3af'};cursor:pointer;font-weight:${sortBy==='click'?'600':'400'};margin-left:6px">${t('产出（点击数）')}</span>
      </div>
      <a href="#promoter" style="color:#4f46e5">${t('去分享管理')} →</a>
    </div>`

  const sharedHtml = sharedOrders.length === 0
    ? `<div class="empty" style="padding:30px"><div class="empty-icon">📭</div><div class="empty-text">${t('还没分享过订单 — 去「待分享订单」开始')}</div></div>`
    : kpiCard + sortBar + sharedOrders.map(o => {
        const stat = sharedByProduct.get(o.product_id) || { count: 0, clicks: 0 }
        const noteN = noteByOrder.get(o.id) || 0
        const anchorN = anchorByProduct.get(o.product_id) || 0
        const orderShort = o.id.slice(-7)
        return `
        <div class="card" style="display:flex;gap:10px;padding:10px;margin-bottom:8px;align-items:center">
          <div style="font-size:28px;flex-shrink:0">${getCategoryIcon(o.category)}</div>
          <div style="flex:1;min-width:0">
            <div style="font-size:13px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(o.product_title)}</div>
            <div style="font-size:11px;color:#6b7280;margin-top:2px"><a href="#order/${o.id}" style="color:#6b7280;text-decoration:none">${t('订单')} ${orderShort}</a> · ${fmtTime(o.updated_at || o.created_at)}</div>
            <div style="font-size:10px;color:#9ca3af;margin-top:2px">📝 ${noteN} · 🔗 ${anchorN} · 🔥 ${stat.clicks} ${t('点击')}</div>
          </div>
          <button class="btn btn-primary btn-sm" style="width:auto;padding:5px 10px;font-size:11px;align-self:center;white-space:nowrap" onclick="viewProductShares('${o.product_id}', 'all', '${o.id}')">👁 ${t('查看分享')}</button>
        </div>`
      }).join('')

  app.innerHTML = shell(`<h1 class="page-title">${t('我的订单')}</h1>${mainTabsHtml}${subTabsHtml}${subTab === 'pending' ? pendingHtml : sharedHtml}`, 'orders')
}

