// 取消分享（两步验证：confirm + 密码 gate）
window.cancelOrderShare = async (shareableId, title) => {
  // 第 1 步：自定义 confirmModal（强警告 + 默认聚焦取消，避免误操作）
  const ok1 = await confirmModal(
    t('确认取消分享') + ` 「${title}」？\n\n` +
    t('⚠ 此操作不可撤销 — 取消后此分享将立即下架，关联的点击 / 转化数据停止累计。') + '\n\n' +
    t('下一步需要验证登录密码。'),
    '⚠ ' + t('确认取消'),
    { danger: true }
  )
  if (!ok1) return
  // 第 2 步：密码 gate
  const ok2 = await requireApiKeyPassword()
  if (!ok2) return
  const r = await DELETE(`/shareables/${shareableId}`)
  if (r.error) return toast$(r.error, 'error')
  toast$(t('已取消分享'))
  // hash-aware re-render：根据用户当前所在页选对应 render，避免跳错页
  const h = location.hash || ''
  const app = document.getElementById('app')
  if (h.startsWith('#promoter')) renderPromoter(app)
  else if (h.startsWith('#note/')) renderNoteLanding(app, h.slice('#note/'.length).split('?')[0])
  else renderOrders(app)
}

