// 订单签名链 — 验证徽标 + 查看器
window.loadChainBadge = async (orderId) => {
  const el = document.getElementById('chain-badge-' + orderId)
  if (!el) return
  try {
    const r = await GET(`/orders/${orderId}/chain`)
    const v = r?.verification
    if (v?.ok && v.total > 0) {
      el.textContent = `🔒 ${t('链验证通过')} · ${v.total} ${t('事件')}`
      el.style.background = '#dcfce7'
      el.style.color = '#15803d'
    } else if (v?.reason === 'chain_incomplete') {
      el.textContent = `⚠️ ${t('链不完整')} ${v.total}/${v.history_count}`
      el.style.background = '#fef3c7'
      el.style.color = '#92400e'
    } else if (v?.total === 0) {
      el.textContent = `⚠️ ${t('无签名链')}`
      el.style.background = '#fef3c7'
      el.style.color = '#92400e'
    } else {
      el.textContent = `⚠️ ${t('链异常')}: ${v?.reason || 'unknown'}`
      el.style.background = '#fee2e2'
      el.style.color = '#b91c1c'
    }
  } catch {
    el.textContent = `❓ ${t('链未知')}`
  }
}

window.openChainViewer = async (orderId) => {
  const r = await GET(`/orders/${orderId}/chain`)
  if (!r?.chain) return
  const v = r.verification
  const headerColor = v.ok ? '#15803d' : '#b91c1c'
  const headerBg    = v.ok ? '#dcfce7' : '#fee2e2'
  const headerText  = v.ok ? `🔒 ${t('链验证通过')} (${v.total} ${t('事件')})` : `⚠️ ${t('链异常')}: ${v.reason} @ seq ${v.firstBrokenSeq}`
  const events = r.chain.map((ev, i) => `
    <div style="background:#fff;border:0.5px solid ${i === v.firstBrokenSeq ? '#fecaca' : '#e5e7eb'};border-radius:8px;padding:10px 12px;margin-bottom:8px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
        <div style="font-size:12px;font-weight:600;color:#1f2937">#${ev.seq} · ${ev.event_type} · ${ev.from_status || '∅'} → ${ev.to_status}</div>
        <div style="font-size:10px;color:#9ca3af">${fmtTime(ev.signed_at)}</div>
      </div>
      <div style="font-size:11px;color:#6b7280;margin-bottom:6px">${ev.actor_role} · <code style="font-family:ui-monospace,Consolas,monospace">${escHtml(ev.actor_id)}</code></div>
      <div style="font-size:10px;color:#9ca3af;font-family:ui-monospace,Consolas,monospace;word-break:break-all">
        <div>${t('hash')}: ${ev.event_hash.slice(0, 16)}…${ev.event_hash.slice(-8)}</div>
        ${ev.prev_event_hash ? `<div>${t('prev')}: ${ev.prev_event_hash.slice(0, 16)}…${ev.prev_event_hash.slice(-8)}</div>` : ''}
        <div>${t('sig')}: ${ev.signature.slice(0, 16)}…${ev.signature.slice(-8)}</div>
      </div>
    </div>
  `).join('')
  _openModal(`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
      <h2 style="font-size:15px;font-weight:600;margin:0">${t('订单签名链')}</h2>
      <button onclick="closeModal()" style="background:none;border:none;font-size:22px;color:#9ca3af;cursor:pointer">×</button>
    </div>
    <div style="background:${headerBg};color:${headerColor};padding:8px 12px;border-radius:8px;font-size:12px;font-weight:600;margin-bottom:12px">${headerText}</div>
    <div style="font-size:11px;color:#8e8e93;margin-bottom:10px;line-height:1.5">${t('每个事件由当事人 api_key HMAC 签名 + hash 链续。任何篡改、删除、伪造都会让验证失败。')}</div>
    ${events}
  `)
}

// 订单阶段时间线 — 横向 stage strip：已完成 / 当前 / 未来
// 异常分支（cancelled / disputed / fault_*）单独显示
// 把"快递单号：SF1234567890 · 顺丰速运"这种 evidence 字符串拆成 单号 + 承运方，
// 渲染为：[📎 单号 (复制) (查询)]
function trackingEvidenceLine(rawLabel) {
  const PREFIX = '快递单号：'
  if (!rawLabel.startsWith(PREFIX)) {
    return `<div style="font-size:13px;color:#374151;margin-top:3px;background:#f9fafb;border-radius:6px;padding:4px 8px">📎 ${escHtml(rawLabel)}</div>`
  }
  const rest = rawLabel.slice(PREFIX.length).trim()
  // 拆出单号（首段非空白）+ 后缀（如 "· 顺丰速运"）
  const m = rest.match(/^([A-Za-z0-9_-]+)(.*)$/)
  if (!m) return `<div style="font-size:13px;color:#374151;margin-top:3px;background:#f9fafb;border-radius:6px;padding:4px 8px">📎 ${escHtml(rawLabel)}</div>`
  const tn = m[1]
  const suffix = m[2].trim()
  const carrier = inferCarrier(tn, suffix)
  const lookupUrl = carrierLookupUrl(tn, carrier)
  return `<div style="font-size:13px;color:#374151;margin-top:3px;background:#f9fafb;border-radius:6px;padding:6px 10px;display:flex;align-items:center;justify-content:space-between;gap:8px;flex-wrap:wrap">
    <div style="display:flex;align-items:center;gap:6px;min-width:0;flex:1">
      <span>📎</span>
      <span style="font-family:monospace;font-weight:600;color:#1f2937">${escHtml(tn)}</span>
      ${carrier ? `<span style="font-size:11px;color:#6b7280">· ${escHtml(carrier)}</span>` : ''}
    </div>
    <div style="display:flex;gap:6px">
      <button onclick="copyTracking('${escAttr(tn)}', this)" style="background:#fff;border:1px solid #e5e7eb;border-radius:6px;padding:3px 10px;font-size:11px;color:#374151;cursor:pointer">${t('复制')}</button>
      ${lookupUrl ? `<a href="${lookupUrl}" target="_blank" rel="noopener" style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:6px;padding:3px 10px;font-size:11px;color:#1d4ed8;text-decoration:none">${t('查询')} →</a>` : ''}
    </div>
  </div>`
}

// 由后缀 / 单号前缀粗略识别快递公司
function inferCarrier(trackingNo, suffix) {
  if (suffix) {
    // 后缀里直接有公司名
    const known = ['顺丰', 'SF', '中通', '圆通', '韵达', '申通', 'EMS', '京东', '德邦', '邮政', 'UPS', 'FedEx', 'DHL', 'USPS']
    for (const k of known) {
      if (suffix.includes(k)) return k
    }
  }
  // 单号前缀启发
  if (/^SF\d/i.test(trackingNo)) return '顺丰'
  if (/^7\d{11}$/.test(trackingNo)) return '中通'
  if (/^YT\d/i.test(trackingNo)) return '圆通'
  if (/^YD\d/i.test(trackingNo)) return '韵达'
  if (/^[A-Z]{2}\d{9}CN$/.test(trackingNo)) return 'EMS'
  if (/^1Z[A-Z0-9]{16}$/i.test(trackingNo)) return 'UPS'
  return ''
}
function carrierLookupUrl(trackingNo, carrier) {
  const encoded = encodeURIComponent(trackingNo)
  // 优先用通用聚合查询（17track / kuaidi100）保证总能查到
  const fallback = `https://www.17track.net/zh-cn#nums=${encoded}`
  if (!carrier) return fallback
  const map = {
    '顺丰':  `https://www.sf-express.com/we/ow/chn/sc/waybill/waybill/${encoded}`,
    'SF':    `https://www.sf-express.com/we/ow/chn/sc/waybill/waybill/${encoded}`,
    'EMS':   `https://www.ems.com.cn/queryList?mailNum=${encoded}`,
    'UPS':   `https://www.ups.com/track?tracknum=${encoded}`,
    'FedEx': `https://www.fedex.com/fedextrack/?trknbr=${encoded}`,
    'DHL':   `https://www.dhl.com/global-en/home/tracking.html?tracking-id=${encoded}`,
    'USPS':  `https://tools.usps.com/go/TrackConfirmAction?tLabels=${encoded}`,
  }
  return map[carrier] || fallback
}
window.copyTracking = (tn, btn) => {
  try {
    navigator.clipboard.writeText(tn)
    if (btn) {
      const orig = btn.textContent
      btn.textContent = t('已复制')
      btn.style.background = '#dcfce7'
      btn.style.color = '#15803d'
      setTimeout(() => { btn.textContent = orig; btn.style.background = '#fff'; btn.style.color = '#374151' }, 1500)
    }
  } catch { alert(tn) }
}

function orderStageTimeline(order, history) {
  const STAGES = [
    { key: 'created',    label: t('下单'),  icon: '📝' },
    { key: 'paid',       label: t('付款'),  icon: '💳' },
    { key: 'accepted',   label: t('接单'),  icon: '✋' },
    { key: 'shipped',    label: t('发货'),  icon: '📦' },
    { key: 'delivered',  label: t('送达'),  icon: '🚚' },
    { key: 'completed',  label: t('完成'),  icon: '✓' },
  ]
  // 异常状态：单独 banner，不画时间线（防误导）
  const ANOMALY = ['disputed', 'cancelled', 'fault_seller', 'fault_buyer', 'fault_logistics', 'refunded_partial', 'refunded_full', 'dispute_dismissed', 'expired']
  if (ANOMALY.includes(order.status)) {
    const colorMap = {
      disputed: '#f59e0b', cancelled: '#6b7280',
      fault_seller: '#dc2626', fault_buyer: '#dc2626', fault_logistics: '#dc2626',
      refunded_full: '#16a34a', refunded_partial: '#3b82f6', dispute_dismissed: '#6b7280', expired: '#9ca3af',
    }
    const labelMap = {
      disputed: t('订单进入争议'), cancelled: t('订单已取消'),
      fault_seller: t('卖家违约'), fault_buyer: t('买家违约'), fault_logistics: t('物流违约'),
      refunded_full: t('已全额退款'), refunded_partial: t('部分退款'),
      dispute_dismissed: t('争议已驳回'), expired: t('订单已超时'),
    }
    const c = colorMap[order.status] || '#6b7280'
    return `<div style="background:#fff;border:0.5px solid #e5e7eb;border-radius:12px;padding:14px 16px;margin-bottom:10px;display:flex;align-items:center;gap:10px">
      <div style="width:8px;height:8px;border-radius:50%;background:${c};flex-shrink:0"></div>
      <div style="flex:1">
        <div style="font-size:14px;font-weight:600;color:#1f2937">${labelMap[order.status] || order.status}</div>
        <div style="font-size:11px;color:#8e8e93;margin-top:2px">${t('查看下方时间线了解流转详情')}</div>
      </div>
    </div>`
  }
  // 正常流：用 history 找每个阶段的完成时间
  // shipped 涵盖 shipped/picked_up/in_transit；delivered 是 delivered；completed = confirmed/completed
  const histByStatus = {}
  for (const h of (history || [])) {
    if (!histByStatus[h.to_status]) histByStatus[h.to_status] = h.created_at
  }
  const completedAt = (stageKey) => {
    if (stageKey === 'created')   return order.created_at
    if (stageKey === 'shipped')   return histByStatus['shipped'] || histByStatus['picked_up'] || histByStatus['in_transit']
    if (stageKey === 'completed') return histByStatus['completed'] || histByStatus['confirmed']
    return histByStatus[stageKey]
  }
  // "当前" = 正在等待的下一阶段（不是已完成的最后阶段）
  // created → 等付款；paid → 等接单；accepted → 等发货；shipped/in_transit → 等送达；
  // delivered → 等买家确认；confirmed/completed → 全部完成
  const statusToIdx = { created: 1, paid: 2, accepted: 3, shipped: 4, picked_up: 4, in_transit: 4, delivered: 5, confirmed: 6, completed: 6 }
  let currentIdx = statusToIdx[order.status] ?? 0

  const dot = (s, i) => {
    const done = i < currentIdx
    const active = i === currentIdx
    const future = i > currentIdx
    const bg = done ? '#16a34a' : active ? '#007aff' : '#e5e7eb'
    const fg = done || active ? '#fff' : '#9ca3af'
    const ts = completedAt(s.key)
    return `<div style="display:flex;flex-direction:column;align-items:center;flex:1;min-width:0;position:relative">
      <div style="width:28px;height:28px;border-radius:50%;background:${bg};color:${fg};display:flex;align-items:center;justify-content:center;font-size:13px;flex-shrink:0;${active ? 'box-shadow:0 0 0 4px rgba(0,122,255,0.2);' : ''}z-index:1">${done ? '✓' : s.icon}</div>
      <div style="font-size:11px;color:${done || active ? '#1f2937' : '#9ca3af'};font-weight:${active ? '600' : '500'};margin-top:4px;text-align:center;white-space:nowrap">${s.label}</div>
      ${ts ? `<div style="font-size:9px;color:#9ca3af;margin-top:1px">${new Date(ts).toLocaleString(window._lang === 'en' ? 'en-US' : 'zh-CN', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' })}</div>` : ''}
    </div>`
  }
  const connector = (i) => {
    const c = i < currentIdx ? '#16a34a' : '#e5e7eb'
    return `<div style="flex:0 0 auto;height:2px;background:${c};align-self:flex-start;margin-top:14px;min-width:8px;flex:1;max-width:40px"></div>`
  }
  const cells = []
  STAGES.forEach((s, i) => {
    cells.push(dot(s, i))
    if (i < STAGES.length - 1) cells.push(connector(i))
  })
  return `<div style="background:#fff;border:0.5px solid #e5e7eb;border-radius:12px;padding:14px 12px;margin-bottom:10px;overflow-x:auto">
    <div style="display:flex;align-items:flex-start;min-width:fit-content">${cells.join('')}</div>
  </div>`
}

// 2026-05-22 物流追踪时间轴 — 竖直 timeline，含 history + 未来截止提示
// 与顶部紧凑 stepper 互补：stepper 给总览，timeline 给细节
function orderTrackingTimeline(order, history, trackingInfo, STATUS_ZH) {
  // 异常订单不显示物流时间线（争议/取消等）— 由顶部 stepper 异常 banner 兜底
  const ANOMALY = ['disputed', 'cancelled', 'fault_seller', 'fault_buyer', 'fault_logistics', 'refunded_partial', 'refunded_full', 'dispute_dismissed', 'expired']
  if (ANOMALY.includes(order.status)) return ''

  // 已完成节点 lookup
  const histByStatus = {}
  const actorByStatus = {}
  for (const h of history) {
    if (!histByStatus[h.to_status]) {
      histByStatus[h.to_status] = h.created_at
      actorByStatus[h.to_status] = { name: h.actor_name, role: h.actor_role, notes: h.notes, evidence: h.evidence_items || [] }
    }
  }
  // 节点定义（buyer 视角友好）
  const NODES = [
    { key: 'paid',       icon: '💳', label: t('已付款'),     deadline: null },
    { key: 'accepted',   icon: '✋', label: t('卖家接单'),   deadline: order.accept_deadline },
    { key: 'shipped',    icon: '📦', label: t('卖家发货'),   deadline: order.ship_deadline },
    { key: 'picked_up',  icon: '🚛', label: t('物流揽收'),   deadline: order.pickup_deadline },
    { key: 'in_transit', icon: '🛣',  label: t('运输中'),     deadline: null },   // 中间态，无独立 deadline
    { key: 'delivered',  icon: '📬', label: t('已送达'),     deadline: order.delivery_deadline },
    { key: 'confirmed',  icon: '✓',  label: t('买家确认'),   deadline: order.confirm_deadline },
  ]
  const statusToIdx = { created: -1, paid: 0, accepted: 1, shipped: 2, picked_up: 3, in_transit: 4, delivered: 5, confirmed: 6, completed: 6 }
  const currentIdx = statusToIdx[order.status] ?? -1
  const now = Date.now()

  const rows = NODES.map((n, i) => {
    const done = histByStatus[n.key] || (n.key === 'confirmed' && (histByStatus.completed || histByStatus.confirmed))
    const isCurrent = i === currentIdx + 1 && !done  // 下一个待办
    const isOverdue = !done && n.deadline && new Date(n.deadline).getTime() < now

    // dot 颜色
    let dotBg, dotFg, dotInner
    if (done) {
      dotBg = '#16a34a'; dotFg = '#fff'; dotInner = '✓'
    } else if (isOverdue) {
      dotBg = '#dc2626'; dotFg = '#fff'; dotInner = '!'
    } else if (isCurrent) {
      dotBg = '#007aff'; dotFg = '#fff'; dotInner = n.icon
    } else {
      dotBg = '#e5e7eb'; dotFg = '#9ca3af'; dotInner = n.icon
    }

    // 右侧文案
    let sub = ''
    if (done) {
      const actor = actorByStatus[n.key]
      sub = `<div style="font-size:11px;color:#6b7280;margin-top:2px">${fmtTime(done)}${actor?.name ? ' · ' + escHtml(actor.name) : ''}</div>`
      if (actor?.notes) sub += `<div style="font-size:11px;color:#6b7280;margin-top:2px">💬 ${escHtml(actor.notes)}</div>`
      // 物流证据（快递单号等）
      const ev = trackingInfo.find(ti => ti.status === n.key)
      if (ev && ev.evidence && ev.evidence.length > 0) {
        sub += (ev.evidence || []).map(e => {
          const label = (n.key === 'picked_up' && !e.startsWith('快递单号：')) ? `快递单号：${e}` : e
          return trackingEvidenceLine(label)
        }).join('')
      }
    } else if (isOverdue) {
      sub = `<div style="font-size:11px;color:#dc2626;font-weight:600;margin-top:2px">⚠ ${t('已超时')} · ${fmtTime(n.deadline)}</div>`
    } else if (isCurrent && n.deadline) {
      sub = `<div style="font-size:11px;color:#007aff;margin-top:2px">⏳ ${fmtCountdown(n.deadline)}</div>`
    } else if (isCurrent) {
      sub = `<div style="font-size:11px;color:#007aff;margin-top:2px">⏳ ${t('进行中')}</div>`
    } else if (n.deadline) {
      sub = `<div style="font-size:11px;color:#9ca3af;margin-top:2px">${t('预计')} ${fmtTime(n.deadline)}</div>`
    }

    // 连接线（除最后一个节点都有）
    const lineColor = done ? '#16a34a' : '#e5e7eb'
    const connector = i < NODES.length - 1
      ? `<div style="position:absolute;left:13px;top:28px;width:2px;height:calc(100% - 4px);background:${lineColor}"></div>`
      : ''

    return `<div style="position:relative;padding-left:38px;padding-bottom:14px">
      ${connector}
      <div style="position:absolute;left:0;top:0;width:28px;height:28px;border-radius:50%;background:${dotBg};color:${dotFg};display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;${isCurrent ? 'box-shadow:0 0 0 4px rgba(0,122,255,0.2)' : ''}">${dotInner}</div>
      <div style="font-size:13px;color:${done ? '#1f2937' : isOverdue ? '#dc2626' : isCurrent ? '#1f2937' : '#9ca3af'};font-weight:${isCurrent || done ? '600' : '500'}">${n.label}</div>
      ${sub}
    </div>`
  }).join('')

  return `<div class="card">
    <div class="action-title">🚚 ${t('物流追踪')}</div>
    <div style="padding:8px 4px 0">${rows}</div>
  </div>`
}

// 倒计时格式化 — 把 deadline 转成"剩 N 天 N 小时"
function fmtCountdown(deadlineIso) {
  if (!deadlineIso) return ''
  const ms = new Date(deadlineIso).getTime() - Date.now()
  if (ms <= 0) return t('已超时')
  const totalMin = Math.floor(ms / 60000)
  const d = Math.floor(totalMin / 1440)
  const h = Math.floor((totalMin % 1440) / 60)
  const m = totalMin % 60
  if (d > 0) return `${t('剩')} ${d} ${t('天')} ${h} ${t('小时')}`
  if (h > 0) return `${t('剩')} ${h} ${t('小时')} ${m} ${t('分')}`
  return `${t('剩')} ${m} ${t('分钟')}`
}

// 下一步引导卡 — 买家/卖家视角不同的 next-action 提示
function nextActionCard(order, isBuyer, isSeller, activeDeadline, isOverdue) {
  const STEP_HINT = {
    created:   { who: 'buyer',  buyer: '请尽快完成付款',     seller: '等待买家付款',
                 overdueFault: 'fault_buyer', overdueConsequence: '订单将被取消，资金原路退回' },
    paid:      { who: 'seller', buyer: '等待卖家接单',       seller: '请尽快接单确认订单',
                 overdueFault: 'fault_seller', overdueConsequence: '卖家信誉 -40 + 全额退款给你' },
    accepted:  { who: 'seller', buyer: '等待卖家发货',       seller: '请按时发货 + 录入物流单号',
                 overdueFault: 'fault_seller', overdueConsequence: '卖家信誉 -40 + 全额退款给你' },
    shipped:   { who: 'logistic', buyer: '等待物流揽收',     seller: '物流已通知，等待揽收',
                 overdueFault: 'fault_logistics', overdueConsequence: '物流信誉 -40 + 卖家可重新指派' },
    picked_up: { who: 'logistic', buyer: '物流揽收中',       seller: '物流揽收中' },
    in_transit:{ who: 'logistic', buyer: '商品运输中',       seller: '商品运输中',
                 overdueFault: 'fault_logistics', overdueConsequence: '物流信誉 -40 + 退款给你' },
    delivered: { who: 'buyer',  buyer: '请确认收货并评价',   seller: '已送达，等待买家确认',
                 overdueFault: 'auto_confirm', overdueConsequence: '系统自动确认收货，资金释放给卖家' },
  }
  const hint = STEP_HINT[order.status]
  if (!hint) return ''
  const myHint = isBuyer ? hint.buyer : isSeller ? hint.seller : ''
  if (!myHint) return ''
  const meIsWhose = (isBuyer && hint.who === 'buyer') || (isSeller && hint.who === 'seller')
  const tone = isOverdue ? '#dc2626' : meIsWhose ? '#007aff' : '#6b7280'
  const bg = isOverdue ? '#fef2f2' : meIsWhose ? '#eff6ff' : '#f9fafb'
  const icon = isOverdue ? '⚠' : meIsWhose ? '👉' : '⏳'
  // 超时 + 我不是违约方 → 给我一个"立即触发判责"按钮（不必等 5min cron tick）
  // 我自己是违约方时只看到警告，不显示按钮（不能自己触发对自己的判责）
  const meAtFault = hint.overdueFault && hint.overdueFault === ('fault_' + (isBuyer ? 'buyer' : isSeller ? 'seller' : ''))
  const canForceTrigger = isOverdue && hint.overdueFault && !meAtFault && (isBuyer || isSeller)
  return `<div style="background:${bg};border:0.5px solid ${isOverdue ? '#fecaca' : '#e5e7eb'};border-radius:12px;padding:14px 16px;margin-bottom:10px">
    <div style="display:flex;align-items:center;gap:10px">
      <div style="font-size:22px;line-height:1">${icon}</div>
      <div style="flex:1">
        <div style="font-size:14px;font-weight:600;color:${tone}">${t(myHint)}</div>
        ${activeDeadline?.deadline ? `<div style="font-size:11px;color:#8e8e93;margin-top:2px">${isOverdue ? t('已超时，协议将自动判责') : fmtCountdown(activeDeadline.deadline)}</div>` : ''}
        ${isOverdue && hint.overdueConsequence ? `<div style="margin-top:8px;padding:8px 10px;background:#fff;border-radius:6px;font-size:12px;color:#7c2d12;border:1px dashed #fecaca">
          ⚖️ ${t('协议处置')}：${t(hint.overdueConsequence)}
        </div>` : ''}
        ${canForceTrigger ? `<button onclick="forceTimeoutCheck('${order.id}')" style="margin-top:10px;background:#dc2626;color:#fff;border:none;border-radius:8px;padding:8px 14px;font-size:13px;font-weight:600;cursor:pointer">⚡ ${t('立即触发判责')}</button>
        <div style="font-size:10px;color:#9ca3af;margin-top:6px">${t('协议巡检每 5 分钟一次；你也可立即触发，无需等待。')}</div>` : ''}
      </div>
    </div>
  </div>`
}

window.forceTimeoutCheck = async (orderId) => {
  if (!confirm(t('立即触发判责？此操作不可撤销。'))) return
  const res = await POST(`/orders/${orderId}/force-timeout-check`, {})
  if (res.error) { toast$(res.error, 'error'); return }
  if (res.changed) {
    toast$(t('已触发判责：') + res.action)
  } else {
    toast$(t('订单状态未变 — 可能还未真正超时，或已被其他人触发'))
  }
  setTimeout(() => renderOrderDetail(document.getElementById('app'), orderId), 800)
}

async function renderOrderDetail(app, orderId) {
  if (!orderId) { navigate('#orders'); return }
  app.innerHTML = shell(loading$(), 'orders')
  const data = await GET(`/orders/${orderId}`)
  if (data.error) { app.innerHTML = shell(alert$('error', data.error), 'orders'); return }

  const { order, history, currentResponsible, activeDeadline, isOverdue, product } = data
  // 如果有争议，拉取含证据的完整争议数据
  let dispute = data.dispute
  if (dispute?.id) {
    const fullDispute = await GET(`/disputes/${dispute.id}`)
    if (!fullDispute.error) dispute = fullDispute
  }
  const isBuyer    = order.buyer_id    === state.user?.id
  const isSeller   = order.seller_id   === state.user?.id
  // 物流方：已分配的 or 尚未分配（可自行揽收）
  const isLogistic = state.user?.role === 'logistics' &&
    (order.logistics_id === state.user?.id || (!order.logistics_id && order.status === 'shipped'))

  // 卖家在 accepted 状态需要物流公司列表
  let logisticsCompanies = []
  if (isSeller && order.status === 'accepted') {
    const lc = await GET('/logistics/companies')
    logisticsCompanies = Array.isArray(lc) ? lc : []
  }

  // 操作按钮
  const actions = getActions(order, isBuyer, isSeller, isLogistic)
  window._dpOrderRail = order.payment_rail  // direct_p2p:路由 mark_paid/confirm 到 Passkey 门(动作在渲染后触发,早设即可);hydrate 移到最终 app.innerHTML 之后(见下)——在此调度会撞 claim-task 的 await 间隙、#dp-order-instr 尚未渲染而 if(!box) 静默 bail → 框永久"加载中"

  const STATUS_ZH = {
    created:'待付款', direct_pay_window:'直付待付款', direct_expired_unconfirmed:'直付超时未确认', paid:'待接单', accepted:'待发货', shipped:'已发货',
    picked_up:'已揽收', in_transit:'运输中', delivered:'待确认',
    confirmed:'已确认', completed:'已完成', disputed:'争议中',
    cancelled:'已取消', fault_seller:'卖家违约', fault_buyer:'买家违约', fault_logistics:'物流违约',
  }

  const historyHtml = (history || []).map(h => `
    <div class="timeline-item">
      <div><span class="timeline-status">${STATUS_ZH[h.from_status] || h.from_status} → ${STATUS_ZH[h.to_status] || h.to_status}</span></div>
      <div class="timeline-actor">${h.actor_name}（${h.actor_role_name || h.actor_role}）</div>
      <div class="timeline-time">${fmtTime(h.created_at)}</div>
      ${h.notes ? `<div class="timeline-evidence" style="color:#6b7280">💬 ${h.notes}</div>` : ''}
      ${(h.evidence_items || []).map(e => `<div class="timeline-evidence">📎 ${e.description}</div>`).join('')}
    </div>`).join('')

  // 物流追踪完整时间轴 — 含订单全流转 + 未到达节点的截止提示
  const trackingHtml = orderTrackingTimeline(order, history || [], data.trackingInfo || [], STATUS_ZH)

  const disputeHtml = dispute ? buildDisputeHtml(dispute, state.user) : ''

  // M7.3c：拉关联 claim verification task（当事人/已投票 verifier 可见）
  const claimData = await GET(`/orders/${orderId}/claim-task`)
  const claimTask = claimData?.task
  const claimAllowedStatuses = new Set(['paid', 'accepted', 'shipped', 'picked_up', 'in_transit', 'delivered', 'disputed'])
  const claimHtml = claimTask
    ? `<div class="card" style="background:linear-gradient(135deg,#eef2ff,#fff);border-color:#c7d2fe">
         <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
           <div style="font-size:13px;font-weight:600;color:#3730a3">🔎 ${t('claim 验证任务')}</div>
           ${claimStatusBadge(claimTask.status)}
         </div>
         <div style="font-size:12px;color:#374151;margin-bottom:8px">
           ${t('针对')}：${CLAIM_TARGET_LABEL()[claimTask.claim_target] || claimTask.claim_target} ·
           ${t('票数')} ${(claimData.votes||[]).length}/${claimData.votes_needed}
         </div>
         <button class="btn btn-outline btn-sm" style="width:auto;font-size:11px;padding:5px 12px" onclick="navigate('#claim-task/${claimTask.id}')">${t('查看任务详情')} →</button>
       </div>`
    : (isBuyer && claimAllowedStatuses.has(order.status))
      ? `<div class="card" style="background:#fafafa;border:1px dashed #d1d5db">
           <div style="font-size:12px;color:#6b7280;margin-bottom:8px;line-height:1.6">
             🔎 ${t('对推荐理由有疑问？发起验证任务')}<br>
             <span style="font-size:11px;color:#9ca3af">${t('锁 10 WAZ 启动，3 verifier 共识仲裁。不可撤销。')}</span>
           </div>
           <button class="btn btn-outline btn-sm" style="width:auto;font-size:12px;padding:6px 14px" onclick="openInitiateClaimModal('${orderId}')">${t('对推荐理由发起验证')}</button>
         </div>`
      : ''

  // 协议层链验证（异步，验证完后更新徽标）
  setTimeout(() => loadChainBadge(orderId), 0)

  app.innerHTML = shell(`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
      <button class="btn btn-gray btn-sm" style="width:auto" onclick="history.back()">${t('← 返回')}</button>
      <div style="display:flex;gap:6px;align-items:center">
        <span id="chain-badge-${orderId}" style="font-size:10px;color:#9ca3af;background:#f3f4f6;padding:3px 8px;border-radius:99px;cursor:pointer" onclick="openChainViewer('${orderId}')">${t('验证中…')}</span>
        ${order.status === 'completed' ? `<button class="btn btn-outline btn-sm" style="width:auto;font-size:11px;padding:4px 10px" onclick="printOrderReceipt('${order.id}')">🧾 ${t('打印收据')}</button>` : ''}
      </div>
    </div>

    ${window.wazEscrowOrderBanner ? window.wazEscrowOrderBanner(order, isBuyer) : ''}${orderStageTimeline(order, history)}
    ${nextActionCard(order, isBuyer, isSeller, activeDeadline, isOverdue)}

    <div class="card">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
        <div style="font-size:13px;color:#6b7280;font-family:monospace">${order.id}</div>
        <div style="display:flex;gap:6px;align-items:center">
          ${(isBuyer || isSeller) ? `<button class="btn btn-sm" style="background:#eef2ff;color:#4338ca;font-size:11px;padding:4px 10px" onclick="openChatForContext('order','${order.id}')">💬 ${t('联系对方')}</button>` : ''}
          ${orderStatusBadges(order)}
        </div>
      </div>
      <div class="detail-row"><span class="detail-label">${t('商品')}</span><span class="detail-value">${product?.title || ''}</span></div>
      <div class="detail-row"><span class="detail-label">${t('金额')}</span><span class="detail-value" style="color:#4f46e5">${order.total_amount} WAZ${usdHint(order.total_amount)}${Number(order.insurance_premium) > 0 ? ` <span style="font-size:10px;color:#6366f1;background:#eef2ff;padding:1px 6px;border-radius:99px;margin-left:4px">🛡 ${t('已购保险')} +${order.insurance_premium}</span>` : ''}</span></div>
      <div class="detail-row"><span class="detail-label">${t('下单时间')}</span><span class="detail-value">${fmtTime(order.created_at)}</span></div>
      ${order.shipping_address ? `<div class="detail-row"><span class="detail-label">${t('收货地址')}</span><span class="detail-value">${order.shipping_address}</span></div>` : ''}
      ${order.anonymous_recipient && order.recipient_code ? `<div class="detail-row"><span class="detail-label">🔒 ${t('取件代号')}</span><span class="detail-value" style="font-family:monospace;font-size:14px;font-weight:700;color:#166534;background:#dcfce7;padding:2px 10px;border-radius:6px;letter-spacing:1px">${escHtml(order.recipient_code)}</span></div><div style="font-size:11px;color:#15803d;padding:0 14px 8px">${t('凭此代号到自提点取件 · 卖家和物流不知道你的真实姓名')}</div>` : ''}
      ${order.anonymous_recipient && !order.recipient_code ? `<div class="detail-row"><span class="detail-label">🔒 ${t('匿名订单')}</span><span class="detail-value" style="font-size:11px;color:#6b7280">${t('买家选择了匿名收货')}</span></div>` : ''}
      ${Number(order.donation_amount) > 0 ? `<div class="detail-row"><span class="detail-label">❤️ ${t('随单捐赠')}</span><span class="detail-value" style="color:#dc2626;font-weight:600">${order.donation_amount} WAZ</span></div>` : ''}
      ${order.gift_recipient_name ? `<div class="detail-row"><span class="detail-label">🎁 ${t('礼物收件人')}</span><span class="detail-value">${escHtml(order.gift_recipient_name)}${order.gift_recipient_phone ? ' · ' + escHtml(order.gift_recipient_phone) : ''}</span></div>${order.gift_message ? `<div class="detail-row"><span class="detail-label">💌 ${t('礼物附言')}</span><span class="detail-value">${escHtml(order.gift_message)}</span></div>` : ''}` : ''}
      ${order.variant_options_snapshot ? `<div class="detail-row"><span class="detail-label">📦 ${t('规格')}</span><span class="detail-value">${formatVariantOptions(order.variant_options_snapshot)}</span></div>` : ''}
      ${order.delivery_window ? `<div class="detail-row"><span class="detail-label">⏱ ${t('配送时段')}</span><span class="detail-value">${formatDeliveryWindow(order.delivery_window)}</span></div>` : ''}
      ${order.content_hash_at_order ? `<div class="detail-row"><span class="detail-label">🔒 ${t('P2P 内容哈希')}</span><span class="detail-value" style="font-family:monospace;font-size:11px;word-break:break-all">${escHtml(order.content_hash_at_order)}</span></div>` : ''}
      ${activeDeadline?.deadline ? `<div class="detail-row"><span class="detail-label">${t('截止')}</span><span class="detail-value" style="color:${isOverdue ? '#dc2626' : '#6b7280'};font-size:12px">${fmtTime(activeDeadline.deadline)}</span></div>` : ''}
    </div>
    ${order.payment_rail === 'direct_p2p' && window.dpOrderDisclosureHtml ? window.dpOrderDisclosureHtml(order) : ''}

    ${trackingHtml}
    ${disputeHtml}
    ${claimHtml}

    ${(order.delivery_window && (isSeller || isLogistic) && ['paid','accepted','shipped','picked_up','in_transit'].includes(order.status)) ? `
    <div class="card" style="background:linear-gradient(135deg,#fffbeb,#fef3c7);border:1px solid #fcd34d;display:flex;gap:10px;align-items:flex-start">
      <div style="font-size:22px;line-height:1.2">⏱</div>
      <div style="flex:1">
        <div style="font-size:13px;font-weight:700;color:#92400e">${t('买家偏好配送时段')}</div>
        <div style="font-size:13px;color:#374151;margin-top:2px">${formatDeliveryWindow(order.delivery_window)}</div>
        <div style="font-size:11px;color:#6b7280;margin-top:4px">${t('请尽量在此时段内安排发货 / 投递')}</div>
      </div>
    </div>` : ''}

    <div id="action-area">
      ${actions ? renderActions(orderId, actions, order, logisticsCompanies) : ''}
      ${sellerDeclineContestPanel(order, orderId, isSeller)}
    </div>

    ${(isBuyer && order.status === 'completed' && product?.id) ? `
    <div class="card" style="background:linear-gradient(135deg,#ecfdf5,#dbeafe)">
      <div style="font-size:14px;font-weight:600;margin-bottom:6px">🔗 ${t('分享这件商品')}</div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:10px">${t('写笔记 / 复制链接 / 生成口令 — 一站完成')}</div>
      <button class="btn btn-primary btn-sm" style="width:auto" onclick="navigate('#promoter?product=${product.id}&source=order')">${t('去分享中心 →')}</button>
    </div>` : ''}

    ${(isBuyer && (order.status === 'completed' || order.status === 'confirmed') && product?.id) ? `
    <div class="card" id="trial-card-${order.id}" style="background:linear-gradient(135deg,#faf5ff,#fdf2f8);border-color:#ddd6fe">
      <div style="font-size:14px;font-weight:600;margin-bottom:6px;color:#6b21a8">🎁 ${t('测评免单')}</div>
      <div id="trial-area-${order.id}" style="font-size:12px;color:#6b7280">${loading$()}</div>
    </div>` : ''}

    ${(isBuyer && order.status === 'completed' && Number(product?.return_days || 0) > 0) ? `
    <div class="card" id="ret-card-${order.id}">
      <div style="font-size:14px;font-weight:600;margin-bottom:6px">↩ ${t('退货')}</div>
      <div id="ret-area-${order.id}" style="font-size:12px;color:#6b7280">${loading$()}</div>
    </div>` : ''}

    ${(isSeller && order.status === 'completed') ? `
    <div class="card" id="ret-card-${order.id}">
      <div style="font-size:14px;font-weight:600;margin-bottom:6px">↩ ${t('退货处理')}</div>
      <div id="ret-area-${order.id}" style="font-size:12px;color:#6b7280">${loading$()}</div>
    </div>` : ''}

    ${((isBuyer || isSeller) && order.status === 'completed') ? `
    <div class="card" id="rate-card-${order.id}">
      <div style="font-size:14px;font-weight:600;margin-bottom:6px">⭐ ${t('交易评价')}</div>
      <div id="rate-area-${order.id}" style="font-size:12px;color:#6b7280">${loading$()}</div>
    </div>` : ''}

    ${(isBuyer && order.status === 'completed') ? `
    <div class="card">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div>
          <div style="font-size:14px;font-weight:600">📝 ${t('为这次购买发笔记')}</div>
          <div style="font-size:11px;color:#9ca3af;margin-top:2px">${state.user?.mlm_ui_visible !== false ? t('分享体验给其他买家，他们通过你的笔记买你拿返佣') : t('分享体验给其他买家（你所在地区返佣将捐入公益基金）')}</div>
        </div>
        <button class="btn btn-outline btn-sm" style="font-size:12px" onclick="navigate('#note-new/${order.id}')">${t('去发布')}</button>
      </div>
    </div>` : ''}

    <div class="card">
      <div class="action-title">${t('完整状态历史')}</div>
      <div class="timeline">${historyHtml || `<div style="color:#6b7280;font-size:13px">${t('暂无记录')}</div>`}</div>
    </div>
  `, 'orders'); if (order.payment_rail === 'direct_p2p' && window.dpHydrateOrderDisclosure) window.dpHydrateOrderDisclosure(order.id)  // direct_p2p:最终 DOM 已就位,#dp-order-instr 必命中(both-acked→收款说明快照;否则 D1/D2 门;非买家→错误提示)。退货/评价 widget 注入各自子容器,不动此框

  // Wave B-3: 退货 widget — 异步加载（仅 completed 订单可退）
  // 买家:有退货窗口可申请/查看;卖家:有退货申请时内联查看+处理(accept/reject/received),无申请则隐藏卡
  if (((isBuyer && Number(product?.return_days || 0) > 0) || isSeller) && order.status === 'completed') {
    try { await renderReturnWidgetForOrder(order, product) } catch (e) { console.error(e) }
  }
  // Wave C-3: 评价 widget
  if ((isBuyer || isSeller) && order.status === 'completed') {
    try { await renderRatingWidget(order, isBuyer, isSeller) } catch (e) { console.error(e) }
  }
  // 2026-05-24 #982：测评免单 widget — 买家可申请名额
  if (isBuyer && (order.status === 'completed' || order.status === 'confirmed') && product?.id) {
    try { await renderTrialClaimWidget(order, product) } catch (e) { console.error(e) }
  }
}

// 2026-05-24 #982：测评免单 widget
async function renderTrialClaimWidget(order, product) {
  const area = document.getElementById('trial-area-' + order.id)
  if (!area) return
  const [campRes, claimsRes] = await Promise.all([
    GET(`/products/${product.id}/trial-campaign`).catch(() => ({ campaign: null })),
    GET('/me/trial-claims').catch(() => ({ items: [] })),
  ])
  const camp = campRes?.campaign
  const myClaim = (claimsRes?.items || []).find(c => c.product_id === product.id)

  if (!camp && !myClaim) {
    area.parentElement?.remove()
    return
  }
  if (myClaim) {
    const statusMap = {
      pending_note: { label: t('待发笔记'), color: '#92400e', bg: '#fef3c7' },
      pending_threshold: { label: t('待评估 reach'), color: '#1e40af', bg: '#dbeafe' },
      refunded: { label: t('已退款'), color: '#166534', bg: '#dcfce7' },
      expired: { label: t('已超时'), color: '#6b7280', bg: '#f3f4f6' },
      cancelled: { label: t('已取消'), color: '#6b7280', bg: '#f3f4f6' },
    }
    const st = statusMap[myClaim.status] || statusMap.pending_note
    const reach = Number(myClaim.reach_score || 0)
    const threshold = Number(myClaim.reach_threshold || 50)
    const pct = Math.min(100, Math.round(reach / threshold * 100))
    const metrics = myClaim.metrics_json ? JSON.parse(myClaim.metrics_json) : null
    area.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <span style="font-size:11px;background:${st.bg};color:${st.color};padding:2px 8px;border-radius:99px;font-weight:600">${st.label}</span>
        ${myClaim.refund_amount ? `<span style="font-size:11px;color:#166534;font-weight:600">✓ ${myClaim.refund_amount} WAZ</span>` : ''}
      </div>
      ${myClaim.status === 'pending_note' ? `
        <div style="font-size:11px;color:#6b7280;margin-bottom:8px">${t('请发布一篇带商品 anchor 的笔记，至少')} ${threshold ? Math.round(threshold * 10) : 500} ${t('浏览或等效转发/转化')}</div>
        <button class="btn btn-primary btn-sm" style="width:auto" onclick="navigate('#note-new/${order.id}?trial=${myClaim.id}')">${t('去发笔记 →')}</button>
      ` : ''}
      ${myClaim.status === 'pending_threshold' ? `
        <div style="font-size:11px;color:#6b7280;margin-bottom:6px">reach: <strong style="color:#1f2937">${Math.round(reach)}</strong> / ${threshold} (${pct}%)</div>
        <div style="width:100%;height:6px;background:#e5e7eb;border-radius:3px;overflow:hidden"><div style="width:${pct}%;height:100%;background:linear-gradient(90deg,#9333ea,#3b82f6)"></div></div>
        ${metrics ? `<div style="font-size:10px;color:#9ca3af;margin-top:6px">${t('浏览')} ${metrics.views} · ${t('转发')} ${metrics.shares} · ${t('转化')} ${metrics.conversions}</div>` : ''}
        ${myClaim.note_id ? `<a href="#share/${myClaim.note_id}" style="font-size:11px;color:#6366f1;margin-top:4px;display:inline-block">${t('查看笔记 →')}</a>` : ''}
      ` : ''}
      ${myClaim.status === 'refunded' ? `<div style="font-size:11px;color:#166534">✨ ${t('已退')} ${myClaim.refund_amount} WAZ，${fmtTime(myClaim.refunded_at)}</div>` : ''}
      ${myClaim.status === 'expired' ? `<div style="font-size:11px;color:#6b7280">${t('30 天内未达阈值，活动已超时')}</div>` : ''}
    `
    return
  }
  // 没申请过 + 有活跃活动
  const remaining = Number(camp.quota_remaining || 0)
  if (remaining <= 0) {
    area.innerHTML = `<div style="font-size:12px;color:#6b7280">${t('名额已满，无法申请')}</div>`
    return
  }
  area.innerHTML = `
    <div style="font-size:11px;color:#6b7280;margin-bottom:8px;line-height:1.5">
      ${t('剩')} <strong style="color:#9333ea">${remaining}</strong> ${t('名额')} · ${t('reach 阈值')} ${camp.reach_threshold} · ${t('笔记需 live')} ${camp.min_days_live} ${t('天')}<br>
      ${t('达阈系统自动从卖家钱包退')} ${order.total_amount} WAZ ${t('全额到你的钱包')}
    </div>
    <button class="btn btn-primary btn-sm" style="width:auto" onclick="doTrialClaim('${product.id}','${order.id}')">🎁 ${t('申请测评名额')}</button>
  `
}

window.doTrialClaim = async (productId, orderId) => {
  const r = await POST(`/products/${productId}/trial-claim`, {})
  if (r.error) { toast(r.error); return }
  toast(t('已申请测评，请发布笔记'))
  setTimeout(() => renderOrderDetail(document.getElementById('app'), orderId), 500)
}

async function renderRatingWidget(order, isBuyer, isSeller) {
  const area = document.getElementById('rate-area-' + order.id)
  if (!area) return
  const r = await GET(`/orders/${order.id}/rating`).catch(() => ({ item: null }))
  const rating = r?.item

  // 双盲提示（卖家视角，买家已评但卖家未反向评 + 窗口未过）
  const maskedHtml = rating && rating.masked ? `
    <div style="font-size:12px;color:#92400e;background:#fef3c7;border-radius:8px;padding:8px 10px;line-height:1.5">
      🔒 ${t('买家已评价，但需双方都评或窗口期满才能查看具体内容。')}
      <div style="font-size:10px;color:#92400e;opacity:0.7;margin-top:2px">${t('窗口截止：')}${fmtTime(rating.hidden_until)}</div>
    </div>
  ` : ''

  // 反向评价区块（卖家可点"评价买家"）
  const buyerRatingPromise = (isBuyer || isSeller) ? GET(`/orders/${order.id}/buyer-rating`).catch(() => ({ item: null })) : Promise.resolve({ item: null })
  const br = await buyerRatingPromise
  const buyerRating = br?.item
  const buyerRatingHtml = buyerRating ? (
    buyerRating.masked ? `
      <div style="margin-top:10px;font-size:12px;color:#92400e;background:#fef3c7;border-radius:8px;padding:8px 10px;line-height:1.5">
        🔒 ${t('卖家已评价你，但需双方都评或窗口期满才能查看。')}
        <div style="font-size:10px;color:#92400e;opacity:0.7;margin-top:2px">${t('窗口截止：')}${fmtTime(buyerRating.hidden_until)}</div>
      </div>` : `
      <div style="margin-top:10px;padding:8px 10px;background:#f0f9ff;border-radius:8px">
        <div style="font-size:12px;font-weight:600;color:#0369a1;margin-bottom:4px">💬 ${t('卖家对买家的评价')}</div>
        <div style="font-size:16px">${'⭐'.repeat(Number(buyerRating.stars))}${'☆'.repeat(5 - Number(buyerRating.stars))}</div>
        ${buyerRating.comment ? `<div style="font-size:13px;color:#374151;margin-top:4px">${escHtml(buyerRating.comment)}</div>` : ''}
      </div>`
  ) : ''

  // 已有 buyer's rating (公开 / 自己看得到)
  if (rating && !rating.masked) {
    const stars = '⭐'.repeat(Number(rating.stars)) + '☆'.repeat(5 - Number(rating.stars))
    const dimsHtml = (rating.dim_quality || rating.dim_speed || rating.dim_service) ? `
      <div style="display:flex;gap:8px;font-size:11px;color:#6b7280;margin-top:6px;flex-wrap:wrap">
        ${rating.dim_quality ? `<span>${t('质量')}: ${'⭐'.repeat(rating.dim_quality)}</span>` : ''}
        ${rating.dim_speed ? `<span>${t('速度')}: ${'⭐'.repeat(rating.dim_speed)}</span>` : ''}
        ${rating.dim_service ? `<span>${t('服务')}: ${'⭐'.repeat(rating.dim_service)}</span>` : ''}
      </div>` : ''
    area.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:16px">${stars}</div>
        <div style="font-size:11px;color:#9ca3af">${fmtTime(rating.created_at)}</div>
      </div>
      ${dimsHtml}
      ${rating.comment ? `<div style="font-size:13px;color:#374151;margin-top:6px;padding:8px 10px;background:#f9fafb;border-radius:6px">${escHtml(rating.comment)}</div>` : ''}
      ${rating.reply ? `<div style="font-size:12px;color:#6366f1;margin-top:6px;padding:8px 10px;background:#eef2ff;border-radius:6px"><strong>${t('卖家回复')}:</strong> ${escHtml(rating.reply)}<div style="font-size:10px;color:#9ca3af;margin-top:2px">${fmtTime(rating.replied_at)}</div></div>` : ''}
      ${rating.buyer_followup ? `<div style="font-size:12px;color:#9a3412;margin-top:6px;padding:8px 10px;background:#fff7ed;border-radius:6px"><strong>${t('买家追问')}:</strong> ${escHtml(rating.buyer_followup)}<div style="font-size:10px;color:#9ca3af;margin-top:2px">${fmtTime(rating.buyer_followup_at)} · 🔒 ${t('对话已锁')}</div></div>` : ''}
      ${isSeller && !rating.reply ? `<button class="btn btn-outline btn-sm" style="margin-top:8px;font-size:11px" onclick="openRatingReplyModal('${order.id}')">${t('回复评价')}</button>` : ''}
      ${isBuyer && rating.reply && !rating.buyer_followup ? `<button class="btn btn-outline btn-sm" style="margin-top:8px;font-size:11px" onclick="openRatingFollowupModal('${order.id}')">↵ ${t('追问一次')}</button>` : ''}
      ${buyerRatingHtml}
      ${isSeller && !buyerRating ? `<button class="btn btn-outline btn-sm" style="margin-top:8px;font-size:11px" onclick="openBuyerRatingModal('${order.id}')">⭐ ${t('评价买家')}</button>` : ''}
    `
    return
  }
  if (rating && rating.masked) {
    area.innerHTML = `
      ${maskedHtml}
      ${buyerRatingHtml}
      ${isSeller && !buyerRating ? `<button class="btn btn-outline btn-sm" style="margin-top:8px;font-size:11px" onclick="openBuyerRatingModal('${order.id}')">⭐ ${t('评价买家')}</button>` : ''}
    `
    return
  }
  if (isBuyer) {
    area.innerHTML = `
      <div style="font-size:12px;color:#6b7280;margin-bottom:8px">${t('给这次交易打个分，帮助其他买家做决策')}</div>
      <button class="btn btn-primary btn-sm" onclick="openRatingModal('${order.id}')">⭐ ${t('评价交易')}</button>
      ${buyerRatingHtml}
    `
  } else {
    area.innerHTML = `
      <div style="font-size:12px;color:#9ca3af">${t('买家尚未评价')}</div>
      ${buyerRatingHtml}
      ${isSeller && !buyerRating ? `<button class="btn btn-outline btn-sm" style="margin-top:8px;font-size:11px" onclick="openBuyerRatingModal('${order.id}')">⭐ ${t('评价买家')}</button>` : ''}
    `
  }
}

// L2-5 维度评分通用 widget
function dimStarsHtml(id, label) {
  return `
    <div style="margin-bottom:10px">
      <div style="font-size:12px;color:#6b7280;margin-bottom:4px">${label}</div>
      <div id="${id}" data-stars="0" style="font-size:20px;letter-spacing:4px;cursor:pointer">
        ${[1,2,3,4,5].map(i => `<span data-i="${i}" onclick="setDimStars('${id}',${i})">☆</span>`).join('')}
      </div>
    </div>`
}

window.setDimStars = (wrapId, n) => {
  const wrap = document.getElementById(wrapId)
  if (!wrap) return
  wrap.dataset.stars = String(n)
  for (const span of wrap.querySelectorAll('span')) {
    span.textContent = Number(span.dataset.i) <= n ? '⭐' : '☆'
  }
}

const dimVal = (id) => {
  const v = Number(document.getElementById(id)?.dataset.stars || 0)
  return v >= 1 && v <= 5 ? v : null
}

window.openRatingModal = (orderId) => {
  const html = `
    <div class="js-modal" style="background:rgba(0,0,0,0.6);position:fixed;inset:0;z-index:1000;display:flex;align-items:flex-end;justify-content:center" onclick="this.remove()">
      <div style="background:#fff;width:100%;max-width:560px;border-radius:16px 16px 0 0;padding:20px;max-height:85vh;overflow-y:auto" onclick="event.stopPropagation()">
        <h2 style="font-size:16px;font-weight:700;margin-bottom:8px">⭐ ${t('评价交易')}</h2>
        <div style="font-size:11px;color:#92400e;background:#fef3c7;padding:6px 10px;border-radius:6px;margin-bottom:12px;line-height:1.5">
          🔒 ${t('双盲评价：卖家在 14 天内反向评价或窗口期满后才能看到你的具体评分。')}
        </div>
        <div style="text-align:center;margin-bottom:14px">
          <div id="rate-stars" data-stars="0" style="font-size:36px;letter-spacing:6px;cursor:pointer">
            ${[1,2,3,4,5].map(i => `<span data-i="${i}" onclick="setRatingStars(${i})">☆</span>`).join('')}
          </div>
          <div id="rate-stars-label" style="font-size:11px;color:#9ca3af;margin-top:4px">${t('点击星星打分')}</div>
        </div>
        <div style="border-top:1px solid #f3f4f6;padding-top:10px;margin-bottom:10px">
          <div style="font-size:12px;font-weight:600;color:#374151;margin-bottom:8px">${t('分项打分（可选）')}</div>
          ${dimStarsHtml('dim-quality', t('商品质量'))}
          ${dimStarsHtml('dim-speed', t('发货速度'))}
          ${dimStarsHtml('dim-service', t('售后服务'))}
        </div>
        <div class="form-group">
          <label class="form-label">${t('文字评价')}</label>
          <textarea class="form-control" id="rate-comment" rows="3" maxlength="1000" placeholder="${t('分享你的体验（可选）')}"></textarea>
        </div>
        <div id="rate-msg" style="margin:8px 0"></div>
        <div style="display:flex;gap:8px">
          <button class="btn btn-gray" style="flex:1" onclick="this.closest('[style*=position]').remove()">${t('取消')}</button>
          <button class="btn btn-primary" style="flex:1" onclick="submitRating('${orderId}')">${t('提交评价')}</button>
        </div>
      </div>
    </div>
  `
  const div = document.createElement('div')
  div.innerHTML = html
  document.body.appendChild(div.firstElementChild)
}

window.setRatingStars = (n) => {
  const wrap = document.getElementById('rate-stars')
  if (!wrap) return
  wrap.dataset.stars = String(n)
  const labels = ['', t('很差'), t('一般'), t('还行'), t('满意'), t('非常满意')]
  document.getElementById('rate-stars-label').textContent = labels[n]
  for (const span of wrap.querySelectorAll('span')) {
    span.textContent = Number(span.dataset.i) <= n ? '⭐' : '☆'
  }
}

window.submitRating = async (orderId) => {
  const stars = Number(document.getElementById('rate-stars').dataset.stars || 0)
  const comment = document.getElementById('rate-comment').value.trim()
  const msg = document.getElementById('rate-msg')
  if (stars < 1 || stars > 5) { msg.innerHTML = alert$('error', t('请先打分')); return }
  msg.innerHTML = loading$()
  const res = await POST(`/orders/${orderId}/rating`, {
    stars, comment,
    dim_quality: dimVal('dim-quality'),
    dim_speed: dimVal('dim-speed'),
    dim_service: dimVal('dim-service'),
  })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  document.querySelector('.js-modal')?.remove()
  toast$(t('评价已提交'))
  renderOrderDetail(document.getElementById('app'), orderId)
}

