// W3 买家追问一次（仅在 seller reply 后可用，限 200 字）
window.openRatingFollowupModal = (orderId) => {
  const html = `
    <div class="js-modal" style="background:rgba(0,0,0,0.6);position:fixed;inset:0;z-index:1000;display:flex;align-items:flex-end;justify-content:center" onclick="this.remove()">
      <div style="background:#fff;width:100%;max-width:560px;border-radius:16px 16px 0 0;padding:20px" onclick="event.stopPropagation()">
        <h2 style="font-size:16px;font-weight:700;margin-bottom:8px">↵ ${t('追问一次')}</h2>
        <div style="font-size:12px;color:#92400e;background:#fffbeb;border:1px solid #fcd34d;border-radius:6px;padding:8px 10px;margin-bottom:10px">⚠ ${t('追问只能一次 · 限 200 字 · 提交后对话锁定无法再追')}</div>
        <div class="form-group">
          <textarea class="form-control" id="rate-followup" rows="3" maxlength="200" placeholder="${t('对卖家回复有疑问？追问一次，将与评价一同公开')}"></textarea>
          <div id="rate-followup-counter" style="text-align:right;font-size:11px;color:#9ca3af;margin-top:4px">0 / 200</div>
        </div>
        <div id="rate-followup-msg" style="margin:8px 0"></div>
        <div style="display:flex;gap:8px">
          <button class="btn btn-gray" style="flex:1" onclick="this.closest('[style*=position]').remove()">${t('取消')}</button>
          <button class="btn btn-primary" style="flex:1" onclick="submitRatingFollowup('${orderId}')">${t('提交追问')}</button>
        </div>
      </div>
    </div>
  `
  const div = document.createElement('div')
  div.innerHTML = html
  document.body.appendChild(div.firstElementChild)
  const ta = document.getElementById('rate-followup')
  const counter = document.getElementById('rate-followup-counter')
  if (ta && counter) ta.addEventListener('input', () => counter.textContent = `${ta.value.length} / 200`)
}

window.submitRatingFollowup = async (orderId) => {
  const followup = (document.getElementById('rate-followup')?.value || '').trim()
  const msg = document.getElementById('rate-followup-msg')
  if (followup.length < 2) { msg.innerHTML = alert$('error', t('追问内容至少 2 字')); return }
  msg.innerHTML = loading$()
  const res = await POST(`/orders/${orderId}/rating/followup`, { followup })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  document.querySelector('.js-modal')?.remove()
  toast$(t('追问已发布'))
  renderOrderDetail(document.getElementById('app'), orderId)
}

// W2 售后协商时间线 — 事件元数据
const RET_TYPE_META = {
  created:   { icon: '↩',  title: '申请退货',  border: '#d97706' },
  message:   { icon: '💬', title: '协商消息',  border: '#3b82f6' },
  accepted:  { icon: '✓',  title: '卖家同意',  border: '#16a34a' },
  rejected:  { icon: '✗',  title: '卖家拒绝',  border: '#dc2626' },
  refunded:  { icon: '💸', title: '已退款',    border: '#16a34a' },
  escalated: { icon: '⚖️', title: '已升级仲裁', border: '#6b21a8' },
  cancelled: { icon: '🚫', title: '已取消',    border: '#6b7280' },
}

function buildReturnTimelineEvent(ev, isMeBuyer) {
  const typeMeta = RET_TYPE_META[ev.type] || { icon: '·', title: ev.type, border: '#9ca3af' }
  const role = ev.actor_role || 'system'
  const roleMeta = TL_ROLE_META[role] || TL_ROLE_META.unknown
  const isMe = (role === 'buyer' && isMeBuyer) || (role === 'seller' && !isMeBuyer)

  let body = ''
  if (ev.type === 'created') {
    const reason = RETURN_REASON_LABEL()[ev.meta?.reason] || ev.meta?.reason || ''
    body = `<div style="font-size:11px;color:#6b7280;margin-bottom:4px">${t('原因')}：${reason}　·　${t('退款金额')}：<strong>${ev.meta?.refund_amount || 0} WAZ</strong></div>
      ${ev.body ? `<div style="font-size:13px;line-height:1.5;white-space:pre-wrap">${escHtml(ev.body)}</div>` : ''}`
  } else if (ev.type === 'escalated') {
    body = `<div style="font-size:13px;line-height:1.5">${t('已创建争议')}
      ${ev.meta?.dispute_id ? `<a href="#dispute/${escHtml(ev.meta.dispute_id)}" style="color:#6b21a8;text-decoration:underline;margin-left:6px">${t('查看争议')} →</a>` : ''}
    </div>`
  } else {
    body = ev.body ? `<div style="font-size:13px;line-height:1.5;white-space:pre-wrap">${escHtml(ev.body)}</div>` : ''
  }

  return `
    <div style="display:flex;gap:10px;margin-bottom:12px;align-items:flex-start">
      <div style="flex-shrink:0;width:28px;height:28px;border-radius:50%;background:${roleMeta.bg};border:2px solid ${typeMeta.border};display:flex;align-items:center;justify-content:center;font-size:13px">${typeMeta.icon}</div>
      <div style="flex:1;min-width:0">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px;flex-wrap:wrap;gap:6px">
          <div style="display:flex;align-items:center;gap:5px;flex-wrap:wrap">
            <span style="background:${roleMeta.bg};color:${roleMeta.tone};padding:1px 6px;border-radius:99px;font-size:10px;font-weight:600">${roleMeta.icon} ${t(roleMeta.label)}${isMe ? ' · ' + t('你') : ''}</span>
            <span style="font-size:10px;color:#9ca3af">· ${t(typeMeta.title)}</span>
          </div>
          <span style="font-size:10px;color:#9ca3af">${fmtTime(ev.ts)}</span>
        </div>
        ${ev.flagged ? fraudBanner(ev.flag_reasons) : ''}
        ${body ? `<div style="background:#fff;border:1px solid #e5e7eb;border-left:3px solid ${typeMeta.border};border-radius:6px;padding:8px 10px">${body}</div>` : ''}
      </div>
    </div>`
}

async function renderReturnWidgetForOrder(order, product) {
  const area = document.getElementById('ret-area-' + order.id)
  if (!area) return
  // P1-5: 订单级直查（取代拉全量列表过滤）
  const r = await GET(`/orders/${order.id}/return-request`).catch(() => ({ item: null }))
  const mine = r?.item || null
  const isSellerView = state.user && state.user.id === order.seller_id
  // 卖家视角:无退货申请则隐藏整张卡(卖家不申请退货,只在有申请时处理)
  if (isSellerView && !mine) {
    const card = area.closest('.card'); if (card) card.style.display = 'none'
    return
  }
  const returnDays = Number(product?.return_days || 0)
  const baseTime = order.updated_at || order.created_at
  const deadline = new Date(baseTime).getTime() + returnDays * 86400 * 1000
  const remainMs = deadline - Date.now()
  const expired = remainMs <= 0
  const remainText = expired
    ? `<span style="color:#dc2626">${t('已超过退货窗口')}</span>`
    : `<span style="color:#16a34a">${t('剩余')} ${Math.ceil(remainMs / 86400000)} ${t('天')}</span>`

  if (mine) {
    // W2: 拉完整 timeline + 消息
    const detail = await GET(`/return-requests/${mine.id}`).catch(() => null)
    const events = detail?.timeline || []
    const item = detail?.item || mine
    const isBuyer = state.user && state.user.id === item.buyer_id
    const STATUS_COLORS = { pending:'#d97706', accepted:'#16a34a', refunded:'#16a34a', rejected:'#dc2626', cancelled:'#6b7280', escalated:'#6b21a8' }
    const STATUS_LABEL = () => ({ pending: t('待卖家处理'), accepted: t('已同意'), refunded: t('已退款'), rejected: t('已拒绝'), cancelled: t('已取消'), escalated: t('已升级仲裁') })

    const isActive = !['refunded', 'cancelled', 'escalated'].includes(item.status)
    const canEscalate = isBuyer && (
      item.status === 'rejected' ||
      (item.status === 'pending' && (Date.now() - new Date(item.created_at).getTime()) >= 7 * 86400 * 1000)
    )

    area.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <div style="font-size:13px;font-weight:600">${t('退货协商')}: <span style="color:${STATUS_COLORS[item.status] || '#374151'}">${STATUS_LABEL()[item.status] || item.status}</span></div>
        ${item.status === 'pending' && isBuyer ? `<button class="btn btn-outline btn-sm" style="font-size:11px;padding:4px 10px" onclick="cancelReturnRequest('${item.id}', '${order.id}')">${t('取消申请')}</button>` : ''}
      </div>

      ${isSellerView && item.status === 'pending' ? `
        <div style="display:flex;gap:8px;margin-bottom:8px">
          <button class="btn btn-success btn-sm" style="flex:1;font-size:12px" onclick="decideReturn('${item.id}','accept','${order.id}')">${t('接受退款')}</button>
          <button class="btn btn-outline btn-sm" style="flex:1;font-size:12px;color:#dc2626;border-color:#fecaca" onclick="decideReturn('${item.id}','reject','${order.id}')">${t('拒绝退货')}</button>
        </div>` : ''}
      ${isSellerView && item.status === 'picked_up' ? `
        <button class="btn btn-success btn-sm" style="width:100%;font-size:12px;margin-bottom:8px" onclick="confirmReturnReceived('${item.id}','${order.id}')">${t('✓ 已收到退货 · 触发退款')}</button>` : ''}

      <div style="padding:10px;background:#fafafa;border-radius:8px;margin-bottom:8px">
        <div style="font-size:11px;font-weight:600;color:#6b7280;margin-bottom:8px">🧾 ${t('协商时间线')} · ${events.length} ${t('条')}</div>
        ${events.map(ev => buildReturnTimelineEvent(ev, isBuyer)).join('')}
      </div>

      ${isActive ? `
        <div style="display:flex;gap:6px;align-items:flex-end">
          <textarea id="ret-msg-${item.id}" rows="1" placeholder="${t('输入消息（按 Enter 发送）')}" style="flex:1;padding:6px 8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;resize:none" onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();sendReturnMessage('${item.id}','${order.id}')}"></textarea>
          <button class="btn btn-primary btn-sm" onclick="sendReturnMessage('${item.id}','${order.id}')" style="padding:6px 12px;font-size:11px">${t('发送')}</button>
        </div>
        <div id="ret-msg-err-${item.id}" style="font-size:11px;color:#dc2626;margin-top:4px"></div>
      ` : ''}

      ${canEscalate ? `
        <div style="margin-top:8px;padding:8px 10px;background:#fef2f2;border:1px solid #fecaca;border-radius:6px">
          <div style="font-size:11px;color:#991b1b;margin-bottom:6px">${item.status === 'rejected' ? t('卖家已拒绝 — 如有异议可升级至平台仲裁') : t('卖家 7 天内未回应 — 可升级至平台仲裁')}</div>
          <button class="btn btn-sm" style="background:#6b21a8;color:#fff;padding:5px 14px;font-size:11px" onclick="escalateReturn('${item.id}','${order.id}')">⚖️ ${t('升级至仲裁')}</button>
        </div>
      ` : ''}
    `
    return
  }

  if (expired) {
    area.innerHTML = `<div style="font-size:12px;color:#9ca3af">${t('已超过')} ${returnDays} ${t('天退货窗口，无法申请')}</div>`
    return
  }

  area.innerHTML = `
    <div style="margin-bottom:8px">${t('退货窗口')}：${returnDays} ${t('天')} · ${remainText}</div>
    <button class="btn btn-outline btn-sm" onclick="openReturnRequestModal('${order.id}', ${Number(order.total_amount)})">${t('申请退货')}</button>
  `
}

window.sendReturnMessage = async (returnId, orderId) => {
  const ta = document.getElementById('ret-msg-' + returnId)
  const errEl = document.getElementById('ret-msg-err-' + returnId)
  const body = (ta?.value || '').trim()
  if (errEl) errEl.textContent = ''
  if (!body) return
  const res = await POST(`/return-requests/${returnId}/messages`, { body })
  if (res.error) { if (errEl) errEl.textContent = res.error; return }
  if (ta) ta.value = ''
  const order = await GET(`/orders/${orderId}`).catch(() => null)
  if (order) {
    const product = await GET(`/products/${order.product_id}`).catch(() => null)
    if (product) renderReturnWidgetForOrder(order, product)
  }
}

window.escalateReturn = async (returnId, orderId) => {
  if (!confirm(t('确定升级到仲裁？协议会冻结卖家资产并指派仲裁员审核。'))) return
  const res = await POST(`/return-requests/${returnId}/escalate`, {})
  if (res.error) return toast$(res.error, 'error')
  toast$(t('已升级仲裁'), 'success')
  setTimeout(() => navigate(`#dispute/${res.dispute_id}`), 800)
}

// Wave C-1: variants 选择器（按 option dimension 分组渲染按钮组）
function renderVariantSelector(variants, basePrice) {
  // 收集所有 option 维度（颜色 / 尺寸 / ...）
  const dims = new Map()  // dim name → Set of values（保持插入顺序）
  for (const v of variants) {
    for (const [k, val] of Object.entries(v.options || {})) {
      if (!dims.has(k)) dims.set(k, new Set())
      dims.get(k).add(val)
    }
  }
  const rows = [...dims.entries()].map(([dim, vals]) => {
    const btns = [...vals].map(val => `
      <button class="variant-btn" data-dim="${escHtml(dim)}" data-val="${escHtml(val)}"
        onclick="selectVariantOption('${escHtml(dim).replace(/'/g,"&#39;")}','${escHtml(val).replace(/'/g,"&#39;")}', ${basePrice})"
        style="padding:6px 12px;border:1px solid #d1d5db;background:#fff;border-radius:6px;font-size:12px;cursor:pointer;margin-right:6px;margin-bottom:6px">${escHtml(val)}</button>
    `).join('')
    return `<div style="margin-bottom:6px">
      <div style="font-size:11px;color:#6b7280;margin-bottom:4px">${escHtml(dim)}</div>
      <div style="display:flex;flex-wrap:wrap">${btns}</div>
    </div>`
  }).join('')
  return `
    <div class="form-group" style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:8px;padding:10px">
      <div style="font-size:12px;color:#374151;font-weight:600;margin-bottom:8px">📦 ${t('选规格')} *</div>
      ${rows}
      <div id="variant-summary" style="font-size:11px;color:#9ca3af;margin-top:6px">${t('请选择所有规格')}</div>
    </div>
  `
}

window.selectVariantOption = (dim, val, basePrice) => {
  // 取消同维度其它按钮 selected 状态（用 data-selected 属性，跨浏览器可靠）
  document.querySelectorAll(`.variant-btn[data-dim="${dim}"]`).forEach(b => {
    b.dataset.selected = '0'
    b.style.background = '#fff'; b.style.borderColor = '#d1d5db'; b.style.color = '#374151'
  })
  // 找到当前点击的按钮并标记
  const btn = document.querySelector(`.variant-btn[data-dim="${dim}"][data-val="${val}"]`)
  if (btn) {
    btn.dataset.selected = '1'
    btn.style.background = '#eef2ff'; btn.style.borderColor = '#6366f1'; btn.style.color = '#3730a3'
  }
  // 收集当前所有选中维度的 val
  const selected = {}
  for (const b of document.querySelectorAll('.variant-btn[data-selected="1"]')) {
    selected[b.dataset.dim] = b.dataset.val
  }
  // 匹配 variant
  const variants = state._variants || []
  const dimsCount = new Set(variants.flatMap(v => Object.keys(v.options || {}))).size
  const summary = document.getElementById('variant-summary')
  if (Object.keys(selected).length < dimsCount) {
    summary.innerHTML = t('请选择所有规格')
    state._selectedVariantId = null
    return
  }
  const match = variants.find(v => {
    return Object.entries(selected).every(([k, val]) => String(v.options[k]) === String(val))
  })
  const buyBtn = document.getElementById('btn-doBuy')
  if (!match) {
    summary.innerHTML = `<span style="color:#dc2626">✗ ${t('该规格组合不可用')}</span>`
    state._selectedVariantId = null
    if (buyBtn) buyBtn.disabled = true
    return
  }
  state._selectedVariantId = match.id
  const price = match.price_override != null ? Number(match.price_override) : Number(basePrice)
  const stockTag = Number(match.stock) > 0
    ? `<span style="color:#16a34a">● ${t('有货')}</span>`
    : `<span style="color:#dc2626">${t('缺货')}</span>`
  summary.innerHTML = `✓ ${price} WAZ · ${stockTag}`
  if (buyBtn) {
    buyBtn.disabled = Number(match.stock) <= 0
    buyBtn.innerHTML = `${t('立即下单')} · ${price} WAZ`
  }
}

// Wave C-2: 地址 → 单行字符串
function buildAddrString(a) {
  if (!a) return ''
  const parts = []
  if (a.region) parts.push(a.region)
  parts.push(a.detail)
  parts.push(a.recipient)
  if (a.phone) parts.push(a.phone)
  return parts.join(' · ')
}

window.openAddressPicker = () => {
  const items = state._addresses || []
  const rows = items.map(it => `
    <div class="card" style="padding:10px 12px;margin-bottom:6px;cursor:pointer${it.is_default ? ';border:1px solid #6366f1;background:#eef2ff' : ''}" onclick="pickAddress('${it.id}')">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
        <div style="font-size:13px;font-weight:600">${escHtml(it.label)}${it.is_default ? ` <span style="font-size:10px;color:#6366f1">${t('默认')}</span>` : ''}</div>
        <div style="font-size:11px;color:#9ca3af">${escHtml(it.recipient)}${it.phone ? ' · ' + escHtml(it.phone) : ''}</div>
      </div>
      <div style="font-size:12px;color:#6b7280">${it.region ? escHtml(it.region) + ' · ' : ''}${escHtml(it.detail)}</div>
    </div>
  `).join('')
  const html = `
    <div class="js-modal" style="background:rgba(0,0,0,0.6);position:fixed;inset:0;z-index:1000;display:flex;align-items:flex-end;justify-content:center" onclick="this.remove()">
      <div style="background:#fff;width:100%;max-width:560px;border-radius:16px 16px 0 0;padding:16px;max-height:70vh;overflow-y:auto" onclick="event.stopPropagation()">
        <h2 style="font-size:15px;font-weight:700;margin-bottom:10px">📍 ${t('选择收货地址')}</h2>
        ${rows}
        <a href="#addresses" style="display:block;text-align:center;padding:10px;font-size:12px;color:#6366f1">+ ${t('管理地址簿')}</a>
      </div>
    </div>
  `
  const div = document.createElement('div')
  div.innerHTML = html
  document.body.appendChild(div.firstElementChild)
}

window.pickAddress = (id) => {
  const a = (state._addresses || []).find(x => x.id === id)
  if (!a) return
  const inp = document.getElementById('inp-addr')
  const txt = buildAddrString(a)
  if (inp) inp.value = txt
  const summary = document.getElementById('addr-summary-text')
  if (summary) { summary.textContent = txt; summary.title = txt }
  toggleOrderAddrEdit(false)
  document.querySelector('.js-modal')?.remove()
}

// 下单页地址折叠 / 展开
window.toggleOrderAddrEdit = (expand) => {
  const collapsed = document.getElementById('addr-collapsed')
  const expanded = document.getElementById('addr-expanded')
  if (!collapsed || !expanded) return
  collapsed.style.display = expand ? 'none' : 'flex'
  expanded.style.display = expand ? '' : 'none'
  if (expand) {
    const inp = document.getElementById('inp-addr')
    if (inp) { try { inp.focus(); inp.setSelectionRange(inp.value.length, inp.value.length) } catch {} }
  } else {
    // 收起时把输入框最新内容同步到摘要
    const inp = document.getElementById('inp-addr')
    const summary = document.getElementById('addr-summary-text')
    if (inp && summary && inp.value.trim()) { summary.textContent = inp.value.trim(); summary.title = inp.value.trim() }
  }
}

// Wave G-5: WAZ → USD 近似（用 USDC peg）显示
function wazToUsd(waz) {
  const rate = Number(state._wazUsdcRate || 1)
  if (rate <= 0) return null
  return Number(waz) / rate  // 1 USDC ≈ 1 USD
}
// 渲染 ≈ $X.XX 小字（默认 buyer / 全局，可选 hidePrefix）
function usdHint(waz, opts = {}) {
  const usd = wazToUsd(waz)
  if (usd == null || !Number.isFinite(usd)) return ''
  const txt = `≈ $${usd.toFixed(2)}`
  return `<span style="font-size:10px;color:#9ca3af;margin-left:4px;font-weight:400">${txt}</span>`
}

// Wave C-1: 规格格式化（订单详情 / 列表用）
function formatVariantOptions(json) {
  let opts
  try { opts = typeof json === 'string' ? JSON.parse(json) : json } catch { return '—' }
  if (!opts || typeof opts !== 'object') return '—'
  return Object.entries(opts).map(([k, v]) => `${escHtml(k)}: ${escHtml(String(v))}`).join(' · ')
}

// Wave B-5: 配送时间窗格式化
function formatDeliveryWindow(json) {
  let w
  try { w = typeof json === 'string' ? JSON.parse(json) : json } catch { return '—' }
  if (!w || typeof w !== 'object') return '—'
  const dayMap = { weekday: t('工作日'), weekend: t('周末'), any: t('任意日') }
  const timeMap = { morning: t('上午 9-12'), afternoon: t('下午 12-18'), evening: t('晚上 18-21'), any: t('任意时段') }
  const day = dayMap[w.day_type] || w.day_type
  const time = timeMap[w.time_range] || w.time_range
  const flex = w.flexible === false ? ` · ${t('严格')}` : ` · ${t('可灵活')}`
  return `${day} · ${time}${flex}`
}

// 2026-05-22 L2：判断 delivery_window 是否匹配当前时段（物流端筛选用）
// 'any' 在 day_type / time_range 任一位置都算"任意符合"
function deliveryWindowMatchesNow(json) {
  let w
  try { w = typeof json === 'string' ? JSON.parse(json) : json } catch { return null }
  if (!w || typeof w !== 'object') return null
  const now = new Date()
  const day = now.getDay()  // 0=Sun, 6=Sat
  const isWeekend = day === 0 || day === 6
  const hour = now.getHours()
  let timeBucket = 'evening'
  if (hour >= 9 && hour < 12) timeBucket = 'morning'
  else if (hour >= 12 && hour < 18) timeBucket = 'afternoon'
  else if (hour < 9 || hour >= 21) timeBucket = null   // 不在 morning/afternoon/evening 三档内
  const dayOk = w.day_type === 'any' || (w.day_type === 'weekday' && !isWeekend) || (w.day_type === 'weekend' && isWeekend)
  const timeOk = w.time_range === 'any' || (timeBucket && timeBucket === w.time_range)
  return dayOk && timeOk
}

function RETURN_REASON_LABEL() {
  return {
    quality: t('质量问题'),
    wrong_item: t('收到错款'),
    damaged: t('运输破损'),
    no_longer_needed: t('不再需要'),
    other: t('其他'),
  }
}

window.openReturnRequestModal = (orderId, total) => {
  const labels = RETURN_REASON_LABEL()
  const html = `
    <div class="js-modal" style="background:rgba(0,0,0,0.6);position:fixed;inset:0;z-index:1000;display:flex;align-items:flex-end;justify-content:center" onclick="this.remove()">
      <div style="background:#fff;width:100%;max-width:560px;border-radius:16px 16px 0 0;padding:20px;max-height:80vh;overflow-y:auto" onclick="event.stopPropagation()">
        <h2 style="font-size:16px;font-weight:700;margin-bottom:12px">↩ ${t('申请退货')}</h2>
        <div class="form-group">
          <label class="form-label">${t('退货原因')} *</label>
          <select class="form-control" id="ret-reason">
            ${Object.entries(labels).map(([k, v]) => `<option value="${k}">${v}</option>`).join('')}
          </select>
        </div>
        <div class="form-group">
          <label class="form-label">${t('详细说明')}</label>
          <textarea class="form-control" id="ret-text" rows="3" maxlength="500" placeholder="${t('描述问题（可选，便于卖家判断）')}"></textarea>
        </div>
        <div class="form-group">
          <label class="form-label">${t('退款金额')} (WAZ) *</label>
          <input class="form-control" id="ret-amount" type="number" min="0.01" max="${total}" step="0.01" value="${total}">
          <div style="font-size:11px;color:#9ca3af;margin-top:2px">${t('订单总额')}: ${total} WAZ · ${t('可申请部分退款')}</div>
        </div>
        <div class="form-group" style="background:#f0fdf4;border:1px solid #86efac;border-radius:8px;padding:10px 12px">
          <label style="display:flex;align-items:flex-start;gap:8px;font-size:12px;color:#166534;cursor:pointer">
            <input type="checkbox" id="ret-pickup" style="width:16px;height:16px;margin-top:2px" onchange="document.getElementById('ret-pickup-addr-row').style.display = this.checked ? 'block' : 'none'">
            <span>📦 ${t('请求上门取件')}<br><span style="font-size:11px;color:#15803d;font-weight:400">${t('卖家会安排物流到指定地址上门收件（免自寄）')}</span></span>
          </label>
          <div id="ret-pickup-addr-row" style="display:none;margin-top:8px">
            <input class="form-control" id="ret-pickup-addr" maxlength="300" placeholder="${t('取件地址（≥ 4 字 · 越具体越好）')}" style="font-size:13px">
          </div>
        </div>
        <div id="ret-msg" style="margin:8px 0"></div>
        <div style="display:flex;gap:8px;margin-top:12px">
          <button class="btn btn-gray" style="flex:1" onclick="this.closest('[style*=position]').remove()">${t('取消')}</button>
          <button class="btn btn-primary" style="flex:1" onclick="submitReturnRequest('${orderId}')">${t('提交申请')}</button>
        </div>
      </div>
    </div>
  `
  const div = document.createElement('div')
  div.innerHTML = html
  document.body.appendChild(div.firstElementChild)
}

window.submitReturnRequest = async (orderId) => {
  const reason = document.getElementById('ret-reason').value
  const reason_text = document.getElementById('ret-text').value.trim()
  const refund_amount = Number(document.getElementById('ret-amount').value)
  const pickup_requested = document.getElementById('ret-pickup')?.checked || false
  const pickup_address = pickup_requested ? (document.getElementById('ret-pickup-addr')?.value.trim() || '') : null
  const msg = document.getElementById('ret-msg')
  if (pickup_requested && (!pickup_address || pickup_address.length < 4)) {
    msg.innerHTML = alert$('error', t('上门取件需填写取件地址（≥ 4 字）')); return
  }
  msg.innerHTML = loading$()
  const res = await POST(`/orders/${orderId}/return-request`, { reason, reason_text, refund_amount, pickup_requested, pickup_address })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  msg.innerHTML = alert$('success', t('退货申请已提交'))
  setTimeout(() => { document.querySelector('.js-modal')?.remove(); renderOrderDetail(document.getElementById('app'), orderId) }, 800)
}

window.cancelReturnRequest = async (id, orderId) => {
  if (!confirm(t('确认取消退货申请？'))) return
  const res = await fetch('/api/return-requests/' + id, { method: 'DELETE', headers: { Authorization: 'Bearer ' + state.apiKey } }).then(r => r.json())
  if (res.error) { alert(res.error); return }
  renderOrderDetail(document.getElementById('app'), orderId)
}

function getActions(order, isBuyer, isSeller, isLogistic) {
  const s = order.status
  const isInPerson = order.fulfillment_mode === 'in_person'
  const isSelfFulfillSeller = isSeller && !order.logistics_id
  // 直付(direct_p2p):买家在 direct_pay_window 标记"我已付款"(Passkey 门) 或取消(不门控);其余阶段沿用通用规则
  if (order.payment_rail === 'direct_p2p' && isBuyer && s === 'direct_pay_window')
    return [{ action: 'mark_paid', label: '✅ 我已付款', style: 'success' }, { action: 'cancel', label: '取消订单', style: 'secondary' }]
  // M8 面交订单：买家在 paid / accepted 都可"面交完成"直接结算
  if (isInPerson && isBuyer && (s === 'paid' || s === 'accepted'))
    return [{ action: 'confirm_in_person', label: '🤝 面交完成 / 确认收货', style: 'success' }]
  if (isSeller && s === 'paid')
    return [{ action: 'accept', label: '接单', style: 'success' }, { action: 'decline', label: '拒绝接单', style: 'danger', custom: 'decline' }]
  if (isSeller && s === 'accepted' && !isInPerson)
    return [{ action: 'ship', label: '确认发货', style: 'success', logisticsSelector: true, trackingInput: true, evidencePlaceholder: '包装状态描述 / 货物说明（可选）' }]
  if (isSeller && s === 'accepted' && isInPerson)
    return [{ action: 'noop_in_person', label: '🤝 面交中（等待买家确认）', style: 'secondary', disabled: true }]
  if ((isLogistic || isSelfFulfillSeller) && s === 'shipped')
    return [{ action: 'pickup', label: '✅ 确认揽收', style: 'success', needsEvidence: true, noteLabel: '快递单号 *', evidencePlaceholder: '如：SF1234567890', helperText: isSelfFulfillSeller ? '自履约订单：你负责回传揽收/单号，超时仍按卖家责任处理。' : '' }]
  if ((isLogistic || isSelfFulfillSeller) && s === 'picked_up')
    return [{ action: 'transit', label: '🚛 开始运输', style: 'primary' }]
  if ((isLogistic || isSelfFulfillSeller) && s === 'in_transit')
    return [{ action: 'deliver', label: '📬 确认投递', style: 'success', needsEvidence: true, noteLabel: '投递凭证', evidencePlaceholder: '门牌照片描述 / 收件人姓名 / 签收时间', helperText: isSelfFulfillSeller ? '自履约投递需留存签收/门牌/交付说明，买家确认后才结算。' : '' }]
  if (isBuyer && s === 'delivered')
    return [{ action: 'confirm', label: '确认收货', style: 'success' }, { action: 'dispute', label: '发起争议', style: 'danger', needsEvidence: true, noteLabel: '争议理由', evidencePlaceholder: '描述问题（货不对版/货损/未收到等）' }]
  return null
}

function renderActions(orderId, actions, order, logisticsCompanies = []) {
  return `
    <div class="action-area">
      <div class="action-title">${t('我的操作')}</div>
      <div id="action-msg"></div>
      ${actions.map((a, i) => `
        ${a.custom === 'decline' ? `
          <button class="btn btn-${a.style}" style="margin-bottom:8px;background:#fff;color:#dc2626;border:1px solid #dc2626"
            onclick="openDeclineModal('${orderId}')">
            ${t(a.label)}
          </button>` :
        a.logisticsSelector ? `
          <div class="form-group">
            <label class="form-label">${t('发货方式')}</label>
            <select class="form-control" id="logi-select-${i}">
              <option value="self">${t('📦 我自己发货（自提自送）')}</option>
              ${logisticsCompanies.map(c => `<option value="${escHtml(c.id)}">${escHtml(c.name)}</option>`).join('')}
            </select>
            <div style="font-size:11px;color:#92400e;background:#fffbeb;border:1px solid #fde68a;border-radius:6px;padding:6px 8px;margin-top:6px;line-height:1.5">${t('自己发货：你负责揽收 / 运输 / 送达,超时或虚假发货仍按卖家责任处理。选物流公司则由物流方流转。')}</div>
          </div>
          ${a.trackingInput ? `
          <div class="form-group">
            <label class="form-label">${t('快递单号')} <span style="font-size:11px;color:#9ca3af;font-weight:400">${t('（可选 · 现在填买家立刻看到；不填等物流揽收时补）')}</span></label>
            <input type="text" class="form-control" id="tracking-${i}" placeholder="${t('如 SF1234567890')}" maxlength="64">
          </div>` : ''}
          <button class="btn btn-${a.style}" style="margin-bottom:8px"
            onclick="handleAction('${orderId}','${a.action}',${i},false,true)">
            ${t(a.label)}
          </button>` :
        a.needsEvidence ? `
          <div class="form-group">
            <label class="form-label">${t(a.noteLabel || '证据说明')}</label>
            ${a.action === 'pickup'
              ? `<input type="text" class="form-control" id="evid-${i}" placeholder="${t(a.evidencePlaceholder || '快递单号')}">`
              : `<textarea class="form-control" id="evid-${i}" placeholder="${t(a.evidencePlaceholder || '')}"></textarea>`}
            ${a.helperText ? `<div style="font-size:11px;color:#92400e;background:#fffbeb;border:1px solid #fde68a;border-radius:6px;padding:6px 8px;margin-top:6px">${t(a.helperText)}</div>` : ''}
          </div>
          <button class="btn btn-${a.style}" style="margin-bottom:8px"
            onclick="handleAction('${orderId}','${a.action}',${i},true,false)">
            ${t(a.label)}
          </button>` : `
          <button class="btn btn-${a.style}" style="margin-bottom:8px"
            onclick="handleAction('${orderId}','${a.action}',${i},false,false)">
            ${t(a.label)}
          </button>`}
      `).join('')}
    </div>`
}

window.handleAction = async (orderId, action, idx, needsEvidence, hasLogisticsSelector) => {
  const msgEl = document.getElementById('action-msg')
  // 直付:买家 mark_paid/confirm/confirm_in_person 是 RISK 动作 → 走两次披露 + Passkey 门(后端硬强制)
  if (window._dpOrderRail === 'direct_p2p' && ['mark_paid', 'confirm', 'confirm_in_person'].includes(action)) return void (window.dpHandleAction && window.dpHandleAction(orderId, action))

  // M8 面交确认：走专用端点，跳过物流状态机
  if (action === 'confirm_in_person') {
    if (!confirm(t('确认已收到物品？escrow 将立即释放给卖家，无法撤销。'))) return
    msgEl.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('确认中...')}</div>`
    const res = await POST(`/orders/${orderId}/confirm-in-person`, {})
    if (res.error) { msgEl.innerHTML = alert$('error', res.error); return }
    msgEl.innerHTML = alert$('success', t('面交完成 — escrow 已释放'))
    maybeThankSponsorAndClear()
    setTimeout(() => renderOrderDetail(document.getElementById('app'), orderId), 1000)
    return
  }
  if (action === 'noop_in_person') return
  const confirmText = {
    ship: t('确认已经发货？发货后买家将看到物流信息，超时/虚假发货可能进入争议或判责。'),
    pickup: t('确认已揽收并回传凭证？请确保单号或揽收说明真实可追踪。'),
    deliver: t('确认已投递？请确保投递凭证真实，买家仍需确认收货后才结算。'),
    confirm: t('确认收货？escrow 将进入结算流程，无法撤销。'),
  }[action]
  if (confirmText && !confirm(confirmText)) return

  let evidDesc = (needsEvidence || hasLogisticsSelector)
    ? (document.getElementById(`evid-${idx}`)?.value?.trim() || '') : ''

  // 揽收：需要快递单号，且自动加前缀
  if (action === 'pickup') {
    if (!evidDesc) { msgEl.innerHTML = alert$('error', t('请填写快递单号')); return }
    if (!evidDesc.startsWith('快递单号：')) evidDesc = `${t('快递单号：')}${evidDesc}`
  }
  // 其他有证据要求的操作
  if (needsEvidence && action !== 'pickup' && !evidDesc) {
    msgEl.innerHTML = alert$('error', t('请填写凭证内容')); return
  }

  // 发货：必须选物流公司，可选填快递单号（直接给买家看，不必等物流揽收）
  let logisticsCompanyId = ''
  if (hasLogisticsSelector) {
    const sel = document.getElementById(`logi-select-${idx}`)
    const choice = sel?.value || 'self'
    const trackingInp = document.getElementById(`tracking-${idx}`)
    const trackingNo = trackingInp?.value?.trim() || ''
    if (choice === 'self') {
      // 自发货:不绑定物流公司(logistics_id 留空 → seller self-fulfill 流转)
      logisticsCompanyId = ''
      evidDesc = trackingNo
        ? `${t('快递单号：')}${trackingNo}${t('（自己发货）')}`
        : t('卖家自己发货（自提自送）—— 后续由你揽收 / 运输 / 送达')
    } else {
      logisticsCompanyId = choice
      const companyName = sel.options[sel.selectedIndex]?.text || logisticsCompanyId
      evidDesc = trackingNo
        ? `${t('快递单号：')}${trackingNo} · ${companyName}`
        : `${t('已交付物流公司：')}${companyName}${t('，快递单号待物流揽收后回传')}`
    }
  }

  msgEl.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('处理中...')}</div>`

  const body = { action, notes: evidDesc, evidence_description: evidDesc,
    ...(logisticsCompanyId ? { logistics_company_id: logisticsCompanyId } : {}) }

  const res = await POST(`/orders/${orderId}/action`, body)
  if (res.error) {
    msgEl.innerHTML = alert$('error', res.error)
  } else {
    msgEl.innerHTML = alert$('success', t('操作成功！'))
    // S8: confirm action 触发 completed → 检查是否首单，若是则致谢 + 清 ctx
    if (action === 'confirm') {
      maybeThankSponsorAndClear()
    }
    setTimeout(() => renderOrderDetail(document.getElementById('app'), orderId), 1000)
  }
}

// ─── 卖家拒单(decline) + 临时判责举证(contest_decline)─── RFC-007 stage 2/3/5 ───────────────
// reason code 元数据(与后端 orders-action.ts DECLINE_REASON_CODES / OBJECTIVE_DECLINE_REASONS 对齐)。
// objective(客观声称)→ 临时判责,需在举证窗口内发起仲裁,不是自动免责;subjective(主观)→ 立即按卖家违约、买家退款。
const DECLINE_REASONS = [
  { code: 'stock_consumed_concurrent', objective: true,  zh: '并发售罄(库存被同时下单耗尽)', en: 'Stock consumed by a concurrent order' },
  { code: 'stale_price_snapshot',      objective: true,  zh: '价格快照过期(下单价已失效)',     en: 'Stale price snapshot' },
  { code: 'force_majeure',             objective: true,  zh: '不可抗力',                          en: 'Force majeure' },
  { code: 'price_regret',              objective: false, zh: '价格反悔(不想按此价卖)',           en: 'Price regret' },
  { code: 'cherry_pick',               objective: false, zh: '挑单(选择性拒单)',                 en: 'Cherry-picking' },
  { code: 'other',                     objective: false, zh: '其他(主观)',                        en: 'Other (subjective)' },
]
function declineReasonOptions() {
  const en = window._lang === 'en'
  return DECLINE_REASONS.map(r => `<option value="${r.code}" data-objective="${r.objective ? '1' : '0'}">${en ? r.en : r.zh}${r.objective ? ` · ${t('客观')}` : ` · ${t('主观')}`}</option>`).join('')
}
// 选中 reason 后的诚实后果提示(主观 vs 客观,绝不把客观拒单说成自动免责)
window.onDeclineReasonChange = () => {
  const sel = document.getElementById('decline-reason')
  const note = document.getElementById('decline-consequence')
  if (!sel || !note) return
  const objective = sel.selectedOptions[0]?.dataset?.objective === '1'
  if (!sel.value) { note.innerHTML = ''; return }
  note.innerHTML = objective
    ? `<div style="background:#fffbeb;border:1px solid #fcd34d;color:#92400e;border-radius:8px;padding:10px;font-size:12px;line-height:1.6">⚠️ ${t('客观理由:订单将先转入【临时判责·卖家违约】并冻结结算。你需在举证窗口内发起仲裁举证翻案 —— 这不是自动免责;窗口过期未举证将按违约终结、买家退款。')}</div>`
    : `<div style="background:#fef2f2;border:1px solid #fca5a5;color:#991b1b;border-radius:8px;padding:10px;font-size:12px;line-height:1.6">⚠️ ${t('主观理由:将立即按【卖家违约】处理,买家全额退款。此操作不可撤销。')}</div>`
}
window.openDeclineModal = (orderId) => {
  const en = window._lang === 'en'
  _openModal(`
    <div style="max-width:440px">
      <h3 style="font-size:16px;font-weight:700;margin-bottom:6px">${t('拒绝接单')}</h3>
      <div style="font-size:12px;color:#6b7280;margin-bottom:12px">${t('拒单会影响买家。请如实选择理由 —— 系统按理由区分【主观违约】与【客观临时判责】,后者需举证。')}</div>
      <div class="form-group">
        <label class="form-label">${t('拒单理由')} <span style="color:#dc2626">*</span></label>
        <select class="form-control" id="decline-reason" onchange="onDeclineReasonChange()">
          <option value="">${en ? '— select a reason —' : '— 请选择理由 —'}</option>
          ${declineReasonOptions()}
        </select>
      </div>
      <div id="decline-consequence" style="margin-bottom:10px"></div>
      <div class="form-group">
        <label class="form-label">${t('说明')} <span style="font-size:11px;color:#9ca3af;font-weight:400">${t('(可选)')}</span></label>
        <textarea class="form-control" id="decline-notes" rows="2" placeholder="${t('补充说明(客观理由建议写清,便于后续举证)')}"></textarea>
      </div>
      <div id="decline-msg"></div>
      <div style="display:flex;gap:8px;margin-top:8px">
        <button class="btn btn-outline" style="flex:1" onclick="closeModal()">${t('取消')}</button>
        <button class="btn btn-danger" style="flex:1;background:#dc2626;border-color:#dc2626;color:#fff" onclick="submitDecline('${orderId}')">${t('确认拒单')}</button>
      </div>
    </div>`)
}
window.submitDecline = async (orderId) => {
  const code = document.getElementById('decline-reason')?.value || ''
  const notes = document.getElementById('decline-notes')?.value?.trim() || ''
  const msg = document.getElementById('decline-msg')
  if (!code) { if (msg) msg.innerHTML = alert$('error', t('请选择拒单理由')); return }
  if (msg) msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('处理中...')}</div>`
  const res = await POST(`/orders/${orderId}/action`, { action: 'decline', decline_reason_code: code, notes })
  if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
  closeModal()
  toast$(res.outcome === 'fault_seller_provisional'
    ? t('已拒单 — 临时判责,请在举证窗口内发起仲裁')
    : t('已拒单 — 已按卖家违约处理,买家将获退款'), 'success')
  setTimeout(() => renderOrderDetail(document.getElementById('app'), orderId), 1000)
}
// 临时判责举证面板:仅卖家、订单 fault_seller + decline_objective_pending=1 + 未结算时显示
function sellerDeclineContestPanel(order, orderId, isSeller) {
  if (!isSeller || order.status !== 'fault_seller' || Number(order.decline_objective_pending) !== 1 || order.settled_fault_at) return ''
  const contested = Number(order.decline_contested) === 1
  const deadline = order.decline_contest_deadline ? fmtTime(order.decline_contest_deadline) : ''
  if (contested) {
    return `<div class="card" style="padding:14px;margin-top:10px;border-left:3px solid #4f46e5;background:#eef2ff">
      <div style="font-size:13px;font-weight:600;color:#3730a3;margin-bottom:4px">⚖️ ${t('已发起仲裁举证')}</div>
      <div style="font-size:12px;color:#374151;line-height:1.6">${t('自动终结已暂停,等待仲裁员裁决:维持→免责全退+退质押;驳回→按违约结算。')}</div>
    </div>`
  }
  return `<div class="card" style="padding:14px;margin-top:10px;border-left:3px solid #d97706;background:#fffbeb">
    <div style="font-size:13px;font-weight:600;color:#92400e;margin-bottom:4px">⏳ ${t('临时判责 — 举证窗口开放')}</div>
    <div style="font-size:12px;color:#7f1d1d;line-height:1.6;margin-bottom:8px">
      ${t('你以客观理由拒单,订单暂判【卖家违约】但尚未结算。你可在窗口内发起人工仲裁举证翻案 —— 这不是自动免责。')}
      ${deadline ? `<br><strong>${t('举证截止')}:</strong> ${escHtml(deadline)} · ${t('过期未举证将按违约终结、买家退款。')}` : ''}
    </div>
    <div class="form-group">
      <label class="form-label">${t('举证说明')} <span style="color:#dc2626">*</span></label>
      <textarea class="form-control" id="contest-evidence" rows="3" placeholder="${t('客观说明拒单理由的证据(如并发订单号、价格变更时间、不可抗力凭证)')}"></textarea>
    </div>
    <div id="contest-msg"></div>
    <button class="btn btn-primary" style="width:100%" onclick="submitContestDecline('${orderId}')">${t('提交举证 / 发起仲裁')}</button>
  </div>`
}
window.submitContestDecline = async (orderId) => {
  const evid = document.getElementById('contest-evidence')?.value?.trim() || ''
  const msg = document.getElementById('contest-msg')
  if (!evid) { if (msg) msg.innerHTML = alert$('error', t('请填写举证说明')); return }
  if (msg) msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('提交中...')}</div>`
  const res = await POST(`/orders/${orderId}/action`, { action: 'contest_decline', evidence_description: evid })
  if (res.error) { if (msg) msg.innerHTML = alert$('error', res.error); return }
  toast$(t('已发起仲裁举证 — 等待仲裁员裁决'), 'success')
  setTimeout(() => renderOrderDetail(document.getElementById('app'), orderId), 1000)
}

// S8: 检查买家是否完成首单，若是 + ShareCtx 还有 sponsor → 一次性致谢 toast + 清 ctx
async function maybeThankSponsorAndClear() {
  const ctx = readShareCtx()
  if (!ctx?.sponsor_id || ctx.first_purchase_at) return  // 没 ctx 或已经致谢过
  try {
    // 通过 growth/tasks 拉一次，确认 first_purchase 已 completed
    const g = await GET('/growth/tasks')
    const fp = g?.tasks?.find(x => x.id === 'first_purchase')
    if (fp?.status !== 'completed') return
    // 致谢 toast（一次性）
    const name = ctx.sponsor_name || '邀请人'
    toast$(`💝 ${t('首单完成！感谢 ')}${escHtml(name)}${t(' 的邀请，TA 也获得分润。后会有期 ~')}`, 'success')
    writeShareCtx({ first_purchase_at: Date.now() })
    // 30 秒后清 ctx（让 toast 看完再清）
    setTimeout(() => clearShareCtx(), 30_000)
  } catch (e) { console.warn('[thank]', e) }
}

