window.doCopyAddress = async () => {
  const el = document.getElementById('deposit-addr')
  const addr = el?.textContent?.trim()
  if (!addr || addr === t('加载中...')) return
  const ok = await copyText(addr)
  if (ok) {
    const btn = el.parentElement?.querySelector('button')
    if (btn) { btn.textContent = `✅ ${t('已复制')}`; setTimeout(() => { btn.textContent = `📋 ${t('复制地址')}` }, 1500) }
  } else {
    prompt(t('复制以下内容'), addr)
  }
}

window.doWithdraw = async () => {
  const addr = document.getElementById('withdraw-addr')?.value?.trim()
  const amount = document.getElementById('withdraw-amount')?.value?.trim()
  const msgEl = document.getElementById('withdraw-msg')
  if (!addr || !amount) { msgEl.innerHTML = alert$('error', t('请填写收款地址和金额')); return }
  // 提现属于不可逆操作 — 强制密码二次验证（即使 api_key 已认证）
  const ok = await requireApiKeyPassword()
  if (!ok) { msgEl.innerHTML = alert$('error', t('已取消')); return }
  msgEl.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('提交中...')}</div>`
  let res = await POST('/wallet/withdraw', { to_address: addr, amount: Number(amount) })
  // WebAuthn gate：用户开启了"提现需 Passkey" → 后端返回 webauthn_required → 弹生物识别 → 重试带 token
  if (res?.webauthn_required && res.purpose === 'withdraw') {
    try {
      msgEl.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('请通过生物识别 / Passkey 确认…')}</div>`
      const token = await requestPasskeyGate('withdraw', res.purpose_data)
      msgEl.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('已确认，正在提交…')}</div>`
      res = await POST('/wallet/withdraw', { to_address: addr, amount: Number(amount) }, { 'X-WebAuthn-Token': token })
    } catch (e) {
      msgEl.innerHTML = alert$('error', t('Passkey 确认失败：') + (e.message || e))
      return
    }
  }
  if (res.error) { msgEl.innerHTML = alert$('error', res.error); return }
  // 大额提现 → 服务端要求邮件确认
  if (res.requires_email_code) {
    openWithdrawEmailConfirmModal(res.request_id, res.email, Number(amount))
    msgEl.innerHTML = ''
    return
  }
  msgEl.innerHTML = alert$('success', `✅ ${escHtml(res.message)}`)
  setTimeout(() => renderWallet(document.getElementById('app')), 2000)
}

