window.cancelWithdrawal = async (requestId) => {
  if (!confirm(t('取消该提现申请？已扣余额会立即退回'))) return
  const r = await POST(`/wallet/withdrawals/${requestId}/cancel`, {})
  if (r.error) { toast$(t('取消失败：') + r.error); return }
  const refunded = Number(r.refunded || 0)
  toast$(refunded > 0 ? t('已取消，退回 ') + refunded.toFixed(2) + ' WAZ' : t('已取消（pending_email 阶段未扣款，无需退回）'))
  setTimeout(() => renderWallet(document.getElementById('app')), 600)
}

