// 个人资料里手动触发的入口（用于已被 dismiss 的情况）
window.installPWAFromProfile = () => {
  localStorage.removeItem('webaz_install_dismissed_until')
  sessionStorage.removeItem('webaz_install_dismissed')
  doInstallPWA()
}

function updateBadge(count) {
  state.unread = count
  // 顶部 navbar 铃铛 / 通用 #notif-badge 元素
  document.querySelectorAll('#notif-badge').forEach(badge => {
    badge.textContent = count > 0 ? count : ''
    badge.style.display = count > 0 ? 'inline' : 'none'
  })
  // 同步底部"消息" tab 聚合红点
  if (typeof updateAggregateChatsBadge === 'function') updateAggregateChatsBadge()
}

// 💬 底部消息 tab 聚合红点：私信 + 通知 + 公告 三源
// ─── SNF Inbox 协议消息收件箱 ─────────────────────────────────
// 1. 登入后 ensureSnfPull 拉一次（只读 list，不消费 — 防 ultrareview bug_003）
// 2. refreshSnfBadge 用 /snf/pending 算未 ack 数量
// 3. #inbox = 落地页（带消息类型路由 + 签名验证 + 显式"全部已读"）

let _snfPulledThisSession = false
window.ensureSnfPull = async () => {
  if (_snfPulledThisSession || !state.apiKey) return
  _snfPulledThisSession = true
  try {
    // 改用 list 端点 — 只读，不会把消息消费掉，UI 刷新还能看到
    const r = await GET('/snf/inbox?limit=50').catch(() => ({ items: [] }))
    if ((r.items || []).length > 0) {
      console.log(`[SNF] listed ${r.items.length} messages`)
      state._snfRecent = r.items
    }
    refreshSnfBadge()
  } catch (e) { console.warn('[SNF] initial list err', e) }
}

window.refreshSnfBadge = async () => {
  if (!state.apiKey) return
  try {
    const r = await GET('/snf/pending').catch(() => ({ pending: 0 }))
    state._snfPending = r.pending || 0
    document.querySelectorAll('#snf-badge').forEach(el => {
      el.textContent = state._snfPending > 0 ? state._snfPending : ''
      el.style.display = state._snfPending > 0 ? 'inline-flex' : 'none'
    })
  } catch {}
}

// 路由分发：根据 message_type 跳到合适的 UI
window.snfRouteMessage = (msg) => {
  if (!msg) return
  switch (msg.message_type) {
    case 'chat':
      // 跳到与 sender 的私聊
      if (msg.sender_id) location.hash = '#chat/' + msg.sender_id
      break
    case 'order_event':
    case 'dispute_evidence':
      // 跳订单详情页（payload 通常含 order_id 或 related_order_id）
      if (msg.related_order_id) location.hash = '#order/' + msg.related_order_id
      else if (msg.payload?.order_id) location.hash = '#order/' + msg.payload.order_id
      break
    case 'protocol_hint':
      // 协议提示通常含跳转 target
      if (msg.payload?.hash) location.hash = msg.payload.hash
      break
    default:
      // custom 类型 — 留在 inbox 页面看
      break
  }
}

async function renderSnfInbox(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'notifications')
  // GET /snf/inbox 现在是只读 list — 含已 ack 的近 30 天消息。刷新页面也能看到
  const fresh = await GET('/snf/inbox?limit=80').catch(() => ({ items: [] }))
  const merged = fresh.items || []
  state._snfRecent = merged
  const unreadCount = merged.filter(m => !m.delivered_at).length
  refreshSnfBadge()

  const TYPE_ICON = {
    chat: '💬', order_event: '📦', dispute_evidence: '⚖️',
    protocol_hint: '🔮', custom: '✨',
  }
  const TYPE_LABEL = {
    chat: t('私聊'), order_event: t('订单事件'),
    dispute_evidence: t('仲裁证据'), protocol_hint: t('协议提示'),
    custom: t('其他'),
  }

  const items = merged.length === 0
    ? `<div class="empty"><div class="empty-icon">📭</div><div class="empty-text">${t('SNF 收件箱空 — 协议级消息会出现在这里')}</div></div>`
    : merged.map(m => {
        const ic = TYPE_ICON[m.message_type] || '📨'
        const lbl = TYPE_LABEL[m.message_type] || m.message_type
        const target = m.related_order_id ? '#order/' + m.related_order_id
                       : m.message_type === 'chat' ? '#chat/' + m.sender_id
                       : null
        const previewText = (() => {
          const p = m.payload || {}
          if (m.message_type === 'chat') return p.text || ''
          if (m.message_type === 'dispute_evidence') return p.description || ''
          if (m.message_type === 'order_event') return `${p.from_status || ''} → ${p.to_status || ''}`
          return JSON.stringify(p).slice(0, 100)
        })()
        const isUnread = !m.delivered_at
        return `
        <div class="card" style="padding:12px 14px;margin-bottom:8px${m.priority > 0 ? ';border-left:3px solid #f59e0b' : isUnread ? ';border-left:3px solid #3b82f6' : ''}${target ? ';cursor:pointer' : ''}${isUnread ? '' : ';opacity:0.85'}" ${target ? `onclick="location.hash='${target}'"` : ''} data-snf-id="${m.id}">
          <div style="display:flex;align-items:flex-start;gap:10px">
            <div style="font-size:22px;line-height:1;flex-shrink:0">${ic}</div>
            <div style="flex:1;min-width:0">
              <div style="display:flex;justify-content:space-between;align-items:center;gap:6px">
                <div style="font-size:13px;font-weight:600;color:#1f2937">${lbl}${m.priority > 0 ? ` <span style="font-size:9px;background:#f59e0b;color:#fff;padding:1px 6px;border-radius:99px;margin-left:4px">HIGH</span>` : ''}${isUnread ? ` <span style="font-size:9px;background:#3b82f6;color:#fff;padding:1px 6px;border-radius:99px;margin-left:4px">NEW</span>` : ''}</div>
                <div style="font-size:10px;color:#9ca3af">${fmtTime(m.created_at)}</div>
              </div>
              <div style="font-size:11px;color:#6b7280;margin-top:2px">${t('来自')} <code style="font-family:ui-monospace,Consolas,monospace">${escHtml(m.sender_id)}</code></div>
              <div style="font-size:13px;color:#374151;margin-top:6px;line-height:1.5;word-break:break-word">${escHtml(previewText.slice(0, 200))}${previewText.length > 200 ? '…' : ''}</div>
              <div style="display:flex;gap:6px;margin-top:6px;align-items:center">
                ${m.signature ? `<button onclick="event.stopPropagation();snfVerifyMsg('${m.id}', this)" style="font-size:10px;background:#eff6ff;border:1px solid #bfdbfe;color:#1d4ed8;padding:2px 8px;border-radius:99px;cursor:pointer">🔐 ${t('验签')}</button>` : ''}
                ${m.related_order_id ? `<a href="#order/${m.related_order_id}" onclick="event.stopPropagation()" style="font-size:10px;color:#6366f1">→ ${t('查看订单')}</a>` : ''}
              </div>
            </div>
          </div>
        </div>`
      }).join('')

  app.innerHTML = shell(`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
      <h1 class="page-title" style="margin:0">📨 ${t('SNF 收件箱')}</h1>
      ${unreadCount > 0 ? `<button onclick="snfAckAll()" style="background:#eff6ff;border:1px solid #bfdbfe;color:#1d4ed8;font-size:12px;padding:6px 14px;border-radius:99px;cursor:pointer">✓ ${t('全部标为已读')} (${unreadCount})</button>` : ''}
    </div>
    <div style="font-size:11px;color:#8e8e93;margin-bottom:14px;line-height:1.5">
      ${t('协议级消息（私聊 / 订单事件 / 仲裁证据 / 协议提示），离线时由服务器代收。每条带 HMAC 签名可独立验签。')}
    </div>
    ${items}
  `, 'notifications')
}

window.snfAckAll = async () => {
  const r = await POST('/snf/ack', {})
  if (r.ok) {
    toast$(t('已标为已读') + ' · ' + (r.acked || 0))
    setTimeout(() => renderSnfInbox(document.getElementById('app')), 400)
  }
}

window.snfVerifyMsg = async (id, btn) => {
  const orig = btn.textContent
  btn.textContent = t('验签中…')
  btn.disabled = true
  try {
    const r = await GET('/snf/' + id + '/verify')
    if (r.ok) {
      btn.textContent = `✓ ${t('签名有效')}`
      btn.style.background = '#dcfce7'; btn.style.borderColor = '#bbf7d0'; btn.style.color = '#15803d'
    } else {
      btn.textContent = `✗ ${r.reason || 'invalid'}`
      btn.style.background = '#fee2e2'; btn.style.borderColor = '#fecaca'; btn.style.color = '#b91c1c'
    }
  } catch {
    btn.textContent = '✗ ' + t('失败')
  }
  setTimeout(() => { btn.textContent = orig; btn.disabled = false; btn.style.background = '#eff6ff'; btn.style.borderColor = '#bfdbfe'; btn.style.color = '#1d4ed8' }, 2500)
}

async function refreshChatsBadge() {
  if (!state.apiKey) return
  try {
    const r = await GET('/conversations')
    state.chatsUnread = (r?.items || []).reduce((a, it) => a + Number(it.my_unread || 0), 0)
  } catch {}
  if (typeof updateAggregateChatsBadge === 'function') updateAggregateChatsBadge()
}
window.refreshChatsBadge = refreshChatsBadge

let toastTimer = null
function showToast(title, body) {
  let toast = document.getElementById('toast')
  if (!toast) {
    toast = document.createElement('div')
    toast.id = 'toast'
    toast.style.cssText = `position:fixed;bottom:76px;left:16px;right:16px;background:#1e1b4b;color:#fff;border-radius:12px;padding:12px 16px;font-size:14px;z-index:999;box-shadow:0 4px 20px rgba(0,0,0,.3);cursor:pointer`
    toast.onclick = () => navigate('#notifications')
    document.body.appendChild(toast)
  }
  toast.innerHTML = `<div style="font-weight:700;margin-bottom:3px">${title}</div><div style="opacity:.85;font-size:13px">${body}</div>`
  toast.style.opacity = '1'
  toast.style.transform = 'translateY(0)'
  clearTimeout(toastTimer)
  toastTimer = setTimeout(() => { toast.style.opacity = '0' }, 4000)
}

// ─── 通知列表页 ───────────────────────────────────────────────

async function renderNotifications(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'notifications')

  // 先抓未读列表（用于视觉标记），然后再 mark-all-read
  const data = await GET('/notifications')
  const list = (data.notifications || [])
  const unreadIds = new Set(list.filter(n => !n.read).map(n => n.id))
  await POST('/notifications/read', {})
  updateBadge(0)

  const routeFor = (n) => n.wish_id ? `#wish/${n.wish_id}` : n.order_id ? `#order/${n.order_id}` : ''
  // 按日期分组：今天 / 昨天 / 更早
  const today = new Date(); today.setHours(0,0,0,0)
  const yesterday = new Date(today.getTime() - 86400000)
  const groupOf = (iso) => {
    const d = new Date(iso); d.setHours(0,0,0,0)
    if (d.getTime() === today.getTime()) return t('今天')
    if (d.getTime() === yesterday.getTime()) return t('昨天')
    return t('更早')
  }
  const groups = {}
  for (const n of list) {
    const k = groupOf(n.created_at)
    if (!groups[k]) groups[k] = []
    groups[k].push(n)
  }
  const renderItem = (n) => {
    const route = routeFor(n)
    const isFresh = unreadIds.has(n.id)
    const isReminder = (n.type || '').startsWith('reminder:')
    const accent = isReminder ? '#f59e0b' : isFresh ? '#4f46e5' : '#e5e7eb'
    return `
      <div class="card" style="${isFresh ? 'border-left:3px solid ' + accent + ';' : ''}padding:12px 14px;margin-bottom:8px${route ? ';cursor:pointer' : ''}" ${route ? `onclick="navigate('${route}')"` : ''}>
        <div style="display:flex;gap:12px;align-items:flex-start">
          <div style="font-size:22px;line-height:1;flex-shrink:0">${n.title.slice(0,2)}</div>
          <div style="flex:1;min-width:0">
            <div style="display:flex;justify-content:space-between;align-items:center;gap:6px">
              <div style="font-weight:600;font-size:14px;color:#1f2937">${escHtml(n.title.slice(2))}</div>
              ${isFresh ? `<span style="font-size:9px;background:${accent};color:#fff;padding:1px 6px;border-radius:99px;font-weight:600;letter-spacing:0.3px">NEW</span>` : ''}
            </div>
            <div style="font-size:13px;color:#6b7280;margin-top:3px;line-height:1.5">${escHtml(n.body)}</div>
            <div style="font-size:11px;color:#9ca3af;margin-top:4px">${fmtTime(n.created_at)}</div>
          </div>
        </div>
      </div>`
  }
  const html = list.length === 0
    ? `<div class="empty"><div class="empty-icon">🔔</div><div class="empty-text">${t('暂无通知')}</div></div>`
    : [t('今天'), t('昨天'), t('更早')]
        .filter(k => groups[k]?.length)
        .map(k => `<div style="font-size:11px;font-weight:600;color:#9ca3af;letter-spacing:0.5px;text-transform:uppercase;margin:14px 0 6px">${k}</div>${groups[k].map(renderItem).join('')}`)
        .join('')

  app.innerHTML = shell(`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px">
      <h1 class="page-title" style="margin:0">${t('通知')}</h1>
      <a href="#inbox" style="font-size:12px;color:#007aff;text-decoration:none;background:#eff6ff;border:0.5px solid #bfdbfe;padding:5px 12px;border-radius:99px">📨 ${t('SNF 收件箱')}${state._snfPending > 0 ? ` <span style="background:#dc2626;color:#fff;font-size:9px;padding:1px 6px;border-radius:99px;margin-left:3px;font-weight:600">${state._snfPending}</span>` : ''}</a>
    </div>
    ${html}
  `, 'notifications')
}

// ─── Skill 市场页 ─────────────────────────────────────────────

async function renderSkills(app) {
  app.innerHTML = shell(loading$(), 'discover')

  const skills = await GET('/skills')
  const isBuyer = state.user?.role === 'buyer'

  const typeIcons = { catalog_sync:'🔄', auto_accept:'⚡', auto_bid:'🤖', price_negotiation:'🤝', quality_guarantee:'🛡️', instant_ship:'🚀' }
  const typeLabels = { catalog_sync:'目录同步', auto_accept:'自动接单', auto_bid:'自动报价', price_negotiation:'价格协商', quality_guarantee:'质量承诺', instant_ship:'极速发货' }

  const groups = {}
  for (const s of skills) {
    if (!groups[s.skill_type]) groups[s.skill_type] = []
    groups[s.skill_type].push(s)
  }

  let html = ''
  if (skills.length === 0) {
    html = `<div class="empty"><div class="empty-icon">⚡</div><div class="empty-text">还没有 Skill，卖家可以去后台发布</div></div>`
  } else {
    for (const [type, items] of Object.entries(groups)) {
      const icon = typeIcons[type] || '⚙️'
      const label = t(typeLabels[type] || type)
      html += `<div style="font-weight:700;margin:16px 0 8px">${icon} ${label}</div>`
      html += items.map(s => skillCard(s, 'buyer')).join('')
    }
  }

  app.innerHTML = shell(`
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
      <button class="btn btn-gray btn-sm" style="width:auto" onclick="history.back()">←</button>
      <h1 class="page-title" style="margin:0">⚡ Skill 市场</h1>
    </div>
    ${isBuyer ? `
    <div class="alert alert-info" style="font-size:13px">
      订阅卖家发布的 Skill，即可享受自动接单、优先推荐、价格协商等特权。
    </div>` : !state.user ? `
    <div class="alert alert-info" style="font-size:13px">
      <a href="#login" style="color:inherit;font-weight:700">登录</a>后即可订阅 Skill
    </div>` : ''}
    <div id="skill-sub-msg"></div>
    ${html}
  `, 'shop')
}

window.toggleSubscribeSkill = async (skillId, currentlySubscribed) => {
  const msgEl = document.getElementById('skill-sub-msg')
  if (currentlySubscribed) {
    await fetch(`/api/skills/${skillId}/subscribe`, { method: 'DELETE', headers: { Authorization: `Bearer ${state.apiKey}` } })
    msgEl.innerHTML = alert$('info', t('已取消订阅'))
  } else {
    const res = await POST(`/skills/${skillId}/subscribe`, {})
    if (res.error) { msgEl.innerHTML = alert$('error', res.error); return }
    msgEl.innerHTML = alert$('success', t('✅ 订阅成功！你将优先看到此卖家商品'))
  }
  setTimeout(() => renderSkills(document.getElementById('app')), 800)
}

// ─── 全局输入框清空按钮（auto-attach × icon） ─────────────────
// 适用于所有可清空输入；半透明，无内容时隐藏。
// 跳过：search-input-wrap (已有内置)、data-no-clear="1"、checkbox/radio/file 等非文本类
const CLEAR_SKIP_TYPES = new Set(['checkbox','radio','submit','button','file','hidden','range','color','image','reset'])
function _attachClearBtn(el) {
  if (!el || el._hasClear) return
  if (el.tagName !== 'INPUT' && el.tagName !== 'TEXTAREA') return
  if (el.tagName === 'INPUT' && CLEAR_SKIP_TYPES.has(el.type)) return
  if (el.dataset.noClear === '1') return
  if (el.readOnly || el.disabled) return
  const parent = el.parentNode
  if (!parent) return
  // 已被 .search-input-wrap / .clear-wrap 包裹 → 不重复
  if (parent.classList?.contains?.('search-input-wrap')) return
  if (parent.classList?.contains?.('clear-wrap')) return

  const wrap = document.createElement('span')
  wrap.className = 'clear-wrap' + ((el.classList.contains('form-control') || el.tagName === 'TEXTAREA' || el.classList.contains('search-input')) ? ' block' : '')
  parent.insertBefore(wrap, el)
  wrap.appendChild(el)

  const btn = document.createElement('button')
  btn.type = 'button'
  btn.className = 'clear-btn'
  btn.textContent = '×'
  btn.setAttribute('aria-label', 'Clear')
  btn.tabIndex = -1
  wrap.appendChild(btn)

  const update = () => wrap.classList.toggle('has-value', !!el.value)
  update()
  el.addEventListener('input',  update)
  el.addEventListener('change', update)
  // mousedown preventDefault 让 input 不失焦
  btn.addEventListener('mousedown', (e) => e.preventDefault())
  btn.addEventListener('click', () => {
    el.value = ''
    el.focus()
    el.dispatchEvent(new Event('input',  { bubbles: true }))
    el.dispatchEvent(new Event('change', { bubbles: true }))
    update()
  })
  el._hasClear = true
}

function _scanClearTargets(root) {
  const r = root || document.body
  if (!r || !r.querySelectorAll) return
  r.querySelectorAll('input, textarea').forEach(_attachClearBtn)
}

if (typeof MutationObserver !== 'undefined') {
  new MutationObserver((muts) => {
    for (const m of muts) {
      for (const n of m.addedNodes) {
        if (n.nodeType !== 1) continue
        if (n.matches?.('input, textarea')) _attachClearBtn(n)
        _scanClearTargets(n)
      }
    }
  }).observe(document.body, { childList: true, subtree: true })
}
// 初次扫描（应对 boot 时已渲染的 login 页等）
setTimeout(_scanClearTargets, 0)

// ─── 启动 ─────────────────────────────────────────────────────

if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('/sw.js').catch(() => {})
}

// 上面 line ~25263 已注册 beforeinstallprompt 监听 + doInstallPWA(带 iOS/通用引导 fallback);
// 此处只补一个 canInstallPWA helper 给 navbar 按钮判 visibility 用。
window.canInstallPWA = () => !!window._installPromptEvent || isIOS()

// 离线状态全局 banner
function ensureOfflineBanner() {
  if (document.getElementById('webaz-offline-banner')) return
  const bar = document.createElement('div')
  bar.id = 'webaz-offline-banner'
  bar.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:9999;background:#fef3c7;color:#92400e;font-size:12px;text-align:center;padding:6px 12px;border-bottom:1px solid #fde68a;font-weight:600;display:none'
  bar.textContent = '📡 ' + (t ? t('当前离线 — 已读内容可看，写操作待恢复') : '离线中')
  document.body.appendChild(bar)
  const setOnline = () => { bar.style.display = 'none' }
  const setOffline = () => { bar.style.display = '' }
  window.addEventListener('online', setOnline)
  window.addEventListener('offline', setOffline)
  // 初始按 navigator.onLine
  if (navigator.onLine) setOnline(); else setOffline()
}
// DOM ready 后挂
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', ensureOfflineBanner)
} else {
  ensureOfflineBanner()
}

