const CLAIM_TARGET_LABEL = () => ({
  price:       t('价格优势'),
  commission:  t('分享佣金'),
  protection:  t('协议保障'),
  return:      t('退货条款'),
  warranty:    t('质保条款'),
  handling:    t('发货时效'),
  other:       t('其他理由'),
})
const CLAIM_STATUS_LABEL = () => ({
  open:               { c:'#92400e', bg:'#fef3c7', l:t('🕐 等待 verifier') },
  sealed:             { c:'#3730a3', bg:'#e0e7ff', l:t('🔒 已封存，待结算') },
  resolved_pass:      { c:'#166534', bg:'#dcfce7', l:t('✅ 验证通过（声明有误）') },
  resolved_fail:      { c:'#991b1b', bg:'#fee2e2', l:t('❌ 验证失败（声明无据）') },
  resolved_no_fault:  { c:'#374151', bg:'#f3f4f6', l:t('⚖️ 双方无责') },
  timeout_no_fault:   { c:'#6b7280', bg:'#f3f4f6', l:t('⏱ 超时无人接单，已退') },
})
const CLAIM_VOTE_LABEL = () => ({ pass: t('支持声明'), fail: t('反对声明'), no_fault: t('双方无责'), abstain: t('弃投（不熟悉）') })

function claimStatusBadge(status) {
  const s = CLAIM_STATUS_LABEL()[status] || { c:'#374151', bg:'#f3f4f6', l:status }
  return `<span style="display:inline-block;font-size:11px;background:${s.bg};color:${s.c};padding:2px 9px;border-radius:99px;font-weight:600">${s.l}</span>`
}

// 渲染 claim verify body（不含 shell，可嵌入个人主页 或 独立页）
function renderClaimVerifyBody(avail, mine) {
  const eligible = avail.eligible === true
  const eligCard = eligible
    ? `<div class="card" style="background:linear-gradient(135deg,#ecfdf5,#dbeafe);border-color:#bbf7d0">
         <div style="font-size:14px;font-weight:700;color:#166534">✅ ${t('你已获 verifier 资格')}</div>
         <div style="font-size:12px;color:#374151;margin-top:6px;line-height:1.7">
           · ${t('资格来源')}：${avail.via === 'whitelist' ? t('verifier 白名单') : t('信誉积分 ≥ 200')}<br>
           · ${t('进行中任务')}：${avail.active} / ${avail.max_active}
         </div>
       </div>`
    : `<div class="card" style="background:linear-gradient(135deg,#fef3c7,#fff);border-color:#fde68a">
         <div style="font-size:14px;font-weight:700;color:#92400e">🔒 ${t('你尚未获 verifier 资格')}</div>
         <div style="font-size:12px;color:#374151;margin-top:6px;line-height:1.7">${escHtml(avail.error || '')}</div>
         <div style="font-size:11px;color:#6b7280;margin-top:8px">${t('如何获得：完成订单累计信誉积分 ≥ 200，或申请加入 verifier 白名单')}</div>
       </div>`

  const tasks = avail.tasks || []
  const taskListHtml = !eligible ? '' : (tasks.length === 0
    ? `<div style="text-align:center;padding:24px;color:#9ca3af;font-size:12px">${t('当前没有可接的验证任务')}</div>`
    : tasks.map(task => `
        <div class="card" style="margin-bottom:10px;padding:14px;cursor:pointer" onclick="navigate('#claim-task/${task.id}')">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
            <span style="font-size:12px;font-weight:600;color:#4338ca">🎯 ${CLAIM_TARGET_LABEL()[task.claim_target] || task.claim_target}</span>
            <span style="font-size:11px;color:#6b7280">${task.votes_count}/3 ${t('票')}</span>
          </div>
          <div style="font-size:13px;color:#111827;line-height:1.5;margin-bottom:6px">${escHtml(task.claim_text)}</div>
          <div style="font-size:11px;color:#6b7280">📦 ${escHtml(task.product_title || '商品')} · ${t('截止')} ${fmtTime(task.deadline_at)}</div>
        </div>`).join(''))

  const myTab = state.claimVerifyTab || 'verifier'
  const tabBtn = (id, label) => `<button onclick="setClaimVerifyTab('${id}')" style="background:${myTab===id?'#4f46e5':'#fff'};color:${myTab===id?'#fff':'#374151'};border:1px solid ${myTab===id?'#4f46e5':'#e5e7eb'};border-radius:6px;padding:5px 12px;font-size:12px;font-weight:600;cursor:pointer">${label}</button>`
  const myList = myTab === 'buyer' ? mine.as_buyer : myTab === 'seller' ? mine.as_seller : mine.as_verifier
  const myListHtml = (myList || []).length === 0
    ? `<div style="text-align:center;padding:18px;color:#9ca3af;font-size:12px">${t('暂无记录')}</div>`
    : (myList || []).map(t2 => `
        <div onclick="navigate('#claim-task/${t2.id}')" style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:10px 12px;margin-bottom:8px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:10px">
          <div style="min-width:0;flex:1">
            <div style="font-size:12px;font-weight:600;color:#374151">${CLAIM_TARGET_LABEL()[t2.claim_target] || t2.claim_target}${t2.vote ? ` · ${t('你投')}：${CLAIM_VOTE_LABEL()[t2.vote] || t2.vote}` : ''}</div>
            <div style="font-size:10px;color:#9ca3af;margin-top:2px">${fmtTime(t2.created_at || t2.voted_at)}</div>
          </div>
          ${claimStatusBadge(t2.status)}
        </div>`).join('')

  return `
    ${eligCard}
    ${eligible ? `
      <div style="font-size:13px;font-weight:600;margin:18px 0 8px;color:#111827">📋 ${t('可接任务')}</div>
      ${taskListHtml}
    ` : ''}
    <div style="font-size:13px;font-weight:600;margin:24px 0 10px;color:#111827">📚 ${t('我相关的任务')}</div>
    <div style="display:flex;gap:6px;margin-bottom:10px;flex-wrap:wrap">
      ${tabBtn('verifier', t('我参与的'))}
      ${tabBtn('buyer', t('我发起的'))}
      ${tabBtn('seller', t('我被诉的'))}
    </div>
    ${myListHtml}`
}

// 异步把 claim verify 面板注入到一个容器节点（个人主页 inline 使用）
async function injectClaimVerifyPanel(containerId) {
  const el = document.getElementById(containerId)
  if (!el) return
  const [avail, mine] = await Promise.all([
    GET('/claim-tasks/available'),
    GET('/claim-tasks/mine'),
  ])
  el.innerHTML = renderClaimVerifyBody(avail, mine)
}

