window.shSetCat = (cat) => {
  _shFilters.cat = cat
  document.querySelectorAll('.sh-cat-pill').forEach(b => {
    const on = b.dataset.cat === cat
    b.style.background = on ? '#4f46e5' : '#fff'
    b.style.color = on ? '#fff' : '#374151'
  })
  shMarketReload()
}
window.shToggleCond = (id) => {
  if (_shFilters.conds.has(id)) _shFilters.conds.delete(id)
  else _shFilters.conds.add(id)
  const c = SH_CONDITIONS.find(x => x.id === id)
  document.querySelectorAll('.sh-cond-pill').forEach(b => {
    if (b.dataset.cond === id) {
      const on = _shFilters.conds.has(id)
      b.style.borderColor = on ? c.color : '#e5e7eb'
      b.style.background = on ? c.color : '#fff'
      b.style.color = on ? '#fff' : '#374151'
    }
  })
  shMarketReload()
}
window.shMarketReload = async () => {
  _shFilters.q = state._aucQ || document.getElementById('sh-q')?.value?.trim() || _shFilters.q
  const grid = document.getElementById('sh-grid'); if (!grid) return
  grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:40px;color:#9ca3af"><div class="spinner" style="display:inline-block"></div></div>`
  const qs = new URLSearchParams()
  if (_shFilters.cat) qs.set('category', _shFilters.cat)
  if (_shFilters.q) qs.set('q', _shFilters.q)
  if (_shFilters.sort && _shFilters.sort !== 'newest') qs.set('sort', _shFilters.sort)
  if (_shFilters.minP) qs.set('min_price', _shFilters.minP)
  if (_shFilters.maxP) qs.set('max_price', _shFilters.maxP)
  if (_shFilters.conds.size > 0) qs.set('condition', [..._shFilters.conds].join(','))
  const r = await GET('/secondhand?' + qs.toString())
  const items = r.items || []
  if (items.length === 0) {
    grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:40px;color:#9ca3af"><div style="font-size:48px;margin-bottom:10px">🛒</div><div style="font-size:13px">${t('暂无物品')}</div><div style="font-size:11px;margin-top:6px;color:#d1d5db">${t('成为第一个发布者')}</div></div>`
    return
  }
  grid.innerHTML = items.map(it => shItemCard(it)).join('')
}

