window.shHandleImagesChange = async (input) => {
  const files = Array.from(input.files || [])
  for (const f of files) {
    if (state.shImages.length >= 9) break
    if (!f.type.startsWith('image/')) continue
    if (f.size > 4_000_000) { alert(t('单张图片不超过 4MB：') + f.name); continue }
    // 压缩到 800px 长边
    const dataURL = await shCompressImage(f, 800)
    state.shImages.push(dataURL)
  }
  shRenderImagesGrid()
  input.value = ''
}
async function shCompressImage(file, maxSide) {
  return new Promise((resolve) => {
    const r = new FileReader()
    r.onload = () => {
      const img = new Image()
      img.onload = () => {
        const scale = Math.min(1, maxSide / Math.max(img.width, img.height))
        const w = Math.round(img.width * scale), h = Math.round(img.height * scale)
        const c = document.createElement('canvas'); c.width = w; c.height = h
        c.getContext('2d').drawImage(img, 0, 0, w, h)
        resolve(c.toDataURL('image/jpeg', 0.82))
      }
      img.onerror = () => resolve(r.result)
      img.src = r.result
    }
    r.readAsDataURL(file)
  })
}
function shRenderImagesGrid() {
  const g = document.getElementById('sh-imgs-grid'); if (!g) return
  g.innerHTML = (state.shImages || []).map((src, i) => `
    <div style="position:relative;aspect-ratio:1;background:#f3f4f6;border-radius:6px;overflow:hidden">
      <img src="${escAttr(src)}" style="width:100%;height:100%;object-fit:cover">
      ${i === 0 ? `<span style="position:absolute;top:4px;left:4px;background:rgba(0,0,0,0.7);color:#fff;font-size:9px;padding:1px 5px;border-radius:3px">${t('封面')}</span>` : ''}
      <button onclick="shRemoveImage(${i})" style="position:absolute;top:4px;right:4px;background:rgba(0,0,0,0.6);color:#fff;border:none;width:20px;height:20px;border-radius:50%;cursor:pointer;font-size:11px;line-height:1">×</button>
    </div>`).join('')
}
window.shRemoveImage = (i) => { state.shImages.splice(i, 1); shRenderImagesGrid() }
window.doShPublish = async () => {
  const title = document.getElementById('sh-title')?.value?.trim()
  const category = document.getElementById('sh-category')?.value
  const condition_grade = document.getElementById('sh-condition')?.value
  const price = parseFloat(document.getElementById('sh-price')?.value)
  const negotiable = !!document.getElementById('sh-negotiable')?.checked
  const fulfillment = document.getElementById('sh-fulfillment')?.value
  const region = document.getElementById('sh-region')?.value?.trim()
  const description = document.getElementById('sh-desc')?.value?.trim()
  const msg = document.getElementById('sh-publish-msg')
  if (!title || title.length < 2) { msg.innerHTML = alert$('error', t('请填写标题')); return }
  if (!price || price <= 0) { msg.innerHTML = alert$('error', t('请填写价格')); return }
  if ((state.shImages || []).length === 0) { msg.innerHTML = alert$('error', t('至少上传 1 张图片')); return }
  msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('发布中…')}</div>`
  const r = await POST('/secondhand', { title, description, category, condition_grade, price, negotiable, images: state.shImages, region: region || undefined, fulfillment })
  if (r.error) { msg.innerHTML = alert$('error', r.error); return }
  state.shImages = []
  msg.innerHTML = alert$('success', `✅ ${t('发布成功')}`)
  setTimeout(() => location.hash = `#secondhand/item/${r.id}`, 700)
}

