window.submitFollowListing = async function(listingId) {
  const body = {
    price:            Number(document.getElementById('lf-price').value),
    stock:            Number(document.getElementById('lf-stock').value),
    fulfillment_type: document.getElementById('lf-ff').value,
    eta_hours:        document.getElementById('lf-eta').value ? Number(document.getElementById('lf-eta').value) : null,
    ship_regions:     document.getElementById('lf-region').value.trim(),
    is_clearance:     document.getElementById('lf-cl').checked ? 1 : 0,
  }
  if (!body.price || body.price <= 0) { document.getElementById('lf-msg').innerHTML = alert$('error', t('价格必须 > 0')); return }
  if (!body.stock || body.stock < 1) { document.getElementById('lf-msg').innerHTML = alert$('error', t('库存至少 1')); return }
  const r = await POST('/listings/' + encodeURIComponent(listingId) + '/offers', body)
  if (r.error) { document.getElementById('lf-msg').innerHTML = alert$('error', r.error); return }
  document.getElementById('lf-msg').innerHTML = alert$('success', t('跟卖成功，押金 ') + r.stake_locked + ' WAZ')
  setTimeout(() => { location.hash = '#listings/' + listingId }, 600)
}

// ─── P3 RFQ 抢单 ─────────────────────────────────────────────────────
const RFQ_URGENCY_CHIPS = [
  { key: 'now',   emoji: '⚡', label: '急要' },
  { key: 'today', emoji: '📅', label: '今天' },
  { key: 'flex',  emoji: '🌊', label: '宽松' },
]
const RFQ_STATUS_LABELS = {
  open:      { color: '#16a34a', label: '征集中' },
  awarded:   { color: '#2563eb', label: '已选定' },
  expired:   { color: '#9ca3af', label: '已过期' },
  cancelled: { color: '#dc2626', label: '已取消' },
}

function rfqRemain(deadlineIso) {
  if (!deadlineIso) return ''
  const ms = new Date(deadlineIso.replace(' ', 'T') + (deadlineIso.includes('Z') ? '' : 'Z')).getTime() - Date.now()
  if (ms <= 0) return t('已过期')
  const m = Math.floor(ms / 60000)
  if (m < 60) return m + ' ' + t('分钟')
  const h = Math.floor(m / 60)
  if (h < 24) return h + 'h'
  return Math.floor(h / 24) + 'd'
}

