// P3d 买家 Agent：自然语言 → 预填表单
window.parseRfqNLP = async function() {
  const text = document.getElementById('rfq-nlp').value.trim()
  const msgEl = document.getElementById('rfq-nlp-msg')
  if (text.length < 4) { msgEl.innerHTML = `<span style="color:#dc2626">${t('请至少描述一句')}</span>`; return }
  msgEl.innerHTML = `<span style="color:#6366f1">${t('AI 解析中…')}</span>`
  const lang = window._lang === 'en' ? 'en' : 'zh'
  const prompt = lang === 'en' ?
`You are an RFQ (Request for Quote) parser for a decentralized commerce protocol called WebAZ.
Parse the buyer's natural-language need into a STRICT JSON object. Output JSON only, no commentary.

Schema:
{
  "title": "concise item name, 5-50 chars",
  "qty": integer >=1,
  "max_price": number (in WAZ, ≈ CNY) or null if unspecified,
  "urgency": "now" | "today" | "flex",   // now = within hours; today = same day; flex = relaxed
  "category": "standard" | "general" | "highvalue" | "restricted",
  // standard = small hardware/parts; general = ordinary goods; highvalue = bulky/expensive (>3000 WAZ); restricted = food/drug/baby
  "award_mode": "manual" | "first_match" | "time_window",
  "notes": "extracted preferences (delivery, specs) — short, max 200 chars, or empty string"
}

Buyer input:
"""
${text}
"""`
    :
`你是去中心化商业协议 WebAZ 的 RFQ 求购单解析助手。把买家的自然语言转成严格的 JSON 对象。只输出 JSON，无任何其他文字。

Schema:
{
  "title": "精炼商品名，5-50 字",
  "qty": 整数 >= 1,
  "max_price": 数字（WAZ，约等于 CNY）或 null 如未提及,
  "urgency": "now" | "today" | "flex",  // now=几小时内；today=今天内；flex=不急
  "category": "standard" | "general" | "highvalue" | "restricted",
  // standard=五金/小标品；general=普通商品；highvalue=大件高价(>3000 WAZ)；restricted=食药婴幼
  "award_mode": "manual" | "first_match" | "time_window",
  "notes": "提取的偏好（履约方式 / 规格 / 地址等）短文本 200 字内，无则空串"
}

买家输入：
"""
${text}
"""`

  let parsed
  try {
    const r = await aiCallLLM({ messages: [{ role: 'user', content: prompt }], max_tokens: 600 })
    const text = (r?.content || []).find(c => c.type === 'text')?.text || ''
    const jsonMatch = text.match(/\{[\s\S]*\}/)
    if (!jsonMatch) throw new Error('no JSON in response')
    parsed = JSON.parse(jsonMatch[0])
  } catch (e) {
    msgEl.innerHTML = `<span style="color:#dc2626">${t('解析失败，请直接填表')}: ${escHtml(String(e.message || e))}</span>`
    return
  }

  // 校验 + 写入字段
  try {
    const validUrg = new Set(['now', 'today', 'flex'])
    const validCat = new Set(['standard', 'general', 'highvalue', 'restricted'])
    const validMode = new Set(['manual', 'first_match', 'time_window'])
    const RFQ_MAX_QTY = 100000
    const RFQ_MAX_PRICE = 1000000
    if (parsed.title && typeof parsed.title === 'string') document.getElementById('rfq-title').value = String(parsed.title).slice(0, 80)
    if (parsed.qty != null && Number(parsed.qty) > 0) {
      const q = Math.min(RFQ_MAX_QTY, Math.floor(Number(parsed.qty)))
      document.getElementById('rfq-qty').value = q
    }
    if (parsed.max_price != null && Number(parsed.max_price) > 0) {
      const p = Math.min(RFQ_MAX_PRICE, Number(parsed.max_price))
      document.getElementById('rfq-max').value = p
    }
    if (parsed.category && validCat.has(parsed.category)) document.getElementById('rfq-cat').value = parsed.category
    if (parsed.urgency && validUrg.has(parsed.urgency)) {
      const r = document.querySelector(`input[name="rfq-urg"][value="${parsed.urgency}"]`)
      if (r) r.checked = true
    }
    if (parsed.award_mode && validMode.has(parsed.award_mode)) document.getElementById('rfq-mode').value = parsed.award_mode
    if (parsed.notes && typeof parsed.notes === 'string') document.getElementById('rfq-notes').value = String(parsed.notes).slice(0, 200)
  } catch (e) {
    msgEl.innerHTML = `<span style="color:#dc2626">${t('解析结果应用失败')}: ${escHtml(String(e.message || e))}</span>`
    return
  }

  msgEl.innerHTML = `<span style="color:#16a34a">✓ ${t('AI 已识别并填入下方，请核对后发布')}</span>`
}

window.submitRfq = async function() {
  const body = {
    title:        document.getElementById('rfq-title').value.trim(),
    qty:          Number(document.getElementById('rfq-qty').value) || 1,
    max_price:    document.getElementById('rfq-max').value ? Number(document.getElementById('rfq-max').value) : null,
    category:     document.getElementById('rfq-cat').value,
    urgency:      document.querySelector('input[name="rfq-urg"]:checked')?.value || 'flex',
    award_mode:   document.getElementById('rfq-mode').value,
    notes:        document.getElementById('rfq-notes').value.trim() || null,
  }
  if (body.title.length < 2) { document.getElementById('rfq-msg').innerHTML = alert$('error', t('标题至少 2 字')); return }
  const r = await POST('/rfqs', body)
  if (r.error) { document.getElementById('rfq-msg').innerHTML = alert$('error', r.error); return }
  document.getElementById('rfq-msg').innerHTML = alert$('success', t('已发布，押金 ') + r.deposit + ' WAZ · ' + t('窗口期 ') + r.window_min + ' ' + t('分钟'))
  setTimeout(() => { location.hash = '#rfq/' + r.id }, 600)
}

