window.sendChatOffer = async (convId, productId) => {
  const amt = Number(document.getElementById('offer-amt')?.value || 0)
  const note = (document.getElementById('offer-note')?.value || '').trim()
  const msgEl = document.getElementById('offer-msg')
  if (!(amt > 0)) { if (msgEl) msgEl.innerHTML = alert$('error', t('报价金额必填')); return }
  const meta = { amount: amt, product_id: productId || null, note }
  const r = await POST(`/conversations/${convId}/messages`, { kind: 'offer', meta })
  if (r.error) { if (msgEl) msgEl.innerHTML = alert$('error', r.error); return }
  document.querySelector('.js-modal')?.remove()
  toast$(t('报价已发送'))
  renderChatDetail(document.getElementById('app'), convId)
}

