window.sendChatTracking = async (convId) => {
  const carrier = (document.getElementById('trk-carrier')?.value || '').trim()
  const no = (document.getElementById('trk-no')?.value || '').trim()
  const msgEl = document.getElementById('trk-msg')
  if (!no) { if (msgEl) msgEl.innerHTML = alert$('error', t('单号必填')); return }
  const r = await POST(`/conversations/${convId}/messages`, { kind: 'tracking', meta: { carrier, tracking_no: no } })
  if (r.error) { if (msgEl) msgEl.innerHTML = alert$('error', r.error); return }
  document.querySelector('.js-modal')?.remove()
  toast$(t('单号已发送'))
  renderChatDetail(document.getElementById('app'), convId)
}

window.sendChat = async function(convId) {
  const inputEl = document.getElementById('chat-input')
  const body = inputEl.value.trim()
  const imgEl = window._chatImg
  const errEl = document.getElementById('chat-msg-err')
  errEl.textContent = ''
  const attachments = []
  if (imgEl?.files?.[0]) {
    const f = imgEl.files[0]
    if (f.size > 200_000) { errEl.textContent = t('图片需 < 200KB'); return }
    const dataUrl = await new Promise((resolve, reject) => { const r = new FileReader(); r.onload = () => resolve(r.result); r.onerror = reject; r.readAsDataURL(f) })
    attachments.push(dataUrl)
  }
  if (!body && attachments.length === 0) return
  const r = await POST('/conversations/' + encodeURIComponent(convId) + '/messages', { body, attachments })
  if (r.error) { errEl.textContent = r.error; return }
  inputEl.value = ''
  if (imgEl) imgEl.value = ''
  window._chatImg = null
  renderChatDetail(document.getElementById('app'), convId)
}

window.chatReport = async function(convId) {
  const reason = prompt(t('举报原因（必填）：欺诈 / 骚扰 / 违规 / 其他'))
  if (!reason) return
  const r = await POST('/conversations/' + encodeURIComponent(convId) + '/report', { reason })
  if (r.error) return alert(r.error)
  alert(t('举报已提交'))
}

