// ─── P2P 原生商店 ─────────────────────────────────────────────
// canonical JSON：递归排序键，去掉空字符串/null/undefined
function p2pCanonicalJson(obj) {
  if (obj === null || obj === undefined || obj === '') return null
  if (Array.isArray(obj)) return obj.map(p2pCanonicalJson).filter(v => v !== null)
  if (typeof obj === 'object') {
    const out = {}
    for (const k of Object.keys(obj).sort()) {
      const v = p2pCanonicalJson(obj[k])
      if (v !== null) out[k] = v
    }
    return out
  }
  return obj
}
async function p2pSha256(str) {
  const enc = new TextEncoder().encode(str)
  const buf = await crypto.subtle.digest('SHA-256', enc)
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('')
}
async function p2pHmacSha256(key, msg) {
  const enc = new TextEncoder()
  const k = await crypto.subtle.importKey('raw', enc.encode(key), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign'])
  const sig = await crypto.subtle.sign('HMAC', k, enc.encode(msg))
  return Array.from(new Uint8Array(sig)).map(b => b.toString(16).padStart(2,'0')).join('')
}

