window.submitP2pPublish = async function() {
  const title = document.getElementById('p2p-title').value.trim()
  const price = Number(document.getElementById('p2p-price').value)
  const stock = Number(document.getElementById('p2p-stock').value) || 1
  const detailRaw = document.getElementById('p2p-detail').value.trim()
  const endpoint = document.getElementById('p2p-endpoint').value.trim()
  const msgEl = document.getElementById('p2p-msg')
  if (title.length < 2) { msgEl.innerHTML = alert$('error', t('商品名至少 2 字')); return }
  if (!price || price <= 0) { msgEl.innerHTML = alert$('error', t('价格必须 > 0')); return }
  let detail
  try { detail = JSON.parse(detailRaw) } catch (e) { msgEl.innerHTML = alert$('error', t('详情 JSON 格式错：') + e.message); return }
  // canonicalize + sha256
  const canonical = JSON.stringify(p2pCanonicalJson(detail))
  const hash = await p2pSha256(canonical)
  const signedAt = new Date().toISOString().replace('T', ' ').slice(0, 19)
  // HMAC 签名
  const signature = await p2pHmacSha256(state.apiKey, hash + '|' + signedAt)
  // thumbnail
  let thumb = null
  if (window._p2pThumb?.files?.[0]) {
    const f = window._p2pThumb.files[0]
    if (f.size > 16000) { msgEl.innerHTML = alert$('error', t('缩略图过大 (≤16KB)')); return }
    thumb = await new Promise((r, j) => { const fr = new FileReader(); fr.onload = () => r(fr.result); fr.onerror = j; fr.readAsDataURL(f) })
  }
  msgEl.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('发布中…')}</div>`
  const r = await POST('/p2p-products', {
    title, price, stock,
    content_hash: hash,
    content_signature: signature,
    content_signed_at: signedAt,
    peer_endpoint: endpoint || null,
    thumbnail_uri: thumb,
    region: state.user?.region || '全国',
    category: 'general',
  })
  if (r.error) { msgEl.innerHTML = alert$('error', r.error); return }
  msgEl.innerHTML = alert$('success', t('已锚定 · hash ') + hash.slice(0, 16) + '…')
  setTimeout(() => location.hash = '#p2p-shop/' + r.id, 600)
}

async function renderP2pDetail(app, id) {
  app.innerHTML = `<div style="padding:14px;max-width:760px;margin:0 auto" id="p2p-detail">${loading$()}</div>`
  const r = await GET('/p2p-products/' + encodeURIComponent(id))
  if (r?.error) { document.getElementById('p2p-detail').innerHTML = alert$('error', r.error); return }
  const p = r.product
  let thumb = ''
  try { const imgs = JSON.parse(p.thumbnail_json || '[]'); thumb = imgs[0] || '' } catch {}

  // 客户端尝试从 peer_endpoint 拉详情并验签
  let verifyStatus = `<span style="color:#9ca3af">${t('未尝试拉取')}</span>`
  let fullDetail = null
  if (p.peer_endpoint && /^https?:\/\//.test(p.peer_endpoint)) {
    try {
      const fetchUrl = p.peer_endpoint.endsWith('/') ? p.peer_endpoint + p.id : p.peer_endpoint
      // P0：5 秒 timeout 防恶意慢节点吊死浏览器
      const ctrl = new AbortController()
      const timer = setTimeout(() => ctrl.abort(), 5000)
      const peerR = await fetch(fetchUrl, { mode: 'cors', signal: ctrl.signal })
      clearTimeout(timer)
      if (!peerR.ok) throw new Error('HTTP ' + peerR.status)
      const raw = await peerR.text()
      if (raw.length > 1_000_000) throw new Error(t('详情过大 (>1MB)'))
      const obj = JSON.parse(raw)
      const canon = JSON.stringify(p2pCanonicalJson(obj))
      const computed = await p2pSha256(canon)
      if (computed === p.content_hash) {
        verifyStatus = `<span style="color:#16a34a;font-weight:600">✅ ${t('已从节点拉取并验证哈希')}</span>`
        fullDetail = obj
      } else {
        verifyStatus = `<span style="color:#dc2626;font-weight:600">⚠ ${t('哈希不匹配！节点返回内容被篡改')}（${t('期望')} ${p.content_hash.slice(0,12)}… ${t('实际')} ${computed.slice(0,12)}…）</span>`
      }
    } catch (e) {
      const msg = e.name === 'AbortError' ? t('节点响应超时 (>5s)') : escHtml(e.message)
      verifyStatus = `<span style="color:#f59e0b">⚠ ${t('节点离线')}（${msg}）</span>`
    }
  }

  document.getElementById('p2p-detail').innerHTML = `
    <button class="btn btn-sm" onclick="history.back()" style="background:#f3f4f6;margin-bottom:14px">←</button>
    <div style="display:flex;gap:14px;margin-bottom:14px">
      ${thumb ? `<img src="${escHtml(thumb)}" style="width:120px;height:120px;object-fit:cover;border-radius:8px;flex-shrink:0">` : ''}
      <div style="flex:1">
        <h2 style="font-size:18px;font-weight:700;margin:0 0 4px">${escHtml(p.title)}</h2>
        <div style="font-size:12px;color:#6b7280;margin-bottom:6px">@${escHtml(p.seller_handle || p.seller_id.slice(0,8))} · ${p.region}</div>
        <div style="color:#dc2626;font-weight:700;font-size:22px;margin-bottom:6px">${p.price} <span style="font-size:11px;color:#9ca3af;font-weight:500">WAZ</span></div>
        <div style="font-size:11px;color:#6b7280">${t('库存')} ${p.stock}</div>
      </div>
    </div>

    <div class="card" style="padding:12px;margin-bottom:12px;background:#fef3c7;border:1px solid #fde68a">
      <div style="font-size:12px;font-weight:600;color:#92400e;margin-bottom:6px">🔒 ${t('P2P 验证状态')}</div>
      <div style="font-size:11px;margin-bottom:4px">${verifyStatus}</div>
      <div style="font-size:10px;color:#92400e;font-family:monospace">hash: ${escHtml(p.content_hash)}</div>
      <div style="font-size:10px;color:#92400e">${t('签名于')} ${fmtTime(p.content_signed_at)} · endpoint: ${escHtml(p.peer_endpoint || '(未提供)')}</div>
    </div>

    ${fullDetail ? `
    <div class="card" style="padding:14px;margin-bottom:12px">
      <div style="font-size:12px;font-weight:600;margin-bottom:6px">📝 ${t('完整详情（节点提供 + 已验证）')}</div>
      <pre style="font-size:11px;color:#374151;background:#f9fafb;padding:8px;border-radius:6px;overflow-x:auto;white-space:pre-wrap">${escHtml(JSON.stringify(fullDetail, null, 2))}</pre>
    </div>` : `
    <div class="card" style="padding:14px;margin-bottom:12px;background:#fafafa;color:#9ca3af;text-align:center">${t('完整详情未能从节点获取 — 仅展示 WebAZ 上的最小信息')}</div>`}

    ${state.user?.role === 'buyer' && p.stock > 0 ? `<button class="btn btn-primary" style="width:100%" onclick="location.hash='#order-product/${p.id}'">${t('购买')} ${p.price} WAZ</button>` : ''}
  `
}

// ─── 价格历史 widget ─────────────────────────────────────────────
const PH_ANOMALY_LABELS = {
  current_below_70pct_median: '⚠ 当前价 < 30 日中位价 70%（可能底价倾销）',
  far_below_category_avg:     '⚠ 远低于同类目均价（< 50%）',
  far_above_category_avg:     '⚠ 远高于同类目均价（> 300%）',
}

async function loadPriceHistory(productId) {
  const el = document.getElementById('ph-' + productId)
  if (!el || el.dataset.loaded === '1') return
  el.dataset.loaded = '1'
  const r = await GET('/products/' + encodeURIComponent(productId) + '/price-history')
  el.innerHTML = renderPriceHistoryHtml(r)
}

function renderPriceHistoryHtml(r) {
  if (r?.error) return alert$('error', r.error)
  if (r?.insufficient_data) {
    return `<div style="text-align:center;color:#9ca3af;padding:24px;font-size:12px">${t('数据不足')} (${r.lifetime_sales}/${r.min_sample} ${t('单')}) · ${t('待累积更多成交后展示统计')}</div>`
  }
  const w = r.windows
  const fmtPrice = (n) => n ? Number(n).toFixed(2) : '—'

  // 价位分布柱状图
  const maxBucketCount = Math.max(...r.price_buckets.map(b => b.count), 1)
  const bucketsHtml = r.price_buckets.map(b => `
    <div style="display:flex;align-items:center;gap:6px;margin-bottom:3px">
      <div style="width:50px;text-align:right;font-size:11px;color:#374151">${fmtPrice(b.price)}</div>
      <div style="flex:1;background:#f3f4f6;border-radius:3px;overflow:hidden;height:14px;position:relative">
        <div style="background:linear-gradient(90deg,#4f46e5,#7c3aed);height:100%;width:${(b.count / maxBucketCount * 100).toFixed(0)}%"></div>
      </div>
      <div style="width:60px;font-size:10px;color:#6b7280">${b.count}${t('单')} · ${b.pct}%</div>
    </div>
  `).join('')

  // 30 日日均 sparkline（用 SVG）— P1 fix：跳过 avg=null 的单日（隐私保护）
  let sparkline = ''
  const dailyWithAvg = r.daily_avg.filter(d => d.avg != null)
  if (dailyWithAvg.length > 1) {
    const maxAvg = Math.max(...dailyWithAvg.map(d => d.avg))
    const minAvg = Math.min(...dailyWithAvg.map(d => d.avg))
    const range = maxAvg - minAvg || 1
    const W = 280, H = 50
    const points = dailyWithAvg.map((d, i) => {
      const x = (i / (dailyWithAvg.length - 1)) * W
      const y = H - ((d.avg - minAvg) / range) * (H - 4) - 2
      return `${x.toFixed(1)},${y.toFixed(1)}`
    }).join(' ')
    sparkline = `<svg viewBox="0 0 ${W} ${H}" width="100%" height="${H}" preserveAspectRatio="none"><polyline points="${points}" fill="none" stroke="#4f46e5" stroke-width="2"/></svg>`
  }

  const flagsHtml = (r.anomaly_flags || []).map(f => `<div style="background:#fef3c7;color:#92400e;padding:8px;border-radius:6px;font-size:12px;margin-bottom:6px">${t(PH_ANOMALY_LABELS[f] || f)}</div>`).join('')

  const windowCard = (label, data) => `
    <div style="flex:1;background:#fafafa;padding:8px;border-radius:6px;text-align:center">
      <div style="font-size:10px;color:#6b7280;margin-bottom:2px">${label}</div>
      <div style="font-size:13px;font-weight:600">${fmtPrice(data.avg)} <span style="font-size:9px;color:#9ca3af">${t('均价')}</span></div>
      <div style="font-size:10px;color:#6b7280;margin-top:2px">${data.sales}${t('单')} · ${fmtPrice(data.volume)} WAZ</div>
    </div>`

  return `
    ${flagsHtml}
    <div style="display:flex;gap:6px;margin-bottom:10px">
      ${windowCard(t('近 30 天'), w.d30)}
      ${windowCard(t('近 90 天'), w.d90)}
      ${windowCard(t('全部'), w.lifetime)}
    </div>
    ${r.category_avg_30d != null ? `<div style="font-size:11px;color:#6b7280;margin-bottom:10px">${t('同类目 30 天均价')}：<strong style="color:#374151">${fmtPrice(r.category_avg_30d)} WAZ</strong>${r.current_price && r.category_avg_30d ? ` · ${t('当前')}${r.current_price > r.category_avg_30d ? '↑' : '↓'}${(Math.abs((r.current_price - r.category_avg_30d) / r.category_avg_30d) * 100).toFixed(0)}%` : ''}</div>` :
      `<div style="font-size:11px;color:#9ca3af;margin-bottom:10px;font-style:italic">${t('未设置具体类目 — 无同类对比（卖家可在商品编辑页选择类目）')}</div>`}
    <div style="font-size:11px;color:#374151;margin-bottom:6px;font-weight:600">${t('价位分布')}（${t('90 天，按成交单数')}）</div>
    ${bucketsHtml}
    ${sparkline ? `<div style="margin-top:14px"><div style="font-size:11px;color:#374151;margin-bottom:4px;font-weight:600">${t('30 日日均价走势')}</div>${sparkline}<div style="display:flex;justify-content:space-between;font-size:10px;color:#9ca3af;margin-top:2px"><span>${r.daily_avg[0].date.slice(5)}</span><span>${r.daily_avg[r.daily_avg.length-1].date.slice(5)}</span></div></div>` : ''}
    <div style="margin-top:10px;font-size:10px;color:#9ca3af;line-height:1.5">📈 p25=${fmtPrice(w.d30.p25)} · ${t('中位')}=${fmtPrice(w.d30.median)} · p75=${fmtPrice(w.d30.p75)}（${t('30 天')}）</div>
  `
}

