// === #admin/wish-reports 慈善举报审核 ===
async function renderAdminWishReports(app) {
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin-content'); return }
  app.innerHTML = shell(loading$(), 'admin-content')
  const status = state._wrStatus || 'pending'
  const r = await GET('/admin/wish-reports?status=' + status).catch(() => ({ items: [] }))
  const items = r?.items || []
  const chipBtn = (k, label) => {
    const on = status === k
    return `<button onclick="setWrStatus('${k}')" style="padding:5px 12px;border-radius:99px;font-size:11px;border:1px solid ${on?'#4f46e5':'#e5e7eb'};background:${on?'#4f46e5':'#fff'};color:${on?'#fff':'#374151'};cursor:pointer;font-weight:${on?'600':'400'}">${label}</button>`
  }
  app.innerHTML = shell(`
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
      <button class="btn btn-gray btn-sm" style="width:auto;font-size:11px" onclick="history.back()">←</button>
      <h1 class="page-title" style="margin:0">🌸 ${t('慈善举报审核')}</h1>
    </div>
    <div style="font-size:11px;color:#6b7280;margin-bottom:14px">${t('3 个不同举报人 → 自动 status=disputed 隐藏；admin 可手动驳回或下架')}</div>
    <div style="display:flex;gap:6px;margin-bottom:14px">
      ${chipBtn('pending', t('待处理'))}
      ${chipBtn('dismissed', t('已驳回'))}
      ${chipBtn('actioned', t('已下架'))}
      ${chipBtn('all', t('全部'))}
    </div>
    ${items.length === 0 ? `<div style="text-align:center;color:#9ca3af;padding:40px 0">${t('暂无举报')}</div>` : items.map(r => `
      <div class="card" style="padding:12px;margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px">
          <div style="flex:1;min-width:0">
            <div style="font-weight:600;font-size:13px;cursor:pointer;color:#4f46e5" onclick="location.hash='#wish/${r.wish_id}'">「${escHtml(r.wish_title)}」</div>
            <div style="font-size:10px;color:#6b7280;margin-top:2px">${t('原因')}: ${escHtml(r.reason)} · @${escHtml(r.reporter_handle || r.reporter_id)} · ${fmtTime(r.created_at)}</div>
            ${r.note ? `<div style="font-size:11px;color:#374151;margin-top:6px;background:#f9fafb;padding:6px 8px;border-radius:6px">${escHtml(r.note)}</div>` : ''}
            <div style="font-size:10px;margin-top:4px;color:${r.wish_status === 'disputed' ? '#dc2626' : '#9ca3af'}">${t('愿望状态')}: ${escHtml(r.wish_status)}</div>
          </div>
          <div style="font-size:10px;padding:2px 8px;border-radius:99px;background:${r.status==='pending'?'#fef3c7':r.status==='dismissed'?'#f3f4f6':'#fee2e2'};color:${r.status==='pending'?'#92400e':r.status==='dismissed'?'#6b7280':'#991b1b'}">${r.status}</div>
        </div>
        ${r.status === 'pending' ? `
          <div style="display:flex;gap:6px;margin-top:8px">
            <button class="btn btn-outline btn-sm" style="flex:1" onclick="adminWrAction('${r.id}','dismiss')">${t('驳回')}</button>
            <button class="btn btn-primary btn-sm" style="flex:1;background:#dc2626" onclick="adminTakedownWish('${r.wish_id}','${r.id}')">${t('强制下架愿望')}</button>
          </div>` : ''}
      </div>
    `).join('')}
  `, 'admin-content')
}
window.setWrStatus = (s) => { state._wrStatus = s; renderAdminWishReports(document.getElementById('app')) }
window.adminWrAction = async (id, action) => {
  if (!confirm(t('确认') + (action === 'dismiss' ? t('驳回') : t('下架')) + t('？'))) return
  const r = await PATCH('/admin/wish-reports/' + id, { action })
  if (r?.error) return alert(r.error)
  renderAdminWishReports(document.getElementById('app'))
}
window.adminTakedownWish = async (wishId, reportId) => {
  const reason = prompt(t('下架原因（必填，会写入审计 + 通知）'))
  if (!reason?.trim()) return
  const r = await POST(`/admin/wishes/${wishId}/takedown`, { reason })
  if (r?.error) return alert(r.error)
  await PATCH('/admin/wish-reports/' + reportId, { action: 'actioned' })
  renderAdminWishReports(document.getElementById('app'))
}

// === #admin/manage-admins 内部账号管理（admin/verifier/logistics/arbitrator 统一创建/撤销）===
async function renderAdminManageAdmins(app) {
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin-users'); return }
  // 客户端守门 — regional admin 不该看到此页（服务端 requireRootAdmin 已守门，此处避免 UI 误导）
  if ((state.user.admin_type || 'root') !== 'root') {
    app.innerHTML = shell(`
      <div class="card" style="padding:20px;text-align:center">
        <div style="font-size:48px;margin-bottom:10px">🔱</div>
        <h2 style="font-size:16px;margin:0 0 8px">${t('仅根管理员可访问')}</h2>
        <div style="font-size:13px;color:#6b7280;line-height:1.6;margin-bottom:14px">
          ${t('区域管理员不能创建 / 编辑 / 管理其他 admin。')}<br>
          ${t('如需扩展权限，请联系 root 管理员。')}
        </div>
        <button class="btn btn-outline" style="width:auto" onclick="location.hash='#admin'">← ${t('返回概览')}</button>
      </div>
    `, 'admin-users')
    return
  }
  app.innerHTML = shell(loading$(), 'admin-users')
  const r = await GET('/admin/admins')
  const items = r?.items || []
  const myType = r?.my_type || 'root'
  const myScope = r?.my_scope || 'global'
  const isRoot = myType === 'root'
  const scopeLabel = { global:'🌐 全球', china:'🇨🇳 中国', us:'🇺🇸 美国', eu:'🇪🇺 欧盟', india:'🇮🇳 印度', singapore:'🇸🇬 新加坡', global_north:'🌏 其他发达' }

  // 权限维度 emoji 映射
  const permIcon = { all:'⭐', users:'👥', content:'📦', arbitration:'⚖', protocol:'⚛', verifier_mgmt:'🔍' }
  // 紧凑行式 admin 列表
  const adminRow = (u) => {
    const perms = Array.isArray(u.admin_permissions) ? u.admin_permissions : []
    return `
    <div style="display:flex;align-items:center;gap:8px;padding:10px 12px;border-bottom:1px solid #f3f4f6">
      <span style="font-size:18px;flex-shrink:0">🛡</span>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;display:flex;align-items:center;gap:6px;flex-wrap:wrap">
          <span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(u.name)}</span>
          ${u.admin_type === 'root' ? '<span style="background:#fee2e2;color:#991b1b;font-size:10px;padding:1px 7px;border-radius:99px;font-weight:600">🔱 ROOT</span>' : '<span style="background:#dbeafe;color:#1e40af;font-size:10px;padding:1px 7px;border-radius:99px;font-weight:600">🌏 REGIONAL</span>'}
          <span style="background:#f3f4f6;color:#6b7280;font-size:10px;padding:1px 7px;border-radius:99px">${t(scopeLabel[u.admin_scope] || u.admin_scope || 'global')}</span>
        </div>
        ${perms.length > 0 ? `<div style="display:flex;gap:4px;flex-wrap:wrap;margin-top:4px">
          ${perms.map(p => `<span style="background:#eef2ff;color:#3730a3;font-size:9px;padding:1px 6px;border-radius:99px;font-weight:500" title="${p}">${permIcon[p] || '·'} ${p}</span>`).join('')}
        </div>` : ''}
        <div style="font-size:10px;color:#9ca3af;margin-top:2px;font-family:monospace">${u.id}${u.email ? ' · ' + escHtml(u.email) : ''}</div>
        <div style="font-size:9px;color:#9ca3af;margin-top:1px">${t('创建于')} ${u.created_at}${u.last_action_at ? ' · ' + t('最近操作') + ' ' + u.last_action_at : ''}</div>
      </div>
      ${isRoot && u.id !== state.user?.id ? `
        <button onclick="revokeAdmin('${u.id}','${escHtml(u.name)}')" style="background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;padding:4px 10px;border-radius:6px;font-size:10px;cursor:pointer;flex-shrink:0">${t('撤销')}</button>
      ` : (u.id === state.user?.id ? `<span style="font-size:9px;color:#9ca3af;flex-shrink:0">${t('当前账户')}</span>` : '')}
    </div>
    `
  }

  app.innerHTML = shell(`
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
      <button class="btn btn-gray btn-sm" style="width:auto;font-size:11px" onclick="history.back()">←</button>
      <h1 class="page-title" style="margin:0">🛡 ${t('内部账号管理')}</h1>
    </div>
    <div style="font-size:11px;color:#6b7280;margin-bottom:14px;line-height:1.6">
      ${t('创建 / 撤销 admin / verifier / logistics / arbitrator 等内部角色账号')}<br>
      <span style="font-size:11px;color:#3730a3;font-weight:600">${t('我的身份')}: ${myType === 'root' ? '🔱 ROOT' : '🌏 REGIONAL'} · ${t(scopeLabel[myScope] || myScope)}</span>
    </div>

    <!-- 统一创建表单 -->
    <div class="card" style="padding:14px;margin-bottom:14px;background:linear-gradient(135deg,#eef2ff,#faf5ff);border-color:#c7d2fe">
      <div style="font-size:13px;font-weight:600;color:#3730a3;margin-bottom:10px">+ ${t('创建内部账号')}</div>

      <div style="margin-bottom:8px">
        <label style="font-size:11px;color:#6b7280">${t('账号类型')}</label>
        <select id="staff-type" onchange="onStaffTypeChange()" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px">
          ${isRoot ? '<option value="admin">🛡 ' + t('管理员') + ' (admin)</option>' : ''}
          <option value="verifier" ${!isRoot?'selected':''}>🔍 ${t('审核员')} (verifier)</option>
          <option value="logistics">🚚 ${t('物流')} (logistics)</option>
          <option value="arbitrator">⚖ ${t('仲裁员')} (arbitrator)</option>
        </select>
      </div>

      <div style="margin-bottom:8px">
        <label style="font-size:11px;color:#6b7280">${t('目标用户 ID')} <span style="color:#9ca3af">(${t('该用户不能持有 buyer/seller 角色')})</span></label>
        <input id="staff-uid" placeholder="usr_xxx" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px;font-family:monospace">
      </div>

      <!-- admin 专属字段（默认隐藏，type=admin 时显示）-->
      <div id="staff-admin-fields" style="display:${isRoot ? 'block' : 'none'};margin-bottom:8px">
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px">
          <div>
            <label style="font-size:11px;color:#6b7280">${t('管理员类型')}</label>
            <select id="ca-type" onchange="onAdminTypeChange()" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px">
              <option value="regional">🌏 ${t('区域管理员')}</option>
              <option value="root">🔱 ${t('根管理员')}</option>
            </select>
          </div>
          <div>
            <label style="font-size:11px;color:#6b7280">${t('管辖区域')}</label>
            <select id="ca-scope" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px">
              <option value="global">🌐 ${t('全球')}</option>
              <option value="china">🇨🇳 ${t('中国')}</option>
              <option value="us">🇺🇸 ${t('美国')}</option>
              <option value="eu">🇪🇺 ${t('欧盟')}</option>
              <option value="india">🇮🇳 ${t('印度')}</option>
              <option value="singapore">🇸🇬 ${t('新加坡')}</option>
              <option value="global_north">🌏 ${t('其他发达地区')}</option>
            </select>
          </div>
        </div>
        <!-- 权限维度（仅 regional 显示；root 隐式 = all）-->
        <div id="ca-perms-wrap">
          <label style="font-size:11px;color:#6b7280">${t('权限维度')} <span style="color:#9ca3af">(${t('regional 可勾选；root 隐式全权')})</span></label>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;margin-top:6px;padding:8px;background:#f9fafb;border-radius:6px">
            <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer">
              <input type="checkbox" class="ca-perm" value="all" onchange="onPermAllChange(this)"> ⭐ ${t('全权')} (all)
            </label>
            <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer">
              <input type="checkbox" class="ca-perm" value="users" checked> 👥 ${t('用户管理')}
            </label>
            <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer">
              <input type="checkbox" class="ca-perm" value="content"> 📦 ${t('内容管理')}
            </label>
            <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer">
              <input type="checkbox" class="ca-perm" value="arbitration"> ⚖ ${t('仲裁审核')}
            </label>
            <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer">
              <input type="checkbox" class="ca-perm" value="protocol"> ⚛ ${t('协议管理')}
            </label>
            <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer">
              <input type="checkbox" class="ca-perm" value="verifier_mgmt"> 🔍 ${t('审核员系统')}
            </label>
          </div>
        </div>
      </div>

      <button class="btn btn-primary" onclick="createInternalStaff()" style="width:100%">${t('创建账号')}</button>
      ${!isRoot ? `<div style="font-size:10px;color:#9ca3af;margin-top:6px">${t('Regional admin 不可创建 admin；如需请联系 root')}</div>` : ''}
    </div>

    <!-- 当前管理员列表 -->
    <div style="font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px">🛡 ${t('管理员列表')} (${items.length})</div>
    <div class="card" style="padding:0;overflow:hidden;margin-bottom:14px">
      ${items.length === 0 ? `<div style="text-align:center;color:#9ca3af;padding:30px 0">${t('暂无 admin')}</div>` : items.map(adminRow).join('')}
    </div>

    <!-- 跳转到其他内部角色 — 物流是外部服务角色，不在此列；只保留审核员 + 仲裁员 -->
    <div style="font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px">${t('其他内部角色')}</div>
    <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px">
      <div onclick="gotoInternalRole('verifier')" class="card" style="padding:12px;text-align:center;cursor:pointer">
        <div style="font-size:20px">🔍</div>
        <div style="font-size:11px;margin-top:4px">${t('审核员')}</div>
        <div style="font-size:9px;color:#9ca3af;margin-top:2px">${t('查看 / 管理')}</div>
      </div>
      <div onclick="gotoInternalRole('arbitrator')" class="card" style="padding:12px;text-align:center;cursor:pointer">
        <div style="font-size:20px">⚖</div>
        <div style="font-size:11px;margin-top:4px">${t('仲裁员')}</div>
        <div style="font-size:9px;color:#9ca3af;margin-top:2px">${t('查看 / 管理')}</div>
      </div>
    </div>
  `, 'admin-users')
  // 初始化字段状态
  if (typeof window.onStaffTypeChange === 'function') window.onStaffTypeChange()
}

window.onStaffTypeChange = () => {
  const type = document.getElementById('staff-type')?.value
  const adminFields = document.getElementById('staff-admin-fields')
  if (adminFields) adminFields.style.display = type === 'admin' ? 'block' : 'none'
}

// 跳转到内部角色列表（提前设 state.filter 后导航；renderAdminUsers 会读取）
window.gotoInternalRole = (role) => {
  state._adminUserType = 'internal'
  state._adminUserRole = role
  state._adminUserRegion = ''   // 清区域筛选
  location.hash = '#admin/users'
}

window.onAdminTypeChange = () => {
  const adminType = document.getElementById('ca-type')?.value
  const permsWrap = document.getElementById('ca-perms-wrap')
  // root admin 隐式 all，权限选项隐藏
  if (permsWrap) permsWrap.style.display = adminType === 'root' ? 'none' : 'block'
}
window.onPermAllChange = (cb) => {
  // 勾选 all 时，自动取消其他；勾其他时自动取消 all
  if (cb.value === 'all' && cb.checked) {
    document.querySelectorAll('.ca-perm').forEach(c => { if (c.value !== 'all') c.checked = false })
  }
}
window.createInternalStaff = async () => {
  const type = document.getElementById('staff-type').value
  const user_id = document.getElementById('staff-uid').value.trim()
  if (!user_id) return alert(t('请填写用户 ID'))
  if (type === 'admin') {
    const admin_type = document.getElementById('ca-type').value
    const admin_scope = document.getElementById('ca-scope').value
    let admin_permissions = []
    if (admin_type === 'regional') {
      admin_permissions = [...document.querySelectorAll('.ca-perm:checked')].map(cb => cb.value)
      if (admin_permissions.length === 0) return alert(t('regional admin 必须至少勾选一项权限'))
      // 勾了 all 就只保留 all
      if (admin_permissions.includes('all')) admin_permissions = ['all']
    }
    const permsLabel = admin_type === 'root' ? '⭐ ALL（root 隐式）' : admin_permissions.join('/')
    if (!confirm(t('确认授予 ') + user_id + t(' 为 ') + (admin_type === 'root' ? 'ROOT' : 'REGIONAL') + ' · ' + admin_scope + ' · ' + permsLabel + '?')) return
    const r = await POST('/admin/admins', { user_id, admin_type, admin_scope, admin_permissions })
    if (r?.error) return alert(r.error)
    alert(t('管理员已创建') + ' · ' + r.user_id)
  } else {
    if (!['verifier','logistics','arbitrator'].includes(type)) return alert(t('类型无效'))
    if (!confirm(t('确认授予 ') + user_id + t(' 为 ') + type + ' ?')) return
    const r = await POST(`/admin/users/${user_id}/grant-role`, { role: type })
    if (r?.error) return alert(r.error)
    alert(t('角色已授予') + ' · ' + type)
  }
  renderAdminManageAdmins(document.getElementById('app'))
}

window.revokeAdmin = async (uid, name) => {
  if (!confirm(t('确认撤销 ') + name + t(' 的 admin 权限？该用户将回到默认角色'))) return
  const r = await DELETE(`/admin/admins/${uid}`)
  if (r?.error) return alert(r.error)
  alert(t('已撤销'))
  renderAdminManageAdmins(document.getElementById('app'))
}

// === #admin/fund-disburse 慈善基金拨款 ===
async function renderAdminFundDisburse(app) {
  if (!isAdmin()) { app.innerHTML = shell(`<div class="alert alert-info">${t('仅限管理员')}</div>`, 'admin-protocol'); return }
  app.innerHTML = shell(loading$(), 'admin-protocol')
  const fundRes = await GET('/admin/charity/fund').catch(() => ({ fund: { balance: 0 } }))
  const fund = fundRes?.fund || { balance: 0, total_donated: 0, total_disbursed: 0, total_redirected: 0 }
  const recent = fundRes?.recent || []
  app.innerHTML = shell(`
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
      <button class="btn btn-gray btn-sm" style="width:auto;font-size:11px" onclick="history.back()">←</button>
      <h1 class="page-title" style="margin:0">🏦 ${t('慈善基金拨款')}</h1>
    </div>
    <div style="font-size:11px;color:#6b7280;margin-bottom:14px;line-height:1.5">${t('从基金池拨款给指定 user_id；用途必填，写入审计 + 推送通知给收款人')}</div>

    <div class="card" style="padding:14px;margin-bottom:14px;background:linear-gradient(135deg,#fef2f2,#fff7ed)">
      <div style="font-size:11px;color:#9ca3af;text-transform:uppercase">${t('当前基金余额')}</div>
      <div style="font-size:28px;font-weight:800;color:#dc2626;line-height:1.2">${Number(fund.balance).toFixed(2)} <span style="font-size:13px;font-weight:600">WAZ</span></div>
      <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;margin-top:10px;font-size:10px;text-align:center">
        <div><div style="font-size:14px;font-weight:700;color:#9333ea">${Number(fund.total_donated).toFixed(1)}</div><div style="color:#9ca3af">${t('累计捐款')}</div></div>
        <div><div style="font-size:14px;font-weight:700;color:#ea580c">${Number(fund.total_redirected||0).toFixed(1)}</div><div style="color:#9ca3af">${t('还愿转入')}</div></div>
        <div><div style="font-size:14px;font-weight:700;color:#16a34a">${Number(fund.total_disbursed).toFixed(1)}</div><div style="color:#9ca3af">${t('已拨款')}</div></div>
      </div>
    </div>

    <div class="card" style="padding:14px;margin-bottom:14px">
      <div style="font-size:13px;font-weight:600;color:#374151;margin-bottom:10px">+ ${t('新拨款')}</div>
      <div style="margin-bottom:8px">
        <label style="font-size:11px;color:#6b7280">${t('收款用户 ID')}</label>
        <input id="fd-user" placeholder="usr_xxx" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px;font-family:monospace">
      </div>
      <div style="margin-bottom:8px">
        <label style="font-size:11px;color:#6b7280">${t('金额 WAZ')}</label>
        <input id="fd-amount" type="number" step="0.01" placeholder="0.00" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:13px">
      </div>
      <div style="margin-bottom:10px">
        <label style="font-size:11px;color:#6b7280">${t('用途（必填，写入审计）')}</label>
        <textarea id="fd-note" rows="2" placeholder="${t('如：医疗救助拨款 - 对应 #wish/xxx')}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px;resize:vertical"></textarea>
      </div>
      <button class="btn btn-primary" onclick="doFundDisburse()" style="width:100%;background:#dc2626">${t('确认拨款')}</button>
    </div>

    <div style="font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px">${t('最近 100 条流水')}</div>
    ${recent.slice(0, 30).map(tx => `
      <div class="card" style="padding:10px;margin-bottom:6px">
        <div style="display:flex;justify-content:space-between;align-items:center">
          <div style="font-size:12px;font-weight:600">${tx.kind === 'donation' ? '💝 ' + t('捐款') : tx.kind === 'repay_redirect' ? '🙏 ' + t('还愿转入') : '🤲 ' + t('拨款')}${tx.from_name ? ' · @' + escHtml(tx.from_name) : ''}${tx.to_name ? ' → @' + escHtml(tx.to_name) : ''}</div>
          <div style="font-size:13px;font-weight:700;color:${tx.kind==='disburse'?'#dc2626':'#16a34a'}">${tx.kind==='disburse'?'−':'+'}${Number(tx.amount).toFixed(2)}</div>
        </div>
        ${tx.note ? `<div style="font-size:11px;color:#6b7280;margin-top:4px">${escHtml(tx.note)}</div>` : ''}
        <div style="font-size:10px;color:#9ca3af;margin-top:4px">${tx.created_at}</div>
      </div>
    `).join('')}
  `, 'admin-protocol')
}
window.doFundDisburse = async () => {
  const to_user_id = document.getElementById('fd-user').value.trim()
  const amount = Number(document.getElementById('fd-amount').value)
  const note = document.getElementById('fd-note').value.trim()
  if (!to_user_id || !amount || !note) return alert(t('请填写完整'))
  if (!confirm(t('确认从基金池拨款 ') + amount + t(' WAZ 给 ') + to_user_id + ' ?')) return
  const r = await POST('/admin/charity/fund/disburse', { to_user_id, amount, note })
  if (r?.error) return alert(r.error)
  alert(t('拨款成功') + ` · +${r.amount} WAZ → ${r.to_user}`)
  renderAdminFundDisburse(document.getElementById('app'))
}

// ─── 📜 全局 Timeline ────────────────────────────────────────
async function renderTimeline(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'me')

  const [ordersRes, notifsRes, charityRes] = await Promise.all([
    GET('/orders').catch(() => []),
    GET('/notifications').catch(() => ({ notifications: [] })),
    GET('/charity/me').catch(() => null),
  ])
  const orders = Array.isArray(ordersRes) ? ordersRes : []
  const notifs = notifsRes?.notifications || []
  const charity = charityRes || {}

  // 聚合事件 — 统一 shape：{ts, icon, color, label, body, route, kind}
  const events = []
  // 订单事件（按状态生成）
  for (const o of orders) {
    const isMine = o.buyer_id === state.user.id
    events.push({
      ts: o.created_at,
      icon: isMine ? '🛒' : '📦',
      color: '#4f46e5',
      label: isMine ? t('下单') : t('收到订单'),
      body: o.product_title + ' · ' + o.total_amount + ' WAZ',
      route: '#order/' + o.id,
      kind: 'order',
    })
    if (o.status === 'completed') {
      events.push({
        ts: o.updated_at || o.created_at,
        icon: '✅', color: '#16a34a',
        label: t('订单完成'),
        body: o.product_title,
        route: '#order/' + o.id,
        kind: 'order',
      })
    }
  }
  // 通知事件
  for (const n of notifs) {
    const route = n.wish_id ? '#wish/' + n.wish_id : n.order_id ? '#order/' + n.order_id : ''
    events.push({
      ts: n.created_at,
      icon: '🔔', color: n.read ? '#9ca3af' : '#dc2626',
      label: n.title || t('通知'),
      body: n.body || '',
      route,
      kind: 'notification',
    })
  }
  // 慈善事件（我的愿望 + 圆梦）
  for (const w of (charity.my_wishes || [])) {
    events.push({
      ts: w.created_at,
      icon: '🌸', color: '#dc2626',
      label: t('我发布愿望'),
      body: w.title,
      route: '#wish/' + w.id,
      kind: 'charity',
    })
  }
  for (const f of (charity.my_fulfillments || [])) {
    if (f.completed_at) events.push({
      ts: f.completed_at,
      icon: '🤝', color: '#16a34a',
      label: t('我圆梦'),
      body: f.title,
      route: '#wish/' + f.id,
      kind: 'charity',
    })
  }

  // 时间倒序排
  events.sort((a, b) => (b.ts || '').localeCompare(a.ts || ''))

  // chip 筛选
  const filter = state._timelineFilter || 'all'
  const groups = {
    all:           { label: t('全部'),     match: () => true },
    order:         { label: t('订单'),     match: e => e.kind === 'order' },
    notification:  { label: t('通知'),     match: e => e.kind === 'notification' },
    charity:       { label: t('慈善'),     match: e => e.kind === 'charity' },
  }
  const counts = Object.fromEntries(Object.entries(groups).map(([k, g]) => [k, events.filter(g.match).length]))
  const chips = `<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px">
    ${Object.entries(groups).map(([k, g]) => {
      const on = filter === k
      return `<button onclick="setTimelineFilter('${k}')" style="padding:4px 10px;border-radius:16px;font-size:11px;border:1px solid ${on?'#4f46e5':'#e5e7eb'};background:${on?'#4f46e5':'#fff'};color:${on?'#fff':'#374151'};cursor:pointer;font-weight:${on?'600':'400'}">${g.label} ${counts[k] > 0 ? '(' + counts[k] + ')' : ''}</button>`
    }).join('')}
  </div>`

  const filtered = events.filter(groups[filter].match)
  // P2.3 客户端分页：30/页 + 加载更多
  const pageSize = 30
  const limit = state._timelineLimit || pageSize
  const visible = filtered.slice(0, limit)
  const hasMore = filtered.length > visible.length

  const list = filtered.length === 0
    ? `<div style="text-align:center;color:#9ca3af;padding:40px 0">${t('暂无事件')}</div>`
    : visible.map(e => `
      <div class="card" style="padding:10px;margin-bottom:8px;display:flex;gap:10px;cursor:${e.route?'pointer':'default'}" ${e.route ? `onclick="navigate('${e.route}')"` : ''}>
        <div style="font-size:18px;flex-shrink:0">${e.icon}</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:600;color:${e.color}">${escHtml(e.label)}</div>
          ${e.body ? `<div style="font-size:11px;color:#374151;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(e.body)}</div>` : ''}
          <div style="font-size:10px;color:#9ca3af;margin-top:2px">${fmtTime(e.ts)}</div>
        </div>
      </div>
    `).join('') + (hasMore ? `
      <div style="text-align:center;margin-top:10px">
        <button onclick="loadMoreTimeline()" style="background:#fff;border:1px solid #e5e7eb;color:#4f46e5;padding:8px 20px;border-radius:8px;font-size:12px;cursor:pointer">${t('加载更多')} (${filtered.length - visible.length})</button>
      </div>` : `<div style="text-align:center;color:#9ca3af;padding:14px 0;font-size:11px">${t('共 ')}${filtered.length}${t(' 条')}</div>`)

  app.innerHTML = shell(`
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
      <button class="btn btn-gray btn-sm" style="width:auto;font-size:11px" onclick="history.back()">←</button>
      <h1 class="page-title" style="margin:0">📜 ${t('Timeline')}</h1>
    </div>
    <div style="font-size:11px;color:#6b7280;margin-bottom:14px;line-height:1.5">${t('全部事件按时间排列 — 订单 / 通知 / 慈善')}</div>
    ${chips}
    ${list}
  `, 'me')
}
window.loadMoreTimeline = () => {
  state._timelineLimit = (state._timelineLimit || 30) + 30
  renderTimeline(document.getElementById('app'))
}
window.setTimelineFilter = (k) => {
  state._timelineFilter = k
  state._timelineLimit = 30   // 切 chip 时重置分页
  renderTimeline(document.getElementById('app'))
}

// ─── 📡 Webhook 订阅中心 ────────────────────────────────────────
async function renderWebhooks(app) {
  if (!state.user) { renderLogin(); return }
  app.innerHTML = shell(loading$(), 'me')
  const r = await GET('/webhooks')
  const items = r?.items || []
  const types = r?.event_types || []

  const itemRow = (h) => `
    <div class="card" style="padding:12px;margin-bottom:8px;${h.active ? '' : 'opacity:0.5'}">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
        <div style="flex:1;min-width:0">
          <div style="font-weight:600;font-size:13px">${escHtml(h.event_type)}</div>
          <div style="font-size:11px;color:#6b7280;margin-top:2px;word-break:break-all">${escHtml(h.target_url)}</div>
          <div style="font-size:10px;color:#9ca3af;margin-top:4px">
            🔥 ${h.fire_count || 0} ${h.fail_count > 0 ? ' · ❌ ' + h.fail_count : ''}
            ${h.last_fired_at ? ' · ' + t('最近') + ' ' + h.last_fired_at : ''}
          </div>
          ${h.last_error ? `<div style="font-size:10px;color:#dc2626;margin-top:2px">⚠ ${escHtml(h.last_error)}</div>` : ''}
        </div>
        <div style="display:flex;flex-direction:column;gap:4px">
          <button onclick="toggleWebhook('${h.id}', ${h.active ? 0 : 1})" style="background:none;border:1px solid #e5e7eb;padding:3px 10px;border-radius:6px;font-size:10px;cursor:pointer;color:#6b7280">${h.active ? t('暂停') : t('启用')}</button>
          <button onclick="deleteWebhook('${h.id}')" style="background:none;border:1px solid #fecaca;padding:3px 10px;border-radius:6px;font-size:10px;cursor:pointer;color:#dc2626">${t('删除')}</button>
        </div>
      </div>
    </div>
  `

  app.innerHTML = shell(`
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
      <button class="btn btn-gray btn-sm" style="width:auto;font-size:11px" onclick="history.back()">←</button>
      <h1 class="page-title" style="margin:0">📡 ${t('Webhook 订阅')}</h1>
    </div>
    <div style="font-size:11px;color:#6b7280;margin-bottom:12px;line-height:1.5">${t('订阅事件 → 推送到你的 endpoint。Agent / 自建系统可实时接收。')}</div>

    <div class="card" style="padding:14px;margin-bottom:14px;background:linear-gradient(135deg,#eef2ff,#faf5ff)">
      <div style="font-size:13px;font-weight:600;color:#3730a3;margin-bottom:10px">+ ${t('新增订阅')}</div>
      <div style="margin-bottom:8px">
        <label style="font-size:11px;color:#6b7280">${t('事件类型')}</label>
        <select id="wh-event" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px">
          ${types.map(et => `<option value="${et}">${et}</option>`).join('')}
        </select>
      </div>
      <div style="margin-bottom:8px">
        <label style="font-size:11px;color:#6b7280">${t('目标 URL（必须 https://）')}</label>
        <input id="wh-url" placeholder="https://my-agent.example.com/webhook" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px">
      </div>
      <div style="margin-bottom:10px">
        <label style="font-size:11px;color:#6b7280">${t('共享密钥 (可空) — 用于 HMAC 签名 X-WebAZ-Signature')}</label>
        <input id="wh-secret" placeholder="${t('可空；填了就会签名')}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;margin-top:4px;font-size:12px">
      </div>
      <div id="wh-test-result" style="font-size:11px;margin-bottom:8px"></div>
      <div style="display:flex;gap:6px">
        <button class="btn btn-outline btn-sm" onclick="testWebhook()" style="flex:1">🧪 ${t('测试连通')}</button>
        <button class="btn btn-primary btn-sm" onclick="createWebhook()" style="flex:1">${t('订阅')}</button>
      </div>
    </div>

    <div style="font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px">${t('我的订阅')} (${items.length}/20)</div>
    ${items.length === 0 ? `<div style="text-align:center;color:#9ca3af;padding:30px 0">${t('暂无订阅')}</div>` : items.map(itemRow).join('')}
  `, 'me')
}

window.testWebhook = async () => {
  const target_url = document.getElementById('wh-url')?.value?.trim()
  const secret = document.getElementById('wh-secret')?.value?.trim() || null
  const out = document.getElementById('wh-test-result')
  if (!target_url) { if (out) out.innerHTML = `<div style="color:#dc2626">⚠ ${t('请填写 URL')}</div>`; return }
  if (out) out.innerHTML = `<div style="color:#6b7280">⏳ ${t('测试中...')}</div>`
  const r = await POST('/webhooks/test', { target_url, secret })
  if (r?.ok) {
    if (out) out.innerHTML = `<div style="color:#16a34a">✓ ${t('连通成功')} · HTTP ${r.status} · ${r.ms}ms</div>`
  } else {
    if (out) out.innerHTML = `<div style="color:#dc2626">✗ ${t('连通失败')}: ${escHtml(r?.error || '未知错误')}</div>`
  }
}

window.createWebhook = async () => {
  const event_type = document.getElementById('wh-event')?.value
  const target_url = document.getElementById('wh-url')?.value?.trim()
  const secret = document.getElementById('wh-secret')?.value?.trim() || null
  if (!target_url) return alert(t('请填写 URL'))
  const r = await POST('/webhooks', { event_type, target_url, secret })
  if (r?.error) return alert(r.error)
  alert(t('订阅已创建'))
  renderWebhooks(document.getElementById('app'))
}
window.toggleWebhook = async (id, active) => {
  const r = await PATCH(`/webhooks/${id}`, { active })
  if (r?.error) return alert(r.error)
  renderWebhooks(document.getElementById('app'))
}
window.deleteWebhook = async (id) => {
  if (!confirm(t('确认删除此订阅？'))) return
  const r = await DELETE(`/webhooks/${id}`)
  if (r?.error) return alert(r.error)
  renderWebhooks(document.getElementById('app'))
}

// ─── 慈善许愿池 ────────────────────────────────────────────────
const CHARITY_CAT_ICON = { medical:'🏥', education:'📚', daily:'🍚', elderly:'👴', disaster:'🌊', tech:'💻', other:'🎁' }
const CHARITY_BADGE = { none:'', bronze:'🥉', silver:'🥈', gold:'🥇', diamond:'💎' }
const CHARITY_KIND_LABEL = () => ({ item: t('实物'), service: t('服务'), cash: t('现金救助') })

function charityCatLabel(k) {
  return t({ medical:'医疗救助', education:'教育求学', daily:'生活物资',
             elderly:'助老', disaster:'灾害互助', tech:'科技/设备', other:'其它' }[k] || k)
}
function charityStatusLabel(s) {
  return t({ open:'待认领', claimed:'圆梦中', completed:'已圆梦', expired:'已过期', cancelled:'已取消', disputed:'争议中' }[s] || s)
}
async function charitySha256(str) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str))
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('')
}

async function renderWishBoard(app) {
  app.innerHTML = shell(`<div id="wish-root">${loading$()}</div>`, 'discover')
  const cat = state._wishCat || ''
  const kind = state._wishKind || ''
  const qs = new URLSearchParams()
  if (cat) qs.set('category', cat)
  if (kind) qs.set('target_kind', kind)
  // 2026-05-24 #974：scoped q
  if (state._wishQ) qs.set('q', state._wishQ)
  // 2026-05-24 P1-12：公开故事板 hero（并行拉取前 3 个故事）
  const [r, storiesRes] = await Promise.all([
    GET('/wishes' + (qs.toString() ? '?' + qs.toString() : '')),
    GET('/charity/stories').catch(() => ({ items: [] })),
  ])
  const items = r?.items || []
  const cats = r?.categories || []
  const stories = (storiesRes?.items || []).slice(0, 3)

  // #957 Tier C：chip 样式与 discover sort chip (indigo) 对齐，跨页统一
  // 慈善红 vibe 由上方 hero 区 (#fdf2f8/#fbcfe8) 保留，filter chip 不再独立用红
  const chip = (val, label, current, fn) =>
    `<button onclick="${fn}('${val}')" style="white-space:nowrap;border:1px solid ${current===val?'#4f46e5':'#e5e7eb'};background:${current===val?'#eef2ff':'#fff'};color:${current===val?'#4f46e5':'#374151'};padding:5px 11px;border-radius:999px;font-size:12px;cursor:pointer;font-weight:${current===val?'600':'400'}">${label}</button>`

  // 2026-05-24 P1-12：hero 故事板（故事先于功能入口）
  const storyHero = stories.length === 0 ? '' : `
    <div style="background:linear-gradient(135deg,#fdf2f8,#fef3c7);border:1px solid #fbcfe8;border-radius:10px;padding:12px;margin-bottom:14px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <div style="font-size:13px;font-weight:700;color:#9d174d">📖 ${t('最近圆梦故事')}</div>
        <a href="#wish/stories" style="font-size:11px;color:#be185d;text-decoration:none">${t('看全部')} →</a>
      </div>
      ${stories.map(s => `
        <div style="background:#fff;border-radius:8px;padding:8px 10px;margin-bottom:6px;cursor:pointer" onclick="navigate('#wish/stories')">
          <div class="line-clamp-1" style="font-size:12px;font-weight:600;color:#374151">💝 ${escHtml(s.title || t('匿名愿望'))}</div>
          ${s.summary ? `<div style="font-size:11px;color:#6b7280;line-height:1.5;margin-top:2px">${escHtml(s.summary.slice(0, 70))}${s.summary.length > 70 ? '…' : ''}</div>` : ''}
        </div>
      `).join('')}
    </div>`

  // 2026-05-24 P1-11：4 二级入口重组为 2x2 + 图标 + 副标题
  const secondaryNav = `
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">
      <a href="#wish/mine" style="display:flex;gap:8px;padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#eef2ff;text-decoration:none;color:inherit">
        <div style="font-size:22px">📂</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:600;color:#4338ca">${t('我的慈善')}</div>
          <div style="font-size:10px;color:#6b7280;line-height:1.4">${t('我许的愿 · 我帮的人')}</div>
        </div>
      </a>
      <a href="#wish/fund" style="display:flex;gap:8px;padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#faf5ff;text-decoration:none;color:inherit">
        <div style="font-size:22px">🏦</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:600;color:#7e22ce">${t('慈善基金')}</div>
          <div style="font-size:10px;color:#6b7280;line-height:1.4">${t('社区池 · 流水公开')}</div>
        </div>
      </a>
      <a href="#wish/stories" style="display:flex;gap:8px;padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#fdf2f8;text-decoration:none;color:inherit">
        <div style="font-size:22px">📖</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:600;color:#be185d">${t('公开故事板')}</div>
          <div style="font-size:10px;color:#6b7280;line-height:1.4">${t('双签同意 · 圆梦记录')}</div>
        </div>
      </a>
      <a href="#wish/leaderboard" style="display:flex;gap:8px;padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#fef3c7;text-decoration:none;color:inherit">
        <div style="font-size:22px">🏆</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:600;color:#92400e">${t('威望榜')}</div>
          <div style="font-size:10px;color:#6b7280;line-height:1.4">${t('善行积分 · 社区认可')}</div>
        </div>
      </a>
    </div>`

  document.getElementById('wish-root').innerHTML = `
    ${renderSmartBuyHeader('wishes')}
    ${discoverMoreTabs('wishes')}
    ${pageHotFeedToggle('#wishes', '#wishes/feed', { hotIcon: '🌸', hotLabel: t('许愿池') })}
    ${simpleHeader('🌸 ' + t('慈善许愿池'),
      t('完全匿名 · 双签锚定 · 双方同意可申请公开'),
      state.user ? [{ icon: '+', label: t('我要许愿'), hash: '#wish/new', primary: true }] : [])}
    ${storyHero}
    ${secondaryNav}
    <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px">
      ${chip('', t('全部类目'), cat, 'setWishCat')}
      ${cats.map(c => chip(c, (CHARITY_CAT_ICON[c]||'') + ' ' + charityCatLabel(c), cat, 'setWishCat')).join('')}
    </div>
    <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px">
      ${chip('', t('全部形式'), kind, 'setWishKind')}
      ${chip('item', t('实物'), kind, 'setWishKind')}
      ${chip('service', t('服务'), kind, 'setWishKind')}
      ${chip('cash', t('现金救助'), kind, 'setWishKind')}
    </div>
    ${items.length === 0 ? emptyState('🌸', t('暂无愿望，做第一个许愿者'), state.user ? { label: t('我要许愿'), hash: '#wish/new' } : null) : items.map(w => `
      <div class="card" style="padding:12px;margin-bottom:8px;cursor:pointer" onclick="location.hash='#wish/${w.id}'">
        <div style="display:flex;gap:8px;align-items:flex-start;margin-bottom:6px">
          <div style="font-size:22px">${CHARITY_CAT_ICON[w.category]||'🎁'}</div>
          <div style="flex:1;min-width:0">
            <div class="line-clamp-2" style="font-weight:600;font-size:14px">${escHtml(w.title)}</div>
            <div class="text-ellipsis" style="font-size:11px;color:#6b7280;margin-top:2px">@${escHtml(w.wisher_handle)} · ${charityCatLabel(w.category)} · ${CHARITY_KIND_LABEL()[w.target_kind]}${w.target_waz ? ' · ' + w.target_waz + ' WAZ' : ''}</div>
          </div>
          <div style="font-size:10px;padding:2px 8px;border-radius:99px;background:${w.status==='open'?'#fef3c7':w.status==='claimed'?'#dbeafe':'#f3f4f6'};color:${w.status==='open'?'#92400e':w.status==='claimed'?'#1e40af':'#6b7280'}">${charityStatusLabel(w.status)}</div>
        </div>
        <div style="font-size:11px;color:#9ca3af;line-height:1.5">${escHtml(w.content_preview)}${w.content_preview && w.content_preview.length >= 120 ? '...' : ''}</div>
      </div>
    `).join('')}
  `
}
window.setWishCat = (v) => { state._wishCat = v; renderWishBoard(document.getElementById('app')) }
window.setWishKind = (v) => { state._wishKind = v; renderWishBoard(document.getElementById('app')) }

// 2026-05-24 慈善许愿 · 动态：新许愿 + 圆梦 + 大额捐款 混合时间线
async function renderWishesFeed(app) {
  app.innerHTML = shell(`<div id="wishes-feed">${loading$()}</div>`, 'discover')
  const q = state._wishQ || ''
  const wishQs = q ? '?q=' + encodeURIComponent(q) : ''
  const [wishesRes, storiesRes, fundRes] = await Promise.all([
    GET('/wishes' + wishQs).catch(() => ({ items: [] })),
    GET('/charity/stories').catch(() => ({ items: [] })),
    GET('/charity/fund').catch(() => ({ recent: [] })),
  ])
  const wishes = (wishesRes?.items || []).slice(0, 15)
  const stories = (storiesRes?.items || []).slice(0, 10)
  const donations = (fundRes?.recent || []).filter(t => t.kind === 'donation').slice(0, 10)

  const events = [
    ...wishes.map(w => ({ kind: 'wish', ts: w.created_at, data: w })),
    ...stories.map(s => ({ kind: 'story', ts: s.disclosed_at || s.created_at, data: s })),
    ...donations.map(d => ({ kind: 'donation', ts: d.created_at, data: d })),
  ].sort((a, b) => (b.ts || '').localeCompare(a.ts || '')).slice(0, 30)

  const body = events.length === 0
    ? feedEmpty('🌸', t('暂无慈善动态'), t('看许愿池'), '#wishes')
    : events.map(e => {
        const d = e.data
        const ts = fmtTime(e.ts)
        if (e.kind === 'wish') {
          return `<div class="card" style="margin-bottom:8px;padding:12px;cursor:pointer" onclick="navigate('#wish/${d.id}')">
            <div style="font-size:13px;line-height:1.5">
              🌸 ${t('新许愿')}：<strong>${escHtml(d.title)}</strong>
              <span style="font-size:11px;color:#9ca3af;margin-left:4px">${CHARITY_CAT_ICON?.[d.category] || ''} ${charityCatLabel?.(d.category) || d.category || ''}</span>
            </div>
            <div style="font-size:11px;color:#6b7280;margin-top:4px">${d.target_kind} ${d.target_waz ? '· ≤' + d.target_waz + ' WAZ' : ''} · ${ts}</div>
          </div>`
        } else if (e.kind === 'story') {
          return `<div class="card" style="margin-bottom:8px;padding:12px;border-left:3px solid #16a34a">
            <div style="font-size:13px;line-height:1.5">
              💝 ${t('愿望已圆')}：<strong>${escHtml(d.title || '匿名愿望')}</strong>
            </div>
            ${d.summary ? `<div style="font-size:11px;color:#6b7280;margin-top:4px">${escHtml(d.summary.slice(0, 80))}${d.summary.length > 80 ? '…' : ''}</div>` : ''}
            <div style="font-size:10px;color:#9ca3af;margin-top:2px">${ts}</div>
          </div>`
        } else {
          return `<div class="card" style="margin-bottom:8px;padding:10px 12px;background:#fef9c3;border-color:#fde047">
            <div style="font-size:12px;color:#854d0e">
              🎁 ${t('新捐款')} <strong>${Number(d.amount).toFixed(2)} WAZ</strong>${d.donor_handle ? ' · @' + escHtml(d.donor_handle) : ''}
            </div>
            <div style="font-size:10px;color:#9ca3af;margin-top:2px">${ts}</div>
          </div>`
        }
      }).join('')

  document.getElementById('wishes-feed').innerHTML = `
    ${renderSmartBuyHeader('wishes')}
    ${discoverMoreTabs('wishes')}
    ${pageHotFeedToggle('#wishes', '#wishes/feed', { hotIcon: '🌸', hotLabel: t('许愿池') })}
    <h2 style="font-size:16px;font-weight:700;margin:14px 0 10px">📡 ${t('慈善动态')}</h2>
    <div style="font-size:11px;color:#6b7280;margin-bottom:14px">${t('新许愿 / 圆梦 / 捐款 · 按时间倒序')}</div>
    ${body}
  `
}

async function renderWishCreate(app) {
  app.innerHTML = `
    <div style="padding:14px;max-width:560px;margin:0 auto">
      <h2 style="font-size:18px;font-weight:700;margin-bottom:14px">🌸 ${t('我要许愿')}</h2>
      <div class="card" style="padding:14px">
        <div style="font-size:11px;color:#6b7280;margin-bottom:14px;line-height:1.5">${t('你的真实身份不会公开。完成时双方签名锚定，可申请共同公开。')}</div>
        <input id="w-title" placeholder="${t('愿望标题（4-100 字）')}" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:10px;font-size:13px" />
        <textarea id="w-content" placeholder="${t('详细描述（10-1000 字）')}" rows="5" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:10px;font-size:13px;resize:vertical"></textarea>
        <label style="display:block;font-size:11px;color:#6b7280;margin-bottom:4px">${t('类目')}</label>
        <select id="w-cat" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:10px;font-size:13px">
          ${['medical','education','daily','elderly','disaster','tech','other'].map(c => `<option value="${c}">${CHARITY_CAT_ICON[c]} ${charityCatLabel(c)}</option>`).join('')}
        </select>
        <label style="display:block;font-size:11px;color:#6b7280;margin-bottom:4px">${t('需求形式')}</label>
        <select id="w-kind" onchange="document.getElementById('w-cash').style.display=this.value==='cash'?'block':'none'" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:10px;font-size:13px">
          <option value="item">${t('实物')}</option>
          <option value="service">${t('服务')}</option>
          <option value="cash">${t('现金救助')}</option>
        </select>
        <div id="w-cash" style="display:none;margin-bottom:10px">
          <label style="display:block;font-size:11px;color:#6b7280;margin-bottom:4px">${t('金额 WAZ（≤ 500）')}</label>
          <input id="w-amt" type="number" step="0.01" min="1" max="500" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;font-size:13px" />
          <label style="display:flex;gap:6px;align-items:center;margin-top:8px;font-size:11px;color:#6b7280;cursor:pointer">
            <input type="checkbox" id="w-escrow" /> ${t('自我托管（锁仓全额；完成时自动转给施善人）')}
          </label>
        </div>
        <label style="display:block;font-size:11px;color:#6b7280;margin-bottom:4px">${t('有效期（小时，24-720）')}</label>
        <input id="w-hours" type="number" value="168" min="24" max="720" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:10px;font-size:13px" />
        <label style="display:flex;gap:6px;align-items:center;margin-bottom:14px;font-size:11px;color:#6b7280;cursor:pointer">
          <input type="checkbox" id="w-public" /> ${t('我接受双方同意后公开本愿')}
        </label>
        <button class="btn btn-primary" onclick="submitWish()" style="width:100%">${t('许愿')}</button>
      </div>
    </div>
  `
}
window.submitWish = async () => {
  const body = {
    title: document.getElementById('w-title').value.trim(),
    content: document.getElementById('w-content').value.trim(),
    category: document.getElementById('w-cat').value,
    target_kind: document.getElementById('w-kind').value,
    window_hours: Number(document.getElementById('w-hours').value),
    allow_public: document.getElementById('w-public').checked ? 1 : 0,
  }
  if (body.target_kind === 'cash') {
    body.target_waz = Number(document.getElementById('w-amt').value)
    body.escrow_self = document.getElementById('w-escrow').checked ? 1 : 0
  }
  const r = await POST('/wishes', body)
  if (r?.error) return alert(r.error)
  alert(t('许愿成功') + ` · @${r.wisher_handle}`)
  location.hash = '#wish/' + r.id
}

async function renderWishDetail(app, id) {
  app.innerHTML = `<div style="padding:14px;max-width:760px;margin:0 auto" id="wd-root">${loading$()}</div>`
  const [w, claimsData] = await Promise.all([
    GET('/wishes/' + id),
    GET('/wishes/' + id + '/claims').catch(() => ({ claims: [] })),
  ])
  if (!w || w.error) {
    document.getElementById('wd-root').innerHTML = `<div style="text-align:center;color:#9ca3af;padding:40px 0">${w?.error || t('愿望不存在')}</div>`
    return
  }
  const wishClaims = claimsData?.claims || []
  const canClaim = state.user && w.status === 'open' && !w.is_wisher
  const canProof = state.user && w.is_fulfiller && w.status === 'claimed'
  const canConfirm = state.user && w.is_wisher && w.status === 'claimed' && (w.fulfillments || []).some(f => f.status === 'proof_pending')
  const canCancel = state.user && w.is_wisher && w.status === 'open'
  const canDisclose = state.user && w.status === 'completed' && (w.is_wisher || w.is_fulfiller) && w.allow_public
  const offeredRepay = (w.repayments || []).find(r => r.status === 'offered')
  const canRepay = state.user && w.is_wisher && w.status === 'completed' && !offeredRepay
  const canRespondRepay = state.user && w.is_fulfiller && offeredRepay
  const confirmedFid = (w.fulfillments || []).find(f => f.status === 'confirmed')?.id

  document.getElementById('wd-root').innerHTML = `
    <div style="display:flex;gap:10px;align-items:flex-start;margin-bottom:10px">
      <div style="font-size:32px">${CHARITY_CAT_ICON[w.category]||'🎁'}</div>
      <div style="flex:1">
        <div style="font-weight:700;font-size:16px">${escHtml(w.title)}</div>
        <div class="text-ellipsis" style="font-size:11px;color:#6b7280;margin-top:4px">@${escHtml(w.wisher_handle)} · ${charityCatLabel(w.category)} · ${CHARITY_KIND_LABEL()[w.target_kind]}${w.target_waz ? ' · ' + w.target_waz + ' WAZ' : ''}${w.escrow_locked > 0 ? ' · 🔒 ' + w.escrow_locked + ' WAZ ' + t('已托管') : ''}</div>
      </div>
      <div style="font-size:11px;padding:3px 10px;border-radius:99px;background:${w.status==='open'?'#fef3c7':w.status==='claimed'?'#dbeafe':w.status==='completed'?'#dcfce7':'#f3f4f6'};color:${w.status==='open'?'#92400e':w.status==='claimed'?'#1e40af':w.status==='completed'?'#166534':'#6b7280'}">${charityStatusLabel(w.status)}</div>
    </div>
    <div class="card" style="padding:14px;margin-bottom:14px">
      <div style="font-size:13px;line-height:1.6;white-space:pre-wrap">${escHtml(w.content)}</div>
      <div style="font-size:10px;color:#9ca3af;margin-top:10px;border-top:1px solid #f3f4f6;padding-top:8px">
        ⏰ ${t('有效至')} ${w.expires_at} · 🔐 commit=${w.commit_hash.slice(0,16)}...
        ${w.allow_public ? '· 🌐 ' + t('接受公开') : '· 🔒 ' + t('保持匿名')}
      </div>
    </div>

    ${(w.fulfillments || []).length > 0 ? `
      <div style="margin-bottom:14px">
        <div style="font-size:12px;color:#6b7280;margin-bottom:6px;font-weight:600">${t('圆梦记录')}</div>
        ${w.fulfillments.map(f => {
          const isAuto = f.wisher_sig === 'AUTO_CONFIRM'
          const deadline = f.status === 'proof_pending'
            ? new Date(new Date(f.created_at.replace(' ','T') + 'Z').getTime() + 14 * 86400000).toISOString().slice(0,10)
            : null
          return `
          <div class="card" style="padding:10px;margin-bottom:6px">
            <div style="display:flex;justify-content:space-between;align-items:center">
              <div style="font-size:12px;font-weight:600">@${escHtml(f.fulfiller_handle)}</div>
              <div style="font-size:10px;padding:2px 8px;border-radius:99px;background:${f.status==='confirmed'?(isAuto?'#dbeafe':'#dcfce7'):'#fef3c7'};color:${f.status==='confirmed'?(isAuto?'#1e40af':'#166534'):'#92400e'}">${
                f.status==='confirmed' ? (isAuto ? '⏱ ' + t('超时自动确认') : '✓ ' + t('已确认')) : t('待确认')
              }</div>
            </div>
            ${f.proof_note ? `<div style="font-size:11px;color:#6b7280;margin-top:6px">${escHtml(f.proof_note)}</div>` : ''}
            <div style="font-size:10px;color:#9ca3af;margin-top:6px">proof=${f.proof_hash.slice(0,20)}... · ${f.created_at}</div>
            ${deadline && w.is_wisher ? `<div style="font-size:10px;color:#ea580c;margin-top:4px">⏰ ${t('请在')} ${deadline} ${t('前确认，否则自动判定圆梦成功')}</div>` : ''}
            ${canConfirm && f.status === 'proof_pending' ? `<button class="btn btn-primary btn-sm" onclick="confirmFulfillment('${id}','${f.id}')" style="margin-top:8px;width:100%">${t('确认完成')}</button>` : ''}
            ${f.disclosed_at ? `<div style="font-size:10px;color:#059669;margin-top:6px">🌐 ${t('已公开')}（${f.disclosed_at}）</div>` :
              (f.status === 'confirmed' && (f.disclose_wisher || f.disclose_fulfiller)) ? `<div style="font-size:10px;color:#9ca3af;margin-top:6px">${f.disclose_wisher?t('许愿人'):''}${f.disclose_wisher&&f.disclose_fulfiller?'+':''}${f.disclose_fulfiller?t('施善人'):''} ${t('已申请公开')}</div>` : ''}
          </div>
          `
        }).join('')}
      </div>
    ` : ''}

    ${(w.repayments || []).length > 0 ? `
      <div style="margin:14px 0">
        <div style="font-size:12px;color:#6b7280;margin-bottom:6px;font-weight:600">🙏 ${t('还愿记录')}</div>
        ${w.repayments.map(r => `
          <div class="card" style="padding:10px;margin-bottom:6px;background:${r.status==='offered'?'#fefce8':'#f9fafb'}">
            <div style="display:flex;justify-content:space-between;align-items:center">
              <div style="font-size:13px;font-weight:600">💎 ${r.amount} WAZ</div>
              <div style="font-size:10px;padding:2px 8px;border-radius:99px;background:${
                r.status==='accepted'?'#dcfce7':
                r.status==='declined_to_fund'?'#fef3c7':
                r.status==='expired_auto_accept'?'#dbeafe':
                '#fef9c3'
              };color:${
                r.status==='accepted'?'#166534':
                r.status==='declined_to_fund'?'#92400e':
                r.status==='expired_auto_accept'?'#1e40af':
                '#854d0e'
              }">${charityRepayStatusLabel(r.status)}</div>
            </div>
            ${r.note ? `<div style="font-size:11px;color:#6b7280;margin-top:6px">${escHtml(r.note)}</div>` : ''}
            <div style="font-size:10px;color:#9ca3af;margin-top:6px">${r.created_at}${r.status==='offered' ? ' · ' + t('自动接受于') + ' ' + r.auto_expire_at : ''}</div>
            ${canRespondRepay && r.id === offeredRepay?.id ? `
              <div style="display:flex;gap:6px;margin-top:8px">
                <button class="btn btn-primary btn-sm" onclick="respondRepay('${id}','${r.id}','accept')" style="flex:1">✓ ${t('接受')}</button>
                <button class="btn btn-secondary btn-sm" onclick="respondRepay('${id}','${r.id}','decline_to_fund')" style="flex:1">🌸 ${t('谢绝 · 转入基金')}</button>
              </div>` : ''}
          </div>
        `).join('')}
      </div>
    ` : ''}

    <div style="display:flex;gap:8px;flex-wrap:wrap">
      ${canClaim ? `<button class="btn btn-primary" onclick="claimWish('${id}')" style="flex:1">🤝 ${t('我来圆梦')}</button>` : ''}
      ${canProof ? `<button class="btn btn-primary" onclick="submitProof('${id}')" style="flex:1">📤 ${t('提交证据')}</button>` : ''}
      ${canRepay && confirmedFid ? `<button class="btn btn-primary" onclick="repayWish('${id}','${confirmedFid}')" style="flex:1">🙏 ${t('我要还愿')}</button>` : ''}
      ${canCancel ? `<button class="btn btn-secondary" onclick="cancelWish('${id}')" style="flex:1">${t('取消愿望')}</button>` : ''}
      ${canDisclose ? `<button class="btn btn-secondary" onclick="discloseWish('${id}')" style="flex:1">🌐 ${t('申请公开')}</button>` : ''}
    </div>
    ${state.user && !w.is_wisher ? `
      <div style="margin-top:14px;text-align:right">
        <button onclick="reportWish('${id}')" style="background:none;border:none;color:#9ca3af;font-size:11px;cursor:pointer;text-decoration:underline">⚠ ${t('举报此愿望')}</button>
      </div>
    ` : ''}

    ${renderGenericClaimsBlock({
      claims: wishClaims, ownerId: w.user_id, ownerCheck: 'wisher', objectId: id,
      apiPath: 'wishes', sectionTitle: '🌸 ' + t('声明验证'),
      targets: [
        { value: 'fake_identity', label: t('受助人身份不实') },
        { value: 'fake_story', label: t('故事编造') },
        { value: 'already_fulfilled', label: t('物资已到位但未关闭') },
        { value: 'duplicate', label: t('重复求助') },
        { value: 'inappropriate', label: t('用途不当') },
        { value: 'other', label: t('其他') },
      ],
      targetLabels: {
        fake_identity: t('身份不实'), fake_story: t('故事编造'),
        already_fulfilled: t('已到位'), duplicate: t('重复'),
        inappropriate: t('用途不当'), other: t('其他'),
      },
      submitFn: 'submitWishClaim',
      reRenderFn: 'renderWishDetail',
      user: state.user,
    })}
  `
}

// ─── Sprint 3 通用 claim block 渲染 + 提交 helpers ───────────
function renderGenericClaimsBlock(opts) {
  const { claims, ownerId, objectId, apiPath, sectionTitle, targets, targetLabels, submitFn, reRenderFn, user } = opts
  const isOwner = user && user.id === ownerId
  const canStart = user && !isOwner
  const upheld = claims.filter(c => c.status === 'resolved_upheld')
  const dismissed = claims.filter(c => c.status === 'resolved_dismissed')
  const open = claims.filter(c => c.status === 'open' || c.status === 'sealed')
  const badge = upheld.length > 0
    ? `<span style="background:#fef2f2;color:#991b1b;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600">⚠ ${upheld.length} ${t('项声明被验证不实')}</span>`
    : (dismissed.length > 0 ? `<span style="background:#dcfce7;color:#166534;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600">✓ ${dismissed.length} ${t('项声明验证属实')}</span>`
       : (open.length > 0 ? `<span style="background:#fef3c7;color:#92400e;font-size:11px;padding:2px 8px;border-radius:99px;font-weight:600">⏳ ${open.length} ${t('项验证中')}</span>` : ''))
  const claimRow = (c) => `
    <div style="padding:8px 12px;border-bottom:1px solid #f3f4f6;font-size:12px">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:6px">
        <span style="font-weight:600;color:#374151">${targetLabels[c.claim_target] || c.claim_target}</span>
        <span style="font-size:10px;color:${c.status==='resolved_upheld'?'#dc2626':c.status==='resolved_dismissed'?'#16a34a':'#f59e0b'};font-weight:600">${c.status==='resolved_upheld'?'⚠ '+t('被验证不实'):c.status==='resolved_dismissed'?'✓ '+t('验证属实'):c.status==='sealed'?'⏳ '+t('结算中'):'⏳ '+(c.votes_count||0)+'/3 '+t('票')}</span>
      </div>
      <div style="color:#6b7280;margin-top:4px;line-height:1.4">${escHtml(c.claim_text)}</div>
      <div style="color:#9ca3af;font-size:10px;margin-top:2px">${t('发起人')}：${escHtml(c.claimant_name||'')} · ${fmtTime(c.created_at)}</div>
    </div>`
  return `
    <details ${(claims.length > 0 || canStart) ? '' : 'style="display:none"'} style="margin-top:14px;background:#fff;border:1px solid #e5e7eb;border-radius:8px" ${upheld.length > 0 ? 'open' : ''}>
      <summary style="padding:10px 12px;font-size:14px;font-weight:600;cursor:pointer;display:flex;justify-content:space-between;align-items:center">
        <span>${sectionTitle} (${claims.length})</span>
        ${badge}
      </summary>
      <div style="padding:0">
        ${claims.length === 0 ? `<div style="padding:14px;text-align:center;font-size:12px;color:#9ca3af">${t('暂无声明 — 你可以发起验证')}</div>` : claims.map(claimRow).join('')}
      </div>
      ${canStart ? `
        <div style="padding:10px 12px;border-top:1px solid #f3f4f6">
          <details>
            <summary style="cursor:pointer;font-size:12px;color:#4f46e5;font-weight:600">+ ${t('发起声明验证')}</summary>
            <div style="padding:10px 0">
              <div style="font-size:11px;color:#6b7280;margin-bottom:8px;line-height:1.5">${t('锁定 5 WAZ 质押 · 3 verifier 共识投票')}</div>
              <select id="gcl-target-${objectId}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;margin-bottom:6px">
                ${targets.map(t2 => `<option value="${t2.value}">${escHtml(t2.label)}</option>`).join('')}
              </select>
              <textarea id="gcl-text-${objectId}" rows="3" placeholder="${t('陈述具体不符内容，至少 6 字')}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;margin-bottom:6px"></textarea>
              <input id="gcl-evid-${objectId}" placeholder="${t('证据 URL（可选）')}" style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;margin-bottom:8px">
              <button class="btn btn-primary btn-sm" onclick="${submitFn}('${objectId}','${apiPath}','${reRenderFn}')" style="width:100%">${t('提交声明验证（锁 5 WAZ）')}</button>
              <div id="gcl-msg-${objectId}" style="margin-top:8px"></div>
            </div>
          </details>
        </div>
      ` : ''}
    </details>
  `
}

async function _submitGenericClaim(objectId, apiPath, reRenderFn) {
  const target = document.getElementById(`gcl-target-${objectId}`)?.value
  const text = document.getElementById(`gcl-text-${objectId}`)?.value?.trim()
  const evid = document.getElementById(`gcl-evid-${objectId}`)?.value?.trim()
  const msg = document.getElementById(`gcl-msg-${objectId}`)
  if (!text || text.length < 6) { msg.innerHTML = alert$('error', t('请填写至少 6 字的陈述')); return }
  msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('提交中...')}</div>`
  const res = await POST(`/${apiPath}/${objectId}/claim`, { claim_target: target, claim_text: text, evidence_uri: evid })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  msg.innerHTML = alert$('success', t('声明已发起 — 锁定') + ` ${res.stake_locked} WAZ`)
  if (reRenderFn && window[reRenderFn]) {
    setTimeout(() => window[reRenderFn](document.getElementById('app'), objectId), 1500)
  }
}
window.submitAuctionClaim = (id, path, fn) => _submitGenericClaim(id, path, fn)
window.submitWishClaim = (id, path, fn) => _submitGenericClaim(id, path, fn)

window.voteAuctionClaim = async (claimId, vote) => {
  const msg = document.getElementById(`acl-vote-msg-${claimId}`)
  msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('投票中...')}</div>`
  const res = await POST(`/auction-claims/${claimId}/vote`, { vote })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  msg.innerHTML = alert$('success', `${t('投票成功')} (${res.votes_collected}/3)`)
  setTimeout(() => renderClaimVerify(document.getElementById('app')), 1500)
}

window.voteWishClaim = async (claimId, vote) => {
  const msg = document.getElementById(`wcl-vote-msg-${claimId}`)
  msg.innerHTML = `<div class="alert alert-info"><span class="spinner"></span>${t('投票中...')}</div>`
  const res = await POST(`/wish-claims/${claimId}/vote`, { vote })
  if (res.error) { msg.innerHTML = alert$('error', res.error); return }
  msg.innerHTML = alert$('success', `${t('投票成功')} (${res.votes_collected}/3)`)
  setTimeout(() => renderClaimVerify(document.getElementById('app')), 1500)
}

window.reportWish = async (id) => {
  const reasons = { spam: t('垃圾信息'), fraud: t('欺诈'), inappropriate: t('不当内容'), other: t('其他') }
  const key = prompt(t('举报原因: spam / fraud / inappropriate / other'))
  if (!key || !reasons[key]) return alert(t('原因无效'))
  const note = prompt(t('补充说明（可空，≤ 300 字）')) || ''
  const r = await POST(`/wishes/${id}/report`, { reason: key, note })
  if (r?.error) return alert(r.error)
  alert(t('举报已提交') + (r.auto_hidden ? ' · ' + t('已达 3 人 自动隐藏') : ` · ${t('当前举报数')}: ${r.total_reports}`))
}

function charityRepayStatusLabel(s) {
  return t({ offered:'等待响应', accepted:'已接受', declined_to_fund:'已转入基金', expired_auto_accept:'超时默认接受' }[s] || s)
}
function charityBlocklistLabel(code) {
  return t({ self_fulfill_fraud:'禁止圆自己的愿' }[code] || code)
}

window.repayWish = async (id, fid) => {
  const amt = prompt(t('还愿金额 WAZ（自愿，施善人可谢绝转入基金）'))
  if (!amt) return
  const amount = Number(amt)
  if (!Number.isFinite(amount) || amount < 0.1) return alert(t('金额需 ≥ 0.1 WAZ'))
  const note = prompt(t('附言（可空）')) || ''
  const r = await POST(`/wishes/${id}/repay`, { fulfillment_id: fid, amount, note })
  if (r?.error) return alert(r.error)
  alert(t('还愿已发起，等待施善人响应 · 7 天未响应自动接受'))
  renderWishDetail(document.getElementById('app'), id)
}
window.respondRepay = async (id, rid, choice) => {
  const tip = choice === 'accept' ? t('接受还愿？金额到账。') : t('谢绝接受？金额转入慈善基金，你 +2 雅量荣誉。')
  if (!confirm(tip)) return
  const r = await POST(`/wishes/${id}/repay/${rid}/respond`, { choice })
  if (r?.error) return alert(r.error)
  alert(t('已响应'))
  renderWishDetail(document.getElementById('app'), id)
}

window.claimWish = async (id) => {
  if (!confirm(t('确认认领？48 小时内须提交完成证据。'))) return
  const r = await POST(`/wishes/${id}/fulfill`)
  if (r?.error) {
    if (r.blocklist_reason) return alert(charityBlocklistLabel(r.blocklist_reason) + ' · ' + t('解除于') + ' ' + r.blocklist_until)
    return alert(r.error)
  }
  alert(t('已认领，请在 48 小时内提交证据'))
  renderWishDetail(document.getElementById('app'), id)
}
window.submitProof = async (id) => {
  const note = prompt(t('请描述完成情况（≤ 500 字）'))
  if (!note) return
  // 客户端 sha256 作为 proof_hash（用户可选附图链接 etc.）
  const link = prompt(t('可附证据链接或简述（可空）')) || ''
  const proofText = `wish:${id}|note:${note}|link:${link}|ts:${Date.now()}`
  const proofHash = await charitySha256(proofText)
  const r = await POST(`/wishes/${id}/proof`, { proof_hash: proofHash, proof_note: note })
  if (r?.error) return alert(r.error)
  alert(t('证据已提交，等待许愿人确认'))
  renderWishDetail(document.getElementById('app'), id)
}
window.confirmFulfillment = async (id, fid) => {
  if (!confirm(t('确认圆梦完成？将释放任何托管资金。'))) return
  const r = await POST(`/wishes/${id}/confirm`, { fulfillment_id: fid })
  if (r?.error) return alert(r.error)
  alert(t('已确认 · 施善人 +10 威望'))
  renderWishDetail(document.getElementById('app'), id)
}
window.cancelWish = async (id) => {
  if (!confirm(t('确认取消？托管金额将退回。'))) return
  const r = await POST(`/wishes/${id}/cancel`)
  if (r?.error) return alert(r.error)
  renderWishDetail(document.getElementById('app'), id)
}
window.discloseWish = async (id) => {
  if (!confirm(t('申请公开本愿？双方都同意后才会公开到故事板。'))) return
  const r = await POST(`/wishes/${id}/disclose`)
  if (r?.error) return alert(r.error)
  alert(r.disclosed ? t('双方都已同意，本愿已公开') : t('已记录，等待对方同意'))
  renderWishDetail(document.getElementById('app'), id)
}

