// Phase C5 — 我的笔记 列表（创作者后台）
// 2026-05-22 audit P1 backlog：草稿列表管理
// 扫 localStorage 所有 webaz_note_draft_<order_id>[_<parent_id>] key
window.listDrafts = () => {
  const drafts = []
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i)
    if (!k || !k.startsWith('webaz_note_draft_')) continue
    let data = {}
    try { data = JSON.parse(localStorage.getItem(k) || '{}') } catch {}
    if (!data.title && !data.body) continue   // 空草稿不算
    // 解析 key: webaz_note_draft_<order_id> or webaz_note_draft_<order_id>_<parent_id>
    const rest = k.replace('webaz_note_draft_', '')
    const parts = rest.split('_')
    // order_id 是 'ord_xxx' 形式（含下划线）— 智能解析
    let orderId, parentId = null
    if (parts.length >= 3 && parts[0] === 'ord' && (parts[parts.length - 2] === 'shr' || parts[parts.length - 2].startsWith('shr'))) {
      // 末尾是 shr_xxx 转发模式
      orderId = parts.slice(0, parts.length - 2).join('_')
      parentId = parts.slice(parts.length - 2).join('_')
    } else {
      orderId = rest
    }
    drafts.push({ key: k, orderId, parentId, title: data.title || '', body: data.body || '', length: (data.title || '').length + (data.body || '').length })
  }
  return drafts
}

window.openDraftsModal = () => {
  const drafts = listDrafts()
  if (drafts.length === 0) {
    toast$(t('暂无草稿'))
    return
  }
  const rows = drafts.map(d => `
    <div style="border:1px solid #e5e7eb;border-radius:8px;padding:10px;margin-bottom:8px">
      <div style="font-size:13px;font-weight:600;color:#1f2937;margin-bottom:4px">${escHtml(d.title || t('(无标题)'))}</div>
      <div style="font-size:11px;color:#6b7280;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;line-height:1.4">${escHtml(d.body || '(无正文)').slice(0, 120)}</div>
      <div style="font-size:10px;color:#9ca3af;margin-top:4px">${t('订单')} ${d.orderId.slice(-7)} · ${d.length} ${t('字')}${d.parentId ? ' · 🔁 ' + t('转发') : ''}</div>
      <div style="display:flex;gap:4px;margin-top:8px">
        <button class="btn btn-primary btn-sm" style="flex:1;font-size:11px;padding:5px 10px" onclick="closeModal(); navigate('#note-new/${d.orderId}${d.parentId ? '?parent=' + d.parentId : ''}')">📝 ${t('继续编辑')}</button>
        <button class="btn btn-outline btn-sm" style="font-size:11px;padding:5px 10px;color:#dc2626;border-color:#fecaca" onclick="deleteDraft('${d.key}', '${escHtml(d.title || '').replace(/'/g, "\\'")}')">🗑 ${t('删除')}</button>
      </div>
    </div>`).join('')
  _openModal(`
    <h2 style="font-size:16px;font-weight:600;margin-bottom:6px">📋 ${t('我的草稿')}</h2>
    <p style="font-size:11px;color:#6b7280;margin-bottom:14px">${t('共')} ${drafts.length} ${t('个未发布草稿 · 草稿仅保存标题/正文（图片需重新选）')}</p>
    ${rows}
    <button class="btn btn-gray" style="width:100%;margin-top:6px" onclick="closeModal()">${t('关闭')}</button>
  `)
}

window.deleteDraft = async (key, title) => {
  const ok = await confirmModal(t('删除草稿') + ` 「${title || t('(无标题)')}」？\n\n` + t('草稿删除后无法恢复'), '🗑 ' + t('确认删除'), { danger: true })
  if (!ok) return
  try { localStorage.removeItem(key) } catch {}
  toast$(t('草稿已删除'))
  // 重新打开 modal 刷新列表
  closeModal()
  setTimeout(() => openDraftsModal(), 300)
}

